function normalizeVectorBackendMode(modeInput, fallback = "local") {
  const mode = String(modeInput || "").trim().toLowerCase();
  if (mode === "qdrant") return "qdrant";
  if (mode === "local" || mode === "local-index") return "local";
  return fallback === "qdrant" ? "qdrant" : "local";
}

function parseSimpleEnvFileContent(contentInput) {
  const content = String(contentInput || "");
  if (!content.trim()) {
    return [];
  }
  const pairs = [];
  for (const rawLine of content.split(/\r?\n/)) {
    const line = String(rawLine || "").trim();
    if (!line || line.startsWith("#")) {
      continue;
    }
    const match = line.match(/^(?:export\s+)?([A-Za-z_][A-Za-z0-9_]*)\s*=\s*(.*)$/);
    if (!match) {
      continue;
    }
    const key = String(match[1] || "").trim();
    let value = String(match[2] || "").trim();
    if (
      (value.startsWith("\"") && value.endsWith("\""))
      || (value.startsWith("'") && value.endsWith("'"))
    ) {
      value = value.slice(1, -1);
    }
    value = value
      .replace(/\\n/g, "\n")
      .replace(/\\"/g, "\"")
      .replace(/\\'/g, "'");
    pairs.push([key, value]);
  }
  return pairs;
}

function hydrateModelProviderEnvFromLocalFiles() {
  const explicitEnvFile = String(process.env.ARIA_MODEL_ENV_FILE || "").trim();
  const rootDir = resolve(__dirname, "..", "..");
  const candidates = [
    explicitEnvFile,
    resolve(rootDir, ".runtime", "secrets", "model-providers.env"),
    resolve(rootDir, ".runtime", "model-providers.env")
  ].filter(Boolean);
  const allowedPrefixes = [
    "ARIA_MODEL_PROVIDER_",
    "ARIA_MODEL_OPENAI_",
    "OPENAI_"
  ];
  let loadedCount = 0;

  for (const envFile of candidates) {
    if (!existsSync(envFile)) {
      continue;
    }
    let fileText = "";
    try {
      fileText = readFileSync(envFile, "utf8");
    } catch {
      continue;
    }
    const entries = parseSimpleEnvFileContent(fileText);
    for (const [key, value] of entries) {
      if (!allowedPrefixes.some((prefix) => key.startsWith(prefix))) {
        continue;
      }
      if (process.env[key] && String(process.env[key]).trim()) {
        continue;
      }
      process.env[key] = value;
      loadedCount += 1;
    }
    if (loadedCount > 0) {
      break;
    }
  }
}

hydrateModelProviderEnvFromLocalFiles();

function normalizeVectorBackendConfig(input = {}, fallbackInput = null) {
  const fallback = fallbackInput && typeof fallbackInput === "object" ? fallbackInput : {
    mode: normalizeVectorBackendMode(VECTOR_BACKEND_ENV_MODE, "local"),
    qdrant: {
      url: QDRANT_ENV_URL,
      apiKey: QDRANT_ENV_API_KEY,
      collection: QDRANT_ENV_COLLECTION || "aria_memory",
      timeoutMs: QDRANT_ENV_TIMEOUT_MS
    }
  };
  const raw = input && typeof input === "object" ? input : {};
  const rawQdrant = raw.qdrant && typeof raw.qdrant === "object" ? raw.qdrant : {};
  const fallbackQdrant = fallback.qdrant && typeof fallback.qdrant === "object" ? fallback.qdrant : {};
  return {
    mode: normalizeVectorBackendMode(raw.mode, fallback.mode || "local"),
    qdrant: {
      url: String(rawQdrant.url || fallbackQdrant.url || "").trim().replace(/\/+$/, ""),
      apiKey: String(rawQdrant.apiKey || fallbackQdrant.apiKey || "").trim(),
      collection: String(rawQdrant.collection || fallbackQdrant.collection || "aria_memory").trim() || "aria_memory",
      timeoutMs: clampInteger(
        Number(rawQdrant.timeoutMs || fallbackQdrant.timeoutMs || QDRANT_ENV_TIMEOUT_MS),
        QDRANT_ENV_TIMEOUT_MS,
        1000,
        30000
      )
    }
  };
}

let vectorBackendConfig = normalizeVectorBackendConfig();

function isQdrantModeSelected() {
  return normalizeVectorBackendMode(vectorBackendConfig?.mode, "local") === "qdrant";
}

function isQdrantEnabled() {
  return isQdrantModeSelected() && Boolean(String(vectorBackendConfig?.qdrant?.url || "").trim());
}

function vectorBackendRuntimeStatus() {
  if (isQdrantEnabled()) {
    return {
      backend: "qdrant",
      qdrantConfigured: true,
      qdrantStatus: "booting"
    };
  }
  if (isQdrantModeSelected()) {
    return {
      backend: "qdrant_misconfigured",
      qdrantConfigured: false,
      qdrantStatus: "missing_url"
    };
  }
  return {
    backend: "local",
    qdrantConfigured: false,
    qdrantStatus: "disabled"
  };
}

const initialVectorBackendRuntime = vectorBackendRuntimeStatus();
const vectorBackendRuntime = {
  backend: initialVectorBackendRuntime.backend,
  qdrant: {
    configured: initialVectorBackendRuntime.qdrantConfigured,
    url: String(vectorBackendConfig?.qdrant?.url || ""),
    collection: String(vectorBackendConfig?.qdrant?.collection || "aria_memory"),
    ready: false,
    lastCheckAt: "",
    lastWriteAt: "",
    lastSearchAt: "",
    lastError: "",
    lastStatus: initialVectorBackendRuntime.qdrantStatus,
    lastUpsertId: "",
    lastSearchHits: 0
  }
};
let qdrantCollectionReady = false;
let qdrantCollectionReadyAt = 0;
let qdrantEnsurePromise = null;

function applyVectorBackendConfig(nextConfigInput = {}, options = {}) {
  const persistCheck = options && typeof options === "object" ? options : {};
  const fallback = {
    mode: normalizeVectorBackendMode(VECTOR_BACKEND_ENV_MODE, "local"),
    qdrant: {
      url: QDRANT_ENV_URL,
      apiKey: QDRANT_ENV_API_KEY,
      collection: QDRANT_ENV_COLLECTION || "aria_memory",
      timeoutMs: QDRANT_ENV_TIMEOUT_MS
    }
  };
  vectorBackendConfig = normalizeVectorBackendConfig(nextConfigInput, fallback);
  const runtime = vectorBackendRuntimeStatus();
  vectorBackendRuntime.backend = runtime.backend;
  vectorBackendRuntime.qdrant.configured = runtime.qdrantConfigured;
  vectorBackendRuntime.qdrant.url = String(vectorBackendConfig?.qdrant?.url || "");
  vectorBackendRuntime.qdrant.collection = String(vectorBackendConfig?.qdrant?.collection || "aria_memory");
  vectorBackendRuntime.qdrant.ready = false;
  vectorBackendRuntime.qdrant.lastCheckAt = persistCheck.keepMetrics ? vectorBackendRuntime.qdrant.lastCheckAt : "";
  vectorBackendRuntime.qdrant.lastWriteAt = persistCheck.keepMetrics ? vectorBackendRuntime.qdrant.lastWriteAt : "";
  vectorBackendRuntime.qdrant.lastSearchAt = persistCheck.keepMetrics ? vectorBackendRuntime.qdrant.lastSearchAt : "";
  vectorBackendRuntime.qdrant.lastError = "";
  vectorBackendRuntime.qdrant.lastStatus = runtime.qdrantStatus;
  vectorBackendRuntime.qdrant.lastUpsertId = "";
  vectorBackendRuntime.qdrant.lastSearchHits = 0;
  qdrantCollectionReady = false;
  qdrantCollectionReadyAt = 0;
  qdrantEnsurePromise = null;
  if (isQdrantEnabled()) {
    void ensureQdrantCollection();
  }
}

function readVectorBackendConfigFromSystemProfile(profileInput = {}) {
  const profile = profileInput && typeof profileInput === "object" ? profileInput : {};
  const layers = profile.layers && typeof profile.layers === "object" ? profile.layers : {};
  const foundation = layers.foundation && typeof layers.foundation === "object" ? layers.foundation : {};
  const storage = foundation.storage && typeof foundation.storage === "object" ? foundation.storage : {};
  const vectorRuntime = storage.vectorRuntime && typeof storage.vectorRuntime === "object"
    ? storage.vectorRuntime
    : {};
  const qdrant = vectorRuntime.qdrant && typeof vectorRuntime.qdrant === "object" ? vectorRuntime.qdrant : {};
  return normalizeVectorBackendConfig({
    mode: vectorRuntime.mode,
    qdrant: {
      url: qdrant.url,
      collection: qdrant.collection,
      timeoutMs: qdrant.timeoutMs
    }
  });
}

function checkLocalCommandAvailable(command) {
  const safe = String(command || "").trim();
  if (!safe) return false;
  try {
    const result = spawnSync("which", [safe], {
      stdio: "pipe",
      encoding: "utf8"
    });
    return result.status === 0;
  } catch {
    return false;
  }
}

async function probeQdrantHealth(urlInput, timeoutMsInput) {
  const url = String(urlInput || "").trim().replace(/\/+$/, "");
  if (!url) {
    return {
      ok: false,
      reason: "url_missing",
      statusCode: 0,
      detail: "Qdrant URL 为空。"
    };
  }
  const timeoutMs = clampInteger(timeoutMsInput, QDRANT_ENV_TIMEOUT_MS, 1000, 30000);
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const response = await fetch(`${url}/health`, {
      method: "GET",
      signal: controller.signal
    });
    if (!response.ok) {
      return {
        ok: false,
        reason: "health_http_error",
        statusCode: response.status,
        detail: `Qdrant /health 返回 ${response.status}`
      };
    }
    return {
      ok: true,
      reason: "health_ok",
      statusCode: response.status,
      detail: "Qdrant 服务可访问。"
    };
  } catch (error) {
    const isTimeout = error instanceof Error && error.name === "AbortError";
    return {
      ok: false,
      reason: isTimeout ? "health_timeout" : "health_fetch_error",
      statusCode: 0,
      detail: error instanceof Error ? error.message : String(error)
    };
  } finally {
    clearTimeout(timer);
  }
}

async function runMemoryBackendSelfCheck(userState) {
  const checkedAt = new Date().toISOString();
  const mode = isQdrantModeSelected() ? "qdrant" : "local";
  const memoryRuntime = buildMemoryPlaneRuntimeSnapshot(userState);
  const checks = [];
  const suggestions = [];

  checks.push({
    id: "runtime_mode",
    label: "当前模式",
    status: "ok",
    detail: mode === "qdrant" ? "当前为 qdrant 外部向量模式。" : "当前为 local-index 本地模式。"
  });

  if (mode === "local") {
    checks.push({
      id: "local_index",
      label: "本地索引可用性",
      status: "ok",
      detail: "local-index 可直接使用，无需额外服务。"
    });
    suggestions.push({
      id: "keep_local",
      title: "继续使用 local-index（推荐）",
      level: "recommended",
      detail: "你当前环境最稳定，适合小白与单机演示。"
    });
    return {
      checkedAt,
      mode,
      overallStatus: "healthy",
      checks,
      suggestions,
      environment: {
        platform: process.platform,
        node: process.version,
        dockerAvailable: checkLocalCommandAvailable("docker"),
        brewAvailable: checkLocalCommandAvailable("brew")
      },
      runtime: memoryRuntime
    };
  }

  const qdrantUrl = String(vectorBackendConfig?.qdrant?.url || "").trim();
  const qdrantCollection = String(vectorBackendConfig?.qdrant?.collection || "aria_memory").trim() || "aria_memory";
  const qdrantTimeout = clampInteger(vectorBackendConfig?.qdrant?.timeoutMs, QDRANT_ENV_TIMEOUT_MS, 1000, 30000);
  const dockerAvailable = checkLocalCommandAvailable("docker");
  const brewAvailable = checkLocalCommandAvailable("brew");

  checks.push({
    id: "qdrant_config",
    label: "Qdrant 配置",
    status: qdrantUrl ? "ok" : "error",
    detail: qdrantUrl
      ? `URL=${qdrantUrl} · collection=${qdrantCollection} · timeout=${qdrantTimeout}ms`
      : "未配置 Qdrant URL。"
  });

  if (!qdrantUrl) {
    suggestions.push({
      id: "set_qdrant_url",
      title: "先填写 Qdrant URL",
      level: "required",
      detail: "在脑系统页填写 `http://127.0.0.1:6333` 后再点保存。"
    });
    suggestions.push({
      id: "rollback_local",
      title: "一键回滚到 local-index",
      level: "recommended",
      detail: "如果你暂时不部署 Qdrant，先回滚能立即恢复稳定。"
    });
    return {
      checkedAt,
      mode,
      overallStatus: "error",
      checks,
      suggestions,
      environment: {
        platform: process.platform,
        node: process.version,
        dockerAvailable,
        brewAvailable
      },
      runtime: memoryRuntime
    };
  }

  const health = await probeQdrantHealth(qdrantUrl, qdrantTimeout);
  checks.push({
    id: "qdrant_health",
    label: "Qdrant 连通性",
    status: health.ok ? "ok" : "error",
    detail: health.detail
  });

  if (health.ok) {
    suggestions.push({
      id: "keep_qdrant",
      title: "保持 qdrant 模式",
      level: "recommended",
      detail: "外部向量库已连通，可承载更大规模长期记忆。"
    });
    return {
      checkedAt,
      mode,
      overallStatus: "healthy",
      checks,
      suggestions,
      environment: {
        platform: process.platform,
        node: process.version,
        dockerAvailable,
        brewAvailable
      },
      runtime: memoryRuntime
    };
  }

  if (dockerAvailable) {
    suggestions.push({
      id: "start_qdrant_with_docker",
      title: "启动 Qdrant（Docker）",
      level: "recommended",
      detail: "可执行：`docker run -d --name aria-qdrant -p 6333:6333 qdrant/qdrant`"
    });
  } else if (process.platform === "darwin" && brewAvailable) {
    suggestions.push({
      id: "install_docker_desktop",
      title: "先安装 Docker Desktop",
      level: "recommended",
      detail: "可执行：`brew install --cask docker`，安装后再启动 Qdrant。"
    });
  } else {
    suggestions.push({
      id: "prepare_qdrant_runtime",
      title: "准备 Qdrant 运行环境",
      level: "recommended",
      detail: "当前未检测到 Docker，请先安装容器运行环境或改回 local-index。"
    });
  }
  suggestions.push({
    id: "rollback_local",
    title: "一键回滚到 local-index",
    level: "safe",
    detail: "若你现在要马上可用，建议先回滚 local-index。"
  });

  return {
    checkedAt,
    mode,
    overallStatus: "error",
    checks,
    suggestions,
    environment: {
      platform: process.platform,
      node: process.version,
      dockerAvailable,
      brewAvailable
    },
    runtime: memoryRuntime
  };
}

