const RUNTIME_GUARDIAN_MODE_PRESETS = Object.freeze({
  eco: Object.freeze({
    mode: "eco",
    label: "节能",
    queueLimit: 1
  }),
  balanced: Object.freeze({
    mode: "balanced",
    label: "平衡",
    queueLimit: RUNTIME_GUARDIAN_SELF_HEAL_QUEUE_LIMIT
  }),
  peak: Object.freeze({
    mode: "peak",
    label: "高峰",
    queueLimit: Math.max(RUNTIME_GUARDIAN_SELF_HEAL_QUEUE_LIMIT, 6)
  })
});

function normalizeRuntimeGuardianMode(modeInput) {
  const value = String(modeInput || "").trim().toLowerCase();
  if (value === "eco" || value === "peak" || value === "balanced") {
    return value;
  }
  return "balanced";
}

function getRuntimeGuardianModePreset(modeInput) {
  const mode = normalizeRuntimeGuardianMode(modeInput);
  return RUNTIME_GUARDIAN_MODE_PRESETS[mode];
}

const RUNTIME_GUARDIAN_HEAL_ACTIONS = Object.freeze([
  "full_heal",
  "queue_replay",
  "schema_repair"
]);

function normalizeRuntimeGuardianHealAction(actionInput) {
  const value = String(actionInput || "").trim().toLowerCase();
  if (RUNTIME_GUARDIAN_HEAL_ACTIONS.includes(value)) {
    return value;
  }
  return "";
}

function resolveRuntimeGuardianActionFromFlags(executeRepair, executeQueue) {
  if (executeRepair && executeQueue) {
    return "full_heal";
  }
  if (executeQueue) {
    return "queue_replay";
  }
  return "schema_repair";
}

