function isExpansionHostAllowed(hostname) {
  const host = String(hostname || "").trim().toLowerCase();
  if (!host) return false;
  if (host === "localhost" || host === "127.0.0.1" || host === "0.0.0.0") {
    return true;
  }
  const whitelist = getExpansionSecurityWhitelist();
  const allowedHosts = whitelist.hosts;
  if (allowedHosts.length === 0) {
    return false;
  }
  return allowedHosts.some((allowedHost) => matchExpansionHost(host, allowedHost));
}

function isExpansionMimeAllowed(contentType) {
  const normalized = String(contentType || "").toLowerCase();
  if (!normalized) return false;
  const whitelist = getExpansionSecurityWhitelist();
  const allowedMimePrefixes = whitelist.mimePrefixes;
  if (allowedMimePrefixes.length === 0) {
    return false;
  }
  return allowedMimePrefixes.some((prefix) => normalized.startsWith(prefix));
}

function matchExpansionHost(host, allowRule) {
  const rule = String(allowRule || "").trim().toLowerCase();
  if (!rule) return false;
  if (rule === "*") return true;
  if (rule.startsWith("*.")) {
    const suffix = rule.slice(2);
    if (!suffix) return false;
    return host === suffix || host.endsWith(`.${suffix}`);
  }
  return host === rule || host.endsWith(`.${rule}`);
}

function getExpansionSecurityWhitelist() {
  const fallback = DEFAULT_EXPANSION_SECURITY_POLICY.whitelist || {};
  const whitelist = expansionSecurityPolicy?.whitelist || fallback;
  const hosts = uniqueStringArray(whitelist.hosts || fallback.hosts || [], 200)
    .map((item) => String(item || "").trim().toLowerCase())
    .filter(Boolean);
  const mimePrefixes = uniqueStringArray(whitelist.mimePrefixes || fallback.mimePrefixes || [], 80)
    .map((item) => String(item || "").trim().toLowerCase())
    .filter(Boolean);
  return {
    hosts,
    mimePrefixes,
    maxDownloadBytes: getExpansionDownloadLimitBytes()
  };
}

function getExpansionDownloadLimitBytes() {
  const fallback = Number(DEFAULT_EXPANSION_SECURITY_POLICY?.whitelist?.maxDownloadBytes || EXPANSION_MAX_DOWNLOAD_BYTES);
  const raw = Number(expansionSecurityPolicy?.whitelist?.maxDownloadBytes);
  if (!Number.isFinite(raw)) {
    return fallback;
  }
  return Math.max(1024, Math.min(raw, 1024 * 1024 * 300));
}

function getExpansionSandboxProfile(profileIdInput = "") {
  const policyProfiles =
    expansionSecurityPolicy?.sandboxProfiles && typeof expansionSecurityPolicy.sandboxProfiles === "object"
      ? expansionSecurityPolicy.sandboxProfiles
      : DEFAULT_EXPANSION_SECURITY_POLICY.sandboxProfiles;
  const fallbackProfileId = String(
    expansionSecurityPolicy?.defaultSandboxProfile || DEFAULT_EXPANSION_SECURITY_POLICY.defaultSandboxProfile || "standard"
  );
  const requestedId = String(profileIdInput || "").trim();
  const selectedId = requestedId && policyProfiles[requestedId] ? requestedId : fallbackProfileId;
  const profile = policyProfiles[selectedId] || policyProfiles.standard || {
    allowPrefixes: ["content."],
    maxCapabilities: 6,
    requireApproval: false
  };
  const allowPrefixes = uniqueStringArray(profile.allowPrefixes || ["content."], 40);
  return {
    id: selectedId,
    allowPrefixes: allowPrefixes.length > 0 ? allowPrefixes : ["content."],
    maxCapabilities: Number.isFinite(Number(profile.maxCapabilities))
      ? Math.max(1, Math.min(Number(profile.maxCapabilities), 40))
      : 6,
    requireApproval: profile.requireApproval === true
  };
}

function expansionCapabilityAllowed(capability, allowPrefixes) {
  const name = String(capability || "").trim();
  if (!name) return false;
  return allowPrefixes.some((prefixRaw) => {
    const prefix = String(prefixRaw || "").trim();
    if (!prefix) return false;
    if (prefix === "*") return true;
    if (prefix.endsWith("*")) {
      const stem = prefix.slice(0, -1);
      return stem ? name.startsWith(stem) : true;
    }
    return name === prefix || name.startsWith(prefix);
  });
}

function applyExpansionCapabilitySandbox(capabilitiesInput, profileId = "") {
  const profile = getExpansionSandboxProfile(profileId);
  const requested = uniqueStringArray(capabilitiesInput || [], 80);
  const granted = [];
  const restricted = [];
  for (const capability of requested) {
    if (!expansionCapabilityAllowed(capability, profile.allowPrefixes)) {
      restricted.push(capability);
      continue;
    }
    if (granted.length >= profile.maxCapabilities) {
      restricted.push(capability);
      continue;
    }
    granted.push(capability);
  }
  return {
    profileId: profile.id,
    granted,
    restricted,
    maxCapabilities: profile.maxCapabilities,
    requireApproval: profile.requireApproval
  };
}

function sanitizeRelativeDownloadPath(input) {
  const raw = String(input || "").trim();
  const fallback = `downloads/${Date.now()}-artifact.bin`;
  if (!raw) {
    return fallback;
  }
  const normalizedRaw = raw
    .replace(/\\/g, "/")
    .replace(/^\/+/, "")
    .replace(/\.\./g, "")
    .replace(/[^a-zA-Z0-9._/-]/g, "-");
  const safe = normalize(normalizedRaw).replace(/\\/g, "/");
  if (!safe || safe.startsWith("../") || safe.includes("/../")) {
    return fallback;
  }
  return safe;
}

function pathWithinRoot(pathInput, rootInput) {
  const target = resolve(String(pathInput || ""));
  const root = resolve(String(rootInput || ""));
  return target === root || target.startsWith(`${root}/`);
}

function resolveLocalFileDeliveryRoots() {
  const envRootsRaw = String(process.env.ARIA_LOCAL_FILE_ALLOWED_ROOTS || "").trim();
  const envRoots = envRootsRaw
    ? envRootsRaw
        .split(",")
        .map((item) => resolve(String(item || "").trim().replace(/^~(?=\/)/, homedir())))
        .filter(Boolean)
    : [];
  const defaults = [
    resolve(homedir(), "Desktop"),
    resolve(homedir(), "Documents"),
    resolve(homedir(), "Downloads"),
    downloadsDir
  ];
  const dedup = new Set();
  const roots = [];
  for (const root of [...envRoots, ...defaults]) {
    const normalized = resolve(root);
    if (!normalized || dedup.has(normalized)) {
      continue;
    }
    dedup.add(normalized);
    roots.push(normalized);
  }
  return roots;
}

function purgeExpiredLocalFileDeliveryTickets(nowMs = Date.now()) {
  const safeNow = Number.isFinite(nowMs) ? nowMs : Date.now();
  for (const [ticketId, ticket] of localFileDeliveryTickets.entries()) {
    const expiresAt = Number(ticket?.expiresAt || 0);
    if (!Number.isFinite(expiresAt) || expiresAt <= safeNow) {
      localFileDeliveryTickets.delete(ticketId);
    }
  }
}

function createLocalFileDeliveryTicket(filePath, title = "") {
  const absolutePath = resolve(String(filePath || "").trim());
  if (!absolutePath) {
    return {
      ok: false,
      reason: "path_required",
      summary: "文件投递失败：缺少文件路径。"
    };
  }
  const allowedRoots = resolveLocalFileDeliveryRoots();
  const inScope = allowedRoots.some((root) => pathWithinRoot(absolutePath, root));
  if (!inScope) {
    return {
      ok: false,
      reason: "path_not_allowed",
      summary: "文件投递失败：文件不在允许目录。",
      path: absolutePath
    };
  }
  if (!existsSync(absolutePath)) {
    return {
      ok: false,
      reason: "file_missing",
      summary: "文件投递失败：目标文件不存在。",
      path: absolutePath
    };
  }
  let stats;
  try {
    stats = statSync(absolutePath);
  } catch (error) {
    return {
      ok: false,
      reason: "file_stat_failed",
      summary: "文件投递失败：无法读取文件状态。",
      error: error instanceof Error ? error.message : String(error)
    };
  }
  if (!stats.isFile()) {
    return {
      ok: false,
      reason: "not_regular_file",
      summary: "文件投递失败：目标不是普通文件。",
      path: absolutePath
    };
  }
  if (stats.size > LOCAL_FILE_DELIVERY_MAX_BYTES) {
    return {
      ok: false,
      reason: "file_too_large",
      summary: `文件投递失败：文件超过大小限制（${LOCAL_FILE_DELIVERY_MAX_BYTES} bytes）。`,
      path: absolutePath,
      size: stats.size
    };
  }
  purgeExpiredLocalFileDeliveryTickets();
  const nowMs = Date.now();
  const ticketId = `lf-${randomUUID()}`;
  const expiresAt = nowMs + Math.max(60 * 1000, LOCAL_FILE_DELIVERY_TICKET_TTL_MS);
  const ticket = {
    id: ticketId,
    path: absolutePath,
    title: String(title || "").trim(),
    name: absolutePath.split("/").pop() || "file.bin",
    size: stats.size,
    createdAt: nowMs,
    expiresAt
  };
  localFileDeliveryTickets.set(ticketId, ticket);
  return {
    ok: true,
    reason: "ticket_created",
    ticketId,
    ticket: {
      id: ticket.id,
      title: ticket.title || ticket.name,
      path: ticket.path,
      name: ticket.name,
      size: ticket.size,
      expiresAt: new Date(ticket.expiresAt).toISOString(),
      downloadUrl: `${PUBLIC_API_BASE}/v1/public/files/${ticket.id}`
    }
  };
}

function extractLocalFileDeliveryTicketId(input) {
  const raw = String(input || "").trim();
  if (!raw) {
    return "";
  }
  const direct = raw.match(/^(lf-[a-zA-Z0-9_-]{12,120})$/);
  if (direct) {
    return String(direct[1] || "").trim();
  }
  const pathMatched = raw.match(/\/v1\/public\/files\/([a-zA-Z0-9_-]{12,120})(?:[/?#]|$)/);
  if (pathMatched) {
    return String(pathMatched[1] || "").trim();
  }
  try {
    const parsed = new URL(raw);
    const matched = String(parsed.pathname || "").match(/\/v1\/public\/files\/([a-zA-Z0-9_-]{12,120})(?:\/|$)/);
    if (matched) {
      return String(matched[1] || "").trim();
    }
  } catch {
    // ignore invalid URL
  }
  return "";
}

function inferMimeTypeByPath(filePath) {
  const lower = String(filePath || "").toLowerCase();
  if (lower.endsWith(".png")) return "image/png";
  if (lower.endsWith(".jpg") || lower.endsWith(".jpeg")) return "image/jpeg";
  if (lower.endsWith(".webp")) return "image/webp";
  if (lower.endsWith(".gif")) return "image/gif";
  if (lower.endsWith(".pdf")) return "application/pdf";
  if (lower.endsWith(".txt")) return "text/plain; charset=utf-8";
  if (lower.endsWith(".md")) return "text/markdown; charset=utf-8";
  if (lower.endsWith(".json")) return "application/json; charset=utf-8";
  if (lower.endsWith(".csv")) return "text/csv; charset=utf-8";
  return "application/octet-stream";
}

function isLoopbackRemoteAddress(addressInput) {
  const address = String(addressInput || "").trim();
  if (!address) return false;
  return address === "::1"
    || address === "127.0.0.1"
    || address === "::ffff:127.0.0.1"
    || address.startsWith("127.");
}

async function safeFetchDownloadArtifact(targetUrl, saveAs) {
  const maxDownloadBytes = getExpansionDownloadLimitBytes();
  let parsed;
  try {
    parsed = new URL(targetUrl);
  } catch {
    return {
      ok: false,
      reason: "invalid_url",
      summary: "URL 无效，无法下载。"
    };
  }

  const protocol = parsed.protocol.toLowerCase();
  if (!["https:", "http:"].includes(protocol)) {
    return {
      ok: false,
      reason: "protocol_not_allowed",
      summary: "仅允许 http/https 下载。"
    };
  }

  if (!isExpansionHostAllowed(parsed.hostname)) {
    return {
      ok: false,
      reason: "host_not_allowed",
      summary: `域名未在白名单：${parsed.hostname}`
    };
  }

  let response;
  try {
    response = await fetch(parsed.toString(), {
      method: "GET",
      redirect: "follow",
      signal: AbortSignal.timeout(20000)
    });
  } catch (error) {
    return {
      ok: false,
      reason: "network_error",
      summary: "下载请求失败。",
      error: error instanceof Error ? error.message : String(error)
    };
  }

  if (!response.ok) {
    return {
      ok: false,
      reason: "download_http_error",
      summary: `下载失败：${response.status} ${response.statusText}`
    };
  }

  const contentLength = Number(response.headers.get("content-length") || 0);
  if (contentLength > maxDownloadBytes) {
    return {
      ok: false,
      reason: "file_too_large",
      summary: `文件超过大小限制（${maxDownloadBytes} bytes）。`
    };
  }

  const contentType = String(response.headers.get("content-type") || "").split(";")[0].trim().toLowerCase();
  if (!isExpansionMimeAllowed(contentType)) {
    return {
      ok: false,
      reason: "mime_not_allowed",
      summary: `文件类型未允许：${contentType || "unknown"}`
    };
  }

  let buffer;
  try {
    const arrayBuffer = await response.arrayBuffer();
    if (arrayBuffer.byteLength > maxDownloadBytes) {
      return {
        ok: false,
        reason: "file_too_large",
        summary: `文件超过大小限制（${maxDownloadBytes} bytes）。`
      };
    }
    buffer = Buffer.from(arrayBuffer);
  } catch (error) {
    return {
      ok: false,
      reason: "read_body_failed",
      summary: "读取下载内容失败。",
      error: error instanceof Error ? error.message : String(error)
    };
  }

  if (!existsSync(downloadsDir)) {
    mkdirSync(downloadsDir, { recursive: true });
  }
  const safeRelative = sanitizeRelativeDownloadPath(saveAs);
  const destinationPath = resolve(downloadsDir, safeRelative);
  if (!destinationPath.startsWith(downloadsDir)) {
    return {
      ok: false,
      reason: "invalid_save_path",
      summary: "保存路径不安全，已拒绝。"
    };
  }
  mkdirSync(dirname(destinationPath), { recursive: true });
  writeFileSync(destinationPath, buffer);
  const sha256 = createHash("sha256").update(buffer).digest("hex");

  return {
    ok: true,
    reason: "download_success",
    savedPath: destinationPath,
    relativePath: safeRelative,
    bytes: buffer.byteLength,
    sha256,
    contentType,
    summary: `下载成功：${safeRelative}（${buffer.byteLength} bytes）`
  };
}

