function normalizeSkillMarketCatalogItem(itemInput = {}, index = 0) {
  const item = itemInput && typeof itemInput === "object" ? itemInput : {};
  const safePackId = String(item.packId || `pack.safe.auto-${index + 1}`)
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9._-]+/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-+|-+$/g, "");
  const safeName = String(item.name || safePackId || `技能-${index + 1}`).trim() || `技能-${index + 1}`;
  const safeSummary = String(item.summary || `${safeName}（自动导入目录）`).trim();
  const safeSource = String(item.source || "").trim() || "catalog://safe-import";
  const aliases = uniqueStringArray([
    ...(Array.isArray(item.aliases) ? item.aliases : []),
    safeName,
    safePackId
  ], 16);
  const capabilities = uniqueStringArray(
    (Array.isArray(item.capabilities) ? item.capabilities : [])
      .map((capability) => String(capability || "").trim())
      .filter((capability) => /^(web\.fetch|file\.download|content\.|skill\.route|runtime\.healthcheck)/.test(capability)),
    12
  );
  return {
    packId: safePackId.startsWith("pack.") ? safePackId : `pack.${safePackId}`,
    name: safeName,
    summary: safeSummary,
    aliases,
    source: safeSource,
    capabilities: capabilities.length > 0
      ? capabilities
      : ["content.summary", "skill.route", "runtime.healthcheck"]
  };
}

function loadSafeSkillMarketCatalogFromDisk() {
  const raw = loadJsonConfigFile(skillMarketSafeCatalogFile, []);
  if (!Array.isArray(raw)) {
    return [];
  }
  return raw
    .map((item, index) => normalizeSkillMarketCatalogItem(item, index))
    .filter((item) => String(item.packId || "").trim());
}

const AUTONOMY_SKILL_MARKET_SAFE_CATALOG = loadSafeSkillMarketCatalogFromDisk();

const AUTONOMY_SKILL_MARKET_CATALOG = (() => {
  const merged = [...AUTONOMY_SKILL_MARKET_BASE_CATALOG, ...AUTONOMY_SKILL_MARKET_SAFE_CATALOG];
  const deduped = [];
  const seenPackIds = new Set();
  for (const item of merged) {
    const packId = String(item?.packId || "").trim().toLowerCase();
    if (!packId || seenPackIds.has(packId)) {
      continue;
    }
    seenPackIds.add(packId);
    deduped.push(item);
  }
  return deduped.slice(0, 120);
})();

