function normalizeQueueStrategy(input, fallback) {
  const raw = input && typeof input === "object" ? input : {};
  const base = fallback && typeof fallback === "object" ? fallback : AUTONOMY_QUEUE_STRATEGY_DEFAULTS.api_call;
  const baseDelayMs = clampInteger(raw.baseDelayMs, base.baseDelayMs, 500, 300000);
  const maxDelayMs = clampInteger(raw.maxDelayMs, base.maxDelayMs, baseDelayMs, 600000);
  return {
    enabled: raw.enabled !== false,
    maxAttempts: clampInteger(raw.maxAttempts, base.maxAttempts, 1, 10),
    baseDelayMs,
    maxDelayMs,
    circuitBreakerThreshold: clampInteger(
      raw.circuitBreakerThreshold,
      base.circuitBreakerThreshold,
      1,
      20
    ),
    circuitOpenMinutes: clampInteger(raw.circuitOpenMinutes, base.circuitOpenMinutes, 1, 240)
  };
}

function createDefaultQueuePolicy() {
  const strategies = {};
  for (const type of AUTONOMY_QUEUE_OPERATION_TYPES) {
    strategies[type] = normalizeQueueStrategy(
      AUTONOMY_QUEUE_STRATEGY_DEFAULTS[type],
      AUTONOMY_QUEUE_STRATEGY_DEFAULTS[type]
    );
  }
  return {
    enabled: true,
    autoProcessOnTick: true,
    processLimit: AUTONOMY_QUEUE_PROCESS_LIMIT,
    strategies
  };
}

function normalizeQueuePolicy(rawInput) {
  const raw = rawInput && typeof rawInput === "object" ? rawInput : {};
  const base = createDefaultQueuePolicy();
  const sourceStrategies = raw.strategies && typeof raw.strategies === "object" ? raw.strategies : {};
  const strategies = {};
  for (const type of AUTONOMY_QUEUE_OPERATION_TYPES) {
    strategies[type] = normalizeQueueStrategy(sourceStrategies[type], base.strategies[type]);
  }
  return {
    enabled: raw.enabled !== false,
    autoProcessOnTick: raw.autoProcessOnTick !== false,
    processLimit: clampInteger(raw.processLimit, base.processLimit, 1, 30),
    strategies
  };
}

function ensureQueuePolicy(autonomy) {
  if (!autonomy.queue || typeof autonomy.queue !== "object") {
    autonomy.queue = createDefaultAutonomyState().queue;
  }
  autonomy.queue.policy = normalizeQueuePolicy(autonomy.queue.policy);
  return autonomy.queue.policy;
}

function getQueueStrategy(autonomy, operationType) {
  const policy = ensureQueuePolicy(autonomy);
  const safeType = AUTONOMY_QUEUE_OPERATION_TYPES.includes(operationType) ? operationType : "api_call";
  return policy.strategies[safeType] || policy.strategies.api_call;
}

function ensureQueueCircuits(queue) {
  if (!queue.circuits || typeof queue.circuits !== "object") {
    queue.circuits = {};
  }
  for (const [type, circuitInput] of Object.entries(queue.circuits)) {
    if (!AUTONOMY_QUEUE_OPERATION_TYPES.includes(type)) {
      delete queue.circuits[type];
      continue;
    }
    const circuit = circuitInput && typeof circuitInput === "object" ? circuitInput : {};
    queue.circuits[type] = {
      operationType: type,
      consecutiveFailures: clampInteger(circuit.consecutiveFailures, 0, 0, 999),
      openUntil: typeof circuit.openUntil === "string" ? circuit.openUntil : "",
      openedAt: typeof circuit.openedAt === "string" ? circuit.openedAt : "",
      lastFailedAt: typeof circuit.lastFailedAt === "string" ? circuit.lastFailedAt : "",
      lastReason: typeof circuit.lastReason === "string" ? circuit.lastReason : "",
      totalOpens: clampInteger(circuit.totalOpens, 0, 0, 9999)
    };
  }
  return queue.circuits;
}

function getQueueCircuit(queue, operationType) {
  const safeType = AUTONOMY_QUEUE_OPERATION_TYPES.includes(operationType) ? operationType : "api_call";
  const circuits = ensureQueueCircuits(queue);
  if (!circuits[safeType]) {
    circuits[safeType] = {
      operationType: safeType,
      consecutiveFailures: 0,
      openUntil: "",
      openedAt: "",
      lastFailedAt: "",
      lastReason: "",
      totalOpens: 0
    };
  }
  return circuits[safeType];
}

function isQueueCircuitOpen(queue, operationType, nowMs = Date.now()) {
  const circuit = getQueueCircuit(queue, operationType);
  const openUntilMs = Date.parse(String(circuit.openUntil || "")) || 0;
  if (openUntilMs > nowMs) {
    return true;
  }
  if (circuit.openUntil) {
    circuit.openUntil = "";
  }
  return false;
}

function markQueueCircuitSuccess(queue, operationType) {
  const circuit = getQueueCircuit(queue, operationType);
  circuit.consecutiveFailures = 0;
  circuit.openUntil = "";
  circuit.openedAt = "";
  circuit.lastReason = "";
}

function markQueueCircuitFailure(queue, operationType, reason, strategy) {
  const circuit = getQueueCircuit(queue, operationType);
  const nowIso = new Date().toISOString();
  circuit.consecutiveFailures += 1;
  circuit.lastReason = String(reason || "");
  circuit.lastFailedAt = nowIso;
  const threshold = clampInteger(strategy.circuitBreakerThreshold, 3, 1, 20);
  if (circuit.consecutiveFailures >= threshold) {
    const openMinutes = clampInteger(strategy.circuitOpenMinutes, 2, 1, 240);
    circuit.openUntil = new Date(Date.now() + openMinutes * 60 * 1000).toISOString();
    circuit.openedAt = nowIso;
    circuit.totalOpens += 1;
    return {
      opened: true,
      openUntil: circuit.openUntil
    };
  }
  return {
    opened: false,
    openUntil: ""
  };
}

