function ensureSharedRuntimeState(storeInput = {}) {
  const store = storeInput && typeof storeInput === "object" ? storeInput : {};
  if (!store.meta || typeof store.meta !== "object") {
    store.meta = {};
  }
  store.meta.schemaVersion = Math.max(
    2,
    clampInteger(Number(store.meta.schemaVersion || 0), 2, 0, 999)
  );
  if (!store.shared || typeof store.shared !== "object") {
    store.shared = {};
  }
  if (!store.shared.autonomy || typeof store.shared.autonomy !== "object") {
    store.shared.autonomy = {};
  }
  const sharedAutonomy = store.shared.autonomy;
  if (!sharedAutonomy.skillLibrary || typeof sharedAutonomy.skillLibrary !== "object") {
    sharedAutonomy.skillLibrary = createDefaultVoyagerSkillLibraryState();
  }
  const holder = {
    skillLibrary: sharedAutonomy.skillLibrary
  };
  sharedAutonomy.skillLibrary = ensureVoyagerSkillLibraryState(holder);
  if (typeof store.shared.updatedAt !== "string") {
    store.shared.updatedAt = "";
  }
  return store;
}

function getSharedVoyagerSkillLibrary(storeInput = null) {
  const activeStore = storeInput && typeof storeInput === "object"
    ? storeInput
    : (runtimeStoreRef && typeof runtimeStoreRef === "object" ? runtimeStoreRef : null);
  if (!activeStore) {
    const holder = {
      skillLibrary: createDefaultVoyagerSkillLibraryState()
    };
    return ensureVoyagerSkillLibraryState(holder);
  }
  ensureSharedRuntimeState(activeStore);
  const sharedAutonomy = activeStore.shared.autonomy;
  const holder = {
    skillLibrary: sharedAutonomy.skillLibrary
  };
  const normalized = ensureVoyagerSkillLibraryState(holder);
  sharedAutonomy.skillLibrary = normalized;
  return normalized;
}

function mergeVoyagerSkillLibraryItems(primaryItemsInput = [], fallbackItemsInput = []) {
  const primaryItems = Array.isArray(primaryItemsInput) ? primaryItemsInput : [];
  const fallbackItems = Array.isArray(fallbackItemsInput) ? fallbackItemsInput : [];
  const mergedMap = new Map();
  for (const sourceItem of fallbackItems) {
    const item = normalizeVoyagerSkillEntry(sourceItem);
    if (!item.id || !item.operationType) {
      continue;
    }
    mergedMap.set(item.id, item);
  }
  for (const sourceItem of primaryItems) {
    const item = normalizeVoyagerSkillEntry(sourceItem);
    if (!item.id || !item.operationType) {
      continue;
    }
    mergedMap.set(item.id, item);
  }
  return Array.from(mergedMap.values()).slice(0, VOYAGER_SKILL_LIBRARY_MAX_ITEMS);
}

function pickLatestIsoValue(...values) {
  let winner = "";
  let winnerMs = 0;
  for (const valueInput of values) {
    const value = String(valueInput || "").trim();
    if (!value) {
      continue;
    }
    const parsedMs = Date.parse(value);
    if (!Number.isFinite(parsedMs) || parsedMs <= 0) {
      if (!winner) {
        winner = value;
      }
      continue;
    }
    if (!winner || parsedMs >= winnerMs) {
      winner = value;
      winnerMs = parsedMs;
    }
  }
  return winner;
}

function buildMergedVoyagerSkillLibraryState(localInput = {}, sharedInput = {}) {
  const localHolder = {
    skillLibrary: localInput
  };
  const sharedHolder = {
    skillLibrary: sharedInput
  };
  const local = ensureVoyagerSkillLibraryState(localHolder);
  const shared = ensureVoyagerSkillLibraryState(sharedHolder);
  return {
    totalLearned: clampInteger(
      Number(local.totalLearned || 0) + Number(shared.totalLearned || 0),
      Number(local.totalLearned || 0) + Number(shared.totalLearned || 0),
      0,
      1000000
    ),
    updatedAt: pickLatestIsoValue(local.updatedAt, shared.updatedAt),
    lastExtractedAt: pickLatestIsoValue(local.lastExtractedAt, shared.lastExtractedAt),
    items: mergeVoyagerSkillLibraryItems(local.items, shared.items)
  };
}

