function normalizeOpenclawFusionProfile(rawInput) {
  const merged = deepMergeConfig(DEFAULT_OPENCLAW_FUSION_PROFILE, rawInput || {});
  const strategyRaw = merged.strategy && typeof merged.strategy === "object" ? merged.strategy : {};
  const architectureRaw = merged.architecture && typeof merged.architecture === "object" ? merged.architecture : {};
  const progressRaw =
    merged.automationProtocol?.progress && typeof merged.automationProtocol.progress === "object"
      ? merged.automationProtocol.progress
      : {};

  const capabilitiesInput = Array.isArray(merged.capabilities) ? merged.capabilities : [];
  const capabilities = [];
  const seenCapabilityIds = new Set();
  for (const capabilityInput of capabilitiesInput) {
    const normalized = normalizeOpenclawFusionCapability(capabilityInput);
    if (!normalized.id || seenCapabilityIds.has(normalized.id)) {
      continue;
    }
    seenCapabilityIds.add(normalized.id);
    capabilities.push(normalized);
  }
  if (capabilities.length === 0) {
    for (const capabilityInput of DEFAULT_OPENCLAW_FUSION_PROFILE.capabilities || []) {
      const normalized = normalizeOpenclawFusionCapability(capabilityInput);
      if (!normalized.id || seenCapabilityIds.has(normalized.id)) {
        continue;
      }
      seenCapabilityIds.add(normalized.id);
      capabilities.push(normalized);
    }
  }

  return {
    version: String(merged.version || DEFAULT_OPENCLAW_FUSION_PROFILE.version),
    enabled: merged.enabled !== false,
    strategy: {
      mode: String(strategyRaw.mode || DEFAULT_OPENCLAW_FUSION_PROFILE.strategy.mode || "reuse-first")
        .trim()
        .toLowerCase(),
      disallowDuplicateBuild:
        strategyRaw.disallowDuplicateBuild !== false
          && merged.strategy?.disallowDuplicateBuild !== false,
      requireExecutionEvidence: strategyRaw.requireExecutionEvidence !== false,
      objective: String(
        strategyRaw.objective || DEFAULT_OPENCLAW_FUSION_PROFILE.strategy.objective || "super-girlfriend-runtime"
      ).trim()
    },
    architecture: {
      gateway: normalizeOpenclawFusionLayer(
        architectureRaw.gateway,
        DEFAULT_OPENCLAW_FUSION_PROFILE.architecture.gateway
      ),
      session: normalizeOpenclawFusionLayer(
        architectureRaw.session,
        DEFAULT_OPENCLAW_FUSION_PROFILE.architecture.session
      ),
      execution: normalizeOpenclawFusionLayer(
        architectureRaw.execution,
        DEFAULT_OPENCLAW_FUSION_PROFILE.architecture.execution
      )
    },
    automationProtocol: {
      progress: {
        longTaskThresholdSec: clampPolicyNumber(
          progressRaw.longTaskThresholdSec,
          DEFAULT_OPENCLAW_FUSION_PROFILE.automationProtocol.progress.longTaskThresholdSec,
          3,
          120
        ),
        intervalSec: clampPolicyNumber(
          progressRaw.intervalSec,
          DEFAULT_OPENCLAW_FUSION_PROFILE.automationProtocol.progress.intervalSec,
          5,
          300
        ),
        blockReportSec: clampPolicyNumber(
          progressRaw.blockReportSec,
          DEFAULT_OPENCLAW_FUSION_PROFILE.automationProtocol.progress.blockReportSec,
          5,
          300
        )
      },
      completionChecklist: uniqueStringArray(
        merged.automationProtocol?.completionChecklist
          || DEFAULT_OPENCLAW_FUSION_PROFILE.automationProtocol.completionChecklist,
        20
      ),
      riskActionsRequireConfirm: uniqueStringArray(
        merged.automationProtocol?.riskActionsRequireConfirm
          || DEFAULT_OPENCLAW_FUSION_PROFILE.automationProtocol.riskActionsRequireConfirm,
        20
      )
    },
    capabilities
  };
}

