function normalizeSuperAutonomyProfile(rawInput) {
  const merged = deepMergeConfig(DEFAULT_SUPER_AUTONOMY_PROFILE, rawInput || {});
  const sourceProductsRaw = merged.sourceProducts && typeof merged.sourceProducts === "object"
    ? merged.sourceProducts
    : {};

  const normalizeSourceProduct = (sourceInput, fallbackInput) => {
    const source = sourceInput && typeof sourceInput === "object" ? sourceInput : {};
    const fallback = fallbackInput && typeof fallbackInput === "object" ? fallbackInput : {};
    return {
      importedCores: uniqueStringArray(source.importedCores || fallback.importedCores || [], 40),
      upgradedCores: uniqueStringArray(source.upgradedCores || fallback.upgradedCores || [], 40)
    };
  };

  const architectureRaw = merged.architecture && typeof merged.architecture === "object"
    ? merged.architecture
    : {};

  const skillInputs = Array.isArray(merged.skillRegistry) ? merged.skillRegistry : [];
  const skills = [];
  const seenSkillIds = new Set();
  for (const skillInput of skillInputs) {
    const skill = normalizeSuperAutonomySkill(skillInput);
    if (!skill.id || seenSkillIds.has(skill.id)) {
      continue;
    }
    seenSkillIds.add(skill.id);
    skills.push(skill);
  }
  if (skills.length === 0) {
    for (const skillInput of DEFAULT_SUPER_AUTONOMY_PROFILE.skillRegistry || []) {
      const skill = normalizeSuperAutonomySkill(skillInput);
      if (!skill.id || seenSkillIds.has(skill.id)) {
        continue;
      }
      seenSkillIds.add(skill.id);
      skills.push(skill);
    }
  }

  const stabilityRaw = merged.stabilityPolicy && typeof merged.stabilityPolicy === "object"
    ? merged.stabilityPolicy
    : {};
  const queueRaw = stabilityRaw.queue && typeof stabilityRaw.queue === "object" ? stabilityRaw.queue : {};
  const circuitRaw = stabilityRaw.circuitBreaker && typeof stabilityRaw.circuitBreaker === "object"
    ? stabilityRaw.circuitBreaker
    : {};
  const targetSloRaw = stabilityRaw.targetSlo && typeof stabilityRaw.targetSlo === "object"
    ? stabilityRaw.targetSlo
    : {};
  const extensionRaw = merged.extensionFreedomPolicy && typeof merged.extensionFreedomPolicy === "object"
    ? merged.extensionFreedomPolicy
    : {};
  const duplicationRaw = merged.duplicationGuard && typeof merged.duplicationGuard === "object"
    ? merged.duplicationGuard
    : {};

  return {
    version: String(merged.version || DEFAULT_SUPER_AUTONOMY_PROFILE.version),
    enabled: merged.enabled !== false,
    mode: String(merged.mode || DEFAULT_SUPER_AUTONOMY_PROFILE.mode || "full-capability-infusion")
      .trim()
      .toLowerCase(),
    objective: String(merged.objective || DEFAULT_SUPER_AUTONOMY_PROFILE.objective || "").trim(),
    sourceProducts: {
      codex: normalizeSourceProduct(
        sourceProductsRaw.codex,
        DEFAULT_SUPER_AUTONOMY_PROFILE.sourceProducts.codex
      ),
      openclaw: normalizeSourceProduct(
        sourceProductsRaw.openclaw,
        DEFAULT_SUPER_AUTONOMY_PROFILE.sourceProducts.openclaw
      ),
      antigravity: normalizeSourceProduct(
        sourceProductsRaw.antigravity,
        DEFAULT_SUPER_AUTONOMY_PROFILE.sourceProducts.antigravity
      )
    },
    architecture: {
      controlPlane: normalizeSuperAutonomyLayer(
        architectureRaw.controlPlane,
        DEFAULT_SUPER_AUTONOMY_PROFILE.architecture.controlPlane
      ),
      executionPlane: normalizeSuperAutonomyLayer(
        architectureRaw.executionPlane,
        DEFAULT_SUPER_AUTONOMY_PROFILE.architecture.executionPlane
      ),
      memoryPlane: normalizeSuperAutonomyLayer(
        architectureRaw.memoryPlane,
        DEFAULT_SUPER_AUTONOMY_PROFILE.architecture.memoryPlane
      ),
      reliabilityPlane: normalizeSuperAutonomyLayer(
        architectureRaw.reliabilityPlane,
        DEFAULT_SUPER_AUTONOMY_PROFILE.architecture.reliabilityPlane
      ),
      extensionPlane: normalizeSuperAutonomyLayer(
        architectureRaw.extensionPlane,
        DEFAULT_SUPER_AUTONOMY_PROFILE.architecture.extensionPlane
      )
    },
    skillRegistry: skills,
    stabilityPolicy: {
      targetSlo: {
        p95LatencyMs: clampPolicyNumber(
          targetSloRaw.p95LatencyMs,
          DEFAULT_SUPER_AUTONOMY_PROFILE.stabilityPolicy.targetSlo.p95LatencyMs,
          200,
          120000
        ),
        maxFailureRate: clampPolicyFloat(
          targetSloRaw.maxFailureRate,
          DEFAULT_SUPER_AUTONOMY_PROFILE.stabilityPolicy.targetSlo.maxFailureRate,
          0.001,
          1
        )
      },
      queue: {
        retryBudgetPerTask: clampPolicyNumber(
          queueRaw.retryBudgetPerTask,
          DEFAULT_SUPER_AUTONOMY_PROFILE.stabilityPolicy.queue.retryBudgetPerTask,
          1,
          10
        ),
        backoffMs: clampPolicyNumber(
          queueRaw.backoffMs,
          DEFAULT_SUPER_AUTONOMY_PROFILE.stabilityPolicy.queue.backoffMs,
          100,
          60000
        ),
        deadLetterReplayEnabled: queueRaw.deadLetterReplayEnabled !== false
      },
      circuitBreaker: {
        failureThreshold: clampPolicyNumber(
          circuitRaw.failureThreshold,
          DEFAULT_SUPER_AUTONOMY_PROFILE.stabilityPolicy.circuitBreaker.failureThreshold,
          1,
          20
        ),
        coolDownMs: clampPolicyNumber(
          circuitRaw.coolDownMs,
          DEFAULT_SUPER_AUTONOMY_PROFILE.stabilityPolicy.circuitBreaker.coolDownMs,
          1000,
          600000
        )
      }
    },
    extensionFreedomPolicy: {
      extensibilityLevel: String(
        extensionRaw.extensibilityLevel || DEFAULT_SUPER_AUTONOMY_PROFILE.extensionFreedomPolicy.extensibilityLevel
      ).trim(),
      sandboxRequired: extensionRaw.sandboxRequired !== false,
      signatureRequiredForPrivileged: extensionRaw.signatureRequiredForPrivileged !== false,
      pluginApiVersion: String(
        extensionRaw.pluginApiVersion || DEFAULT_SUPER_AUTONOMY_PROFILE.extensionFreedomPolicy.pluginApiVersion
      ).trim(),
      approvedExtensionChannels: uniqueStringArray(
        extensionRaw.approvedExtensionChannels
          || DEFAULT_SUPER_AUTONOMY_PROFILE.extensionFreedomPolicy.approvedExtensionChannels,
        20
      )
    },
    duplicationGuard: {
      disallowDuplicateImplementation: duplicationRaw.disallowDuplicateImplementation !== false,
      preferReuseEndpoints: uniqueStringArray(
        duplicationRaw.preferReuseEndpoints || DEFAULT_SUPER_AUTONOMY_PROFILE.duplicationGuard.preferReuseEndpoints,
        80
      )
    }
  };
}

function normalizeSceneOrchestrationPolicy(rawInput) {
  const merged = deepMergeConfig(DEFAULT_SCENE_ORCHESTRATION_POLICY, rawInput || {});
  const scenes = {};
  const allowedScenes = ["work", "fun", "life", "love", "coding"];
  for (const scene of allowedScenes) {
    const source = merged.scenes && typeof merged.scenes === "object" ? merged.scenes[scene] : null;
    const fallback = DEFAULT_SCENE_ORCHESTRATION_POLICY.scenes[scene];
    const sourceMemoryStrategy = source?.memoryStrategy && typeof source.memoryStrategy === "object"
      ? source.memoryStrategy
      : null;
    const fallbackMemoryStrategy = fallback?.memoryStrategy && typeof fallback.memoryStrategy === "object"
      ? fallback.memoryStrategy
      : null;
    scenes[scene] = {
      defaultPanel: String(source?.defaultPanel || fallback.defaultPanel),
      mode: String(source?.mode || fallback.mode),
      priority: uniqueStringArray(source?.priority || fallback.priority, 12),
      capabilities: uniqueStringArray(source?.capabilities || fallback?.capabilities || [], 16),
      requiredSkills: uniqueStringArray(source?.requiredSkills || fallback?.requiredSkills || [], 20),
      responseStyle: uniqueStringArray(source?.responseStyle || fallback?.responseStyle || [], 12),
      promptFile: String(source?.promptFile || fallback?.promptFile || "").trim(),
      systemPrompt: sanitizeSceneSystemPromptText(
        source?.systemPrompt || fallback?.systemPrompt || "",
        {
          maxChars: 40000,
          maxLines: 1600
        }
      ),
      memoryStrategy: {
        longTermWeight: clampPolicyFloat(
          sourceMemoryStrategy?.longTermWeight,
          fallbackMemoryStrategy?.longTermWeight ?? 0.6,
          0,
          1
        ),
        shortTermWeight: clampPolicyFloat(
          sourceMemoryStrategy?.shortTermWeight,
          fallbackMemoryStrategy?.shortTermWeight ?? 0.4,
          0,
          1
        ),
        recallTopK: clampPolicyNumber(
          sourceMemoryStrategy?.recallTopK,
          fallbackMemoryStrategy?.recallTopK ?? 6,
          1,
          20
        ),
        allowCrossSceneRecall: sourceMemoryStrategy?.allowCrossSceneRecall !== false
      }
    };
  }

  const panelSceneMap = {};
  const mergedPanelSceneMap =
    merged.panelSceneMap && typeof merged.panelSceneMap === "object" ? merged.panelSceneMap : {};
  for (const [panelId, scene] of Object.entries({
    ...DEFAULT_SCENE_ORCHESTRATION_POLICY.panelSceneMap,
    ...mergedPanelSceneMap
  })) {
    const normalizedScene = String(scene || "").trim();
    panelSceneMap[panelId] = allowedScenes.includes(normalizedScene)
      ? normalizedScene
      : DEFAULT_SCENE_ORCHESTRATION_POLICY.panelSceneMap[panelId] || "love";
  }

  const mergedEventTriggers = merged.eventTriggers && typeof merged.eventTriggers === "object"
    ? merged.eventTriggers
    : {};
  const fallbackEventTriggers = DEFAULT_SCENE_ORCHESTRATION_POLICY.eventTriggers
    && typeof DEFAULT_SCENE_ORCHESTRATION_POLICY.eventTriggers === "object"
    ? DEFAULT_SCENE_ORCHESTRATION_POLICY.eventTriggers
    : {};
  const eventTriggerKeys = new Set([
    ...Object.keys(fallbackEventTriggers),
    ...Object.keys(mergedEventTriggers)
  ]);
  const eventTriggers = {};
  for (const key of eventTriggerKeys) {
    eventTriggers[key] = uniqueStringArray(
      mergedEventTriggers[key] || fallbackEventTriggers[key] || [],
      16
    );
  }

  return {
    version: String(merged.version || DEFAULT_SCENE_ORCHESTRATION_POLICY.version),
    scenes,
    panelSceneMap,
    eventTriggers
  };
}

