function normalizeOpenclawIncidentPlaybook(rawInput) {
  const merged = deepMergeConfig(DEFAULT_OPENCLAW_INCIDENT_PLAYBOOK, rawInput || {});
  const incidentsInput = Array.isArray(merged.incidents) ? merged.incidents : [];
  const incidents = [];
  const seenIds = new Set();
  for (const item of incidentsInput) {
    const normalized = normalizeOpenclawIncidentEntry(item);
    if (!normalized.id || seenIds.has(normalized.id)) {
      continue;
    }
    seenIds.add(normalized.id);
    incidents.push(normalized);
  }
  if (incidents.length === 0) {
    for (const item of DEFAULT_OPENCLAW_INCIDENT_PLAYBOOK.incidents || []) {
      const normalized = normalizeOpenclawIncidentEntry(item);
      if (!normalized.id || seenIds.has(normalized.id)) {
        continue;
      }
      seenIds.add(normalized.id);
      incidents.push(normalized);
    }
  }
  return {
    version: String(merged.version || DEFAULT_OPENCLAW_INCIDENT_PLAYBOOK.version),
    objective: String(merged.objective || DEFAULT_OPENCLAW_INCIDENT_PLAYBOOK.objective).trim(),
    incidents
  };
}

function normalizeAriaPersonaLevel(input, fallback = "L2") {
  const fallbackLevel = String(fallback || "L2").trim().toUpperCase();
  const normalizedFallback = ARIA_PERSONA_LEVELS.includes(fallbackLevel) ? fallbackLevel : "L2";
  const normalized = String(input || "").trim().toUpperCase();
  return ARIA_PERSONA_LEVELS.includes(normalized) ? normalized : normalizedFallback;
}

function normalizeAriaPersonaRuleLines(input, fallbackLines = [], limit = 8) {
  const fallback = uniqueStringArray(fallbackLines, limit)
    .map((item) => String(item || "").trim())
    .filter(Boolean);
  const rows = uniqueStringArray(Array.isArray(input) ? input : fallback, limit)
    .map((item) => String(item || "").trim())
    .filter(Boolean);
  return rows.length > 0 ? rows : fallback;
}

function normalizeAriaPersonaLevelProfile(level, input, fallbackInput = {}) {
  const fallback = fallbackInput && typeof fallbackInput === "object" ? fallbackInput : {};
  const raw = input && typeof input === "object" ? input : {};
  return {
    label: String(raw.label || fallback.label || level).trim() || level,
    summary: String(raw.summary || fallback.summary || "").trim(),
    autoCapabilityBootstrap: raw.autoCapabilityBootstrap === true
      || (raw.autoCapabilityBootstrap !== false && fallback.autoCapabilityBootstrap === true),
    autoInstallSkills: raw.autoInstallSkills === true
      || (raw.autoInstallSkills !== false && fallback.autoInstallSkills === true),
    autoSelfRepair: raw.autoSelfRepair === true
      || (raw.autoSelfRepair !== false && fallback.autoSelfRepair === true),
    forceAutoRepair: raw.forceAutoRepair === true
      || (raw.forceAutoRepair !== false && fallback.forceAutoRepair === true),
    maxAutoInstallSkills: clampPolicyNumber(raw.maxAutoInstallSkills, fallback.maxAutoInstallSkills || 2, 1, 6),
    outputContract: normalizeAriaPersonaRuleLines(
      raw.outputContract,
      fallback.outputContract || []
    ),
    proactivePolicy: normalizeAriaPersonaRuleLines(
      raw.proactivePolicy,
      fallback.proactivePolicy || []
    ),
    fallbackStyle: String(raw.fallbackStyle || fallback.fallbackStyle || "").trim()
  };
}

function normalizeAriaPersonaIntensityPolicy(rawInput) {
  const merged = deepMergeConfig(DEFAULT_ARIA_PERSONA_INTENSITY_POLICY, rawInput || {});
  const raw = merged && typeof merged === "object"
    ? merged
    : cloneJsonPayload(DEFAULT_ARIA_PERSONA_INTENSITY_POLICY);

  const sceneOverridesInput = raw.sceneOverrides && typeof raw.sceneOverrides === "object"
    ? raw.sceneOverrides
    : {};
  const sceneOverrides = {};
  for (const scene of ARIA_PERSONA_SCENES) {
    const fallbackSceneLevel = DEFAULT_ARIA_PERSONA_INTENSITY_POLICY.sceneOverrides[scene];
    sceneOverrides[scene] = normalizeAriaPersonaLevel(
      sceneOverridesInput[scene],
      fallbackSceneLevel
    );
  }

  const levelsInput = raw.levels && typeof raw.levels === "object" ? raw.levels : {};
  const levels = {};
  for (const level of ARIA_PERSONA_LEVELS) {
    levels[level] = normalizeAriaPersonaLevelProfile(
      level,
      levelsInput[level],
      DEFAULT_ARIA_PERSONA_INTENSITY_POLICY.levels[level]
    );
  }

  const safetyInput = raw.safety && typeof raw.safety === "object" ? raw.safety : {};
  const fallbackSafety = DEFAULT_ARIA_PERSONA_INTENSITY_POLICY.safety;
  const highRiskKeywords = uniqueStringArray(
    safetyInput.highRiskKeywords || fallbackSafety.highRiskKeywords,
    32
  )
    .map((item) => String(item || "").trim())
    .filter(Boolean);

  return {
    enabled: raw.enabled !== false,
    activeLevel: normalizeAriaPersonaLevel(
      raw.activeLevel,
      DEFAULT_ARIA_PERSONA_INTENSITY_POLICY.activeLevel
    ),
    sceneOverrides,
    levels,
    safety: {
      requireHumanConfirmForHighRisk: safetyInput.requireHumanConfirmForHighRisk !== false,
      highRiskKeywords: highRiskKeywords.length > 0
        ? highRiskKeywords
        : cloneJsonPayload(fallbackSafety.highRiskKeywords),
      allowInterruptHotword: String(
        safetyInput.allowInterruptHotword || fallbackSafety.allowInterruptHotword
      ).trim() || fallbackSafety.allowInterruptHotword,
      emergencyStopInstruction: String(
        safetyInput.emergencyStopInstruction || fallbackSafety.emergencyStopInstruction
      ).trim() || fallbackSafety.emergencyStopInstruction
    }
  };
}

function resolveAriaPersonaIntensity(sceneInput = "", taskTypeInput = "") {
  const scene = String(sceneInput || "").trim().toLowerCase();
  const taskType = String(taskTypeInput || "").trim();
  const personaRaw = systemProfile?.layers?.application?.personaIntensity;
  const policy = normalizeAriaPersonaIntensityPolicy(personaRaw);
  const resolvedScene = ARIA_PERSONA_SCENES.includes(scene) ? scene : "";
  const sceneOverrideLevel = resolvedScene
    ? normalizeAriaPersonaLevel(policy.sceneOverrides?.[resolvedScene], "")
    : "";
  const activeLevel = normalizeAriaPersonaLevel(
    sceneOverrideLevel || policy.activeLevel,
    DEFAULT_ARIA_PERSONA_INTENSITY_POLICY.activeLevel
  );
  const levelProfile = policy.levels?.[activeLevel] || policy.levels.L2;
  return {
    enabled: policy.enabled !== false,
    scene: resolvedScene,
    taskType,
    activeLevel,
    sceneOverrideLevel,
    levelProfile,
    safety: policy.safety,
    policy
  };
}

function personaInputLooksHighRisk(input = "", safetyPolicyInput = {}) {
  const text = String(input || "").trim().toLowerCase();
  if (!text) {
    return false;
  }
  const safetyPolicy = safetyPolicyInput && typeof safetyPolicyInput === "object" ? safetyPolicyInput : {};
  const keywords = uniqueStringArray(
    safetyPolicy.highRiskKeywords || DEFAULT_ARIA_PERSONA_INTENSITY_POLICY.safety.highRiskKeywords,
    40
  )
    .map((item) => String(item || "").trim().toLowerCase())
    .filter(Boolean);
  if (keywords.some((keyword) => keyword && text.includes(keyword))) {
    return true;
  }
  return /(password|otp|2fa|token|authorize|bank|payment|transfer|delete|publish|rm\s+-rf|root|sudo|\bssh\b)/i.test(
    text
  );
}

function applyPersonaIntensityToRuleBasedReply(baseText, userInput = "", personaRuntimeInput = {}) {
  const text = String(baseText || "").trim();
  if (!text) {
    return "";
  }
  const personaRuntime = personaRuntimeInput && typeof personaRuntimeInput === "object"
    ? personaRuntimeInput
    : {};
  const level = normalizeAriaPersonaLevel(personaRuntime.activeLevel, "L2");
  const safety = personaRuntime.safety && typeof personaRuntime.safety === "object"
    ? personaRuntime.safety
    : DEFAULT_ARIA_PERSONA_INTENSITY_POLICY.safety;
  const isHighRisk = personaInputLooksHighRisk(userInput, safety);
  const lines = text
    .split(/\n+/)
    .map((item) => String(item || "").trim())
    .filter(Boolean);
  const deduped = [];
  for (const line of lines) {
    if (!deduped.includes(line)) {
      deduped.push(line);
    }
  }
  if (deduped.length === 0) {
    return "";
  }
  const runtimeScene = String(personaRuntime.scene || "").trim().toLowerCase();
  const runtimeTaskType = String(personaRuntime.taskType || "").trim().toLowerCase();
  const suppressExecutionTone = shouldSuppressExecutionToneForScene(runtimeScene, userInput);
  const explicitExecutionIntent = !suppressExecutionTone && chatIntentRequestsExecution(userInput);
  const preferCompanionTone = !explicitExecutionIntent && (
    runtimeTaskType === "emotional_companion"
    || runtimeTaskType === "general_chat"
    || runtimeTaskType === "general"
    || runtimeScene === "love"
    || runtimeScene === "life"
    || runtimeScene === "fun"
  );
  const inferredGoal = inferConciseGoalFromInput(userInput);
  const hasInferredGoal = inferredGoal && inferredGoal !== "当前任务";
  const sharedNextStepLine = preferCompanionTone
    ? (
      hasInferredGoal
        ? pickRandom([
          `下一步：你先缓一口气，我们从「${inferredGoal}」里最轻的一步开始。`,
          `下一步：你点头我就陪你从「${inferredGoal}」的第一小步走起。`,
          `下一步：先把心稳住，我陪你把「${inferredGoal}」拆成一口能咽下的小步。`
        ])
        : pickRandom([
          "下一步：你告诉我现在最想先稳住哪一点，我陪你。",
          "下一步：先喝口水，我在这儿等你一句“继续”。",
          "下一步：你不用急，我们先做最小的一步就好。"
        ])
    )
    : (
      hasInferredGoal
        ? pickRandom([
          `下一步：你拍板优先级后，我先冲「${inferredGoal}」。`,
          `下一步：我先推进「${inferredGoal}」，你补一句时限我就开跑。`,
          `下一步：我按「${inferredGoal}」往下做，卡点我会第一时间回你。`
        ])
        : pickRandom([
          "下一步：你给我一个时限或数量，我继续推进。",
          "下一步：你定优先级，我马上并行推进。",
          "下一步：你补一句关键限制，我直接开做。"
        ])
    );
  const highRiskLine = pickRandom([
    "这类操作有风险，我先和你二次确认再执行。",
    "涉及权限/资金/隐私，我会先等你确认后继续。",
    "这个动作风险较高，我先拿到确认再往下走。"
  ]);

  if (level === "L1") {
    const compact = deduped.slice(0, 2);
    if (isHighRisk) {
      compact.push(highRiskLine);
    } else if (!compact.some((line) => /^下一步[:：]/.test(line))) {
      compact.push(sharedNextStepLine);
    }
    return compact.slice(0, 3).join("\n");
  }

  if (level === "L2") {
    const compact = deduped.slice(0, 3);
    if (isHighRisk) {
      compact.push(highRiskLine);
    } else if (!compact.some((line) => /^下一步[:：]/.test(line))) {
      compact.push(sharedNextStepLine);
    }
    return compact.slice(0, 4).join("\n");
  }

  const advanced = deduped.slice(0, 3);
  if (!advanced.some((line) => /^执行策略[:：]|^陪伴节奏[:：]/.test(line))) {
    const strategyLine = preferCompanionTone
      ? (
        hasInferredGoal
          ? pickRandom([
            `陪伴节奏：我先接住你的情绪，再陪你把「${inferredGoal}」走到可落地。`,
            `陪伴节奏：先让你稳下来，再把「${inferredGoal}」拆成可执行小步。`,
            `陪伴节奏：我会边安抚边推进「${inferredGoal}」，不让你一个人扛。`
          ])
          : pickRandom([
            "陪伴节奏：先把你现在的情绪接住，再一起推进最小一步。",
            "陪伴节奏：我会先稳住你，再给你不费力也能做到的下一步。",
            "陪伴节奏：这轮我先陪你，再把问题慢慢拆开。"
          ])
      )
      : (
        hasInferredGoal
          ? pickRandom([
            `执行策略：我会围绕「${inferredGoal}」并行推进，并在关键节点主动回执。`,
            `执行策略：以「${inferredGoal}」为主线，先快跑关键步骤，再补齐细节。`,
            `执行策略：我先锁定「${inferredGoal}」的高优先级动作，持续给你进展回报。`
          ])
          : pickRandom([
            "执行策略：我会持续跟进目标，并在关键节点主动回执。",
            "执行策略：先推进高价值步骤，再按结果回补细节。",
            "执行策略：我会边执行边汇报，确保你随时可接管。"
          ])
      );
    advanced.push(strategyLine);
  }
  if (isHighRisk) {
    advanced.push(pickRandom([
      "安全闸门：该请求触发高风险确认，收到你确认后我再执行。",
      "安全闸门：这一步会先二次确认，避免误操作。",
      "安全闸门：我先拿到你的明确确认，再推进高风险动作。"
    ]));
  } else if (!advanced.some((line) => /^下一步[:：]/.test(line))) {
    advanced.push(sharedNextStepLine);
  }
  return advanced.slice(0, 5).join("\n");
}

function normalizeSystemProfile(rawInput, modelPolicyInput) {
  const merged = deepMergeConfig(DEFAULT_SYSTEM_PROFILE, rawInput || {});
  const profile = merged && typeof merged === "object" ? merged : cloneJsonPayload(DEFAULT_SYSTEM_PROFILE);
  const validSceneSet = new Set(["work", "fun", "life", "love", "coding"]);

  const layers = profile.layers && typeof profile.layers === "object"
    ? profile.layers
    : cloneJsonPayload(DEFAULT_SYSTEM_PROFILE.layers);
  profile.layers = layers;

  if (!layers.foundation || typeof layers.foundation !== "object") {
    layers.foundation = cloneJsonPayload(DEFAULT_SYSTEM_PROFILE.layers.foundation);
  }
  if (!layers.foundation.storage || typeof layers.foundation.storage !== "object") {
    layers.foundation.storage = cloneJsonPayload(DEFAULT_SYSTEM_PROFILE.layers.foundation.storage);
  }
  const storage = layers.foundation.storage;
  const rawVectorRuntime = storage.vectorRuntime && typeof storage.vectorRuntime === "object"
    ? storage.vectorRuntime
    : {};
  const normalizedVectorConfig = normalizeVectorBackendConfig({
    mode: rawVectorRuntime.mode,
    qdrant: rawVectorRuntime.qdrant
  });
  storage.vectorRuntime = {
    mode: normalizedVectorConfig.mode,
    qdrant: {
      url: normalizedVectorConfig.qdrant.url,
      collection: normalizedVectorConfig.qdrant.collection,
      timeoutMs: normalizedVectorConfig.qdrant.timeoutMs
    }
  };

  if (!layers.technology || typeof layers.technology !== "object") {
    layers.technology = cloneJsonPayload(DEFAULT_SYSTEM_PROFILE.layers.technology);
  }
  if (!layers.technology.bridge || typeof layers.technology.bridge !== "object") {
    layers.technology.bridge = cloneJsonPayload(DEFAULT_SYSTEM_PROFILE.layers.technology.bridge);
  }
  layers.technology.bridge.enabled = layers.technology.bridge.enabled !== false;
  layers.technology.bridge.base = String(layers.technology.bridge.base || BRIDGE_BASE).trim() || BRIDGE_BASE;

  if (!layers.technology.runtimeGuardian || typeof layers.technology.runtimeGuardian !== "object") {
    layers.technology.runtimeGuardian = cloneJsonPayload(
      DEFAULT_SYSTEM_PROFILE.layers.technology.runtimeGuardian
    );
  }
  layers.technology.runtimeGuardian.enabled = layers.technology.runtimeGuardian.enabled !== false;
  layers.technology.runtimeGuardian.watchdog = layers.technology.runtimeGuardian.watchdog !== false;
  layers.technology.runtimeGuardian.autoHeal = layers.technology.runtimeGuardian.autoHeal !== false;

  if (!layers.application || typeof layers.application !== "object") {
    layers.application = cloneJsonPayload(DEFAULT_SYSTEM_PROFILE.layers.application);
  }
  layers.application.enabledScenes = uniqueStringArray(
    layers.application.enabledScenes || DEFAULT_SYSTEM_PROFILE.layers.application.enabledScenes,
    10
  ).filter((scene) => validSceneSet.has(scene));
  if (layers.application.enabledScenes.length === 0) {
    layers.application.enabledScenes = cloneJsonPayload(
      DEFAULT_SYSTEM_PROFILE.layers.application.enabledScenes
    );
  }
  layers.application.personaIntensity = normalizeAriaPersonaIntensityPolicy(
    layers.application.personaIntensity
  );

  if (!layers.model || typeof layers.model !== "object") {
    layers.model = cloneJsonPayload(DEFAULT_SYSTEM_PROFILE.layers.model);
  }
  const providerIds = new Set((modelPolicyInput?.providers || []).map((item) => String(item.id || "")));
  const fallbackDefaultRoute = modelPolicyInput?.providers?.[0]?.id
    || DEFAULT_SYSTEM_PROFILE.layers.model.defaultRoute;
  const fallbackFallbackRoute = modelPolicyInput?.providers?.[1]?.id
    || modelPolicyInput?.providers?.[0]?.id
    || DEFAULT_SYSTEM_PROFILE.layers.model.fallbackRoute;
  const requestedDefaultRoute = String(layers.model.defaultRoute || "").trim();
  const requestedFallbackRoute = String(layers.model.fallbackRoute || "").trim();
  layers.model.defaultRoute = providerIds.has(requestedDefaultRoute)
    ? requestedDefaultRoute
    : fallbackDefaultRoute;
  layers.model.fallbackRoute = providerIds.has(requestedFallbackRoute)
    ? requestedFallbackRoute
    : fallbackFallbackRoute;

  if (!profile.execution || typeof profile.execution !== "object") {
    profile.execution = cloneJsonPayload(DEFAULT_SYSTEM_PROFILE.execution);
  }
  if (!profile.execution.slo || typeof profile.execution.slo !== "object") {
    profile.execution.slo = cloneJsonPayload(DEFAULT_SYSTEM_PROFILE.execution.slo);
  }
  profile.execution.slo.p95LatencyMs = clampPolicyNumber(
    profile.execution.slo.p95LatencyMs,
    DEFAULT_SYSTEM_PROFILE.execution.slo.p95LatencyMs,
    200,
    120000
  );
  profile.execution.slo.maxFailureRate = clampPolicyFloat(
    profile.execution.slo.maxFailureRate,
    DEFAULT_SYSTEM_PROFILE.execution.slo.maxFailureRate,
    0.001,
    1
  );

  profile.version = String(profile.version || DEFAULT_SYSTEM_PROFILE.version);
  profile.product = String(profile.product || DEFAULT_SYSTEM_PROFILE.product);
  return profile;
}

function writeJsonConfigFile(filePath, payload) {
  writeFileSync(filePath, `${JSON.stringify(payload, null, 2)}\n`, "utf8");
}

function ensureJsonConfigFile(filePath, defaultPayload) {
  if (!existsSync(filePath)) {
    writeFileSync(filePath, JSON.stringify(defaultPayload, null, 2), "utf8");
  }
}

function loadJsonConfigFile(filePath, defaultPayload) {
  ensureJsonConfigFile(filePath, defaultPayload);
  try {
    const parsed = JSON.parse(readFileSync(filePath, "utf8"));
    if (parsed && typeof parsed === "object") {
      return parsed;
    }
  } catch {
    return cloneJsonPayload(defaultPayload);
  }
  return cloneJsonPayload(defaultPayload);
}

function clampPolicyNumber(input, fallback, min, max) {
  const parsed = Number.parseInt(String(input ?? ""), 10);
  if (!Number.isFinite(parsed)) {
    return fallback;
  }
  return Math.max(min, Math.min(max, parsed));
}

function normalizeAutonomyPolicy(rawInput) {
  const raw = rawInput && typeof rawInput === "object" ? rawInput : {};
  const autonomy = raw.autonomy && typeof raw.autonomy === "object" ? raw.autonomy : {};
  return {
    version: String(raw.version || DEFAULT_AUTONOMY_POLICY.version),
    autonomy: {
      enabled: autonomy.enabled !== false,
      idleMinutesBeforeNudge: clampPolicyNumber(
        autonomy.idleMinutesBeforeNudge,
        DEFAULT_AUTONOMY_POLICY.autonomy.idleMinutesBeforeNudge,
        3,
        180
      ),
      maxPendingInbox: clampPolicyNumber(
        autonomy.maxPendingInbox,
        DEFAULT_AUTONOMY_POLICY.autonomy.maxPendingInbox,
        1,
        20
      ),
      selfLearningEnabled: autonomy.selfLearningEnabled !== false,
      selfRepairEnabled: autonomy.selfRepairEnabled !== false
    }
  };
}

function loadAutonomyPolicyFromDisk() {
  ensureAutonomyPolicyFile();
  try {
    const raw = JSON.parse(readFileSync(autonomyPolicyFile, "utf8"));
    return normalizeAutonomyPolicy(raw);
  } catch {
    return normalizeAutonomyPolicy(DEFAULT_AUTONOMY_POLICY);
  }
}

function loadSystemProfileFromDisk() {
  const raw = loadJsonConfigFile(systemProfileFile, DEFAULT_SYSTEM_PROFILE);
  const normalizedModel = normalizeModelRoutingPolicy(loadJsonConfigFile(modelRoutingPolicyFile, DEFAULT_MODEL_ROUTING_POLICY));
  return normalizeSystemProfile(raw, normalizedModel);
}

function loadModelRoutingPolicyFromDisk() {
  const raw = loadJsonConfigFile(modelRoutingPolicyFile, DEFAULT_MODEL_ROUTING_POLICY);
  return normalizeModelRoutingPolicy(raw);
}

function loadOpenclawFusionProfileFromDisk() {
  const raw = loadJsonConfigFile(openclawFusionProfileFile, DEFAULT_OPENCLAW_FUSION_PROFILE);
  return normalizeOpenclawFusionProfile(raw);
}

function loadSuperAutonomyProfileFromDisk() {
  const raw = loadJsonConfigFile(superAutonomyProfileFile, DEFAULT_SUPER_AUTONOMY_PROFILE);
  return normalizeSuperAutonomyProfile(raw);
}

function loadExpansionSecurityPolicyFromDisk() {
  const raw = loadJsonConfigFile(expansionSecurityPolicyFile, DEFAULT_EXPANSION_SECURITY_POLICY);
  return normalizeExpansionSecurityPolicy(raw);
}

function resolveScenePromptScene(sceneInput, fallback = "love") {
  const scene = String(sceneInput || "").trim().toLowerCase();
  if (scene === "work" || scene === "fun" || scene === "life" || scene === "love" || scene === "coding") {
    return scene;
  }
  return fallback;
}

function decodeRtfUnicodeChar(codeInput) {
  const parsed = Number.parseInt(String(codeInput || "0"), 10);
  if (!Number.isFinite(parsed)) {
    return "";
  }
  let value = parsed;
  if (value < 0) {
    value = 65536 + value;
  }
  try {
    return String.fromCodePoint(value);
  } catch {
    return "";
  }
}

function stripRtfToPlainText(rtfInput) {
  const rtf = String(rtfInput || "");
  if (!rtf.trim()) {
    return "";
  }
  return rtf
    .replace(/\r\n/g, "\n")
    .replace(/\\\r?\n/g, "")
    .replace(/\\par[d]?/gi, "\n")
    .replace(/\\line/gi, "\n")
    .replace(/\\tab/gi, "\t")
    .replace(/\\u(-?\d+)\??/g, (_, code) => decodeRtfUnicodeChar(code))
    .replace(/\\'([0-9a-fA-F]{2})/g, (_, hex) => {
      const value = Number.parseInt(hex, 16);
      return Number.isFinite(value) ? String.fromCharCode(value) : "";
    })
    .replace(/\\[a-zA-Z]+-?\d* ?/g, "")
    .replace(/[{}]/g, "")
    .replace(/\\\\/g, "\\")
    .replace(/\\~/g, " ")
    .trim();
}

function readScenePromptFile(filePath) {
  const ext = extname(filePath).toLowerCase();
  let text = "";
  if (ext === ".rtf") {
    try {
      const converted = spawnSync("textutil", ["-convert", "txt", "-stdout", filePath], {
        encoding: "utf8",
        timeout: 4000,
        maxBuffer: 8 * 1024 * 1024
      });
      if (converted.status === 0 && typeof converted.stdout === "string" && converted.stdout.trim()) {
        text = converted.stdout;
      }
    } catch {
      text = "";
    }
  }
  if (!text) {
    const raw = readFileSync(filePath, "utf8");
    text = ext === ".rtf" ? stripRtfToPlainText(raw) : raw;
  }
  return sanitizeSceneSystemPromptText(text, {
    maxChars: SCENE_PROMPT_MAX_CHARS,
    maxLines: SCENE_PROMPT_MAX_LINES
  });
}

function resolveScenePromptCandidatePaths(sceneInput) {
  const scene = resolveScenePromptScene(sceneInput);
  const configuredPromptFile = String(sceneOrchestrationPolicy?.scenes?.[scene]?.promptFile || "").trim();
  const candidates = [
    configuredPromptFile,
    ...(Array.isArray(SCENE_PROMPT_FILE_MAP[scene]) ? SCENE_PROMPT_FILE_MAP[scene] : [])
  ];
  const deduped = [];
  const seen = new Set();
  for (const candidate of candidates) {
    const value = String(candidate || "").trim();
    if (!value) {
      continue;
    }
    const normalizedPath = isAbsolute(value) ? value : resolve(scenePromptRootDir, value);
    if (seen.has(normalizedPath)) {
      continue;
    }
    seen.add(normalizedPath);
    deduped.push(normalizedPath);
  }
  return deduped;
}

function loadScenePromptEntryFromDisk(sceneInput) {
  const scene = resolveScenePromptScene(sceneInput);
  const candidatePaths = resolveScenePromptCandidatePaths(scene);
  const loadedAt = new Date().toISOString();
  let promptText = "";
  let sourceFile = "";
  let error = "";
  for (const filePath of candidatePaths) {
    if (!existsSync(filePath)) {
      continue;
    }
    try {
      const nextPrompt = readScenePromptFile(filePath);
      if (nextPrompt) {
        promptText = nextPrompt;
        sourceFile = filePath;
        error = "";
        break;
      }
    } catch (readError) {
      error = readError instanceof Error ? readError.message : String(readError);
    }
  }
  const promptHash = promptText
    ? createHash("sha256").update(promptText).digest("hex").slice(0, 16)
    : "";
  return {
    scene,
    prompt: promptText,
    sourceFile,
    hash: promptHash,
    chars: promptText.length,
    loadedAt,
    error
  };
}

function computeScenePromptSourceSignature() {
  const tokens = [scenePromptRootDir];
  const allScenes = ["work", "fun", "life", "love", "coding"];
  const seen = new Set();
  for (const scene of allScenes) {
    for (const filePath of resolveScenePromptCandidatePaths(scene)) {
      if (seen.has(filePath)) {
        continue;
      }
      seen.add(filePath);
      if (!existsSync(filePath)) {
        tokens.push(`${filePath}:missing`);
        continue;
      }
      try {
        const stats = statSync(filePath);
        tokens.push(`${filePath}:${stats.mtimeMs}:${stats.size}`);
      } catch {
        tokens.push(`${filePath}:error`);
      }
    }
  }
  return createHash("sha256").update(tokens.sort().join("|")).digest("hex").slice(0, 24);
}

function loadScenePromptRegistryFromDisk() {
  const scenes = {};
  const loadedAt = new Date().toISOString();
  for (const scene of ["work", "fun", "life", "love", "coding"]) {
    scenes[scene] = loadScenePromptEntryFromDisk(scene);
  }
  const versionSeed = JSON.stringify(
    Object.fromEntries(
      Object.entries(scenes).map(([scene, value]) => [
        scene,
        {
          hash: value.hash || "",
          sourceFile: value.sourceFile || ""
        }
      ])
    )
  );
  return {
    rootDir: scenePromptRootDir,
    loadedAt,
    version: createHash("sha256").update(versionSeed).digest("hex").slice(0, 16),
    scenes
  };
}

function refreshScenePromptRegistryIfNeeded(options = {}) {
  const force = options.force === true;
  const nextSignature = computeScenePromptSourceSignature();
  if (!force && nextSignature === scenePromptRegistrySignature) {
    return {
      changed: false,
      registry: scenePromptRegistry
    };
  }
  scenePromptRegistry = loadScenePromptRegistryFromDisk();
  scenePromptRegistrySignature = nextSignature;
  return {
    changed: true,
    registry: scenePromptRegistry
  };
}

function resolveActiveScenePrompt(sceneInput, options = {}) {
  const scene = resolveScenePromptScene(sceneInput);
  const context = options && typeof options === "object" ? options : {};
  const refreshed = context.registry && typeof context.registry === "object"
    ? context.registry
    : refreshScenePromptRegistryIfNeeded().registry;
  const sceneEntry = refreshed?.scenes?.[scene] || {};
  const filePrompt = sanitizeSceneSystemPromptText(sceneEntry.prompt || "", {
    maxChars: SCENE_PROMPT_MAX_CHARS,
    maxLines: SCENE_PROMPT_MAX_LINES
  });
  const policyPrompt = sanitizeSceneSystemPromptText(
    sceneOrchestrationPolicy?.scenes?.[scene]?.systemPrompt || "",
    {
      maxChars: SCENE_PROMPT_MAX_CHARS,
      maxLines: SCENE_PROMPT_MAX_LINES
    }
  );
  const prompt = filePrompt || policyPrompt;
  const source = filePrompt
    ? "file"
    : policyPrompt
      ? "scene_policy"
      : "none";
  const sourceFile = filePrompt ? String(sceneEntry.sourceFile || "") : "";
  const hash = prompt
    ? createHash("sha256").update(prompt).digest("hex").slice(0, 16)
    : "";
  return {
    scene,
    prompt,
    source,
    sourceFile,
    hash,
    chars: prompt.length
  };
}

function buildScenePromptRegistryPreview() {
  const refreshed = refreshScenePromptRegistryIfNeeded().registry;
  const scenes = {};
  for (const scene of ["work", "fun", "life", "love", "coding"]) {
    const resolved = resolveActiveScenePrompt(scene, { registry: refreshed });
    const sceneEntry = refreshed?.scenes?.[scene] || {};
    scenes[scene] = {
      enabled: Boolean(resolved.prompt),
      source: resolved.source,
      sourceFile: resolved.sourceFile || sceneEntry.sourceFile || "",
      filename: resolved.sourceFile ? basename(resolved.sourceFile) : "",
      chars: resolved.chars || 0,
      hash: resolved.hash || "",
      loadedAt: sceneEntry.loadedAt || refreshed.loadedAt || "",
      readError: sceneEntry.error || ""
    };
  }
  return {
    rootDir: refreshed?.rootDir || scenePromptRootDir,
    loadedAt: refreshed?.loadedAt || "",
    version: refreshed?.version || "unknown",
    scenes
  };
}

function buildRuleBasedOpeningFromScenePrompt(sceneInput = "", promptInput = "", options = {}) {
  const scene = resolveScenePromptScene(sceneInput);
  const prompt = String(promptInput || "").trim();
  const userInput = String(options?.userInput || "").trim();
  const styleLine = pickSceneStyleLine(scene, userInput, "opening", {
    userState: options?.userState
  });
  if (!prompt) {
    return styleLine;
  }
  const sceneOpenings = {
    coding: [
      "收到，我先对齐目标，再给你可落地实现和验证回执。",
      "好，我先锁定实现边界，再把结果和验证一起交付给你。",
      "明白，我先拆清需求，再按可执行结果给你回执。"
    ],
    work: [
      "收到，我先对齐目标，然后直接推进并同步关键进展。",
      "好，我先确认优先级，接着执行并把结果回给你。",
      "明白，我先抓主目标，边执行边给你清晰反馈。"
    ],
    fun: [
      "来，放轻松，我们马上开玩，节奏我来带。",
      "好呀，我们直接开局，先让互动热起来。",
      "走起，先给你一个有趣开场，再一起接着玩。"
    ],
    life: [
      "好，我会用轻松不压迫的方式，给你实用又能落地的安排。",
      "收到，我先把生活重点理顺，再给你可执行清单。",
      "明白，我先稳住节奏，再给你温和但有效的下一步。"
    ],
    love: [
      "我在，先接住你的感受，再陪你一步步把事理顺。",
      "抱抱你，我先听你这刻最在意的点，然后一起解决。",
      "我在呢，先让你安心下来，我们再一起把问题拆开。"
    ]
  };
  const sceneOpeningCandidates = sceneOpenings[scene] || [];
  if (styleLine) {
    return styleLine;
  }
  if (sceneOpeningCandidates.length > 0) {
    return pickRandom(sceneOpeningCandidates);
  }
  if (scene === "coding") {
    return "收到，我先对齐目标，再给你可落地实现和验证回执。";
  }
  if (scene === "work") {
    return "收到，我先确认目标，然后执行并给你结果和下一步。";
  }
  if (scene === "fun") {
    return "来，轻松一点，我们直接开始互动。";
  }
  if (scene === "life") {
    return "好，我会给你温和提醒和可落地清单。";
  }
  if (scene === "love") {
    return "我在，先接住你的情绪，再一起把问题拆开。";
  }
  if (/代码|编程|调试|修复|补丁|回执|验证|需求/i.test(prompt)) {
    return pickRandom(sceneOpenings.coding);
  }
  if (/工作|目标|执行|步骤|清单|复盘|交付/i.test(prompt)) {
    return pickRandom(sceneOpenings.work);
  }
  if (/娱乐|互动|轻快|游戏|节奏|有趣/i.test(prompt)) {
    return pickRandom(sceneOpenings.fun);
  }
  if (/生活|家人|提醒|习惯|清单|日程/i.test(prompt)) {
    return pickRandom(sceneOpenings.life);
  }
  if (/情感|共情|陪伴|亲密|治愈|安全感/i.test(prompt)) {
    return pickRandom(sceneOpenings.love);
  }
  return "";
}

function mergeRuleBasedReplyWithScenePrompt(sceneInput, replyInput, promptInput, openingInput = "") {
  const reply = String(replyInput || "").trim();
  if (!reply) {
    return "";
  }
  const opening = String(openingInput || "").trim() || buildRuleBasedOpeningFromScenePrompt(sceneInput, promptInput);
  if (!opening) {
    return reply;
  }
  if (reply.startsWith(opening)) {
    return reply;
  }
  if (reply.includes("\n")) {
    return `${opening}\n${reply}`.trim();
  }
  return `${opening} ${reply}`.trim();
}

function loadSceneOrchestrationPolicyFromDisk() {
  const raw = loadJsonConfigFile(sceneOrchestrationPolicyFile, DEFAULT_SCENE_ORCHESTRATION_POLICY);
  return normalizeSceneOrchestrationPolicy(raw);
}

function loadOpenclawIncidentPlaybookFromDisk() {
  const raw = loadJsonConfigFile(openclawIncidentPlaybookFile, DEFAULT_OPENCLAW_INCIDENT_PLAYBOOK);
  return normalizeOpenclawIncidentPlaybook(raw);
}

function ensureDataFile() {
  if (!existsSync(dataDir)) {
    mkdirSync(dataDir, { recursive: true });
  }
  if (!existsSync(dataFile)) {
    writeFileSync(dataFile, JSON.stringify(createStore(), null, 2), "utf8");
  }
}

function loadStore() {
  ensureDataFile();
  try {
    const raw = readFileSync(dataFile, "utf8");
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object" || !parsed.users || !parsed.devices) {
      return createStore();
    }
    return ensureSharedRuntimeState(parsed);
  } catch {
    return createStore();
  }
}

function saveStore(store) {
  ensureDataFile();
  ensureSharedRuntimeState(store);
  writeFileSync(dataFile, JSON.stringify(store, null, 2), "utf8");
}

function parseIsoTimestampMs(valueInput) {
  const parsed = Date.parse(String(valueInput || "").trim());
  if (!Number.isFinite(parsed) || parsed <= 0) {
    return 0;
  }
  return parsed;
}

function shouldPersistGuestAuthTouch(updatedAtInput, nowMs = Date.now()) {
  const lastWriteMs = parseIsoTimestampMs(updatedAtInput);
  if (lastWriteMs <= 0) {
    return true;
  }
  return nowMs - lastWriteMs >= GUEST_AUTH_TOUCH_WRITE_INTERVAL_MS;
}

function pruneStaleGuestUsers(store, options = {}) {
  const users = store?.users && typeof store.users === "object" ? store.users : null;
  if (!users) {
    return {
      removedCount: 0,
      removedUserIds: []
    };
  }
  const nowMs = Number.isFinite(Number(options.nowMs)) ? Number(options.nowMs) : Date.now();
  const retentionMs = clampInteger(
    Number(options.retentionMs),
    GUEST_STORE_PRUNE_RETENTION_MS,
    60 * 60 * 1000,
    365 * 24 * 60 * 60 * 1000
  );
  const maxUsers = clampInteger(Number(options.maxUsers), GUEST_STORE_MAX_USERS, 1, 200000);
  const preserveUserIds = new Set(
    (Array.isArray(options.preserveUserIds) ? options.preserveUserIds : [])
      .map((item) => String(item || "").trim())
      .filter(Boolean)
  );
  const guestEntries = [];
  for (const [userIdRaw, userState] of Object.entries(users)) {
    const userId = String(userIdRaw || "").trim();
    if (!userId || !userState || typeof userState !== "object") {
      continue;
    }
    const profile = userState.profile && typeof userState.profile === "object" ? userState.profile : {};
    if (profile.isGuest === false) {
      continue;
    }
    const updatedMs = Math.max(
      parseIsoTimestampMs(userState.updatedAt),
      parseIsoTimestampMs(profile.updatedAt)
    );
    guestEntries.push({
      userId,
      updatedMs
    });
  }
  if (guestEntries.length === 0) {
    return {
      removedCount: 0,
      removedUserIds: []
    };
  }

  const keepByCount = new Set(
    [...guestEntries]
      .sort((left, right) => right.updatedMs - left.updatedMs)
      .slice(0, maxUsers)
      .map((item) => item.userId)
  );
  const removedUserIds = [];
  for (const entry of guestEntries) {
    if (preserveUserIds.has(entry.userId)) {
      continue;
    }
    const staleByTime = entry.updatedMs <= 0 || nowMs - entry.updatedMs > retentionMs;
    const staleByCapacity = !keepByCount.has(entry.userId);
    if (staleByTime || staleByCapacity) {
      removedUserIds.push(entry.userId);
    }
  }
  if (removedUserIds.length === 0) {
    return {
      removedCount: 0,
      removedUserIds: []
    };
  }

  const removeSet = new Set(removedUserIds);
  for (const userId of removeSet) {
    delete users[userId];
  }
  if (store.devices && typeof store.devices === "object") {
    for (const [bindingKey, boundUserIdRaw] of Object.entries(store.devices)) {
      const boundUserId = String(boundUserIdRaw || "").trim();
      if (boundUserId && removeSet.has(boundUserId)) {
        delete store.devices[bindingKey];
      }
    }
  }
  return {
    removedCount: removedUserIds.length,
    removedUserIds
  };
}

function maybePruneStaleGuestUsers(store, options = {}) {
  const nowMs = Number.isFinite(Number(options.nowMs)) ? Number(options.nowMs) : Date.now();
  const force = options.force === true;
  if (!force && nowMs - guestStoreLastPrunedAtMs < GUEST_STORE_PRUNE_INTERVAL_MS) {
    return {
      removedCount: 0,
      removedUserIds: [],
      skipped: true
    };
  }
  guestStoreLastPrunedAtMs = nowMs;
  const result = pruneStaleGuestUsers(store, {
    nowMs,
    retentionMs: options.retentionMs,
    maxUsers: options.maxUsers,
    preserveUserIds: options.preserveUserIds
  });
  return {
    ...result,
    skipped: false
  };
}

function normalizeXhsPipelineInput(rawInput = {}, options = {}) {
  const raw = rawInput && typeof rawInput === "object" ? rawInput : {};
  const fallbackAssetsDir = resolve(homedir(), "Desktop/xhs-assets");
  const fallbackOutputRoot = resolve(xhsPipelineOutputRoot);
  const theme = String(raw.theme || raw.topic || raw.title || "").trim();
  const assetsDirRaw = String(raw.assetsDir || raw.assetsPath || "").trim();
  const outputRootRaw = String(raw.outputRoot || fallbackOutputRoot).trim();
  return {
    theme,
    assetsDir: resolve(assetsDirRaw || fallbackAssetsDir),
    outputRoot: resolve(outputRootRaw || fallbackOutputRoot),
    publish: raw.publish === true,
    headless: raw.headless === true,
    skipUpload: raw.skipUpload === true,
    model: String(raw.model || "").trim(),
    maxAssets: clampInteger(raw.maxAssets, 8, 1, 24),
    clipDurationImageSec: clampPolicyFloat(raw.clipDurationImageSec, 2.8, 1, 20),
    clipDurationVideoSec: clampPolicyFloat(raw.clipDurationVideoSec, 6, 1, 30),
    nonInteractive: options.nonInteractive !== false
  };
}

function buildXhsPipelineArgs(input) {
  const args = [xhsPipelineScriptFile, "--theme", input.theme, "--assets", input.assetsDir, "--out", input.outputRoot];
  if (input.publish) {
    args.push("--publish");
  }
  if (input.headless) {
    args.push("--headless");
  }
  if (input.skipUpload) {
    args.push("--skip-upload");
  }
  if (input.nonInteractive) {
    args.push("--non-interactive");
  }
  if (input.model) {
    args.push("--model", input.model);
  }
  if (Number.isFinite(Number(input.maxAssets))) {
    args.push("--maxAssets", String(input.maxAssets));
  }
  if (Number.isFinite(Number(input.clipDurationImageSec))) {
    args.push("--clipDurationImageSec", String(input.clipDurationImageSec));
  }
  if (Number.isFinite(Number(input.clipDurationVideoSec))) {
    args.push("--clipDurationVideoSec", String(input.clipDurationVideoSec));
  }
  return args;
}

function sanitizeXhsPipelineJob(jobInput = {}) {
  const job = jobInput && typeof jobInput === "object" ? jobInput : {};
  return {
    id: String(job.id || ""),
    userId: String(job.userId || ""),
    status: String(job.status || "unknown"),
    reason: String(job.reason || ""),
    summary: String(job.summary || ""),
    startedAt: String(job.startedAt || ""),
    updatedAt: String(job.updatedAt || ""),
    finishedAt: String(job.finishedAt || ""),
    exitCode: Number.isFinite(Number(job.exitCode)) ? Number(job.exitCode) : null,
    pid: Number.isFinite(Number(job.pid)) ? Number(job.pid) : 0,
    input: job.input || {},
    outputDir: String(job.outputDir || ""),
    videoFile: String(job.videoFile || ""),
    uploadStatus: String(job.uploadStatus || ""),
    runId: String(job.runId || ""),
    error: String(job.error || ""),
    logs: Array.isArray(job.logs) ? job.logs.slice(-120) : [],
    result: job.result || null
  };
}

function appendXhsPipelineJobLog(jobInput, channel = "stdout", chunkInput = "") {
  const job = jobInput && typeof jobInput === "object" ? jobInput : null;
  if (!job) {
    return;
  }
  const chunk = String(chunkInput || "");
  if (!chunk) {
    return;
  }
  const lines = chunk.split(/\r?\n/).map((line) => String(line || "").trim()).filter(Boolean);
  const nowIso = new Date().toISOString();
  if (!Array.isArray(job.logs)) {
    job.logs = [];
  }
  for (const line of lines) {
    const safeLine = line
      .replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F\u007F]/g, " ")
      .replace(/\s+/g, " ")
      .trim();
    if (!safeLine) {
      continue;
    }
    job.logs.push({
      at: nowIso,
      channel,
      text: safeLine.slice(0, 2000)
    });
    if (safeLine.startsWith("RunID:")) {
      job.runId = safeLine.replace(/^RunID:\s*/i, "").trim();
    } else if (safeLine.startsWith("输出目录:")) {
      const outputDir = safeLine.replace(/^输出目录:\s*/i, "").trim();
      if (outputDir) {
        job.outputDir = resolve(outputDir);
      }
    } else if (safeLine.startsWith("视频文件:")) {
      const videoFile = safeLine.replace(/^视频文件:\s*/i, "").trim();
      if (videoFile) {
        job.videoFile = resolve(videoFile);
      }
    } else if (safeLine.startsWith("上传状态:")) {
      job.uploadStatus = safeLine.replace(/^上传状态:\s*/i, "").trim();
    }
  }
  if (job.logs.length > 240) {
    job.logs = job.logs.slice(-240);
  }
}

function pruneXhsPipelineJobs(maxKeep = 80) {
  const entries = Array.from(xhsPipelineJobs.values());
  if (entries.length <= maxKeep) {
    return;
  }
  const removable = entries
    .filter((item) => String(item.status || "") !== "running" && String(item.status || "") !== "queued")
    .sort((left, right) => {
      const leftMs = Date.parse(String(left.updatedAt || left.startedAt || "")) || 0;
      const rightMs = Date.parse(String(right.updatedAt || right.startedAt || "")) || 0;
      return leftMs - rightMs;
    });
  while (xhsPipelineJobs.size > maxKeep && removable.length > 0) {
    const item = removable.shift();
    if (!item) break;
    xhsPipelineJobs.delete(item.id);
  }
}

function listXhsPipelineJobsForUser(userId, limit = 12) {
  return Array.from(xhsPipelineJobs.values())
    .filter((item) => String(item.userId || "") === String(userId || ""))
    .sort((left, right) => {
      const leftMs = Date.parse(String(left.startedAt || "")) || 0;
      const rightMs = Date.parse(String(right.startedAt || "")) || 0;
      return rightMs - leftMs;
    })
    .slice(0, Math.max(1, Math.min(30, Number(limit || 12))))
    .map((item) => sanitizeXhsPipelineJob(item));
}

function resolveXhsPipelineNextStep(jobInput = null) {
  if (!jobInput || typeof jobInput !== "object") {
    return "第 1 步：填写主题与素材目录；第 2 步：点击“开始执行”；第 3 步：按回执检查上传结果。";
  }
  const job = jobInput;
  const status = String(job.status || "");
  if (status === "running" || status === "queued") {
    return "正在执行：先等待“文案/剪辑/上传”日志完成，再看最终回执。";
  }
  if (status === "completed") {
    const uploadStatus = String(job.uploadStatus || "");
    if (uploadStatus === "skip_upload") {
      return "已完成文案和剪辑。下一步：关闭 skipUpload 后重跑即可自动上传。";
    }
    if (uploadStatus === "uploaded_waiting_publish") {
      return "已上传并填充文案。下一步：在小红书页面手动点击发布。";
    }
    return "流程已闭环完成。下一步：更换主题或素材继续批量执行。";
  }
  const errorText = `${String(job.error || "")} ${String(job.summary || "")}`.toLowerCase();
  if (/登录|login|上传控件|publish/.test(errorText)) {
    return "失败原因偏向登录态。下一步：先登录小红书创作平台，再重试。";
  }
  return "执行失败。下一步：根据日志修正主题/素材目录后重试。";
}

function startXhsPipelineJobForUser(userId, rawInput = {}) {
  const input = normalizeXhsPipelineInput(rawInput, {
    nonInteractive: true
  });
  if (!input.theme) {
    return {
      ok: false,
      reason: "theme_required",
      message: "缺少主题，请先输入主题。"
    };
  }
  if (!existsSync(xhsPipelineScriptFile)) {
    return {
      ok: false,
      reason: "script_missing",
      message: `脚本不存在：${xhsPipelineScriptFile}`
    };
  }
  if (!existsSync(input.assetsDir)) {
    try {
      mkdirSync(input.assetsDir, { recursive: true });
    } catch (error) {
      return {
        ok: false,
        reason: "assets_dir_create_failed",
        message: `素材目录创建失败：${input.assetsDir} (${error instanceof Error ? error.message : String(error)})`
      };
    }
  }
  const running = Array.from(xhsPipelineJobs.values()).find((job) => (
    String(job.userId || "") === String(userId || "")
    && (String(job.status || "") === "running" || String(job.status || "") === "queued")
  ));
  if (running) {
    return {
      ok: false,
      reason: "job_already_running",
      message: "已有执行中的任务，请等待完成后再启动新的任务。",
      job: sanitizeXhsPipelineJob(running)
    };
  }

  const jobId = `xhs-job-${randomUUID()}`;
  const nowIso = new Date().toISOString();
  const args = buildXhsPipelineArgs(input);
  const job = {
    id: jobId,
    userId: String(userId || ""),
    status: "queued",
    reason: "queued",
    summary: "任务已入队，准备执行。",
    startedAt: nowIso,
    updatedAt: nowIso,
    finishedAt: "",
    exitCode: null,
    pid: 0,
    input,
    outputDir: "",
    videoFile: "",
    uploadStatus: "",
    runId: "",
    error: "",
    logs: [],
    result: null,
    child: null
  };
  xhsPipelineJobs.set(jobId, job);
  pruneXhsPipelineJobs(80);

  try {
    const child = spawn(process.execPath, args, {
      cwd: resolve(__dirname, "..", ".."),
      env: process.env,
      stdio: ["ignore", "pipe", "pipe"]
    });
    job.child = child;
    job.pid = Number(child.pid || 0);
    job.status = "running";
    job.reason = "running";
    job.summary = "脚本运行中：文案生成 → 自动剪辑 → 小红书上传。";
    job.updatedAt = new Date().toISOString();
    appendXhsPipelineJobLog(job, "system", `spawn node ${args.join(" ")}`);

    if (child.stdout) {
      child.stdout.on("data", (chunk) => {
        appendXhsPipelineJobLog(job, "stdout", String(chunk || ""));
        job.updatedAt = new Date().toISOString();
      });
    }
    if (child.stderr) {
      child.stderr.on("data", (chunk) => {
        appendXhsPipelineJobLog(job, "stderr", String(chunk || ""));
        job.updatedAt = new Date().toISOString();
      });
    }
    child.on("error", (error) => {
      job.status = "failed";
      job.reason = "spawn_error";
      job.summary = "任务启动失败。";
      job.error = error instanceof Error ? error.message : String(error);
      job.updatedAt = new Date().toISOString();
      job.finishedAt = job.updatedAt;
      appendXhsPipelineJobLog(job, "system", `spawn_error: ${job.error}`);
    });
    child.on("close", (code, signal) => {
      const now = new Date().toISOString();
      job.exitCode = Number.isFinite(Number(code)) ? Number(code) : -1;
      job.updatedAt = now;
      job.finishedAt = now;
      job.child = null;
      if (job.exitCode === 0) {
        job.status = "completed";
        job.reason = "completed";
        job.summary = "流程执行完成。";
      } else {
        job.status = "failed";
        job.reason = signal ? `terminated_${signal}` : "process_exit_non_zero";
        job.summary = "流程执行失败，请查看日志。";
      }
      const outputDir = String(job.outputDir || "").trim();
      if (outputDir) {
        const resultPath = resolve(outputDir, "pipeline-result.json");
        if (existsSync(resultPath)) {
          try {
            const parsed = JSON.parse(readFileSync(resultPath, "utf8"));
            job.result = parsed;
            if (parsed?.video?.output) {
              job.videoFile = String(parsed.video.output);
            }
            if (parsed?.upload?.reason) {
              job.uploadStatus = String(parsed.upload.reason);
            }
            if (parsed?.upload?.error) {
              job.error = String(parsed.upload.error);
            }
          } catch {
            // ignore parse failures
          }
        }
      }
      appendXhsPipelineJobLog(
        job,
        "system",
        `process_closed code=${job.exitCode} signal=${String(signal || "")} status=${job.status}`
      );
      if (!job.error && job.status === "failed") {
        const lastErrorLine = (job.logs || [])
          .slice()
          .reverse()
          .find((item) => String(item.channel || "") === "stderr" || /失败|error|exception/i.test(String(item.text || "")));
        if (lastErrorLine) {
          job.error = String(lastErrorLine.text || "").slice(0, 500);
        }
      }
    });
  } catch (error) {
    job.status = "failed";
    job.reason = "spawn_exception";
    job.summary = "任务启动异常。";
    job.error = error instanceof Error ? error.message : String(error);
    job.updatedAt = new Date().toISOString();
    job.finishedAt = job.updatedAt;
    appendXhsPipelineJobLog(job, "system", `spawn_exception: ${job.error}`);
    return {
      ok: false,
      reason: "spawn_exception",
      message: job.error,
      job: sanitizeXhsPipelineJob(job)
    };
  }

  return {
    ok: true,
    job: sanitizeXhsPipelineJob(job)
  };
}

function createDefaultUserState(userId, options = {}) {
  const state = {
    userId,
    profile: {
      name: options.name || `Guest-${userId.slice(-6)}`,
      platform: options.platform || "unknown",
      isGuest: true
    },
    preferences: {
      mode: "陪伴",
      online: true
    },
    messages: [...defaultMessages],
    memoryHighlights: [
      "用户希望 Aria 语气温柔但执行效率高。",
      "用户在高压时段更需要任务拆解和节奏引导。"
    ],
    memorySystem: createDefaultMemorySystemState(),
    engagement: createDefaultEngagementState(),
    proactive: createDefaultProactiveState(),
    autonomy: createDefaultAutonomyState(),
    workday: createDefaultWorkdayState(),
    deviceOps: createDefaultDeviceOpsState(),
    workbench: createDefaultWorkbenchState(),
    expansion: createDefaultExpansionState(),
    sceneConfig: createDefaultSceneConfigState(),
    funGames: createDefaultFunGamesState(),
    funRuleTemplates: createDefaultFunRuleTemplateState(),
    codingPatchGate: createDefaultCodingPatchGateState(),
    updatedAt: new Date().toISOString()
  };
  ensureSceneMessageVault(state);
  ensureMemoryPlaneState(state);
  return state;
}

function ensureEngagementState(userState) {
  if (!userState.engagement || typeof userState.engagement !== "object") {
    userState.engagement = createDefaultEngagementState();
  }
  const engagement = userState.engagement;

  if (!engagement.today || typeof engagement.today !== "object") {
    engagement.today = createDefaultEngagementState().today;
  }
  if (!Array.isArray(engagement.recentEvents)) {
    engagement.recentEvents = [];
  }
  if (typeof engagement.xp !== "number") {
    engagement.xp = 0;
  }
  if (typeof engagement.streakDays !== "number") {
    engagement.streakDays = 0;
  }
  if (typeof engagement.lastActiveDay !== "string") {
    engagement.lastActiveDay = "";
  }
  if (typeof engagement.lastEventAt !== "string") {
    engagement.lastEventAt = "";
  }
  if (typeof engagement.lastEventType !== "string") {
    engagement.lastEventType = "";
  }
  if (typeof engagement.today.messageCount !== "number") {
    engagement.today.messageCount = 0;
  }
  if (typeof engagement.today.checkinDone !== "boolean") {
    engagement.today.checkinDone = false;
  }
  if (typeof engagement.today.questCompleted !== "boolean") {
    engagement.today.questCompleted = false;
  }
  if (typeof engagement.today.rewardClaimed !== "boolean") {
    engagement.today.rewardClaimed = false;
  }
  if (!engagement.today.date || typeof engagement.today.date !== "string") {
    engagement.today.date = todayKey();
  }

  const nowDay = todayKey();
  if (engagement.today.date !== nowDay) {
    engagement.today = {
      date: nowDay,
      messageCount: 0,
      checkinDone: false,
      questCompleted: false,
      rewardClaimed: false
    };
  }

  engagement.level = calculateLevel(engagement.xp);
  return engagement;
}

function sanitizeEngagement(engagementInput) {
  const engagement = engagementInput || createDefaultEngagementState();
  return {
    xp: engagement.xp,
    level: engagement.level,
    streakDays: engagement.streakDays,
    lastActiveDay: engagement.lastActiveDay,
    lastEventAt: engagement.lastEventAt,
    lastEventType: engagement.lastEventType,
    today: {
      date: engagement.today.date,
      messageCount: engagement.today.messageCount,
      checkinDone: engagement.today.checkinDone,
      questCompleted: engagement.today.questCompleted,
      rewardClaimed: engagement.today.rewardClaimed
    },
    recentEvents: engagement.recentEvents
  };
}

function ensureProactiveState(userState) {
  if (!userState.proactive || typeof userState.proactive !== "object") {
    userState.proactive = createDefaultProactiveState();
  }
  const proactive = userState.proactive;
  if (typeof proactive.todayDate !== "string" || !proactive.todayDate) {
    proactive.todayDate = todayKey();
  }
  if (typeof proactive.sentCount !== "number") {
    proactive.sentCount = 0;
  }
  if (typeof proactive.maxDaily !== "number") {
    proactive.maxDaily = 3;
  }
  if (typeof proactive.cooldownMinutes !== "number") {
    proactive.cooldownMinutes = 90;
  }
  if (!proactive.quietHours || typeof proactive.quietHours !== "object") {
    proactive.quietHours = { start: 23, end: 7 };
  }
  proactive.quietHours.start = clampInteger(proactive.quietHours.start, 23, 0, 23);
  proactive.quietHours.end = clampInteger(proactive.quietHours.end, 7, 0, 23);
  if (typeof proactive.lastSentAt !== "string") {
    proactive.lastSentAt = "";
  }
  if (typeof proactive.lastType !== "string") {
    proactive.lastType = "";
  }
  if (!Array.isArray(proactive.recent)) {
    proactive.recent = [];
  }

  const currentDay = todayKey();
  if (proactive.todayDate !== currentDay) {
    proactive.todayDate = currentDay;
    proactive.sentCount = 0;
  }

  return proactive;
}

function sanitizeProactive(proactiveInput) {
  const proactive = proactiveInput || createDefaultProactiveState();
  return {
    todayDate: proactive.todayDate,
    sentCount: proactive.sentCount,
    maxDaily: proactive.maxDaily,
    cooldownMinutes: proactive.cooldownMinutes,
    quietHours: {
      start: proactive.quietHours.start,
      end: proactive.quietHours.end
    },
    lastSentAt: proactive.lastSentAt,
    lastType: proactive.lastType,
    recent: proactive.recent
  };
}

function normalizeVoyagerDifficulty(valueInput = "", fallback = "L1") {
  const value = String(valueInput || "").trim().toUpperCase();
  if (["L1", "L2", "L3"].includes(value)) {
    return value;
  }
  return ["L1", "L2", "L3"].includes(String(fallback || "").trim().toUpperCase())
    ? String(fallback || "").trim().toUpperCase()
    : "L1";
}

function summarizeOperationPattern(operationInput = {}) {
  const operation = operationInput && typeof operationInput === "object" ? operationInput : {};
  const type = String(operation.type || "").trim();
  if (!type) {
    return "";
  }
  if (type === "web_research") {
    return `query=${String(operation.query || "").trim().slice(0, 80)}`;
  }
  if (type === "research_bundle") {
    return `bundle=${String(operation.title || operation.query || "").trim().slice(0, 80)}`;
  }
  if (type === "skill_discovery") {
    return `query=${String(operation.query || "").trim().slice(0, 80)} autoInstall=${operation.autoInstall === true}`;
  }
  if (type === "structured_template") {
    return `template=${String(operation.templateId || "").trim()}`;
  }
  if (type === "browser_automation") {
    return `mode=${String(operation.mode || "").trim()} url=${String(operation.url || "").trim().slice(0, 80)}`;
  }
  if (type === "channel_send") {
    return `channel=${String(operation.channel || "").trim()}`;
  }
  if (type === "shell_command") {
    return String(operation.command || "").trim().split(/\s+/).slice(0, 6).join(" ");
  }
  if (type === "code_patch_loop") {
    return `cwd=${String(operation.cwd || "").trim()} objective=${String(operation.objective || "").trim().slice(0, 80)}`;
  }
  if (type === "device_task") {
    return `taskType=${String(operation.taskType || "").trim()}`;
  }
  if (type === "file_search") {
    return `query=${String(operation.query || "").trim().slice(0, 80)}`;
  }
  if (type === "api_call") {
    return `${String(operation.method || "GET").toUpperCase()} ${String(operation.url || "").trim().slice(0, 80)}`;
  }
  return "";
}

function normalizeVoyagerSkillSample(sampleInput = {}) {
  const sample = sampleInput && typeof sampleInput === "object" ? sampleInput : {};
  return {
    at: String(sample.at || "").trim(),
    dispatchId: String(sample.dispatchId || "").trim(),
    status: String(sample.status || "").trim().toLowerCase() || "completed",
    summary: String(sample.summary || "").trim().slice(0, 300),
    evidence: Array.isArray(sample.evidence)
      ? sample.evidence.map((item) => String(item || "").trim()).filter(Boolean).slice(0, 6)
      : []
  };
}

function normalizeVoyagerSkillEntry(entryInput = {}) {
  const entry = entryInput && typeof entryInput === "object" ? entryInput : {};
  const samples = Array.isArray(entry.samples)
    ? entry.samples
      .map((item) => normalizeVoyagerSkillSample(item))
      .filter((item) => item.summary || item.dispatchId)
      .slice(0, VOYAGER_SKILL_LIBRARY_MAX_SAMPLES)
    : [];
  const statsInput = entry.stats && typeof entry.stats === "object" ? entry.stats : {};
  const success = clampInteger(statsInput.success, 0, 0, 100000);
  const failed = clampInteger(statsInput.failed, 0, 0, 100000);
  const blocked = clampInteger(statsInput.blocked, 0, 0, 100000);
  const total = clampInteger(statsInput.total, success + failed + blocked, 0, 200000);
  const denominator = Math.max(1, total || success + failed + blocked);
  const successRate = Number((Math.max(0, success) / denominator).toFixed(4));
  return {
    id: String(entry.id || "").trim(),
    name: String(entry.name || "").trim().slice(0, 120),
    scene: normalizeMemoryScene(entry.scene || "work", "work"),
    operationType: String(entry.operationType || "").trim().slice(0, 40),
    signature: String(entry.signature || "").trim().slice(0, 200),
    description: String(entry.description || "").trim().slice(0, 400),
    prerequisites: Array.isArray(entry.prerequisites)
      ? entry.prerequisites.map((item) => String(item || "").trim()).filter(Boolean).slice(0, 10)
      : [],
    reuseHints: Array.isArray(entry.reuseHints)
      ? entry.reuseHints.map((item) => String(item || "").trim()).filter(Boolean).slice(0, 10)
      : [],
    operationPattern: entry.operationPattern && typeof entry.operationPattern === "object"
      ? normalizeQueueOperation(entry.operationPattern)
      : null,
    latestSummary: String(entry.latestSummary || "").trim().slice(0, 300),
    firstLearnedAt: String(entry.firstLearnedAt || "").trim(),
    lastUsedAt: String(entry.lastUsedAt || "").trim(),
    sourceDispatchIds: Array.isArray(entry.sourceDispatchIds)
      ? entry.sourceDispatchIds.map((item) => String(item || "").trim()).filter(Boolean).slice(0, 20)
      : [],
    stats: {
      success,
      failed,
      blocked,
      total: clampInteger(total, success + failed + blocked, 0, 200000),
      successRate
    },
    samples
  };
}

function ensureVoyagerSkillLibraryState(autonomyInput = {}) {
  const autonomy = autonomyInput && typeof autonomyInput === "object" ? autonomyInput : {};
  if (!autonomy.skillLibrary || typeof autonomy.skillLibrary !== "object") {
    autonomy.skillLibrary = createDefaultVoyagerSkillLibraryState();
  }
  const skillLibrary = autonomy.skillLibrary;
  if (typeof skillLibrary.totalLearned !== "number") {
    skillLibrary.totalLearned = 0;
  }
  if (typeof skillLibrary.updatedAt !== "string") {
    skillLibrary.updatedAt = "";
  }
  if (typeof skillLibrary.lastExtractedAt !== "string") {
    skillLibrary.lastExtractedAt = "";
  }
  if (!Array.isArray(skillLibrary.items)) {
    skillLibrary.items = [];
  }
  skillLibrary.items = skillLibrary.items
    .map((item) => normalizeVoyagerSkillEntry(item))
    .filter((item) => item.id && item.operationType)
    .slice(0, VOYAGER_SKILL_LIBRARY_MAX_ITEMS);
  return skillLibrary;
}

function sanitizeVoyagerSkillLibraryState(input = {}, options = {}) {
  const skillLibrary = input && typeof input === "object" ? input : createDefaultVoyagerSkillLibraryState();
  const includePatterns = options && typeof options === "object" ? options.includePatterns === true : false;
  const includeSamples = options && typeof options === "object" ? options.includeSamples === true : false;
  const items = Array.isArray(skillLibrary.items) ? skillLibrary.items : [];
  return {
    totalLearned: clampInteger(skillLibrary.totalLearned, 0, 0, 1000000),
    updatedAt: String(skillLibrary.updatedAt || "").trim(),
    lastExtractedAt: String(skillLibrary.lastExtractedAt || "").trim(),
    totalItems: items.length,
    items: items.slice(0, VOYAGER_SKILL_LIBRARY_MAX_ITEMS).map((item) => ({
      id: String(item.id || "").trim(),
      name: String(item.name || "").trim(),
      scene: normalizeMemoryScene(item.scene || "work", "work"),
      operationType: String(item.operationType || "").trim(),
      signature: String(item.signature || "").trim(),
      description: String(item.description || "").trim(),
      prerequisites: Array.isArray(item.prerequisites) ? item.prerequisites : [],
      reuseHints: Array.isArray(item.reuseHints) ? item.reuseHints : [],
      latestSummary: String(item.latestSummary || "").trim(),
      firstLearnedAt: String(item.firstLearnedAt || "").trim(),
      lastUsedAt: String(item.lastUsedAt || "").trim(),
      stats: item.stats && typeof item.stats === "object"
        ? {
          success: clampInteger(item.stats.success, 0, 0, 100000),
          failed: clampInteger(item.stats.failed, 0, 0, 100000),
          blocked: clampInteger(item.stats.blocked, 0, 0, 100000),
          total: clampInteger(item.stats.total, 0, 0, 200000),
          successRate: Number(item.stats.successRate || 0)
        }
        : {
          success: 0,
          failed: 0,
          blocked: 0,
          total: 0,
          successRate: 0
        },
      score: Number(item.score || 0),
      sourceDispatchIds: Array.isArray(item.sourceDispatchIds) ? item.sourceDispatchIds.slice(0, 20) : [],
      ...(includePatterns ? {
        operationPattern: item.operationPattern && typeof item.operationPattern === "object"
          ? item.operationPattern
          : null
      } : {}),
      ...(includeSamples ? {
        samples: Array.isArray(item.samples)
          ? item.samples.map((sample) => normalizeVoyagerSkillSample(sample)).slice(0, VOYAGER_SKILL_LIBRARY_MAX_SAMPLES)
          : []
      } : {})
    }))
  };
}

function normalizeVoyagerCurriculumTask(taskInput = {}) {
  const task = taskInput && typeof taskInput === "object" ? taskInput : {};
  return {
    id: String(task.id || "").trim(),
    title: String(task.title || "").trim().slice(0, 140),
    objective: String(task.objective || "").trim().slice(0, 500),
    prompt: String(task.prompt || "").trim().slice(0, 500),
    scene: normalizeMemoryScene(task.scene || "work", "work"),
    difficulty: normalizeVoyagerDifficulty(task.difficulty || "L1"),
    status: String(task.status || "generated").trim().toLowerCase(),
    createdAt: String(task.createdAt || "").trim(),
    executedAt: String(task.executedAt || "").trim(),
    dispatchId: String(task.dispatchId || "").trim(),
    dispatchStatus: String(task.dispatchStatus || "").trim().toLowerCase(),
    failureType: String(task.failureType || "").trim(),
    retryable: task.retryable === true,
    missingDependency: String(task.missingDependency || "").trim(),
    dependencySkills: Array.isArray(task.dependencySkills)
      ? task.dependencySkills.map((item) => String(item || "").trim()).filter(Boolean).slice(0, 10)
      : [],
    requiredOperationTypes: Array.isArray(task.requiredOperationTypes)
      ? task.requiredOperationTypes.map((item) => String(item || "").trim()).filter(Boolean).slice(0, 12)
      : [],
    successCriteria: Array.isArray(task.successCriteria)
      ? task.successCriteria.map((item) => String(item || "").trim()).filter(Boolean).slice(0, 12)
      : [],
    rationale: Array.isArray(task.rationale)
      ? task.rationale.map((item) => String(item || "").trim()).filter(Boolean).slice(0, 10)
      : [],
    score: Number(task.score || 0),
    operations: normalizeGoalPlanOperations(task.operations || []),
    alternatives: Array.isArray(task.alternatives)
      ? task.alternatives
        .map((item) => ({
          id: String(item?.id || "").trim(),
          title: String(item?.title || "").trim().slice(0, 120),
          score: Number(item?.score || 0),
          requiredOperationTypes: Array.isArray(item?.requiredOperationTypes)
            ? item.requiredOperationTypes.map((value) => String(value || "").trim()).filter(Boolean).slice(0, 8)
            : []
        }))
        .slice(0, 5)
      : []
  };
}

function ensureVoyagerCurriculumState(autonomyInput = {}) {
  const autonomy = autonomyInput && typeof autonomyInput === "object" ? autonomyInput : {};
  if (!autonomy.curriculum || typeof autonomy.curriculum !== "object") {
    autonomy.curriculum = createDefaultVoyagerCurriculumState();
  }
  const curriculum = autonomy.curriculum;
  if (typeof curriculum.totalGenerated !== "number") {
    curriculum.totalGenerated = 0;
  }
  if (typeof curriculum.totalExecuted !== "number") {
    curriculum.totalExecuted = 0;
  }
  if (typeof curriculum.totalCompleted !== "number") {
    curriculum.totalCompleted = 0;
  }
  if (typeof curriculum.lastGeneratedAt !== "string") {
    curriculum.lastGeneratedAt = "";
  }
  if (typeof curriculum.lastTaskId !== "string") {
    curriculum.lastTaskId = "";
  }
  if (!Array.isArray(curriculum.history)) {
    curriculum.history = [];
  }
  curriculum.history = curriculum.history
    .map((item) => normalizeVoyagerCurriculumTask(item))
    .filter((item) => item.id)
    .slice(0, VOYAGER_CURRICULUM_HISTORY_MAX);
  return curriculum;
}

function sanitizeVoyagerCurriculumTask(taskInput = {}, options = {}) {
  const task = normalizeVoyagerCurriculumTask(taskInput);
  const includeOperations = options && typeof options === "object" ? options.includeOperations === true : false;
  const includePrompt = options && typeof options === "object" ? options.includePrompt === true : false;
  return {
    id: task.id,
    title: task.title,
    objective: task.objective,
    ...(includePrompt ? { prompt: task.prompt } : {}),
    scene: task.scene,
    difficulty: task.difficulty,
    status: task.status,
    createdAt: task.createdAt,
    executedAt: task.executedAt,
    dispatchId: task.dispatchId,
    dispatchStatus: task.dispatchStatus,
    failureType: task.failureType,
    retryable: task.retryable,
    missingDependency: task.missingDependency,
    dependencySkills: task.dependencySkills,
    requiredOperationTypes: task.requiredOperationTypes,
    successCriteria: task.successCriteria,
    rationale: task.rationale,
    score: task.score,
    ...(includeOperations ? { operations: task.operations } : {}),
    alternatives: task.alternatives
  };
}

function sanitizeVoyagerCurriculumState(input = {}, options = {}) {
  const curriculum = input && typeof input === "object" ? input : createDefaultVoyagerCurriculumState();
  const includeOperations = options && typeof options === "object" ? options.includeOperations === true : false;
  const includePrompt = options && typeof options === "object" ? options.includePrompt === true : false;
  const history = Array.isArray(curriculum.history) ? curriculum.history : [];
  return {
    totalGenerated: clampInteger(curriculum.totalGenerated, 0, 0, 1000000),
    totalExecuted: clampInteger(curriculum.totalExecuted, 0, 0, 1000000),
    totalCompleted: clampInteger(curriculum.totalCompleted, 0, 0, 1000000),
    lastGeneratedAt: String(curriculum.lastGeneratedAt || "").trim(),
    lastTaskId: String(curriculum.lastTaskId || "").trim(),
    history: history.slice(0, VOYAGER_CURRICULUM_HISTORY_MAX).map((item) => sanitizeVoyagerCurriculumTask(item, {
      includeOperations,
      includePrompt
    }))
  };
}

function appendVoyagerCurriculumHistory(curriculumInput = {}, taskInput = {}) {
  const targetCurriculum = curriculumInput && typeof curriculumInput === "object"
    ? curriculumInput
    : createDefaultVoyagerCurriculumState();
  const holder = {
    curriculum: targetCurriculum
  };
  const curriculum = ensureVoyagerCurriculumState(holder);
  const task = normalizeVoyagerCurriculumTask(taskInput);
  if (!task.id) {
    return null;
  }
  curriculum.history.unshift(task);
  if (curriculum.history.length > VOYAGER_CURRICULUM_HISTORY_MAX) {
    curriculum.history.length = VOYAGER_CURRICULUM_HISTORY_MAX;
  }
  curriculum.totalGenerated = clampInteger(
    Number(curriculum.totalGenerated || 0) + 1,
    1,
    0,
    1000000
  );
  curriculum.lastGeneratedAt = task.createdAt || new Date().toISOString();
  curriculum.lastTaskId = task.id;
  return task;
}

function markVoyagerCurriculumOutcome(autonomyInput = {}, taskIdInput = "", dispatchInput = null, verificationInput = {}) {
  const autonomy = autonomyInput && typeof autonomyInput === "object" ? autonomyInput : {};
  const taskId = String(taskIdInput || "").trim();
  if (!taskId) {
    return null;
  }
  const curriculum = ensureVoyagerCurriculumState(autonomy);
  const index = curriculum.history.findIndex((item) => String(item?.id || "").trim() === taskId);
  if (index < 0) {
    return null;
  }
  const dispatch = dispatchInput && typeof dispatchInput === "object" ? dispatchInput : null;
  const verification = verificationInput && typeof verificationInput === "object" ? verificationInput : {};
  const task = normalizeVoyagerCurriculumTask(curriculum.history[index]);
  const nowIso = new Date().toISOString();
  const dispatchStatus = String(dispatch?.status || task.dispatchStatus || "").trim().toLowerCase();
  const status = String(verification.completed === true
    ? "completed"
    : (dispatchStatus || task.status || "generated")).trim().toLowerCase();
  const nextTask = {
    ...task,
    status,
    executedAt: nowIso,
    dispatchId: String(dispatch?.id || task.dispatchId || "").trim(),
    dispatchStatus,
    failureType: String(verification.failureType || task.failureType || "").trim(),
    retryable: verification.retryable === true,
    missingDependency: String(verification.missingDependency || task.missingDependency || "").trim()
  };
  curriculum.history[index] = normalizeVoyagerCurriculumTask(nextTask);
  curriculum.totalExecuted = clampInteger(
    Number(curriculum.totalExecuted || 0) + 1,
    1,
    0,
    1000000
  );
  if (status === "completed") {
    curriculum.totalCompleted = clampInteger(
      Number(curriculum.totalCompleted || 0) + 1,
      1,
      0,
      1000000
    );
  }
  return curriculum.history[index];
}

function ensureAutonomyState(userState) {
  if (!userState.autonomy || typeof userState.autonomy !== "object") {
    userState.autonomy = createDefaultAutonomyState();
  }
  const autonomy = userState.autonomy;
  if (typeof autonomy.enabled !== "boolean") {
    autonomy.enabled = true;
  }
  if (typeof autonomy.kernelVersion !== "string" || !autonomy.kernelVersion) {
    autonomy.kernelVersion = AUTONOMY_KERNEL_VERSION;
  }
  if (typeof autonomy.tickCount !== "number") {
    autonomy.tickCount = 0;
  }
  if (typeof autonomy.lastTickAt !== "string") {
    autonomy.lastTickAt = "";
  }
  if (typeof autonomy.lastRepairAt !== "string") {
    autonomy.lastRepairAt = "";
  }
  if (typeof autonomy.lastLearnAt !== "string") {
    autonomy.lastLearnAt = "";
  }
  if (typeof autonomy.generatedCount !== "number") {
    autonomy.generatedCount = 0;
  }
  if (!autonomy.learning || typeof autonomy.learning !== "object") {
    autonomy.learning = createDefaultAutonomyState().learning;
  }
  if (!autonomy.learning.feedback || typeof autonomy.learning.feedback !== "object") {
    autonomy.learning.feedback = createDefaultAutonomyState().learning.feedback;
  }
  if (!autonomy.learning.adaptive || typeof autonomy.learning.adaptive !== "object") {
    autonomy.learning.adaptive = createDefaultAutonomyState().learning.adaptive;
  }
  if (!autonomy.learning.flywheel || typeof autonomy.learning.flywheel !== "object") {
    autonomy.learning.flywheel = createDefaultFlywheelLearningState();
  }
  if (typeof autonomy.learning.feedback.executed !== "number") {
    autonomy.learning.feedback.executed = 0;
  }
  if (typeof autonomy.learning.feedback.ignored !== "number") {
    autonomy.learning.feedback.ignored = 0;
  }
  if (typeof autonomy.learning.feedback.dismissed !== "number") {
    autonomy.learning.feedback.dismissed = 0;
  }
  if (typeof autonomy.learning.feedback.total !== "number") {
    autonomy.learning.feedback.total = 0;
  }
  if (typeof autonomy.learning.adaptive.maxDailyOffset !== "number") {
    autonomy.learning.adaptive.maxDailyOffset = 0;
  }
  if (typeof autonomy.learning.adaptive.cooldownOffsetMinutes !== "number") {
    autonomy.learning.adaptive.cooldownOffsetMinutes = 0;
  }
  if (typeof autonomy.learning.adaptive.idleOffsetMinutes !== "number") {
    autonomy.learning.adaptive.idleOffsetMinutes = 0;
  }
  if (typeof autonomy.learning.flywheel.version !== "string") {
    autonomy.learning.flywheel.version = "2026.3.flywheel.v1";
  }
  if (typeof autonomy.learning.flywheel.totalSignals !== "number") {
    autonomy.learning.flywheel.totalSignals = 0;
  }
  if (typeof autonomy.learning.flywheel.emotionalQualityAvg !== "number") {
    autonomy.learning.flywheel.emotionalQualityAvg = 0;
  }
  if (typeof autonomy.learning.flywheel.executionSuccessAvg !== "number") {
    autonomy.learning.flywheel.executionSuccessAvg = 0;
  }
  if (typeof autonomy.learning.flywheel.combinedScoreAvg !== "number") {
    autonomy.learning.flywheel.combinedScoreAvg = 0;
  }
  if (typeof autonomy.learning.flywheel.executionEligibleCount !== "number") {
    autonomy.learning.flywheel.executionEligibleCount = 0;
  }
  if (typeof autonomy.learning.flywheel.executionCompletedCount !== "number") {
    autonomy.learning.flywheel.executionCompletedCount = 0;
  }
  if (typeof autonomy.learning.flywheel.executionPartialCount !== "number") {
    autonomy.learning.flywheel.executionPartialCount = 0;
  }
  if (typeof autonomy.learning.flywheel.executionFailedCount !== "number") {
    autonomy.learning.flywheel.executionFailedCount = 0;
  }
  if (typeof autonomy.learning.flywheel.fallbackCount !== "number") {
    autonomy.learning.flywheel.fallbackCount = 0;
  }
  if (typeof autonomy.learning.flywheel.learningRuns !== "number") {
    autonomy.learning.flywheel.learningRuns = 0;
  }
  if (typeof autonomy.learning.flywheel.lastSignalAt !== "string") {
    autonomy.learning.flywheel.lastSignalAt = "";
  }
  if (typeof autonomy.learning.flywheel.lastLearnedAt !== "string") {
    autonomy.learning.flywheel.lastLearnedAt = "";
  }
  if (!Array.isArray(autonomy.learning.flywheel.recentSignals)) {
    autonomy.learning.flywheel.recentSignals = [];
  }
  if (autonomy.learning.flywheel.recentSignals.length > FLYWHEEL_SIGNAL_HISTORY_LIMIT) {
    autonomy.learning.flywheel.recentSignals = autonomy.learning.flywheel.recentSignals.slice(0, FLYWHEEL_SIGNAL_HISTORY_LIMIT);
  }
  if (!autonomy.learning.flywheel.providerScores || typeof autonomy.learning.flywheel.providerScores !== "object") {
    autonomy.learning.flywheel.providerScores = {};
  }
  if (typeof autonomy.learning.lastFeedbackAt !== "string") {
    autonomy.learning.lastFeedbackAt = "";
  }
  if (!autonomy.dispatch || typeof autonomy.dispatch !== "object") {
    autonomy.dispatch = createDefaultAutonomyState().dispatch;
  }
  if (typeof autonomy.dispatch.totalRuns !== "number") {
    autonomy.dispatch.totalRuns = 0;
  }
  if (typeof autonomy.dispatch.successRuns !== "number") {
    autonomy.dispatch.successRuns = 0;
  }
  if (typeof autonomy.dispatch.failedRuns !== "number") {
    autonomy.dispatch.failedRuns = 0;
  }
  if (typeof autonomy.dispatch.lastRunAt !== "string") {
    autonomy.dispatch.lastRunAt = "";
  }
  if (typeof autonomy.dispatch.lastPrompt !== "string") {
    autonomy.dispatch.lastPrompt = "";
  }
  if (!Array.isArray(autonomy.dispatch.history)) {
    autonomy.dispatch.history = [];
  }
  if (autonomy.dispatch.history.length > 80) {
    autonomy.dispatch.history = autonomy.dispatch.history.slice(0, 80);
  }
  if (!autonomy.queue || typeof autonomy.queue !== "object") {
    autonomy.queue = createDefaultAutonomyState().queue;
  }
  if (!Array.isArray(autonomy.queue.items)) {
    autonomy.queue.items = [];
  }
  if (!Array.isArray(autonomy.queue.deadLetters)) {
    autonomy.queue.deadLetters = [];
  }
  autonomy.queue.policy = normalizeQueuePolicy(autonomy.queue.policy);
  ensureQueueCircuits(autonomy.queue);
  if (!autonomy.queue.stats || typeof autonomy.queue.stats !== "object") {
    autonomy.queue.stats = createDefaultAutonomyState().queue.stats;
  }
  if (typeof autonomy.queue.stats.processed !== "number") {
    autonomy.queue.stats.processed = 0;
  }
  if (typeof autonomy.queue.stats.succeeded !== "number") {
    autonomy.queue.stats.succeeded = 0;
  }
  if (typeof autonomy.queue.stats.retried !== "number") {
    autonomy.queue.stats.retried = 0;
  }
  if (typeof autonomy.queue.stats.deadLettered !== "number") {
    autonomy.queue.stats.deadLettered = 0;
  }
  if (typeof autonomy.queue.stats.recursionGuardDropped !== "number") {
    autonomy.queue.stats.recursionGuardDropped = 0;
  }
  if (typeof autonomy.queue.stats.archivedDeadLetters !== "number") {
    autonomy.queue.stats.archivedDeadLetters = 0;
  }
  if (typeof autonomy.queue.stats.lastProcessAt !== "string") {
    autonomy.queue.stats.lastProcessAt = "";
  }
  const queueSanitized = sanitizeAutonomyQueueRecursiveEntries(autonomy.queue);
  if (queueSanitized.removedTotal > 0) {
    autonomy.queue.stats.recursionGuardDropped += queueSanitized.removedTotal;
    const touchedDispatchIds = new Set();
    for (const item of queueSanitized.removedPendingItems || []) {
      if (item?.dispatchId) {
        touchedDispatchIds.add(String(item.dispatchId));
      }
      updateQueuedDispatchStepFromQueue(autonomy, item, {
        status: "failed",
        reason: "shell_command_recursive_guard_blocked",
        output: {
          summary: "命中递归防护闸，队列任务已自动移除。"
        },
        finishedAt: new Date().toISOString()
      });
    }
    for (const dispatchId of touchedDispatchIds) {
      reconcileQueuedDispatchStatus(autonomy, dispatchId);
    }
  }
  if (autonomy.queue.items.length > AUTONOMY_QUEUE_MAX_ITEMS) {
    autonomy.queue.items.length = AUTONOMY_QUEUE_MAX_ITEMS;
  }
  if (autonomy.queue.deadLetters.length > AUTONOMY_QUEUE_MAX_ITEMS) {
    autonomy.queue.deadLetters.length = AUTONOMY_QUEUE_MAX_ITEMS;
  }
  ensureVoyagerSkillLibraryState(autonomy);
  ensureVoyagerCurriculumState(autonomy);
  if (!Array.isArray(autonomy.inbox)) {
    autonomy.inbox = [];
  }
  if (!Array.isArray(autonomy.timeline)) {
    autonomy.timeline = [];
  }
  autonomy.timeline = autonomy.timeline
    .filter((item) => item && typeof item === "object")
    .map((item) => ({
      id: String(item.id || ""),
      flowId: String(item.flowId || ""),
      source: String(item.source || "autonomy"),
      stage: String(item.stage || "info"),
      status: String(item.status || "info"),
      title: String(item.title || "自主执行事件"),
      detail: String(item.detail || ""),
      at: String(item.at || ""),
      refs: item.refs && typeof item.refs === "object" ? item.refs : {}
    }))
    .filter((item) => item.id);
  if (autonomy.timeline.length > 180) {
    autonomy.timeline.length = 180;
  }
  if (!Array.isArray(autonomy.maintenance)) {
    autonomy.maintenance = [];
  }
  return autonomy;
}

const AUTONOMY_FAILURE_LAYER_RULES = [
  {
    id: "network",
    label: "网络/接口",
    hint: "网络异常、接口不可达或超时。",
    reasons: new Set([
      "bridge_unavailable",
      "api_call_exception",
      "api_call_http_error",
      "fetch_download_failed",
      "target_url_required",
      "invalid_url"
    ])
  },
  {
    id: "permission",
    label: "权限",
    hint: "未授权桌面/手机能力，系统拒绝执行。",
    reasons: new Set([
      "permission_required",
      "global_control_permission_required",
      "capability_permission_required"
    ])
  },
  {
    id: "policy",
    label: "策略拦截",
    hint: "安全策略或队列策略主动拦截执行。",
    reasons: new Set([
      "host_not_allowed",
      "method_not_allowed",
      "command_prefix_blocked",
      "command_disallowed",
      "circuit_open",
      "queue_strategy_disabled"
    ])
  },
  {
    id: "execution",
    label: "执行异常",
    hint: "任务本身报错或运行时异常。",
    reasons: new Set([
      "command_failed",
      "dispatch_exception",
      "task_execution_failed",
      "unsupported_step",
      "task_plan_failed",
      "expansion_install_failed"
    ])
  }
];

function classifyAutonomyFailureLayer(reasonInput) {
  const reason = String(reasonInput || "").trim();
  for (const layer of AUTONOMY_FAILURE_LAYER_RULES) {
    if (layer.reasons.has(reason)) {
      return layer.id;
    }
  }
  if (reason.includes("permission")) {
    return "permission";
  }
  if (reason.includes("policy") || reason.includes("blocked")) {
    return "policy";
  }
  if (reason.includes("network") || reason.includes("timeout") || reason.includes("http")) {
    return "network";
  }
  return "execution";
}

function buildAutonomyFailureInsights(autonomyInput) {
  const autonomy = autonomyInput || createDefaultAutonomyState();
  const buckets = {};
  for (const layer of AUTONOMY_FAILURE_LAYER_RULES) {
    buckets[layer.id] = {
      id: layer.id,
      label: layer.label,
      hint: layer.hint,
      count: 0,
      examples: []
    };
  }

  const seenExamples = new Set();
  const addFailure = (reason, summary) => {
    const layerId = classifyAutonomyFailureLayer(reason);
    const bucket = buckets[layerId] || buckets.execution;
    bucket.count += 1;
    const text = String(summary || reason || "未知错误").trim();
    if (!text || seenExamples.has(`${layerId}:${text}`)) {
      return;
    }
    seenExamples.add(`${layerId}:${text}`);
    if (bucket.examples.length < 3) {
      bucket.examples.push(text);
    }
  };

  const recentHistory = Array.isArray(autonomy.dispatch?.history) ? autonomy.dispatch.history.slice(0, 20) : [];
  for (const report of recentHistory) {
    for (const step of report.steps || []) {
      if (step.status !== "failed" && step.status !== "blocked") {
        continue;
      }
      addFailure(step.reason, step.output?.summary || step.title || "");
    }
  }

  const deadLetters = Array.isArray(autonomy.queue?.deadLetters) ? autonomy.queue.deadLetters.slice(0, 40) : [];
  for (const item of deadLetters) {
    addFailure(item.lastError, item.lastSummary || item.dispatchPrompt || "");
  }

  const layers = AUTONOMY_FAILURE_LAYER_RULES.map((layer) => buckets[layer.id]);
  return {
    totalFailures: layers.reduce((sum, item) => sum + item.count, 0),
    layers
  };
}

function sanitizeFlywheelLearningState(flywheelInput = {}) {
  const flywheel = flywheelInput && typeof flywheelInput === "object"
    ? flywheelInput
    : createDefaultFlywheelLearningState();
  const providerScores = flywheel.providerScores && typeof flywheel.providerScores === "object"
    ? flywheel.providerScores
    : {};
  const taskLeaderboards = {};
  for (const [taskType, scoreMap] of Object.entries(providerScores)) {
    if (!scoreMap || typeof scoreMap !== "object") {
      continue;
    }
    const rows = Object.values(scoreMap)
      .filter((item) => item && typeof item === "object")
      .map((item) => {
        const runs = clampInteger(item.runs, 0, 0, 1000000);
        const fallbackRuns = clampInteger(item.fallbackRuns, 0, 0, runs);
        return {
          providerId: String(item.providerId || ""),
          model: String(item.model || ""),
          runs,
          emotionalAvg: clampPolicyFloat(item.emotionalAvg, 0, 0, 1),
          executionAvg: clampPolicyFloat(item.executionAvg, 0, 0, 1),
          combinedAvg: clampPolicyFloat(item.combinedAvg, 0, 0, 1),
          fallbackRate: runs > 0 ? clampPolicyFloat(fallbackRuns / runs, 0, 0, 1) : 0,
          lastAt: String(item.lastAt || "")
        };
      })
      .filter((item) => item.providerId)
      .sort((left, right) => {
        if (right.combinedAvg !== left.combinedAvg) {
          return right.combinedAvg - left.combinedAvg;
        }
        return right.runs - left.runs;
      });
    if (rows.length > 0) {
      taskLeaderboards[taskType] = rows.slice(0, 8);
    }
  }
  const totalSignals = clampInteger(flywheel.totalSignals, 0, 0, 1000000);
  const executionEligibleCount = clampInteger(flywheel.executionEligibleCount, 0, 0, 1000000);
  const executionCompletedCount = clampInteger(flywheel.executionCompletedCount, 0, 0, 1000000);
  const fallbackCount = clampInteger(flywheel.fallbackCount, 0, 0, totalSignals);
  return {
    version: String(flywheel.version || "2026.3.flywheel.v1"),
    totalSignals,
    emotionalQualityAvg: clampPolicyFloat(flywheel.emotionalQualityAvg, 0, 0, 1),
    executionSuccessAvg: clampPolicyFloat(flywheel.executionSuccessAvg, 0, 0, 1),
    combinedScoreAvg: clampPolicyFloat(flywheel.combinedScoreAvg, 0, 0, 1),
    executionEligibleCount,
    executionCompletedCount,
    executionPartialCount: clampInteger(flywheel.executionPartialCount, 0, 0, 1000000),
    executionFailedCount: clampInteger(flywheel.executionFailedCount, 0, 0, 1000000),
    executionCompletionRate: executionEligibleCount > 0
      ? clampPolicyFloat(executionCompletedCount / executionEligibleCount, 0, 0, 1)
      : 0,
    fallbackRate: totalSignals > 0 ? clampPolicyFloat(fallbackCount / totalSignals, 0, 0, 1) : 0,
    learningRuns: clampInteger(flywheel.learningRuns, 0, 0, 1000000),
    lastSignalAt: String(flywheel.lastSignalAt || ""),
    lastLearnedAt: String(flywheel.lastLearnedAt || ""),
    recentSignals: Array.isArray(flywheel.recentSignals)
      ? flywheel.recentSignals
        .filter((item) => item && typeof item === "object")
        .slice(0, 40)
        .map((item) => ({
          id: String(item.id || ""),
          at: String(item.at || ""),
          flowId: String(item.flowId || ""),
          scene: String(item.scene || ""),
          taskType: String(item.taskType || ""),
          providerId: String(item.providerId || ""),
          model: String(item.model || ""),
          fallback: item.fallback === true,
          emotionalScore: clampPolicyFloat(item.emotionalScore, 0, 0, 1),
          executionScore: clampPolicyFloat(item.executionScore, 0, 0, 1),
          combinedScore: clampPolicyFloat(item.combinedScore, 0, 0, 1),
          dispatchStatus: String(item.dispatchStatus || ""),
          executionEligible: item.executionEligible === true,
          executed: item.executed === true,
          reason: String(item.reason || "")
        }))
      : [],
    taskLeaderboards
  };
}

function sanitizeAutonomy(autonomyInput) {
  const autonomy = autonomyInput || createDefaultAutonomyState();
  const queue = autonomy.queue || createDefaultAutonomyState().queue;
  const timeline = Array.isArray(autonomy.timeline)
    ? autonomy.timeline
      .filter((item) => item && typeof item === "object")
      .map((item) => ({
        id: String(item.id || ""),
        flowId: String(item.flowId || ""),
        source: String(item.source || "autonomy"),
        stage: String(item.stage || "info"),
        status: String(item.status || "info"),
        title: String(item.title || "自主执行事件"),
        detail: String(item.detail || ""),
        at: String(item.at || ""),
        refs: item.refs && typeof item.refs === "object" ? item.refs : {}
      }))
      .filter((item) => item.id)
    : [];
  return {
    enabled: autonomy.enabled,
    kernelVersion: autonomy.kernelVersion || AUTONOMY_KERNEL_VERSION,
    tickCount: autonomy.tickCount,
    lastTickAt: autonomy.lastTickAt,
    lastRepairAt: autonomy.lastRepairAt,
    lastLearnAt: autonomy.lastLearnAt,
    generatedCount: autonomy.generatedCount,
    learning: {
      feedback: {
        executed: autonomy.learning.feedback.executed,
        ignored: autonomy.learning.feedback.ignored,
        dismissed: autonomy.learning.feedback.dismissed,
        total: autonomy.learning.feedback.total
      },
      adaptive: {
        maxDailyOffset: autonomy.learning.adaptive.maxDailyOffset,
        cooldownOffsetMinutes: autonomy.learning.adaptive.cooldownOffsetMinutes,
        idleOffsetMinutes: autonomy.learning.adaptive.idleOffsetMinutes
      },
      flywheel: sanitizeFlywheelLearningState(autonomy.learning.flywheel || createDefaultFlywheelLearningState()),
      lastFeedbackAt: autonomy.learning.lastFeedbackAt
    },
    dispatch: autonomy.dispatch || createDefaultAutonomyState().dispatch,
    skillLibrary: sanitizeVoyagerSkillLibraryState(autonomy.skillLibrary || createDefaultVoyagerSkillLibraryState(), {
      includePatterns: false,
      includeSamples: false
    }),
    curriculum: sanitizeVoyagerCurriculumState(autonomy.curriculum || createDefaultVoyagerCurriculumState(), {
      includeOperations: false,
      includePrompt: false
    }),
    queue,
    inbox: Array.isArray(autonomy.inbox) ? autonomy.inbox : [],
    timeline,
    failureInsights: buildAutonomyFailureInsights(autonomy),
    maintenance: Array.isArray(autonomy.maintenance) ? autonomy.maintenance : []
  };
}

