const runtimeGuardian = createRuntimeGuardianState();

function findIncidentPlaybookEntry(reasonInput, messageInput = "") {
  const haystack = `${String(reasonInput || "")} ${String(messageInput || "")}`
    .toLowerCase()
    .trim();
  if (!haystack) {
    return null;
  }
  for (const incident of openclawIncidentPlaybook?.incidents || []) {
    const keywords = Array.isArray(incident.symptomKeywords) ? incident.symptomKeywords : [];
    if (keywords.length === 0) {
      continue;
    }
    if (keywords.some((keyword) => keyword && haystack.includes(String(keyword).toLowerCase()))) {
      return incident;
    }
  }
  return null;
}

function appendIncidentGuardrailMemory(incident, runtimeIssue) {
  if (!incident || typeof incident !== "object" || !store || !store.users) {
    return;
  }
  const cooldownKey = `incident_guardrail:${String(incident.id || "")}`;
  const nowMs = Date.now();
  const lastAtMs = Number(runtimeGuardian.issueCooldown[cooldownKey] || 0);
  if (nowMs - lastAtMs < 5 * 60 * 1000) {
    return;
  }
  runtimeGuardian.issueCooldown[cooldownKey] = nowMs;
  const atIso = new Date(nowMs).toISOString();
  let changed = false;
  for (const userState of Object.values(store.users || {})) {
    if (!userState || typeof userState !== "object") {
      continue;
    }
    const remembered = rememberIncidentGuardrailForUser(userState, incident, {
      reason: "runtime_auto_guardrail",
      issueMessage: String(runtimeIssue?.message || ""),
      at: atIso
    });
    changed = changed || remembered;
  }

  if (changed) {
    saveStore(store);
  }
}

function rememberIncidentGuardrailForUser(userState, incident, options = {}) {
  if (!userState || typeof userState !== "object" || !incident || typeof incident !== "object") {
    return false;
  }
  const atIso = String(options.at || new Date().toISOString());
  const reason = String(options.reason || "manual_guardrail");
  const guardrailText = String(incident.guardrail || "").trim();
  const rootCauseText = String(incident.rootCause || "").trim();
  const issueMessage = String(options.issueMessage || "").trim();
  const memoryText = `防复发守则[${incident.title}]：${guardrailText || "发现同类故障时先执行健康巡检。"}`
    + (rootCauseText ? `（根因：${rootCauseText}）` : "")
    + (issueMessage ? `（样本：${issueMessage.slice(0, 80)}）` : "");
  if (!Array.isArray(userState.memoryHighlights)) {
    userState.memoryHighlights = [];
  }
  const beforeLen = userState.memoryHighlights.length;
  dedupePush(userState.memoryHighlights, memoryText, 60);
  const memoryChanged = userState.memoryHighlights.length !== beforeLen;

  const autonomy = ensureAutonomyState(userState);
  if (!Array.isArray(autonomy.maintenance)) {
    autonomy.maintenance = [];
  }
  const maintenanceEntry = {
    id: `maintenance-incident-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
    type: "incident_guardrail",
    message: `已写入防复发守则：${incident.title}`,
    at: atIso,
    reason
  };
  autonomy.maintenance.unshift(maintenanceEntry);
  if (autonomy.maintenance.length > 80) {
    autonomy.maintenance.length = 80;
  }
  userState.updatedAt = atIso;
  return memoryChanged || autonomy.maintenance.length > 0;
}

function buildOpenclawIncidentPlaybookSnapshot(options = {}) {
  const incidents = Array.isArray(openclawIncidentPlaybook?.incidents)
    ? openclawIncidentPlaybook.incidents
    : [];
  const issueSample = Array.isArray(runtimeGuardian.issues) ? runtimeGuardian.issues.slice(0, 40) : [];
  const matchMap = new Map();
  for (const issue of issueSample) {
    const incident = findIncidentPlaybookEntry(issue.reason, issue.message);
    if (!incident) {
      continue;
    }
    const key = String(incident.id || "");
    if (!key) {
      continue;
    }
    const current = matchMap.get(key) || {
      incident,
      hitCount: 0,
      lastAt: "",
      samples: []
    };
    current.hitCount += 1;
    current.lastAt = current.lastAt && current.lastAt > issue.at ? current.lastAt : String(issue.at || "");
    const sampleText = String(issue.message || issue.reason || "").trim();
    if (sampleText && !current.samples.includes(sampleText) && current.samples.length < 3) {
      current.samples.push(sampleText);
    }
    matchMap.set(key, current);
  }

  const sortedMatches = Array.from(matchMap.values()).sort((a, b) => {
    if (b.hitCount !== a.hitCount) {
      return b.hitCount - a.hitCount;
    }
    return String(b.lastAt || "").localeCompare(String(a.lastAt || ""));
  });
  const limit = clampInteger(options.limit, 6, 1, 20);
  const topMatches = sortedMatches.slice(0, limit).map((entry) => ({
    id: String(entry.incident.id || ""),
    title: String(entry.incident.title || ""),
    layer: String(entry.incident.layer || "execution"),
    hitCount: entry.hitCount,
    lastAt: entry.lastAt,
    rootCause: String(entry.incident.rootCause || ""),
    guardrail: String(entry.incident.guardrail || ""),
    autoFix: Array.isArray(entry.incident.autoFix) ? entry.incident.autoFix.slice(0, 5) : [],
    verifyEndpoint: String(entry.incident.verifyEndpoint || ""),
    samples: entry.samples
  }));
  const matchedIdSet = new Set(topMatches.map((item) => item.id));
  const unresolved = incidents
    .filter((item) => !matchedIdSet.has(String(item.id || "")))
    .slice(0, 6)
    .map((item) => ({
      id: String(item.id || ""),
      title: String(item.title || ""),
      layer: String(item.layer || "execution"),
      guardrail: String(item.guardrail || "")
    }));
  const recommendations = [];
  const seenRecommendation = new Set();
  for (const entry of topMatches) {
    const line = `${entry.title}：${entry.guardrail || "优先执行运行时健康检查。"}`.trim();
    if (!line || seenRecommendation.has(line)) {
      continue;
    }
    seenRecommendation.add(line);
    recommendations.push(line);
    if (recommendations.length >= 8) {
      break;
    }
  }
  if (recommendations.length === 0) {
    for (const item of incidents.slice(0, 3)) {
      const line = `${item.title}：${item.guardrail || "优先执行运行时健康检查。"}`.trim();
      if (!line || seenRecommendation.has(line)) {
        continue;
      }
      seenRecommendation.add(line);
      recommendations.push(line);
    }
  }
  return {
    version: String(openclawIncidentPlaybook?.version || DEFAULT_OPENCLAW_INCIDENT_PLAYBOOK.version),
    objective: String(openclawIncidentPlaybook?.objective || DEFAULT_OPENCLAW_INCIDENT_PLAYBOOK.objective),
    totalIncidents: incidents.length,
    matchedCount: topMatches.length,
    unresolvedCount: Math.max(0, incidents.length - topMatches.length),
    matched: topMatches,
    unresolved,
    recommendations,
    generatedAt: new Date().toISOString()
  };
}

function classifyRuntimeFailureLayer(reasonInput, messageInput = "", statusCodeInput = 0) {
  const reason = String(reasonInput || "").trim().toLowerCase();
  const message = String(messageInput || "").trim().toLowerCase();
  const statusCode = Number(statusCodeInput || 0);
  for (const layer of RUNTIME_FAILURE_LAYER_RULES) {
    if (layer.reasons.has(reason)) {
      return layer.id;
    }
  }
  if (statusCode === 401 || statusCode === 403 || reason.includes("permission")) {
    return "permission";
  }
  if (statusCode === 429 || reason.includes("policy") || reason.includes("blocked")) {
    return "policy";
  }
  if (
    reason.includes("network")
    || reason.includes("timeout")
    || reason.includes("fetch")
    || message.includes("failed to fetch")
    || message.includes("etimedout")
    || statusCode === 0
  ) {
    return "network";
  }
  return "execution";
}

function pushRuntimeIssue(input = {}) {
  const now = Date.now();
  const reason = String(input.reason || "unexpected_status").trim() || "unexpected_status";
  const message = String(input.message || "").trim();
  const source = String(input.source || "runtime").trim() || "runtime";
  const statusCode = Number(input.statusCode || 0);
  const layer = classifyRuntimeFailureLayer(reason, message, statusCode);
  const fingerprint = `${source}:${layer}:${reason}:${message || "-"}`.slice(0, 480);
  const lastSeenAt = Number(runtimeGuardian.issueCooldown[fingerprint] || 0);
  if (now - lastSeenAt < RUNTIME_GUARDIAN_ISSUE_COOLDOWN_MS) {
    return;
  }
  runtimeGuardian.issueCooldown[fingerprint] = now;

  runtimeGuardian.issues.unshift({
    id: `runtime-issue-${now}-${Math.floor(Math.random() * 10000)}`,
    at: new Date(now).toISOString(),
    layer,
    reason,
    message,
    source,
    statusCode
  });
  if (runtimeGuardian.issues.length > RUNTIME_GUARDIAN_ISSUE_LIMIT) {
    runtimeGuardian.issues.length = RUNTIME_GUARDIAN_ISSUE_LIMIT;
  }

  const matchedIncident = findIncidentPlaybookEntry(reason, message);
  if (matchedIncident) {
    appendIncidentGuardrailMemory(matchedIncident, {
      reason,
      message,
      at: new Date(now).toISOString()
    });
  }
}

function bindRuntimeRequestMetric(res, context = {}) {
  res[RESPONSE_RUNTIME_METRIC_KEY] = {
    pathname: String(context.pathname || "/"),
    method: String(context.method || "UNKNOWN"),
    startedAt: Number(context.startedAt || Date.now()),
    recorded: false
  };
}

function finalizeRuntimeRequestMetric(res, statusCode = 0) {
  const metric = res[RESPONSE_RUNTIME_METRIC_KEY];
  if (!metric || metric.recorded) {
    return;
  }
  metric.recorded = true;
  const durationMs = Math.max(0, Date.now() - Number(metric.startedAt || Date.now()));
  recordApiRequestMetric(metric.pathname, metric.method, Number(statusCode || 0), durationMs);
}

function appendRuntimeSelfHealReport(input = {}) {
  const nowIso = new Date().toISOString();
  const report = {
    id: `runtime-heal-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
    at: nowIso,
    action: normalizeRuntimeGuardianHealAction(input.action) || "full_heal",
    mode: normalizeRuntimeGuardianMode(input.mode),
    reason: String(input.reason || "watchdog"),
    summary: String(input.summary || ""),
    actions: Array.isArray(input.actions) ? input.actions.slice(0, 8) : [],
    queue: input.queue && typeof input.queue === "object"
      ? {
          pendingBefore: Number(input.queue.pendingBefore || 0),
          deadLettersBefore: Number(input.queue.deadLettersBefore || 0),
          pendingAfter: Number(input.queue.pendingAfter || 0),
          deadLettersAfter: Number(input.queue.deadLettersAfter || 0)
        }
      : {
          pendingBefore: 0,
          deadLettersBefore: 0,
          pendingAfter: 0,
          deadLettersAfter: 0
        },
    touchedUsers: Number(input.touchedUsers || 0),
    changedUsers: Number(input.changedUsers || 0),
    queueProcessed: Number(input.queueProcessed || 0),
    queueSucceeded: Number(input.queueSucceeded || 0),
    queueDeadLettered: Number(input.queueDeadLettered || 0),
    saved: input.saved === true
  };
  runtimeGuardian.reports.unshift(report);
  if (runtimeGuardian.reports.length > RUNTIME_GUARDIAN_REPORT_LIMIT) {
    runtimeGuardian.reports.length = RUNTIME_GUARDIAN_REPORT_LIMIT;
  }
  runtimeGuardian.watchdog.lastSelfHealAt = nowIso;
  runtimeGuardian.watchdog.lastSelfHealReason = report.reason;
  runtimeGuardian.watchdog.lastSelfHealSummary = report.summary;
}

function recordApiRequestMetric(pathname, method, statusCode, durationMs) {
  const api = runtimeGuardian.api;
  const nowIso = new Date().toISOString();
  api.lastCheckedAt = nowIso;
  api.requestTotal += 1;
  const isFailure = statusCode >= 500 || statusCode === 0;
  const isSlow = durationMs >= RUNTIME_GUARDIAN_REQUEST_WARN_MS;
  const isCritical = durationMs >= RUNTIME_GUARDIAN_REQUEST_CRITICAL_MS;
  if (isFailure) {
    api.requestFailed += 1;
    api.status = "degraded";
    api.lastErrorAt = nowIso;
    api.lastError = `HTTP ${statusCode || 0} (${String(method || "UNKNOWN")} ${String(pathname || "/")})`;
    pushRuntimeIssue({
      source: "api_request",
      reason: "internal_error",
      message: api.lastError,
      statusCode
    });
  } else if (statusCode === 401 || statusCode === 403) {
    pushRuntimeIssue({
      source: "api_request",
      reason: "unauthorized",
      message: `权限不足：${String(method || "UNKNOWN")} ${String(pathname || "/")}`,
      statusCode
    });
  } else if (statusCode === 429) {
    pushRuntimeIssue({
      source: "api_request",
      reason: "action_disabled_by_policy",
      message: `策略限流：${String(method || "UNKNOWN")} ${String(pathname || "/")}`,
      statusCode
    });
  } else {
    api.lastOkAt = nowIso;
    if (!api.lastErrorAt || (Date.now() - Date.parse(api.lastErrorAt) > 120000)) {
      api.status = "up";
    }
  }
  if (isSlow) {
    api.requestSlow += 1;
  }
  if (isCritical) {
    api.requestCritical += 1;
    pushRuntimeIssue({
      source: "api_latency",
      reason: "timeout",
      message: `请求耗时 ${durationMs}ms: ${String(method || "UNKNOWN")} ${String(pathname || "/")}`,
      statusCode
    });
  }
  api.recent.unshift({
    at: nowIso,
    method: String(method || "UNKNOWN"),
    path: String(pathname || "/"),
    statusCode: Number(statusCode || 0),
    durationMs: Number(durationMs || 0)
  });
  if (api.recent.length > RUNTIME_GUARDIAN_RECENT_REQUEST_LIMIT) {
    api.recent.length = RUNTIME_GUARDIAN_RECENT_REQUEST_LIMIT;
  }
}

async function probeBridgeRuntimeHealth(source = "runtime_probe") {
  const startedAt = Date.now();
  const nowIso = new Date(startedAt).toISOString();
  runtimeGuardian.bridge.lastCheckedAt = nowIso;
  runtimeGuardian.watchdog.lastProbeStatus = "checking";
  try {
    const response = await fetch(`${BRIDGE_BASE}/health`, {
      method: "GET",
      signal: AbortSignal.timeout(RUNTIME_GUARDIAN_BRIDGE_TIMEOUT_MS)
    });
    const durationMs = Date.now() - startedAt;
    runtimeGuardian.bridge.lastLatencyMs = durationMs;
    if (response.ok) {
      runtimeGuardian.bridge.status = "up";
      runtimeGuardian.bridge.lastOkAt = new Date().toISOString();
      runtimeGuardian.bridge.lastError = "";
      runtimeGuardian.watchdog.lastProbeStatus = "up";
      return { ok: true, statusCode: response.status, durationMs };
    }
    runtimeGuardian.bridge.status = "down";
    runtimeGuardian.bridge.lastErrorAt = new Date().toISOString();
    runtimeGuardian.bridge.lastError = `HTTP ${response.status}`;
    runtimeGuardian.watchdog.lastProbeStatus = "down";
    pushRuntimeIssue({
      source,
      reason: response.status === 401 || response.status === 403 ? "forbidden" : "bridge_http_error",
      message: `Bridge 探针失败：HTTP ${response.status}`,
      statusCode: response.status
    });
    return { ok: false, statusCode: response.status, durationMs };
  } catch (error) {
    runtimeGuardian.bridge.status = "down";
    runtimeGuardian.bridge.lastErrorAt = new Date().toISOString();
    runtimeGuardian.bridge.lastError = error instanceof Error ? error.message : String(error);
    runtimeGuardian.watchdog.lastProbeStatus = "down";
    pushRuntimeIssue({
      source,
      reason: "bridge_unreachable",
      message: runtimeGuardian.bridge.lastError,
      statusCode: 0
    });
    return { ok: false, statusCode: 0, durationMs: Date.now() - startedAt };
  }
}

function buildRuntimeFailureInsights() {
  const buckets = {};
  for (const layer of RUNTIME_FAILURE_LAYER_RULES) {
    buckets[layer.id] = {
      id: layer.id,
      label: layer.label,
      hint: layer.hint,
      count: 0,
      examples: []
    };
  }

  for (const issue of runtimeGuardian.issues.slice(0, 120)) {
    const bucket = buckets[issue.layer] || buckets.execution;
    bucket.count += 1;
    if (bucket.examples.length < 3) {
      const example = String(issue.message || issue.reason || "未知异常").trim();
      if (example && !bucket.examples.includes(example)) {
        bucket.examples.push(example);
      }
    }
  }

  const layers = RUNTIME_FAILURE_LAYER_RULES.map((layer) => buckets[layer.id]);
  return {
    totalFailures: layers.reduce((sum, item) => sum + item.count, 0),
    layers
  };
}

function buildRuntimeSloSnapshot() {
  const recentTotal = runtimeGuardian.api.recent.length;
  const recentSlow = runtimeGuardian.api.recent.filter(
    (item) => Number(item.durationMs || 0) >= RUNTIME_GUARDIAN_REQUEST_WARN_MS
  ).length;
  const requestTotal = Number(runtimeGuardian.api.requestTotal || 0);
  const requestFailed = Number(runtimeGuardian.api.requestFailed || 0);
  const failureRate = requestTotal > 0 ? requestFailed / requestTotal : 0;
  const slowRate = recentTotal > 0 ? recentSlow / recentTotal : 0;
  let status = "ok";
  let summary = "SLO 稳定。";
  if (failureRate >= RUNTIME_GUARDIAN_SLO_ERROR_CRITICAL || slowRate >= RUNTIME_GUARDIAN_SLO_SLOW_CRITICAL) {
    status = "critical";
    summary = "SLO 超出红线，接口失败率或慢请求占比过高。";
  } else if (failureRate >= RUNTIME_GUARDIAN_SLO_ERROR_WARN || slowRate >= RUNTIME_GUARDIAN_SLO_SLOW_WARN) {
    status = "warning";
    summary = "SLO 接近风险区，建议关注失败率和慢请求。";
  }
  return {
    warnMs: RUNTIME_GUARDIAN_REQUEST_WARN_MS,
    criticalMs: RUNTIME_GUARDIAN_REQUEST_CRITICAL_MS,
    recentSlowCount: recentSlow,
    recentTotal,
    requestTotal,
    requestFailed,
    failureRate: Number(failureRate.toFixed(4)),
    slowRate: Number(slowRate.toFixed(4)),
    failureWarnThreshold: RUNTIME_GUARDIAN_SLO_ERROR_WARN,
    failureCriticalThreshold: RUNTIME_GUARDIAN_SLO_ERROR_CRITICAL,
    slowWarnThreshold: RUNTIME_GUARDIAN_SLO_SLOW_WARN,
    slowCriticalThreshold: RUNTIME_GUARDIAN_SLO_SLOW_CRITICAL,
    status,
    summary
  };
}

function summarizeRuntimeOutage(aggregatedQueue, sloSnapshot = buildRuntimeSloSnapshot()) {
  const queuePending = Number(aggregatedQueue.pending || 0);
  const queueDeadLetters = Number(aggregatedQueue.deadLetters || 0);
  const queueDeadLettersRecent24h = Number(
    aggregatedQueue.deadLettersRecent24h !== undefined
      ? aggregatedQueue.deadLettersRecent24h
      : queueDeadLetters
  );
  const bridgeDown = runtimeGuardian.bridge.status === "down";
  const apiDegraded = runtimeGuardian.api.status !== "up";
  const queuePendingPressured = queuePending >= RUNTIME_GUARDIAN_QUEUE_PENDING_WARN;
  const queueDeadLetterPressured =
    queueDeadLettersRecent24h >= RUNTIME_GUARDIAN_QUEUE_DEAD_WARN
    && queuePending >= Math.max(2, Math.floor(RUNTIME_GUARDIAN_QUEUE_PENDING_WARN / 2));
  const queuePressured = queuePendingPressured || queueDeadLetterPressured;

  if (bridgeDown || apiDegraded || sloSnapshot.status === "critical") {
    return {
      status: "critical",
      summary: "运行时通道异常，存在请求失败风险。",
      recommendation: "先执行 `bash scripts/dev-runtime.sh`，再在“自主内核”里运行一次自修复和队列处理。",
      cause: bridgeDown ? "bridge_down" : apiDegraded ? "api_degraded" : "slo_critical"
    };
  }
  if (queuePressured || sloSnapshot.status === "warning") {
    return {
      status: "warning",
      summary: "系统压力偏高，建议尽快处理积压任务。",
      recommendation: "进入“自主内核”面板，点击“处理重试队列”，并观察失败根因面板。",
      cause: queuePressured ? "queue_pressure" : "slo_warning"
    };
  }
  return {
    status: "ok",
    summary: "运行时链路稳定。",
    recommendation: "当前无需人工干预。",
    cause: "stable"
  };
}

function aggregateRuntimeQueuePressure() {
  let pending = 0;
  let deadLetters = 0;
  let deadLettersRecent24h = 0;
  let recursionGuardDropped = 0;
  let archivedDeadLetters = 0;
  const nowMs = Date.now();
  const recentWindowMs = 24 * 60 * 60 * 1000;
  for (const userState of Object.values(store.users || {})) {
    if (!userState || typeof userState !== "object") {
      continue;
    }
    const queue = userState.autonomy?.queue;
    if (!queue || typeof queue !== "object") {
      continue;
    }
    pending += Array.isArray(queue.items) ? queue.items.length : 0;
    const queueDeadLetters = Array.isArray(queue.deadLetters) ? queue.deadLetters : [];
    deadLetters += queueDeadLetters.length;
    for (const item of queueDeadLetters) {
      if (!item || typeof item !== "object") {
        continue;
      }
      const stamp = String(item.failedAt || item.updatedAt || item.createdAt || "").trim();
      const stampMs = Date.parse(stamp) || 0;
      if (stampMs > 0 && nowMs - stampMs <= recentWindowMs) {
        deadLettersRecent24h += 1;
      }
    }
    recursionGuardDropped += Number(queue.stats?.recursionGuardDropped || 0);
    archivedDeadLetters += Number(queue.stats?.archivedDeadLetters || 0);
  }
  return {
    pending,
    deadLetters,
    deadLettersRecent24h,
    recursionGuardDropped,
    archivedDeadLetters
  };
}

function buildRuntimeHealthPayload() {
  const queue = aggregateRuntimeQueuePressure();
  const failureInsights = buildRuntimeFailureInsights();
  const slo = buildRuntimeSloSnapshot();
  const outage = summarizeRuntimeOutage(queue, slo);
  const incidentPlaybook = buildOpenclawIncidentPlaybookSnapshot({ limit: 6 });
  const cooldownRemainingMs = Math.max(
    0,
    (Date.parse(runtimeGuardian.watchdog.cooldownUntil || "") || 0) - Date.now()
  );
  return {
    runtime: {
      api: {
        status: runtimeGuardian.api.status,
        lastCheckedAt: runtimeGuardian.api.lastCheckedAt,
        lastOkAt: runtimeGuardian.api.lastOkAt,
        lastErrorAt: runtimeGuardian.api.lastErrorAt,
        lastError: runtimeGuardian.api.lastError,
        requestTotal: runtimeGuardian.api.requestTotal,
        requestFailed: runtimeGuardian.api.requestFailed,
        requestSlow: runtimeGuardian.api.requestSlow,
        requestCritical: runtimeGuardian.api.requestCritical
      },
      bridge: {
        status: runtimeGuardian.bridge.status,
        lastCheckedAt: runtimeGuardian.bridge.lastCheckedAt,
        lastOkAt: runtimeGuardian.bridge.lastOkAt,
        lastErrorAt: runtimeGuardian.bridge.lastErrorAt,
        lastError: runtimeGuardian.bridge.lastError,
        lastLatencyMs: runtimeGuardian.bridge.lastLatencyMs
      },
      queue,
      slo,
      watchdog: {
        enabled: runtimeGuardian.watchdog.enabled,
        cycleRunning: runtimeGuardian.watchdog.cycleRunning,
        tickCount: runtimeGuardian.watchdog.tickCount,
        lastTickAt: runtimeGuardian.watchdog.lastTickAt,
        lastErrorAt: runtimeGuardian.watchdog.lastErrorAt,
        lastError: runtimeGuardian.watchdog.lastError,
        cooldownUntil: runtimeGuardian.watchdog.cooldownUntil,
        cooldownRemainingMs,
        selfHealCooldownMs: RUNTIME_GUARDIAN_SELF_HEAL_COOLDOWN_MS,
        lastSelfHealAt: runtimeGuardian.watchdog.lastSelfHealAt,
        lastSelfHealSummary: runtimeGuardian.watchdog.lastSelfHealSummary,
        lastSelfHealReason: runtimeGuardian.watchdog.lastSelfHealReason,
        lastProbeStatus: runtimeGuardian.watchdog.lastProbeStatus,
        skippedReason: runtimeGuardian.watchdog.skippedReason,
        lastManualAction: runtimeGuardian.watchdog.lastManualAction,
        lastManualActionAt: runtimeGuardian.watchdog.lastManualActionAt,
        lastManualActionStatus: runtimeGuardian.watchdog.lastManualActionStatus,
        lastManualActionSummary: runtimeGuardian.watchdog.lastManualActionSummary,
        lastConfigChangeAt: runtimeGuardian.watchdog.lastConfigChangeAt,
        lastConfigChangeSummary: runtimeGuardian.watchdog.lastConfigChangeSummary,
        lastConfigChangeSource: runtimeGuardian.watchdog.lastConfigChangeSource,
        mode: normalizeRuntimeGuardianMode(runtimeGuardian.watchdog.mode),
        modeLabel: getRuntimeGuardianModePreset(runtimeGuardian.watchdog.mode).label,
        queueLimit: clampInteger(
          runtimeGuardian.watchdog.queueLimit,
          getRuntimeGuardianModePreset(runtimeGuardian.watchdog.mode).queueLimit,
          1,
          20
        ),
        modePresets: Object.values(RUNTIME_GUARDIAN_MODE_PRESETS).map((item) => ({
          mode: item.mode,
          label: item.label,
          queueLimit: item.queueLimit
        }))
      },
      outage
    },
    failureInsights,
    recentIssues: runtimeGuardian.issues.slice(0, 6),
    selfHealReports: runtimeGuardian.reports.slice(0, 6),
    incidentPlaybook,
    generatedAt: new Date().toISOString()
  };
}

function updateRuntimeGuardianConfig(input = {}) {
  const payload = input && typeof input === "object" ? input : {};
  const previousEnabled = runtimeGuardian.watchdog.enabled;
  const previousMode = normalizeRuntimeGuardianMode(runtimeGuardian.watchdog.mode);
  const previousQueueLimit = clampInteger(
    runtimeGuardian.watchdog.queueLimit,
    getRuntimeGuardianModePreset(runtimeGuardian.watchdog.mode).queueLimit,
    1,
    20
  );
  if (typeof payload.enabled === "boolean") {
    runtimeGuardian.watchdog.enabled = payload.enabled;
  }

  let modeChanged = false;
  if (payload.mode !== undefined) {
    runtimeGuardian.watchdog.mode = normalizeRuntimeGuardianMode(payload.mode);
    modeChanged = true;
  } else {
    runtimeGuardian.watchdog.mode = normalizeRuntimeGuardianMode(runtimeGuardian.watchdog.mode);
  }

  const preset = getRuntimeGuardianModePreset(runtimeGuardian.watchdog.mode);
  if (payload.queueLimit !== undefined) {
    runtimeGuardian.watchdog.queueLimit = clampInteger(payload.queueLimit, preset.queueLimit, 1, 20);
  } else if (modeChanged) {
    runtimeGuardian.watchdog.queueLimit = preset.queueLimit;
  } else {
    runtimeGuardian.watchdog.queueLimit = clampInteger(
      runtimeGuardian.watchdog.queueLimit,
      preset.queueLimit,
      1,
      20
    );
  }

  const changed =
    previousEnabled !== runtimeGuardian.watchdog.enabled
    || previousMode !== runtimeGuardian.watchdog.mode
    || previousQueueLimit !== runtimeGuardian.watchdog.queueLimit;
  if (changed) {
    const nowIso = new Date().toISOString();
    const enabledLabel = runtimeGuardian.watchdog.enabled ? "启用自动巡检" : "暂停自动巡检";
    const modeLabel = `模式 ${preset.label}`;
    const queueLabel = `单轮上限 ${runtimeGuardian.watchdog.queueLimit}`;
    runtimeGuardian.watchdog.lastConfigChangeAt = nowIso;
    runtimeGuardian.watchdog.lastConfigChangeSummary = `${enabledLabel} · ${modeLabel} · ${queueLabel}`;
    runtimeGuardian.watchdog.lastConfigChangeSource = String(payload.source || "runtime_guardian_config");
  }

  return {
    enabled: runtimeGuardian.watchdog.enabled,
    mode: runtimeGuardian.watchdog.mode,
    modeLabel: preset.label,
    queueLimit: runtimeGuardian.watchdog.queueLimit,
    changed,
    lastConfigChangeAt: runtimeGuardian.watchdog.lastConfigChangeAt,
    lastConfigChangeSummary: runtimeGuardian.watchdog.lastConfigChangeSummary
  };
}

async function runRuntimeGuardianCycle(options = {}) {
  const currentConfig = updateRuntimeGuardianConfig({});
  const force = options.force === true;
  const source = String(
    options.source || (force ? "runtime_watchdog_manual" : "runtime_watchdog")
  );
  const mode = currentConfig.mode;
  const modePreset = getRuntimeGuardianModePreset(mode);
  const requestedQueueLimit = clampInteger(
    options.queueLimit,
    currentConfig.queueLimit,
    1,
    20
  );
  const executeRepair = options.executeRepair !== false;
  const executeQueue = options.executeQueue !== false;
  const action =
    normalizeRuntimeGuardianHealAction(options.action)
    || resolveRuntimeGuardianActionFromFlags(executeRepair, executeQueue);
  const isManualTrigger = force || source.includes("manual");
  const queueLimit = clampInteger(
    requestedQueueLimit,
    modePreset.queueLimit,
    1,
    20
  );
  const result = {
    ok: true,
    source,
    force,
    mode,
    action,
    queueLimit,
    executeRepair,
    executeQueue,
    executed: false,
    skippedReason: "",
    reason: "",
    summary: "",
    outageStatus: "ok",
    queue: {
      pendingBefore: 0,
      deadLettersBefore: 0,
      pendingAfter: 0,
      deadLettersAfter: 0
    },
    touchedUsers: 0,
    changedUsers: 0,
    queueProcessed: 0,
    queueSucceeded: 0,
    queueDeadLettered: 0,
    queueDeadLettersCompacted: 0,
    reportId: ""
  };

  const setManualActionSnapshot = (status, summary) => {
    if (!isManualTrigger) {
      return;
    }
    const nowIso = new Date().toISOString();
    runtimeGuardian.watchdog.lastManualAction = action;
    runtimeGuardian.watchdog.lastManualActionAt = nowIso;
    runtimeGuardian.watchdog.lastManualActionStatus = String(status || "skipped");
    runtimeGuardian.watchdog.lastManualActionSummary = String(summary || "");
  };

  if (!currentConfig.enabled && !force) {
    runtimeGuardian.watchdog.skippedReason = "watchdog_disabled";
    result.skippedReason = "watchdog_disabled";
    result.reason = "watchdog_disabled";
    result.summary = "Runtime Guardian 当前已停用。";
    setManualActionSnapshot("skipped", result.summary);
    return result;
  }
  if (runtimeGuardian.watchdog.cycleRunning) {
    runtimeGuardian.watchdog.skippedReason = "watchdog_busy";
    result.skippedReason = "watchdog_busy";
    result.reason = "watchdog_busy";
    result.summary = "Runtime Guardian 正在执行上一轮巡检，请稍后重试。";
    setManualActionSnapshot("skipped", result.summary);
    return result;
  }

  runtimeGuardian.watchdog.cycleRunning = true;
  runtimeGuardian.watchdog.tickCount += 1;
  runtimeGuardian.watchdog.lastTickAt = new Date().toISOString();
  runtimeGuardian.watchdog.skippedReason = "";

  try {
    runtimeGuardian.watchdog.lastError = "";
    runtimeGuardian.watchdog.lastErrorAt = "";
    await probeBridgeRuntimeHealth(source);
    const queueBefore = aggregateRuntimeQueuePressure();
    result.queue.pendingBefore = queueBefore.pending;
    result.queue.deadLettersBefore = queueBefore.deadLetters;
    const sloSnapshot = buildRuntimeSloSnapshot();
    const outage = summarizeRuntimeOutage(queueBefore, sloSnapshot);
    result.outageStatus = outage.status;

    if (!executeRepair && !executeQueue) {
      runtimeGuardian.watchdog.skippedReason = "no_action_selected";
      result.skippedReason = "no_action_selected";
      result.reason = "no_action_selected";
      result.summary = "未选择任何动作，已跳过执行。";
      result.queue.pendingAfter = queueBefore.pending;
      result.queue.deadLettersAfter = queueBefore.deadLetters;
      setManualActionSnapshot("skipped", result.summary);
      return result;
    }

    if (outage.status === "ok" && !force) {
      runtimeGuardian.watchdog.cooldownUntil = "";
      runtimeGuardian.watchdog.skippedReason = "stable";
      result.skippedReason = "stable";
      result.reason = "stable";
      result.summary = "当前链路稳定，本轮无需自愈。";
      result.queue.pendingAfter = queueBefore.pending;
      result.queue.deadLettersAfter = queueBefore.deadLetters;
      setManualActionSnapshot("skipped", result.summary);
      return result;
    }

    const nowMs = Date.now();
    const cooldownUntilMs = Date.parse(runtimeGuardian.watchdog.cooldownUntil || "") || 0;
    if (!force && cooldownUntilMs > nowMs) {
      runtimeGuardian.watchdog.skippedReason = "cooldown";
      result.skippedReason = "cooldown";
      result.reason = "cooldown";
      result.summary = "仍在冷却窗口，暂不重复触发自愈。";
      result.queue.pendingAfter = queueBefore.pending;
      result.queue.deadLettersAfter = queueBefore.deadLetters;
      setManualActionSnapshot("skipped", result.summary);
      return result;
    }
    if (runtimeAutonomy.cycleRunning) {
      runtimeGuardian.watchdog.skippedReason = "autonomy_cycle_running";
      result.skippedReason = "autonomy_cycle_running";
      result.reason = "autonomy_cycle_running";
      result.summary = "自治主循环正在运行，请稍后重试。";
      result.queue.pendingAfter = queueBefore.pending;
      result.queue.deadLettersAfter = queueBefore.deadLetters;
      setManualActionSnapshot("skipped", result.summary);
      return result;
    }

    const actions = [];
    let mutated = false;
    const shouldProcessQueue = executeQueue && runtimeGuardian.bridge.status === "up";
    if (executeQueue && !shouldProcessQueue) {
      actions.push("queue_skipped_bridge_down");
    }
    for (const userState of Object.values(store.users || {})) {
      if (!userState || typeof userState !== "object") {
        continue;
      }
      result.touchedUsers += 1;
      let userChanged = false;

      if (executeRepair && autonomySelfRepair(userState)) {
        userChanged = true;
        actions.push("schema_repair");
      }

      if (shouldProcessQueue) {
        const queueResult = await processAutonomyQueue(userState, {
          limit: queueLimit
        });
        result.queueProcessed += queueResult.processed;
        result.queueSucceeded += queueResult.succeeded;
        result.queueDeadLettered += queueResult.deadLettered;
        if (queueResult.changed) {
          userChanged = true;
          actions.push("queue_recover");
        }
      }
      const deadLetterCompaction = compactAutonomyDeadLetters(userState, {
        keepLimit: Math.max(queueLimit * 4, AUTONOMY_DEAD_LETTER_KEEP_LIMIT_PER_USER)
      });
      if (deadLetterCompaction.changed) {
        result.queueDeadLettersCompacted += deadLetterCompaction.removed;
        userChanged = true;
        actions.push("dead_letter_compact");
      }

      if (userChanged) {
        const autonomy = ensureAutonomyState(userState);
        appendMaintenanceRecord(
          autonomy,
          "runtime_watchdog",
          `Runtime Guardian 自愈触发：${outage.summary}`
        );
        userState.updatedAt = new Date().toISOString();
        result.changedUsers += 1;
        mutated = true;
      }
    }

    const queueAfter = aggregateRuntimeQueuePressure();
    result.queue.pendingAfter = queueAfter.pending;
    result.queue.deadLettersAfter = queueAfter.deadLetters;
    if (mutated) {
      saveStore(store);
    }
    runtimeGuardian.watchdog.cooldownUntil = new Date(
      nowMs + RUNTIME_GUARDIAN_SELF_HEAL_COOLDOWN_MS
    ).toISOString();
    result.executed = true;
    if (executeRepair && executeQueue) {
      result.reason = outage.cause || outage.status || (force ? "manual_full_heal" : "watchdog");
      result.summary = `watchdog 已执行自愈+重放：触达 ${result.touchedUsers} 个用户，修复 ${result.changedUsers} 个用户，处理队列 ${result.queueProcessed} 项，压缩 dead-letter ${result.queueDeadLettersCompacted} 项。`;
    } else if (executeQueue) {
      result.reason = "queue_replay";
      result.summary = `watchdog 已执行失败任务重放：触达 ${result.touchedUsers} 个用户，处理队列 ${result.queueProcessed} 项，压缩 dead-letter ${result.queueDeadLettersCompacted} 项。`;
    } else {
      result.reason = "schema_repair";
      result.summary = `watchdog 已执行结构自修复：触达 ${result.touchedUsers} 个用户，修复 ${result.changedUsers} 个用户。`;
    }
    appendRuntimeSelfHealReport({
      action,
      mode,
      reason: result.reason,
      summary: result.summary,
      actions: Array.from(new Set(actions)),
      queue: {
        pendingBefore: queueBefore.pending,
        deadLettersBefore: queueBefore.deadLetters,
        pendingAfter: queueAfter.pending,
        deadLettersAfter: queueAfter.deadLetters
      },
      touchedUsers: result.touchedUsers,
      changedUsers: result.changedUsers,
      queueProcessed: result.queueProcessed,
      queueSucceeded: result.queueSucceeded,
      queueDeadLettered: result.queueDeadLettered,
      queueDeadLettersCompacted: result.queueDeadLettersCompacted,
      saved: mutated
    });
    setManualActionSnapshot("executed", result.summary);
    result.reportId = runtimeGuardian.reports[0]?.id || "";
    return result;
  } catch (error) {
    runtimeGuardian.watchdog.lastErrorAt = new Date().toISOString();
    runtimeGuardian.watchdog.lastError = error instanceof Error ? error.message : String(error);
    pushRuntimeIssue({
      source,
      reason: "internal_error",
      message: runtimeGuardian.watchdog.lastError,
      statusCode: 0
    });
    result.ok = false;
    result.reason = "internal_error";
    result.summary = runtimeGuardian.watchdog.lastError;
    result.skippedReason = "runtime_error";
    setManualActionSnapshot("failed", result.summary);
    return result;
  } finally {
    runtimeGuardian.watchdog.cycleRunning = false;
  }
}

function ensureWorkdayState(userState) {
  if (!userState.workday || typeof userState.workday !== "object") {
    userState.workday = createDefaultWorkdayState();
  }
  const workday = userState.workday;

  if (typeof workday.date !== "string" || !workday.date) {
    workday.date = todayKey();
  }
  if (typeof workday.clarityScore !== "number") {
    workday.clarityScore = 68;
  }
  if (typeof workday.affectionScore !== "number") {
    workday.affectionScore = 72;
  }
  if (typeof workday.flowStreakDays !== "number") {
    workday.flowStreakDays = 0;
  }
  if (typeof workday.flowCombo !== "number") {
    workday.flowCombo = 0;
  }
  if (typeof workday.focusMinutes !== "number") {
    workday.focusMinutes = 0;
  }
  if (typeof workday.totalQuestXp !== "number") {
    workday.totalQuestXp = 0;
  }
  if (typeof workday.completedCount !== "number") {
    workday.completedCount = 0;
  }
  if (!Array.isArray(workday.quests) || workday.quests.length === 0) {
    workday.quests = buildWorkdayQuests(workday.date);
  }
  if (!Array.isArray(workday.rewardLog)) {
    workday.rewardLog = [];
  }
  if (typeof workday.lastCheckinAt !== "string") {
    workday.lastCheckinAt = "";
  }
  if (typeof workday.lastSummary !== "string") {
    workday.lastSummary = "";
  }

  for (const quest of workday.quests) {
    if (!quest || typeof quest !== "object") {
      continue;
    }
    if (typeof quest.id !== "string" || !quest.id) {
      quest.id = `wq-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
    }
    if (typeof quest.code !== "string") {
      quest.code = "custom";
    }
    if (typeof quest.title !== "string") {
      quest.title = "未命名任务";
    }
    if (typeof quest.description !== "string") {
      quest.description = "";
    }
    if (typeof quest.category !== "string") {
      quest.category = "execution";
    }
    if (typeof quest.minutes !== "number") {
      quest.minutes = 10;
    }
    if (typeof quest.rewardXp !== "number") {
      quest.rewardXp = 10;
    }
    if (typeof quest.careBonus !== "number") {
      quest.careBonus = 0;
    }
    if (!["todo", "done"].includes(quest.status)) {
      quest.status = "todo";
    }
    if (typeof quest.completedAt !== "string") {
      quest.completedAt = "";
    }
    if (typeof quest.note !== "string") {
      quest.note = "";
    }
  }

  const nowDay = todayKey();
  if (workday.date !== nowDay) {
    const doneCount = workday.quests.filter((item) => item.status === "done").length;
    const completionRate = workday.quests.length > 0 ? doneCount / workday.quests.length : 0;
    const diff = dayDiff(workday.date, nowDay);
    if (completionRate >= 0.66) {
      workday.flowStreakDays = diff === 1 ? workday.flowStreakDays + 1 : 1;
    } else if (diff > 1) {
      workday.flowStreakDays = 0;
    }
    workday.date = nowDay;
    workday.flowCombo = 0;
    workday.focusMinutes = 0;
    workday.totalQuestXp = 0;
    workday.completedCount = 0;
    workday.quests = buildWorkdayQuests(nowDay);
    workday.lastSummary = "";
  }

  workday.clarityScore = clampInteger(workday.clarityScore, 68, 20, 100);
  workday.affectionScore = clampInteger(workday.affectionScore, 72, 20, 100);
  workday.flowStreakDays = Math.max(0, clampInteger(workday.flowStreakDays, 0, 0, 365));
  workday.flowCombo = Math.max(0, clampInteger(workday.flowCombo, 0, 0, 999));
  workday.focusMinutes = Math.max(0, clampInteger(workday.focusMinutes, 0, 0, 1000));
  workday.totalQuestXp = Math.max(0, clampInteger(workday.totalQuestXp, 0, 0, 50000));
  workday.completedCount = workday.quests.filter((item) => item.status === "done").length;

  if (workday.rewardLog.length > 80) {
    workday.rewardLog.length = 80;
  }

  return workday;
}

function sanitizeWorkday(workdayInput) {
  const workday = workdayInput || createDefaultWorkdayState();
  return {
    date: workday.date,
    clarityScore: workday.clarityScore,
    affectionScore: workday.affectionScore,
    flowStreakDays: workday.flowStreakDays,
    flowCombo: workday.flowCombo,
    focusMinutes: workday.focusMinutes,
    totalQuestXp: workday.totalQuestXp,
    completedCount: workday.completedCount,
    totalCount: Array.isArray(workday.quests) ? workday.quests.length : 0,
    quests: Array.isArray(workday.quests)
      ? workday.quests.map((item) => ({
          id: item.id,
          code: item.code,
          title: item.title,
          description: item.description,
          category: item.category,
          minutes: item.minutes,
          rewardXp: item.rewardXp,
          careBonus: item.careBonus,
          status: item.status,
          completedAt: item.completedAt,
          note: item.note
        }))
      : [],
    rewardLog: Array.isArray(workday.rewardLog) ? workday.rewardLog : [],
    lastCheckinAt: workday.lastCheckinAt,
    lastSummary: workday.lastSummary
  };
}

function appendWorkbenchFeed(workbench, title, summary, source = "system") {
  const item = {
    id: `wb-feed-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
    title: String(title || "工作台回执"),
    summary: String(summary || ""),
    source: String(source || "system"),
    at: new Date().toISOString()
  };
  workbench.centerFeed.unshift(item);
  if (workbench.centerFeed.length > 60) {
    workbench.centerFeed.length = 60;
  }
  return item;
}

function buildCodingPlanFromIntent(intent) {
  const trimmed = String(intent || "").trim();
  if (!trimmed) {
    return [
      "确认目标和交付物",
      "拆成 3 个可执行步骤",
      "产出代码和验证清单"
    ];
  }
  return [
    `理解目标：${trimmed}`,
    "拆解任务并确认输入输出",
    "生成代码/脚本并标记关键点",
    "执行测试并自动修复常见报错",
    "输出最终回执和下一步建议"
  ];
}

function ensureWorkbenchState(userState) {
  if (!userState.workbench || typeof userState.workbench !== "object") {
    userState.workbench = createDefaultWorkbenchState();
  }
  const workbench = userState.workbench;

  if (typeof workbench.layoutVersion !== "string" || !workbench.layoutVersion) {
    workbench.layoutVersion = "work-scene-whiteboard-v1";
  }
  if (!Array.isArray(workbench.leftModules) || workbench.leftModules.length === 0) {
    workbench.leftModules = createDefaultWorkbenchState().leftModules;
  }
  if (!Array.isArray(workbench.rightTools) || workbench.rightTools.length === 0) {
    workbench.rightTools = createDefaultWorkbenchState().rightTools;
  }
  if (!workbench.modelCenter || typeof workbench.modelCenter !== "object") {
    workbench.modelCenter = createDefaultWorkbenchState().modelCenter;
  }
  if (!Array.isArray(workbench.modelCenter.options) || workbench.modelCenter.options.length === 0) {
    workbench.modelCenter.options = WORKBENCH_MODEL_OPTIONS;
  }
  if (typeof workbench.modelCenter.currentModel !== "string" || !workbench.modelCenter.currentModel) {
    workbench.modelCenter.currentModel = workbench.modelCenter.options[0]?.id || WORKBENCH_MODEL_OPTIONS[0].id;
  }
  if (!workbench.coding || typeof workbench.coding !== "object") {
    workbench.coding = createDefaultWorkbenchState().coding;
  }
  if (typeof workbench.coding.autopilotEnabled !== "boolean") {
    workbench.coding.autopilotEnabled = false;
  }
  if (!Array.isArray(workbench.coding.recentIntents)) {
    workbench.coding.recentIntents = [];
  }
  if (!Array.isArray(workbench.coding.lastPlan)) {
    workbench.coding.lastPlan = [];
  }
  if (!workbench.coding.workspace || typeof workbench.coding.workspace !== "object") {
    workbench.coding.workspace = createDefaultWorkbenchState().coding.workspace;
  }
  if (typeof workbench.coding.workspace.cwd !== "string" || !workbench.coding.workspace.cwd) {
    workbench.coding.workspace.cwd = createDefaultWorkbenchState().coding.workspace.cwd;
  }
  if (typeof workbench.coding.workspace.absolutePath !== "string") {
    workbench.coding.workspace.absolutePath = "";
  }
  if (typeof workbench.coding.workspace.exists !== "boolean") {
    workbench.coding.workspace.exists = false;
  }
  if (typeof workbench.coding.workspace.openedAt !== "string") {
    workbench.coding.workspace.openedAt = "";
  }
  if (typeof workbench.coding.workspace.lastAction !== "string") {
    workbench.coding.workspace.lastAction = "";
  }
  if (!Array.isArray(workbench.coding.workspace.entries)) {
    workbench.coding.workspace.entries = [];
  }
  const shouldRefreshCodingWorkspace = !workbench.coding.workspace.absolutePath
    || workbench.coding.workspace.entries.length === 0
    || workbench.coding.workspace.exists !== true;
  if (shouldRefreshCodingWorkspace) {
    const workspaceSnapshot = buildCodingWorkspaceSnapshot(workbench.coding.workspace.cwd, {
      fallback: "apps/desktop",
      openedAt: workbench.coding.workspace.openedAt || "",
      lastAction: workbench.coding.workspace.lastAction || ""
    });
    workbench.coding.workspace = workspaceSnapshot;
    if (!workbench.coding.workspace.lastAction) {
      workbench.coding.workspace.lastAction = `工作目录：${workspaceSnapshot.cwd}`;
    }
  }
  if (!Array.isArray(workbench.centerFeed) || workbench.centerFeed.length === 0) {
    workbench.centerFeed = createDefaultWorkbenchState().centerFeed;
  }
  if (!workbench.inputBar || typeof workbench.inputBar !== "object") {
    workbench.inputBar = createDefaultWorkbenchState().inputBar;
  }
  if (typeof workbench.inputBar.hashtagEnabled !== "boolean") {
    workbench.inputBar.hashtagEnabled = true;
  }
  if (typeof workbench.inputBar.voiceEnabled !== "boolean") {
    workbench.inputBar.voiceEnabled = true;
  }
  if (typeof workbench.inputBar.placeholder !== "string" || !workbench.inputBar.placeholder) {
    workbench.inputBar.placeholder = createDefaultWorkbenchState().inputBar.placeholder;
  }
  if (typeof workbench.updatedAt !== "string") {
    workbench.updatedAt = new Date().toISOString();
  }

  for (const module of workbench.leftModules) {
    if (!module || typeof module !== "object") {
      continue;
    }
    if (typeof module.id !== "string" || !module.id) {
      module.id = `left-${Math.random().toString(36).slice(2, 9)}`;
    }
    if (typeof module.title !== "string") {
      module.title = "未命名模块";
    }
    if (typeof module.note !== "string") {
      module.note = "";
    }
    if (typeof module.enabled !== "boolean") {
      module.enabled = true;
    }
    if (typeof module.status !== "string" || !module.status) {
      module.status = module.enabled ? "ready" : "disabled";
    }
  }

  for (const tool of workbench.rightTools) {
    if (!tool || typeof tool !== "object") {
      continue;
    }
    if (typeof tool.id !== "string" || !tool.id) {
      tool.id = `tool-${Math.random().toString(36).slice(2, 9)}`;
    }
    if (typeof tool.title !== "string") {
      tool.title = "未命名工具";
    }
    if (typeof tool.summary !== "string") {
      tool.summary = "";
    }
    if (typeof tool.status !== "string" || !tool.status) {
      tool.status = "idle";
    }
    if (typeof tool.lastRunAt !== "string") {
      tool.lastRunAt = "";
    }
    if (typeof tool.lastResult !== "string") {
      tool.lastResult = "";
    }
  }

  if (workbench.coding.recentIntents.length > 30) {
    workbench.coding.recentIntents.length = 30;
  }
  if (workbench.coding.lastPlan.length > 12) {
    workbench.coding.lastPlan.length = 12;
  }
  if (workbench.coding.workspace.entries.length > 40) {
    workbench.coding.workspace.entries.length = 40;
  }
  if (workbench.centerFeed.length > 60) {
    workbench.centerFeed.length = 60;
  }

  return workbench;
}

function sanitizeWorkbenchState(workbenchInput) {
  const workbench = workbenchInput || createDefaultWorkbenchState();
  return {
    layoutVersion: workbench.layoutVersion,
    leftModules: Array.isArray(workbench.leftModules) ? workbench.leftModules : [],
    rightTools: Array.isArray(workbench.rightTools) ? workbench.rightTools : [],
    modelCenter: workbench.modelCenter || createDefaultWorkbenchState().modelCenter,
    coding: workbench.coding || createDefaultWorkbenchState().coding,
    centerFeed: Array.isArray(workbench.centerFeed) ? workbench.centerFeed : [],
    inputBar: workbench.inputBar || createDefaultWorkbenchState().inputBar,
    updatedAt: workbench.updatedAt || ""
  };
}

function extractUrlsFromText(text) {
  const matches = String(text || "").match(/https?:\/\/[^\s)<>"']+/gi) || [];
  const deduped = new Set();
  for (const raw of matches) {
    const cleaned = raw.replace(/[),.;!?，。！？；：]+$/g, "");
    if (cleaned) {
      deduped.add(cleaned);
    }
  }
  return Array.from(deduped).slice(0, 6);
}

function buildPackIdFromUrl(url) {
  const normalized = String(url || "")
    .replace(/^https?:\/\//i, "")
    .replace(/[^a-zA-Z0-9._-]/g, "-")
    .slice(0, 42);
  return `pack.remote.${normalized || Date.now()}`;
}

function detectDispatchDeviceTasks(intentText) {
  const text = String(intentText || "").trim();
  if (!text) {
    return [];
  }
  const normalized = normalizeIntentText(text);
  const signals = buildIntentSignalSnapshot(text);
  const hits = [];
  const testKeywords = (keywords = []) => keywords.some((keyword) => {
    const normalizedKeyword = normalizeIntentText(keyword);
    return normalizedKeyword && normalized.includes(normalizedKeyword);
  });
  const testTaskSemanticFallback = (taskType) => {
    if (taskType === "desktop_focus_cleanup") {
      const hasCleanupAction = /(整理|清理|归档|收纳|收拾|归类|分类|cleanup|tidy|organize)/i.test(normalized);
      const hasDesktopContext = signals.object.computer || signals.context.desktop;
      const hasFileObject = signals.object.file || signals.object.image || signals.object.document;
      return (hasDesktopContext && hasCleanupAction)
        || (hasDesktopContext && hasFileObject && signals.action.execute);
    }
    if (taskType === "desktop_mail_inbox_zero") {
      const hasMailObject = /邮件|邮箱|收件箱|mail|email|inbox/i.test(normalized);
      const hasMailAction = /(清理|整理|归档|分拣|归类|zero|清空|梳理)/i.test(normalized);
      return hasMailObject && (hasMailAction || signals.action.execute);
    }
    if (taskType === "mobile_album_cleanup") {
      const hasMobileContext = signals.context.mobile || /手机|移动端|ios|android/.test(normalized);
      const hasAlbumObject = /相册|照片|图片|photo|image|album/i.test(normalized);
      const hasCleanupAction = /(整理|清理|去重|归档|分类|cleanup|organize)/i.test(normalized);
      return hasMobileContext && hasAlbumObject && (hasCleanupAction || signals.action.execute);
    }
    if (taskType === "mobile_sms_digest") {
      const hasSmsObject = /短信|sms|message|消息/.test(normalized);
      const hasDigestAction = /(汇总|摘要|待办|总结|梳理|digest|todo)/i.test(normalized);
      return hasSmsObject && (hasDigestAction || signals.action.execute);
    }
    if (taskType === "mobile_email_digest") {
      const hasMobileContext = signals.context.mobile || /手机|移动端|ios|android/.test(normalized);
      const hasMailObject = /邮件|邮箱|mail|email/.test(normalized);
      const hasDigestAction = /(汇总|摘要|待办|总结|梳理|digest|todo)/i.test(normalized);
      return hasMobileContext && hasMailObject && (hasDigestAction || signals.action.execute);
    }
    if (taskType === "desktop_hardware_check") {
      const hasDesktopContext = signals.object.computer || signals.context.desktop;
      const hasHardwareObject = /硬件|cpu|内存|电池|磁盘|性能|状态|资源/.test(normalized);
      const hasCheckAction = /(检查|巡检|监测|查看|诊断|health|check|inspect)/i.test(normalized);
      return (hasHardwareObject && hasCheckAction) || (hasDesktopContext && hasHardwareObject);
    }
    return false;
  };
  for (const rule of DISPATCH_TASK_RULES) {
    const matched = testKeywords(rule.keywords) || testTaskSemanticFallback(rule.taskType);
    if (!matched) {
      continue;
    }
    hits.push({
      type: "device_task",
      taskType: rule.taskType,
      title: rule.title
    });
  }
  return hits;
}

function uniqueIntentTokens(input = [], limit = 20) {
  const deduped = new Set();
  const result = [];
  for (const item of input) {
    const normalized = String(item || "").trim();
    if (!normalized || deduped.has(normalized)) {
      continue;
    }
    deduped.add(normalized);
    result.push(normalized);
    if (result.length >= limit) {
      break;
    }
  }
  return result;
}

