function formatTemplateDateLabel(dateInput = new Date()) {
  const date = dateInput instanceof Date ? dateInput : new Date(dateInput);
  const weekdayMap = ["周日", "周一", "周二", "周三", "周四", "周五", "周六"];
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  const weekday = weekdayMap[date.getDay()] || "";
  return `${year}-${month}-${day} ${weekday}`.trim();
}

function formatTemplateTimeLabel(dateInput = new Date()) {
  const date = dateInput instanceof Date ? dateInput : new Date(dateInput);
  const hour = String(date.getHours()).padStart(2, "0");
  const minute = String(date.getMinutes()).padStart(2, "0");
  return `${hour}:${minute}`;
}

function parseChineseCountToken(tokenInput = "", fallback = 2) {
  const token = String(tokenInput || "").trim();
  if (!token) {
    return fallback;
  }
  if (/^\d+$/.test(token)) {
    return clampInteger(Number(token), fallback, 1, 12);
  }
  const map = {
    一: 1,
    二: 2,
    两: 2,
    俩: 2,
    三: 3,
    四: 4,
    五: 5,
    六: 6,
    七: 7,
    八: 8,
    九: 9,
    十: 10
  };
  return clampInteger(map[token] || fallback, fallback, 1, 12);
}

function resolveReusableTemplateIdByText(textInput = "") {
  const text = String(textInput || "").toLowerCase();
  if (!text) {
    return "";
  }
  if (/每日\s*ai|ai\s*资讯|ai\s*新闻|资讯|快报|日报|周报|news/i.test(text)) {
    return "daily_ai_news";
  }
  if (/菜谱|食谱|做饭|晚餐|早餐|午餐|吃什么|备菜|减脂餐|家常菜/i.test(text)) {
    return "recipe_plan";
  }
  if (/就医|挂号|看病|问诊|医院|科室|症状|诊疗|门诊|急诊/i.test(text)) {
    return "medical_triage";
  }
  if (/会议纪要|复盘|汇报|行动项|会议总结|会议记录/i.test(text)) {
    return "meeting_brief";
  }
  if (/待办|清单|日程|安排|提醒|本周计划|今日计划/i.test(text)) {
    return "life_todo";
  }
  return "";
}

function inferReusableTemplateVariables(textInput = "", templateId = "") {
  const text = String(textInput || "").trim();
  const now = new Date();
  const dateLabel = formatTemplateDateLabel(now);
  const timeLabel = formatTemplateTimeLabel(now);
  const topic = text
    .replace(/帮我|请|一下|麻烦|先|然后|再|并且|并/g, " ")
    .replace(/做|生成|写|发|发布|发帖|整理|输出|给我|一份|一个|一条|模板|卡片|结论|建议|方案/gi, " ")
    .replace(/\s+/g, " ")
    .trim()
    .slice(0, 80);
  let tone = "专业清晰";
  if (/轻松|有趣|活泼|口语/.test(text)) tone = "轻松友好";
  if (/正式|严谨|商务|给老板/.test(text)) tone = "正式商务";
  const platform = /小红书|rednote|xiaohongshu/i.test(text)
    ? "小红书"
    : /飞书|feishu|lark/i.test(text)
      ? "飞书"
      : /微信|wechat/i.test(text)
        ? "微信"
        : "通用";
  const audience = /老板|上级|客户|用户|妈妈|父母|朋友|同事/.exec(text)?.[0] || "通用读者";
  const servingsMatch = text.match(/(\d{1,2}|一|二|两|俩|三|四|五|六)\s*人份?/);
  const servings = parseChineseCountToken(servingsMatch?.[1] || "", 2);
  const mealType = /早餐/.test(text) ? "早餐" : /午餐/.test(text) ? "午餐" : /晚餐/.test(text) ? "晚餐" : "家常餐";
  const symptom = (() => {
    const explicit = text.match(/(?:症状|不舒服|感觉|出现)\s*[:：]?\s*([^\n，。]{2,32})/);
    if (explicit?.[1]) return explicit[1];
    if (/发烧/.test(text)) return "发烧";
    if (/咳嗽/.test(text)) return "咳嗽";
    if (/头痛/.test(text)) return "头痛";
    if (/肚子痛|腹痛/.test(text)) return "腹痛";
    return "待补充症状";
  })();
  const urgency = /急|立刻|马上|严重|高烧|胸痛|呼吸困难/.test(text) ? "高" : /不急|慢性|复诊/.test(text) ? "低" : "中";
  return {
    templateId,
    dateLabel,
    timeLabel,
    topic: topic || "默认主题",
    tone,
    audience,
    platform,
    servings,
    mealType,
    symptom,
    urgency
  };
}

