async function executeDeviceTask(userState, taskId) {
  const deviceOps = ensureDeviceOpsState(userState);
  const autonomy = ensureAutonomyState(userState);
  const task = deviceOps.tasks.find((item) => item.id === taskId);
  if (!task) {
    return {
      ok: false,
      reason: "task_not_found",
      task: null,
      deviceOps: sanitizeDeviceOps(deviceOps)
    };
  }

  const capability = capabilityById(task.capabilityId);
  const permission = capability ? deviceOps.permissions[capability.id] : "prompt";
  const flowId = resolveFlowId(task.flowId, "flow-device-task");
  if (permission !== "granted") {
    task.status = "needs_permission";
    task.reason = "执行前需要权限授权";
    appendDeviceAudit(
      deviceOps,
      "task_blocked",
      `任务 ${task.title} 被拦截：权限未授权。`,
      {
        taskId: task.id,
        capabilityId: task.capabilityId,
        permission
      }
    );
    appendAutonomyTimeline(autonomy, {
      flowId,
      source: "device",
      stage: "device_task_blocked",
      status: "warning",
      title: `设备任务待授权：${task.title}`,
      detail: `${task.capabilityId} 未授权，任务暂停。`,
      refs: {
        taskId: task.id,
        taskType: task.type,
        capabilityId: task.capabilityId
      }
    });
    return {
      ok: false,
      reason: "permission_required",
      task,
      deviceOps: sanitizeDeviceOps(deviceOps)
    };
  }

  task.status = "running";
  task.startedAt = new Date().toISOString();
  let output = null;
  let bridgeTrace = null;
  if (deviceOps.bridge.enabled) {
    const bridgeResult = await executeTaskByBridge(task, deviceOps);
    bridgeTrace = bridgeResult.bridge || null;
    if (bridgeResult.ok && bridgeResult.output) {
      output = bridgeResult.output;
    }
  }
  if (!output && task.type === "desktop_web_research") {
    const researchResult = await runAutonomyWebResearch({
      query: String(task.payload?.query || task.summary || task.title || "").trim(),
      maxResults: clampInteger(task.payload?.maxResults, 5, 1, 20)
    });
    output = {
      summary: researchResult.summary || "网页检索执行完成。",
      metrics: {
        queryLength: String(task.payload?.query || task.summary || "").length,
        resultCount: Array.isArray(researchResult.items) ? researchResult.items.length : 0
      },
      items: Array.isArray(researchResult.items) ? researchResult.items : []
    };
    if (!researchResult.ok) {
      output.error = researchResult.error || researchResult.reason || "web_research_failed";
    }
  }
  if (!output) {
    output = synthesizeDeviceTaskOutput(task);
  }
  task.status = "completed";
  task.finishedAt = new Date().toISOString();
  task.reason = "execution_finished";
  task.output = output;

  appendDeviceAudit(
    deviceOps,
    "task_completed",
    `任务 ${task.title} 执行完成。`,
    {
      taskId: task.id,
      capabilityId: task.capabilityId,
      metrics: output.metrics,
      bridge: bridgeTrace
    }
  );
  appendAutonomyTimeline(autonomy, {
    flowId,
    source: "device",
    stage: "device_task_completed",
    status: "success",
    title: `设备任务完成：${task.title}`,
    detail: String(output?.summary || "任务执行完成"),
    refs: {
      taskId: task.id,
      taskType: task.type,
      capabilityId: task.capabilityId,
      source: task.source || ""
    }
  });

  return {
    ok: true,
    reason: "task_completed",
    task,
    deviceOps: sanitizeDeviceOps(deviceOps)
  };
}

function workdaySummaryLine(workday) {
  const completionRatio =
    workday.quests.length > 0 ? Math.round((workday.completedCount / workday.quests.length) * 100) : 0;
  return `清晰度 ${workday.clarityScore} · 爱的能量 ${workday.affectionScore} · 今日完成 ${completionRatio}%`;
}

function workdayCheckin(userState, payload = {}) {
  const workday = ensureWorkdayState(userState);
  const energy = clampInteger(payload.energy, 3, 1, 5);
  const pressure = clampInteger(payload.pressure, 3, 1, 5);
  const focusIntent = String(payload.focusIntent || "").trim();

  const clarityDelta = energy >= 4 ? 6 : energy >= 3 ? 4 : 1;
  const pressurePenalty = pressure >= 4 ? -4 : pressure === 3 ? -2 : 0;
  workday.clarityScore = clampInteger(
    workday.clarityScore + clarityDelta + pressurePenalty,
    workday.clarityScore,
    20,
    100
  );
  workday.affectionScore = clampInteger(
    workday.affectionScore + (pressure >= 4 ? 3 : 2),
    workday.affectionScore,
    20,
    100
  );
  workday.lastCheckinAt = new Date().toISOString();
  workday.lastSummary = focusIntent
    ? `今日意图：${focusIntent.slice(0, 80)}；${workdaySummaryLine(workday)}`
    : workdaySummaryLine(workday);

  workday.rewardLog.unshift({
    id: `wr-${Date.now()}-${Math.floor(Math.random() * 1000)}`,
    type: "checkin",
    summary: `完成工作状态签到（能量 ${energy}/5，压力 ${pressure}/5）`,
    at: workday.lastCheckinAt
  });
  if (workday.rewardLog.length > 80) {
    workday.rewardLog.length = 80;
  }

  return {
    energy,
    pressure,
    guidance:
      pressure >= 4
        ? "今天先保命线推进：只做 1 个最关键任务，剩余任务交给我分批处理。"
        : "状态不错，建议先打掉最高杠杆任务，再进入 25 分钟冲刺。",
    workday: sanitizeWorkday(workday)
  };
}

function completeWorkdayQuest(userState, questId, note = "") {
  const workday = ensureWorkdayState(userState);
  const quest = workday.quests.find((item) => item.id === questId || item.code === questId);
  if (!quest) {
    return {
      ok: false,
      reason: "quest_not_found",
      workday: sanitizeWorkday(workday),
      xpGain: 0
    };
  }
  if (quest.status === "done") {
    return {
      ok: true,
      reason: "quest_already_completed",
      workday: sanitizeWorkday(workday),
      xpGain: 0
    };
  }

  quest.status = "done";
  quest.completedAt = new Date().toISOString();
  quest.note = String(note || "").slice(0, 120);

  workday.completedCount = workday.quests.filter((item) => item.status === "done").length;
  workday.focusMinutes += quest.minutes;
  workday.totalQuestXp += quest.rewardXp;
  workday.flowCombo += 1;
  workday.clarityScore = clampInteger(
    workday.clarityScore + (quest.category === "clarity" ? 8 : 4),
    workday.clarityScore,
    20,
    100
  );
  workday.affectionScore = clampInteger(
    workday.affectionScore + quest.careBonus,
    workday.affectionScore,
    20,
    100
  );
  workday.lastSummary = workdaySummaryLine(workday);
  workday.rewardLog.unshift({
    id: `wr-${Date.now()}-${Math.floor(Math.random() * 1000)}`,
    type: "quest",
    summary: `完成任务：${quest.title}，获得 ${quest.rewardXp} XP`,
    at: quest.completedAt
  });
  if (workday.rewardLog.length > 80) {
    workday.rewardLog.length = 80;
  }

  const engagement = ensureEngagementState(userState);
  const nowIso = new Date().toISOString();
  markActiveDay(engagement, todayKey());
  engagement.xp += quest.rewardXp;
  engagement.level = calculateLevel(engagement.xp);
  engagement.lastEventAt = nowIso;
  engagement.lastEventType = "workday_quest";
  engagement.recentEvents.unshift({
    id: `evt-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
    type: "workday_quest",
    xpGain: quest.rewardXp,
    at: nowIso,
    metadata: {
      questId: quest.id,
      questCode: quest.code
    }
  });
  if (engagement.recentEvents.length > 50) {
    engagement.recentEvents.length = 50;
  }

  return {
    ok: true,
    reason: "quest_completed",
    quest,
    xpGain: quest.rewardXp,
    workday: sanitizeWorkday(workday),
    engagement: sanitizeEngagement(engagement)
  };
}

function markActiveDay(engagement, activeDay) {
  if (engagement.lastActiveDay === activeDay) {
    return;
  }
  const diff = dayDiff(engagement.lastActiveDay, activeDay);
  if (Number.isNaN(diff)) {
    engagement.streakDays = 1;
  } else if (diff === 1) {
    engagement.streakDays = Math.max(1, engagement.streakDays + 1);
  } else if (diff <= 0) {
    engagement.streakDays = Math.max(1, engagement.streakDays || 1);
  } else {
    engagement.streakDays = 1;
  }
  engagement.lastActiveDay = activeDay;
}

function applyEngagementEvent(userState, type, metadata = {}) {
  const now = new Date();
  const nowIso = now.toISOString();
  const activeDay = todayKey(now);
  const engagement = ensureEngagementState(userState);

  let xpGain = engagementEventXp[type] || 0;
  if (type === "daily_checkin" && engagement.today.checkinDone) {
    xpGain = 0;
  }
  if (type === "quest_complete" && engagement.today.questCompleted) {
    xpGain = 0;
  }
  if (type === "reward_claim" && engagement.today.rewardClaimed) {
    xpGain = 0;
  }

  if (type === "message_sent") {
    engagement.today.messageCount += 1;
  }
  if (type === "daily_checkin") {
    engagement.today.checkinDone = true;
  }
  if (type === "quest_complete") {
    engagement.today.questCompleted = true;
  }
  if (type === "reward_claim") {
    engagement.today.rewardClaimed = true;
  }

  const shouldMarkActive =
    type === "message_sent" ||
    type === "daily_checkin" ||
    type === "quest_complete" ||
    type === "reward_claim" ||
    type === "session_resume";
  if (shouldMarkActive) {
    markActiveDay(engagement, activeDay);
  }

  engagement.xp += xpGain;
  engagement.level = calculateLevel(engagement.xp);
  engagement.lastEventAt = nowIso;
  engagement.lastEventType = type;
  engagement.recentEvents.unshift({
    id: `evt-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
    type,
    xpGain,
    at: nowIso,
    metadata
  });
  if (engagement.recentEvents.length > 50) {
    engagement.recentEvents.length = 50;
  }

  return {
    xpGain,
    engagement: sanitizeEngagement(engagement)
  };
}

function getUserState(store, userId) {
  ensureSharedRuntimeState(store);
  if (!store.users[userId]) {
    store.users[userId] = createDefaultUserState(userId);
    saveStore(store);
  }
  const userState = store.users[userId];
  ensureSceneMessageVault(userState);
  return userState;
}

function sanitizeMemorySystemState(userState, options = {}) {
  const memorySystem = ensureMemoryPlaneState(userState);
  const scene = normalizeMemoryScene(options.scene, "");
  const maxItems = clampInteger(options.limit, 12, 1, 80);
  const sceneRecords = scene
    ? memorySystem.sceneVaults[scene].items
    : memorySystem.vectorIndex.items;
  return {
    version: String(memorySystem.version || "2026.3.8"),
    backend: String(memorySystem.backend || "local-vector-index"),
    vectorDim: clampInteger(memorySystem.vectorDim, MEMORY_VECTOR_DIM, 16, 2048),
    architecture: memorySystem.architecture,
    summary: {
      longTerm: memorySystem.longTerm.items.length,
      middleTerm: memorySystem.middleTerm.items.length,
      shortTerm: memorySystem.shortTerm.items.length,
      temporary: memorySystem.temporary.items.length,
      vectorIndex: memorySystem.vectorIndex.items.length,
      sceneCounts: Object.fromEntries(
        MEMORY_SCENES.map((sceneId) => [sceneId, memorySystem.sceneVaults[sceneId].items.length])
      )
    },
    jobs: memorySystem.jobs,
    stats: memorySystem.stats,
    scene: scene || null,
    sceneItems: sceneRecords.slice(0, maxItems).map((item) => ({
      id: String(item.id || ""),
      scene: normalizeMemoryScene(item.scene, "love"),
      tier: normalizeMemoryTier(item.tier, "long_term"),
      source: String(item.source || "memory"),
      content: String(item.content || ""),
      importance: clampPolicyFloat(item.importance, 0.6, 0, 1),
      confidence: clampPolicyFloat(item.confidence, 0.6, 0, 1),
      updatedAt: String(item.updatedAt || item.createdAt || ""),
      tags: uniqueStringArray(item.tags || [], 12)
    }))
  };
}

function buildMemoryPlaneRuntimeSnapshot(userState) {
  if (isQdrantEnabled() && !qdrantCollectionReady && !qdrantEnsurePromise) {
    void ensureQdrantCollection();
  }
  const memorySystem = ensureMemoryPlaneState(userState);
  const sceneCounts = Object.fromEntries(
    MEMORY_SCENES.map((sceneId) => [sceneId, memorySystem.sceneVaults[sceneId].items.length])
  );
  return {
    backend: vectorBackendRuntime.backend,
    vector: {
      mode: isQdrantModeSelected() ? "qdrant" : "local-index",
      qdrant: {
        configured: vectorBackendRuntime.qdrant.configured,
        url: vectorBackendRuntime.qdrant.url,
        collection: vectorBackendRuntime.qdrant.collection,
        ready: vectorBackendRuntime.qdrant.ready,
        lastCheckAt: vectorBackendRuntime.qdrant.lastCheckAt,
        lastWriteAt: vectorBackendRuntime.qdrant.lastWriteAt,
        lastSearchAt: vectorBackendRuntime.qdrant.lastSearchAt,
        lastStatus: vectorBackendRuntime.qdrant.lastStatus,
        lastError: vectorBackendRuntime.qdrant.lastError,
        lastUpsertId: vectorBackendRuntime.qdrant.lastUpsertId,
        lastSearchHits: vectorBackendRuntime.qdrant.lastSearchHits
      }
    },
    architecture: memorySystem.architecture,
    memorySummary: {
      longTerm: memorySystem.longTerm.items.length,
      middleTerm: memorySystem.middleTerm.items.length,
      shortTerm: memorySystem.shortTerm.items.length,
      temporary: memorySystem.temporary.items.length,
      vectorIndex: memorySystem.vectorIndex.items.length,
      sceneCounts
    },
    jobs: memorySystem.jobs,
    stats: memorySystem.stats
  };
}

function sanitizeState(state) {
  const sceneMessages = ensureSceneMessageVault(state);
  const engagement = ensureEngagementState(state);
  const proactive = ensureProactiveState(state);
  const autonomy = ensureAutonomyState(state);
  const workday = ensureWorkdayState(state);
  const deviceOps = ensureDeviceOpsState(state);
  const workbench = ensureWorkbenchState(state);
  const expansion = ensureExpansionState(state);
  const sceneConfig = ensureSceneConfigState(state);
  const funGames = ensureFunGamesState(state);
  const funRuleTemplates = ensureFunRuleTemplateState(state);
  return {
    userId: state.userId,
    profile: state.profile,
    preferences: state.preferences,
    messages: state.messages,
    sceneMessages: Object.fromEntries(
      MEMORY_SCENES.map((scene) => [scene, (sceneMessages[scene] || []).map((item) => ({ ...item }))])
    ),
    memoryHighlights: state.memoryHighlights,
    memorySystem: sanitizeMemorySystemState(state),
    engagement: sanitizeEngagement(engagement),
    proactive: sanitizeProactive(proactive),
    autonomy: sanitizeAutonomy(autonomy),
    workday: sanitizeWorkday(workday),
    deviceOps: sanitizeDeviceOps(deviceOps),
    workbench: sanitizeWorkbenchState(workbench),
    expansion: sanitizeExpansionState(expansion),
    sceneConfig: sanitizeSceneConfigState(sceneConfig),
    funGames: sanitizeFunGames(funGames),
    funRuleTemplates: sanitizeFunRuleTemplates(funRuleTemplates),
    updatedAt: state.updatedAt
  };
}

const OPENCLAW_SESSION_LIMIT = 20;
const OPENCLAW_SESSION_HISTORY_LIMIT = 60;
const openclawSessionBuckets = new Map();

function createOpenclawSession(sessionInput = {}) {
  const raw = sessionInput && typeof sessionInput === "object" ? sessionInput : {};
  const nowIso = new Date().toISOString();
  const history = Array.isArray(raw.history) ? raw.history : [];
  return {
    id: String(raw.id || `sess-${Date.now()}-${Math.floor(Math.random() * 10000)}`),
    runtime: String(raw.runtime || "aria-main"),
    mode: String(raw.mode || "session"),
    channel: String(raw.channel || "desktop-web"),
    purpose: String(raw.purpose || "general"),
    status: String(raw.status || "ready"),
    createdAt: String(raw.createdAt || nowIso),
    lastActiveAt: String(raw.lastActiveAt || nowIso),
    messageCount: clampInteger(raw.messageCount, history.length, 0, 999999),
    lastMessagePreview: String(raw.lastMessagePreview || "").slice(0, 180),
    history: history
      .filter((item) => item && typeof item === "object")
      .slice(0, OPENCLAW_SESSION_HISTORY_LIMIT)
      .map((item) => ({
        id: String(item.id || `smsg-${Date.now()}-${Math.floor(Math.random() * 10000)}`),
        role: String(item.role || "user"),
        text: String(item.text || ""),
        at: String(item.at || nowIso)
      }))
  };
}

function getOpenclawSessionBucket(userState) {
  const userId = String(userState?.userId || "guest");
  let bucket = openclawSessionBuckets.get(userId);
  const nowIso = new Date().toISOString();
  const fallbackMainId = `sess-main-${(userId || "guest").slice(-6) || "guest"}`;
  if (!bucket || typeof bucket !== "object") {
    const lastMessage = Array.isArray(userState?.messages) && userState.messages.length > 0
      ? userState.messages[userState.messages.length - 1]
      : null;
    bucket = {
      currentSessionId: fallbackMainId,
      sessions: [
        createOpenclawSession({
          id: fallbackMainId,
          runtime: "aria-main",
          mode: "session",
          channel: "desktop-web",
          purpose: "primary_companion",
          status: "ready",
          createdAt: nowIso,
          lastActiveAt: lastMessage && lastMessage.timestamp
            ? new Date(lastMessage.timestamp).toISOString()
            : nowIso,
          messageCount: Array.isArray(userState?.messages) ? userState.messages.length : 0,
          lastMessagePreview: String(lastMessage?.text || "").slice(0, 180),
          history: []
        })
      ]
    };
    openclawSessionBuckets.set(userId, bucket);
  }

  if (!Array.isArray(bucket.sessions)) {
    bucket.sessions = [];
  }
  if (bucket.sessions.length === 0) {
    bucket.sessions.push(createOpenclawSession({
      id: fallbackMainId,
      runtime: "aria-main",
      mode: "session",
      channel: "desktop-web",
      purpose: "primary_companion",
      status: "ready",
      createdAt: nowIso,
      lastActiveAt: nowIso
    }));
  }
  bucket.sessions = bucket.sessions
    .slice(0, OPENCLAW_SESSION_LIMIT)
    .map((session) => createOpenclawSession(session));
  const existingIds = new Set(bucket.sessions.map((session) => session.id));
  if (!bucket.currentSessionId || !existingIds.has(bucket.currentSessionId)) {
    bucket.currentSessionId = bucket.sessions[0]?.id || fallbackMainId;
  }
  openclawSessionBuckets.set(userId, bucket);
  return bucket;
}

function spawnOpenclawSession(userState, payload = {}) {
  const bucket = getOpenclawSessionBucket(userState);
  const nowIso = new Date().toISOString();
  const session = createOpenclawSession({
    id: `sess-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
    runtime: String(payload.runtime || "subagent"),
    mode: String(payload.mode || "session"),
    channel: String(payload.channel || "desktop-web"),
    purpose: String(payload.purpose || "ad-hoc-task"),
    status: "ready",
    createdAt: nowIso,
    lastActiveAt: nowIso,
    messageCount: 0,
    history: []
  });
  bucket.sessions.unshift(session);
  if (bucket.sessions.length > OPENCLAW_SESSION_LIMIT) {
    bucket.sessions.length = OPENCLAW_SESSION_LIMIT;
  }
  bucket.currentSessionId = session.id;
  const autonomy = ensureAutonomyState(userState);
  appendAutonomyTimeline(autonomy, {
    source: "openclaw_session",
    stage: "session_spawned",
    status: "success",
    title: "Aria Kernel 子会话已创建",
    detail: `${session.id} (${session.runtime})`,
    refs: {
      sessionId: session.id,
      runtime: session.runtime,
      mode: session.mode
    }
  });
  return session;
}

function sendOpenclawSessionMessage(userState, payload = {}) {
  const bucket = getOpenclawSessionBucket(userState);
  const targetSessionId = String(payload.sessionId || bucket.currentSessionId || "").trim();
  const text = String(payload.text || "").trim();
  if (!targetSessionId) {
    return {
      ok: false,
      reason: "session_id_required",
      message: "sessionId is required"
    };
  }
  const session = bucket.sessions.find((item) => item.id === targetSessionId);
  if (!session) {
    return {
      ok: false,
      reason: "session_not_found",
      message: "Session not found"
    };
  }
  if (!text) {
    return {
      ok: false,
      reason: "text_required",
      message: "text is required"
    };
  }

  const nowIso = new Date().toISOString();
  const userMessage = {
    id: `smsg-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
    role: "user",
    text,
    at: nowIso
  };
  const ackMessage = {
    id: `smsg-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
    role: "assistant",
    text: `已接收，会通过 ${session.runtime} 执行：${text.slice(0, 120)}`,
    at: nowIso
  };
  session.history.unshift(ackMessage);
  session.history.unshift(userMessage);
  if (session.history.length > OPENCLAW_SESSION_HISTORY_LIMIT) {
    session.history.length = OPENCLAW_SESSION_HISTORY_LIMIT;
  }
  session.messageCount += 2;
  session.lastActiveAt = nowIso;
  session.lastMessagePreview = text.slice(0, 180);
  bucket.currentSessionId = session.id;

  const autonomy = ensureAutonomyState(userState);
  appendAutonomyTimeline(autonomy, {
    source: "openclaw_session",
    stage: "session_message",
    status: "success",
    title: "Aria Kernel 会话收到任务",
    detail: `${session.id} -> ${text.slice(0, 90)}`,
    refs: {
      sessionId: session.id
    }
  });

  return {
    ok: true,
    reason: "accepted",
    session,
    receipt: {
      sessionId: session.id,
      acceptedAt: nowIso,
      messageId: userMessage.id,
      ack: ackMessage.text
    }
  };
}

function buildOpenclawTaskCenterSnapshot(userState) {
  const autonomy = ensureAutonomyState(userState);
  const queue = autonomy.queue || createDefaultAutonomyState().queue;
  const pending = (queue.items || []).slice(0, 16).map((item) => ({
    id: String(item.id || ""),
    flowId: String(item.flowId || ""),
    type: String(item.operation?.type || "unknown"),
    status: String(item.status || "pending"),
    attempts: clampInteger(item.attempts, 0, 0, 20),
    maxAttempts: clampInteger(item.maxAttempts, 1, 1, 20),
    summary: String(item.lastSummary || item.dispatchPrompt || "")
  }));
  const completed = (autonomy.dispatch?.history || [])
    .slice(0, 16)
    .map((item) => {
      const completedSteps = (item.steps || []).filter((step) => step.status === "completed").length;
      const failedSteps = (item.steps || []).filter((step) => step.status === "failed").length;
      return {
        id: String(item.id || ""),
        flowId: String(item.flowId || ""),
        prompt: String(item.prompt || ""),
        status: String(item.status || "unknown"),
        completedSteps,
        failedSteps,
        finishedAt: String(item.finishedAt || item.createdAt || "")
      };
    });
  const deadLetters = (queue.deadLetters || []).slice(0, 16).map((item) => ({
    id: String(item.id || ""),
    flowId: String(item.flowId || ""),
    type: String(item.operation?.type || "unknown"),
    attempts: clampInteger(item.attempts, 0, 0, 20),
    maxAttempts: clampInteger(item.maxAttempts, 1, 1, 20),
    reason: String(item.lastError || item.lastSummary || "unknown_error"),
    failedAt: String(item.failedAt || item.updatedAt || "")
  }));

  const ledgerSynced = completed.length + pending.length + deadLetters.length > 0;
  return {
    queue: {
      pendingCount: queue.items?.length || 0,
      deadLetterCount: queue.deadLetters?.length || 0
    },
    summary: {
      ledgerSynced,
      pendingCount: queue.items?.length || 0,
      completedCount: autonomy.dispatch?.totalRuns || 0,
      deadLetterCount: queue.deadLetters?.length || 0
    },
    pending,
    completed,
    deadLetters,
    updatedAt: new Date().toISOString()
  };
}

function buildOpenclawExecutionCenterSnapshot(userState) {
  const autonomy = ensureAutonomyState(userState);
  const dispatchHistory = Array.isArray(autonomy.dispatch?.history) ? autonomy.dispatch.history : [];
  const executionLog = dispatchHistory.slice(0, 12).map((item) => ({
    id: String(item.id || ""),
    flowId: String(item.flowId || ""),
    source: String(item.source || "autonomy"),
    kernel: String(item.kernel || AUTONOMY_KERNEL_VERSION),
    status: String(item.status || "unknown"),
    prompt: String(item.prompt || ""),
    stepCount: Array.isArray(item.steps) ? item.steps.length : 0,
    failedSteps: Array.isArray(item.steps) ? item.steps.filter((step) => step.status === "failed").length : 0,
    createdAt: String(item.createdAt || ""),
    finishedAt: String(item.finishedAt || "")
  }));
  const timeline = Array.isArray(autonomy.timeline) ? autonomy.timeline : [];
  const deliveryLog = timeline.slice(0, 20).map((item) => ({
    id: String(item.id || ""),
    flowId: String(item.flowId || ""),
    source: String(item.source || "autonomy"),
    stage: String(item.stage || "info"),
    status: String(item.status || "info"),
    title: String(item.title || ""),
    detail: String(item.detail || ""),
    at: String(item.at || "")
  }));
  const evidenceCoverage = executionLog.length > 0
    ? Math.round(((deliveryLog.length > 0 ? 1 : 0) + 1) / 2 * 100)
    : 0;
  return {
    summary: {
      executionCount: executionLog.length,
      deliveryCount: deliveryLog.length,
      evidenceCoverage
    },
    executionLog,
    deliveryLog,
    updatedAt: new Date().toISOString()
  };
}

function buildOpenclawGatewayStatusSnapshot() {
  const bridge = runtimeGuardian.bridge || {};
  const watchdog = runtimeGuardian.watchdog || {};
  const api = runtimeGuardian.api || {};
  const incidentSnapshot = buildOpenclawIncidentPlaybookSnapshot({ limit: 3 });
  const bootAt = Date.parse(String(runtimeGuardian.bootAt || ""));
  const uptimeSec = Number.isNaN(bootAt) ? 0 : Math.max(0, Math.floor((Date.now() - bootAt) / 1000));
  const bridgeHealthy = bridge.status === "up" || bridge.status === "ok";
  const apiHealthy = api.status === "up";
  const status = apiHealthy && bridgeHealthy ? "up" : apiHealthy ? "degraded" : "down";
  return {
    status,
    host: HOST,
    port: PORT,
    transport: {
      preferred: "websocket",
      fallback: "sse"
    },
    uptimeSec,
    bridge: {
      status: bridge.status || "unknown",
      lastCheckedAt: bridge.lastCheckedAt || "",
      lastLatencyMs: Number(bridge.lastLatencyMs || 0)
    },
    watchdog: {
      enabled: watchdog.enabled !== false,
      mode: watchdog.mode || "balanced",
      queueLimit: Number(watchdog.queueLimit || 0),
      lastProbeStatus: watchdog.lastProbeStatus || "unknown"
    },
    incidentPlaybook: {
      version: incidentSnapshot.version,
      matchedCount: incidentSnapshot.matchedCount,
      totalIncidents: incidentSnapshot.totalIncidents
    },
    versions: runtimeSystemConfig.versions
  };
}

function buildOpenclawModelFallbackSnapshot() {
  const runtime = buildModelRouterRuntimeSnapshot();
  const providerRuntimes = Array.isArray(runtime.providerRuntimes) ? runtime.providerRuntimes : [];
  const enabledProviders = providerRuntimes.filter((item) => item.enabled !== false);
  const readyProviders = enabledProviders.filter((item) => item.apiKeyConfigured);
  const modelLayer = systemProfile?.layers?.model || {};
  const defaultRoute = String(modelLayer.defaultRoute || "");
  const fallbackRoute = String(modelLayer.fallbackRoute || "");
  const fallbackEnabled = fallbackRoute && fallbackRoute !== defaultRoute;
  const fallbackProviderExists = enabledProviders.some((item) => item.id === fallbackRoute);
  const fallbackReady = fallbackEnabled ? fallbackProviderExists : enabledProviders.length >= 1;
  return {
    policy: {
      defaultRoute,
      fallbackRoute,
      degradeStrategy: modelRoutingPolicy?.degradeStrategy || {},
      realCallEnabled: runtime.realCallEnabled === true
    },
    providers: providerRuntimes,
    summary: {
      enabledProviderCount: enabledProviders.length,
      readyProviderCount: readyProviders.length,
      fallbackEnabled: Boolean(fallbackEnabled),
      fallbackReady
    },
    updatedAt: new Date().toISOString()
  };
}

function buildOpenclawFlywheelSnapshot(userState, options = {}) {
  const taskType = String(options.taskType || "").trim();
  const limit = clampInteger(options.limit, 40, 1, 120);
  const flywheel = buildFlywheelLearningSnapshot(userState, {
    taskType
  });
  const trimmedSignals = Array.isArray(flywheel.recentSignals)
    ? flywheel.recentSignals.slice(0, limit)
    : [];
  return {
    ...flywheel,
    recentSignals: trimmedSignals,
    modelRouterRuntime: buildModelRouterRuntimeSnapshot(taskType || "")
  };
}

function buildOpenclawProgressProtocolSnapshot(userState) {
  const autonomy = ensureAutonomyState(userState);
  const queue = autonomy.queue || createDefaultAutonomyState().queue;
  const progress = openclawFusionProfile?.automationProtocol?.progress
    || DEFAULT_OPENCLAW_FUSION_PROFILE.automationProtocol.progress;
  const checklist = uniqueStringArray(
    openclawFusionProfile?.automationProtocol?.completionChecklist
      || DEFAULT_OPENCLAW_FUSION_PROFILE.automationProtocol.completionChecklist,
    20
  );
  const pendingCount = queue.items?.length || 0;
  const deadLetterCount = queue.deadLetters?.length || 0;
  return {
    progress,
    checklist,
    status: {
      longTaskThresholdSec: clampPolicyNumber(progress.longTaskThresholdSec, 8, 3, 120),
      intervalSec: clampPolicyNumber(progress.intervalSec, 30, 5, 300),
      blockReportSec: clampPolicyNumber(progress.blockReportSec, 30, 5, 300),
      pendingCount,
      deadLetterCount,
      lastDispatchAt: String(autonomy.dispatch?.lastRunAt || ""),
      lastTickAt: String(autonomy.lastTickAt || "")
    },
    updatedAt: new Date().toISOString()
  };
}

function buildOpenclawHeartbeatSnapshot(userState) {
  const autonomy = ensureAutonomyState(userState);
  const gateway = buildOpenclawGatewayStatusSnapshot();
  const queue = autonomy.queue || createDefaultAutonomyState().queue;
  return {
    alive: gateway.status !== "down",
    at: new Date().toISOString(),
    gatewayStatus: gateway.status,
    bridgeStatus: gateway.bridge.status,
    lastProbeStatus: gateway.watchdog.lastProbeStatus,
    autonomyTick: clampInteger(autonomy.tickCount, 0, 0, 999999),
    queuePending: queue.items?.length || 0,
    deadLetters: queue.deadLetters?.length || 0
  };
}

function evaluateFusionReuseCoverage(capability) {
  const profileCapability = capability && typeof capability === "object" ? capability : {};
  const reuseModules = uniqueStringArray(profileCapability.reuseModules || [], 40);
  const reuseEndpoints = uniqueStringArray(profileCapability.reuseEndpoints || [], 60);
  const matchedModules = reuseModules.filter((item) => FUSION_REUSE_MODULE_CATALOG.has(item));
  const matchedEndpoints = reuseEndpoints.filter((item) => FUSION_REUSE_ENDPOINT_CATALOG.has(item));
  const missingModules = reuseModules.filter((item) => !FUSION_REUSE_MODULE_CATALOG.has(item));
  const missingEndpoints = reuseEndpoints.filter((item) => !FUSION_REUSE_ENDPOINT_CATALOG.has(item));
  const hasCoverage = matchedModules.length + matchedEndpoints.length > 0;
  return {
    hasCoverage,
    matchedModules,
    matchedEndpoints,
    missingModules,
    missingEndpoints
  };
}

function buildOpenclawFusionRuntimeStatus(userState) {
  const profile = openclawFusionProfile || normalizeOpenclawFusionProfile(DEFAULT_OPENCLAW_FUSION_PROFILE);
  const autonomy = ensureAutonomyState(userState);
  const workbench = ensureWorkbenchState(userState);
  const expansion = ensureExpansionState(userState);
  const deviceOps = ensureDeviceOpsState(userState);
  const bridgeReady = deviceOps.bridge.enabled && deviceOps.bridge.lastStatus !== "down";

  const checkpoints = [
    {
      id: "gateway_ready",
      title: "网关层复用就绪",
      ready: Boolean(runtimeSystemConfig.loadedAt) && Boolean(runtimeSystemConfig.versions.systemProfile)
    },
    {
      id: "session_ready",
      title: "会话层复用就绪",
      ready: Array.isArray(userState.messages) && userState.messages.length > 0
    },
    {
      id: "execution_ready",
      title: "执行层复用就绪",
      ready: autonomy.enabled === true && bridgeReady
    },
    {
      id: "memory_ready",
      title: "记忆系统复用就绪",
      ready: Array.isArray(userState.memoryHighlights) && userState.memoryHighlights.length > 0
    },
    {
      id: "security_ready",
      title: "扩展安全三件套就绪",
      ready: expansionSecurityPolicy.requireSandbox !== false
        && Boolean(expansionSecurityPolicy.whitelist?.hosts?.length)
    },
    {
      id: "automation_ready",
      title: "自动化闭环就绪",
      ready: Array.isArray(autonomy.timeline) && autonomy.timeline.length > 0
    }
  ];

  const readinessScore = Math.round(
    checkpoints.reduce((sum, item) => sum + itemScore(item.ready), 0) / checkpoints.length
  );

  const capabilityStatuses = (profile.capabilities || []).map((capability) => {
    const coverage = evaluateFusionReuseCoverage(capability);
    const enabled = String(capability.status || "enabled").toLowerCase() !== "disabled";
    const noDuplicateBuild = capability.noDuplicateBuild !== false;
    const ready = enabled && noDuplicateBuild && coverage.hasCoverage;
    return {
      id: String(capability.id || ""),
      name: String(capability.name || ""),
      status: ready ? "ready" : "growing",
      enabled,
      noDuplicateBuild,
      reusedModules: coverage.matchedModules,
      reusedEndpoints: coverage.matchedEndpoints,
      missingModules: coverage.missingModules,
      missingEndpoints: coverage.missingEndpoints
    };
  });

  const enabledCapabilityCount = capabilityStatuses.filter((item) => item.enabled).length;
  const readyCapabilityCount = capabilityStatuses.filter((item) => item.status === "ready").length;
  const duplicateRiskCount = capabilityStatuses.filter((item) => item.noDuplicateBuild !== true).length;

  return {
    profileVersion: String(profile.version || ""),
    enabled: profile.enabled === true,
    strategy: profile.strategy,
    architecture: profile.architecture,
    readinessScore,
    checkpoints: checkpoints.map((item) => ({
      id: item.id,
      title: item.title,
      status: item.ready ? "ready" : "growing"
    })),
    summary: {
      enabledCapabilityCount,
      readyCapabilityCount,
      duplicateRiskCount,
      bridgeReady,
      dispatchRuns: autonomy.dispatch?.totalRuns || 0,
      timelineEvents: Array.isArray(autonomy.timeline) ? autonomy.timeline.length : 0,
      workbenchFeeds: Array.isArray(workbench.centerFeed) ? workbench.centerFeed.length : 0,
      expansionPackCount: Array.isArray(expansion.packs) ? expansion.packs.length : 0
    },
    capabilities: capabilityStatuses
  };
}

function evaluateSuperSkillCoverage(skill) {
  const skillProfile = skill && typeof skill === "object" ? skill : {};
  const endpoints = uniqueStringArray(skillProfile.endpoints || [], 20);
  const reusedEndpoints = endpoints.filter((item) => FUSION_REUSE_ENDPOINT_CATALOG.has(item));
  const missingEndpoints = endpoints.filter((item) => !FUSION_REUSE_ENDPOINT_CATALOG.has(item));
  const required = skillProfile.required !== false;
  const ready = !required || (reusedEndpoints.length > 0 && missingEndpoints.length === 0);
  return {
    id: String(skillProfile.id || ""),
    name: String(skillProfile.name || ""),
    source: String(skillProfile.source || "unknown"),
    innovationLevel: String(skillProfile.innovationLevel || "enhanced"),
    required,
    ready,
    reusedEndpoints,
    missingEndpoints
  };
}

function buildSuperAutonomyRuntimeStatus(userState) {
  const profile = superAutonomyProfile || normalizeSuperAutonomyProfile(DEFAULT_SUPER_AUTONOMY_PROFILE);
  const autonomy = ensureAutonomyState(userState);
  const deviceOps = ensureDeviceOpsState(userState);
  const expansion = ensureExpansionState(userState);
  const workbench = ensureWorkbenchState(userState);
  const gateway = buildOpenclawGatewayStatusSnapshot();
  const sessionBucket = getOpenclawSessionBucket(userState);
  const taskCenter = buildOpenclawTaskCenterSnapshot(userState);
  const executionCenter = buildOpenclawExecutionCenterSnapshot(userState);
  const modelFallback = buildOpenclawModelFallbackSnapshot();
  const progressProtocol = buildOpenclawProgressProtocolSnapshot(userState);
  const bridgeReady = deviceOps.bridge.enabled && deviceOps.bridge.lastStatus !== "down";
  const dispatch = autonomy.dispatch || createDefaultAutonomyState().dispatch;
  const modelProviderCount = Array.isArray(modelRoutingPolicy?.providers) ? modelRoutingPolicy.providers.length : 0;

  const skillStatuses = (profile.skillRegistry || []).map((skill) => evaluateSuperSkillCoverage(skill));
  const requiredSkills = skillStatuses.filter((item) => item.required);
  const requiredReady = requiredSkills.filter((item) => item.ready).length;
  const requiredTotal = requiredSkills.length || 1;
  const skillReadiness = Math.round((requiredReady / requiredTotal) * 100);

  const checkpoints = [
    {
      id: "skill_registry_ready",
      title: "核心技能注册就绪",
      ready: skillReadiness >= 80
    },
    {
      id: "dispatch_runtime_ready",
      title: "调度执行链路就绪",
      ready: autonomy.enabled === true && dispatch.totalRuns >= 0
    },
    {
      id: "gateway_runtime_ready",
      title: "网关与心跳治理就绪",
      ready: gateway.status !== "down" && gateway.watchdog.enabled === true
    },
    {
      id: "session_runtime_ready",
      title: "多会话编排就绪",
      ready: Array.isArray(sessionBucket.sessions) && sessionBucket.sessions.length >= 1
    },
    {
      id: "task_ledger_ready",
      title: "任务账本与交付日志就绪",
      ready: taskCenter.summary.ledgerSynced && executionCenter.summary.deliveryCount >= 1
    },
    {
      id: "bridge_runtime_ready",
      title: "Bridge 硬件执行就绪",
      ready: bridgeReady
    },
    {
      id: "model_router_ready",
      title: "多模型路由与降级就绪",
      ready: modelProviderCount >= 2 && modelFallback.summary.fallbackReady
    },
    {
      id: "extension_sandbox_ready",
      title: "扩展自由度与安全边界就绪",
      ready: expansionSecurityPolicy.requireSandbox !== false
        && Boolean(expansionSecurityPolicy.signature?.trustedSigners?.length)
    },
    {
      id: "duplication_guard_ready",
      title: "禁止重复开发策略就绪",
      ready: profile.duplicationGuard?.disallowDuplicateImplementation === true
    }
  ];

  const readinessScore = Math.round(
    checkpoints.reduce((sum, item) => sum + itemScore(item.ready), 0) / checkpoints.length
  );
  const missingRequiredSkills = skillStatuses
    .filter((item) => item.required && !item.ready)
    .map((item) => ({
      id: item.id,
      name: item.name,
      missingEndpoints: item.missingEndpoints
    }));

  return {
    profileVersion: String(profile.version || ""),
    enabled: profile.enabled === true,
    mode: profile.mode,
    objective: profile.objective,
    readinessScore,
    checkpoints: checkpoints.map((item) => ({
      id: item.id,
      title: item.title,
      status: item.ready ? "ready" : "growing"
    })),
    sourceProducts: profile.sourceProducts,
    architecture: profile.architecture,
    stabilityPolicy: profile.stabilityPolicy,
    extensionFreedomPolicy: profile.extensionFreedomPolicy,
    duplicationGuard: profile.duplicationGuard,
    summary: {
      skillReadiness,
      requiredSkillsReady: requiredReady,
      requiredSkillsTotal: requiredSkills.length,
      missingRequiredSkillCount: missingRequiredSkills.length,
      bridgeReady,
      gatewayStatus: gateway.status,
      sessionCount: sessionBucket.sessions.length,
      dispatchRuns: dispatch.totalRuns || 0,
      timelineEvents: Array.isArray(autonomy.timeline) ? autonomy.timeline.length : 0,
      expansionPackCount: Array.isArray(expansion.packs) ? expansion.packs.length : 0,
      workbenchFeeds: Array.isArray(workbench.centerFeed) ? workbench.centerFeed.length : 0,
      taskLedgerPending: taskCenter.summary.pendingCount,
      taskLedgerDeadLetters: taskCenter.summary.deadLetterCount
    },
    gateway,
    sessions: {
      currentSessionId: sessionBucket.currentSessionId,
      total: sessionBucket.sessions.length
    },
    taskCenter: {
      summary: taskCenter.summary
    },
    executionCenter: {
      summary: executionCenter.summary
    },
    modelFallback: {
      summary: modelFallback.summary,
      policy: modelFallback.policy
    },
    progressProtocol: {
      status: progressProtocol.status
    },
    skills: skillStatuses,
    missingRequiredSkills
  };
}

function scoreLabel(score) {
  if (score >= 80) return "ready";
  if (score >= 55) return "growing";
  return "blocked";
}

function itemScore(isReady) {
  return isReady ? 100 : 30;
}

function buildCapabilityAssessment(userState) {
  const autonomy = ensureAutonomyState(userState);
  const workbench = ensureWorkbenchState(userState);
  const expansion = ensureExpansionState(userState);
  const deviceOps = ensureDeviceOpsState(userState);
  const fusionRuntime = buildOpenclawFusionRuntimeStatus(userState);
  const superAutonomyRuntime = buildSuperAutonomyRuntimeStatus(userState);

  const dispatch = autonomy.dispatch || createDefaultAutonomyState().dispatch;
  const globalControlGranted = deviceOps.permissions["desktop.global_control"] === "granted";
  const bridgeAlive = deviceOps.bridge.enabled && deviceOps.bridge.lastStatus !== "down";

  const codexAbilities = [
    {
      id: "plan_and_split",
      title: "任务拆解与计划生成",
      ready: workbench.coding.autopilotEnabled === true
    },
    {
      id: "auto_bugfix_loop",
      title: "自动构建与修复链路",
      ready: dispatch.totalRuns > 0
    },
    {
      id: "code_runtime_execution",
      title: "命令执行与结果回执",
      ready: globalControlGranted
    }
  ];
  const codexScore = Math.round(
    codexAbilities.reduce((sum, item) => sum + itemScore(item.ready), 0) / codexAbilities.length
  );

  const antigravityAbilities = [
    {
      id: "minimal_work_scene",
      title: "极简单入口工作台",
      ready: workbench.layoutVersion === "work-scene-whiteboard-v1"
    },
    {
      id: "clear_feedback_flow",
      title: "执行回执可视化",
      ready: Array.isArray(workbench.centerFeed) && workbench.centerFeed.length > 0
    },
    {
      id: "learnable_interaction",
      title: "小白可读交互引导",
      ready: Array.isArray(userState.messages) && userState.messages.length >= 1
    }
  ];
  const antigravityScore = Math.round(
    antigravityAbilities.reduce((sum, item) => sum + itemScore(item.ready), 0) / antigravityAbilities.length
  );

  const openclawAbilities = [
    {
      id: "autonomy_kernel",
      title: "自主调度内核",
      ready: autonomy.enabled === true && dispatch.totalRuns >= 0
    },
    {
      id: "expansion_runtime",
      title: "扩展安装与下载内核",
      ready: expansion.independenceMode === true && expansion.packs.length > 0
    },
    {
      id: "device_bridge_runtime",
      title: "设备桥接执行内核",
      ready: bridgeAlive
    },
    {
      id: "session_orchestration_runtime",
      title: "多会话编排与子智能体",
      ready: (getOpenclawSessionBucket(userState).sessions || []).length >= 1
    },
    {
      id: "task_ledger_runtime",
      title: "任务账本与交付日志",
      ready: buildOpenclawExecutionCenterSnapshot(userState).summary.deliveryCount >= 1
    },
    {
      id: "fusion_reuse_protocol",
      title: "融合复用协议（不重复开发）",
      ready: fusionRuntime.enabled === true && fusionRuntime.summary.duplicateRiskCount === 0
    },
    {
      id: "super_autonomy_stack",
      title: "超级女友全能力灌注栈",
      ready: superAutonomyRuntime.enabled === true && superAutonomyRuntime.readinessScore >= 80
    }
  ];
  const openclawScore = Math.round(
    openclawAbilities.reduce((sum, item) => sum + itemScore(item.ready), 0) / openclawAbilities.length
  );

  const coreScores = {
    codex: codexScore,
    antigravity: antigravityScore,
    openclaw: openclawScore
  };

  const cores = AGENT_CORE_BLUEPRINTS.map((core) => {
    const abilities = core.id === "codex"
      ? codexAbilities
      : core.id === "antigravity"
        ? antigravityAbilities
        : openclawAbilities;
    const score = coreScores[core.id] || 0;
    return {
      id: core.id,
      owner: core.owner,
      name: core.name,
      summary: core.summary,
      score,
      state: scoreLabel(score),
      abilities: abilities.map((item) => ({
        id: item.id,
        title: item.title,
        status: item.ready ? "ready" : "growing"
      }))
    };
  });

  const independenceChecks = [
    {
      id: "kernel_self_running",
      title: "自治内核持续运行",
      ready: autonomy.enabled === true
    },
    {
      id: "no_external_operator",
      title: "脱离三方在线值守",
      ready: dispatch.totalRuns > 0
    },
    {
      id: "permissioned_computer_control",
      title: "授权后可真实操作电脑",
      ready: globalControlGranted
    },
    {
      id: "expansion_download_ready",
      title: "联网下载与扩展可执行",
      ready: expansion.packs.length > 0
    },
    {
      id: "bridge_runtime_ready",
      title: "Bridge 执行链路可用",
      ready: bridgeAlive
    },
    {
      id: "evidence_ledger_ready",
      title: "任务账本与执行证据可回放",
      ready: buildOpenclawExecutionCenterSnapshot(userState).summary.deliveryCount >= 1
    },
    {
      id: "fusion_protocol_ready",
      title: "融合复用协议已生效",
      ready: fusionRuntime.enabled === true && fusionRuntime.readinessScore >= 70
    },
    {
      id: "super_autonomy_ready",
      title: "全能力灌注架构已生效",
      ready: superAutonomyRuntime.enabled === true && superAutonomyRuntime.readinessScore >= 80
    }
  ];
  const independenceScore = Math.round(
    independenceChecks.reduce((sum, item) => sum + itemScore(item.ready), 0) / independenceChecks.length
  );

  return {
    version: AUTONOMY_KERNEL_VERSION,
    generatedAt: new Date().toISOString(),
    independent: independenceScore >= 70,
    independenceScore,
    fusion: fusionRuntime,
    superAutonomy: superAutonomyRuntime,
    cores,
    checks: independenceChecks.map((item) => ({
      id: item.id,
      title: item.title,
      status: item.ready ? "ready" : "growing"
    }))
  };
}

function normalizeMessageScene(sceneInput, fallback = "love") {
  const scene = normalizeSoulScene(sceneInput);
  if (MEMORY_SCENES.includes(scene)) {
    return scene;
  }
  const fallbackScene = String(fallback || "").trim().toLowerCase();
  return MEMORY_SCENES.includes(fallbackScene) ? fallbackScene : "love";
}

function sanitizeChatMessage(messageInput = {}, fallbackScene = "love") {
  const message = messageInput && typeof messageInput === "object" ? messageInput : {};
  const roleRaw = String(message.role || "aria").trim().toLowerCase();
  const role = roleRaw === "user" ? "user" : "aria";
  const timestamp = Number.isFinite(Number(message.timestamp))
    ? Number(message.timestamp)
    : Date.now();
  return {
    id: String(message.id || `${role}-${Date.now()}-${Math.floor(Math.random() * 10000)}`),
    role,
    text: String(message.text || ""),
    time: String(message.time || nowTime()),
    timestamp,
    scene: normalizeMessageScene(message.scene, fallbackScene)
  };
}

function createEmptySceneMessageVault() {
  return Object.fromEntries(MEMORY_SCENES.map((scene) => [scene, []]));
}

function ensureSceneMessageVault(userState) {
  if (!Array.isArray(userState.messages)) {
    userState.messages = [...defaultMessages];
  }
  const sanitizedMessages = userState.messages
    .map((item) => sanitizeChatMessage(item, "love"))
    .slice(-CHAT_MESSAGE_MAX_TOTAL);
  userState.messages = sanitizedMessages;

  if (!userState.sceneMessages || typeof userState.sceneMessages !== "object") {
    userState.sceneMessages = createEmptySceneMessageVault();
  }
  for (const scene of MEMORY_SCENES) {
    if (!Array.isArray(userState.sceneMessages[scene])) {
      userState.sceneMessages[scene] = [];
    }
  }

  const rebuilt = createEmptySceneMessageVault();
  for (const item of userState.messages) {
    const scene = normalizeMessageScene(item.scene, "love");
    rebuilt[scene].push({
      ...item,
      scene
    });
  }
  for (const scene of MEMORY_SCENES) {
    userState.sceneMessages[scene] = rebuilt[scene].slice(-CHAT_MESSAGE_MAX_PER_SCENE);
  }

  return userState.sceneMessages;
}

function toMessage(role, text, scene = "love") {
  return sanitizeChatMessage(
    {
      id: `${role}-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
      role,
      text,
      time: nowTime(),
      timestamp: Date.now(),
      scene
    },
    scene
  );
}

function appendChatMessage(userState, role, text, sceneInput = "love") {
  const scene = normalizeMessageScene(sceneInput, "love");
  const message = toMessage(role, text, scene);
  userState.messages.push(message);
  if (userState.messages.length > CHAT_MESSAGE_MAX_TOTAL) {
    userState.messages = userState.messages.slice(-CHAT_MESSAGE_MAX_TOTAL);
  }
  ensureSceneMessageVault(userState);
  return message;
}

function isBootMessageId(messageIdInput) {
  const messageId = String(messageIdInput || "").trim().toLowerCase();
  return messageId.startsWith("boot-");
}

function withdrawLastChatTurn(userState, options = {}) {
  const sceneFilter = normalizeSoulScene(options.scene);
  const removeAssistantReply = toBooleanFlag(options.removeAssistantReply, true);
  ensureSceneMessageVault(userState);
  const messages = Array.isArray(userState.messages) ? userState.messages : [];
  if (messages.length === 0) {
    return {
      ok: false,
      reason: "message_empty",
      scene: sceneFilter
    };
  }

  let userMessageIndex = -1;
  for (let index = messages.length - 1; index >= 0; index -= 1) {
    const message = messages[index];
    if (!message || message.role !== "user") {
      continue;
    }
    if (isBootMessageId(message.id)) {
      continue;
    }
    const messageScene = normalizeMessageScene(message.scene, "love");
    if (sceneFilter && messageScene !== sceneFilter) {
      continue;
    }
    userMessageIndex = index;
    break;
  }

  if (userMessageIndex < 0) {
    return {
      ok: false,
      reason: sceneFilter ? "scene_user_message_not_found" : "user_message_not_found",
      scene: sceneFilter
    };
  }

  const removeIndexes = [userMessageIndex];
  if (removeAssistantReply) {
    for (let index = userMessageIndex + 1; index < messages.length; index += 1) {
      const message = messages[index];
      if (!message) {
        continue;
      }
      if (message.role === "user") {
        break;
      }
      const messageScene = normalizeMessageScene(message.scene, "love");
      if (sceneFilter && messageScene !== sceneFilter) {
        break;
      }
      removeIndexes.push(index);
    }
  }

  const removeSet = new Set(removeIndexes);
  const removedMessages = messages
    .filter((_, index) => removeSet.has(index))
    .map((item) => ({ ...item }));
  userState.messages = messages.filter((_, index) => !removeSet.has(index));
  ensureSceneMessageVault(userState);

  const userMessage = removedMessages.find((item) => item.role === "user") || null;
  const assistantRemovedCount = removedMessages.filter((item) => item.role !== "user").length;

  return {
    ok: true,
    reason: "withdrawn",
    scene: sceneFilter,
    removedCount: removedMessages.length,
    assistantRemovedCount,
    userMessage,
    removedMessageIds: removedMessages
      .map((item) => String(item.id || "").trim())
      .filter(Boolean),
    removedMessages
  };
}

function getRecentSceneMessages(userState, sceneInput = "love", limitInput = 6) {
  const scene = normalizeMessageScene(sceneInput, "love");
  const limit = clampInteger(limitInput, 6, 1, 20);
  const sceneMessages = ensureSceneMessageVault(userState);
  const scoped = Array.isArray(sceneMessages[scene]) ? sceneMessages[scene] : [];
  return scoped.slice(-limit);
}

function dedupePush(list, value, max = 20) {
  if (!value) {
    return;
  }
  const normalized = value.trim();
  if (!normalized) {
    return;
  }
  if (list.some((item) => item === normalized)) {
    return;
  }
  list.unshift(normalized);
  if (list.length > max) {
    list.length = max;
  }
}

function hashText(input) {
  let hash = 0;
  const content = String(input || "");
  for (let index = 0; index < content.length; index += 1) {
    hash = (hash * 31 + content.charCodeAt(index)) >>> 0;
  }
  return hash.toString(36);
}

function memoryItemId(source, index, content) {
  return `mem-${source}-${index}-${hashText(content).slice(0, 6)}`;
}

function normalizeSearchText(value) {
  return String(value || "")
    .toLowerCase()
    .replace(/\s+/g, " ")
    .trim();
}

function tokenizeSearchQuery(value) {
  const normalized = normalizeSearchText(value);
  if (!normalized) {
    return [];
  }
  return Array.from(
    new Set(
      normalized
        .split(/[\s,，。！？!?；;、:：/|\\]+/)
        .map((item) => item.trim())
        .filter(Boolean)
    )
  ).slice(0, 10);
}

function normalizeMemoryScene(sceneInput, fallback = "love") {
  const scene = String(sceneInput || "").trim().toLowerCase();
  if (MEMORY_SCENES.includes(scene)) {
    return scene;
  }
  return fallback;
}

function normalizeMemoryTier(tierInput, fallback = "long_term") {
  const tier = String(tierInput || "").trim().toLowerCase();
  if (tier === "long_term" || tier === "mid_term" || tier === "short_term" || tier === "temporary") {
    return tier;
  }
  return fallback;
}

function normalizeMemoryArchitectureMode(modeInput, fallback = "three_plus_one") {
  const mode = String(modeInput || "").trim().toLowerCase();
  if (mode === "three_plus_one" || mode === "3+1" || mode === "three-plus-one") {
    return "three_plus_one";
  }
  if (mode === "classic" || mode === "legacy") {
    return "classic";
  }
  return fallback === "classic" ? "classic" : "three_plus_one";
}

function normalizeMemoryArchitectureState(input = {}, options = {}) {
  const raw = input && typeof input === "object" ? input : {};
  const fallbackMode = normalizeMemoryArchitectureMode(
    options.fallbackMode,
    normalizeMemoryArchitectureMode(MEMORY_ARCH_ENV_MODE, "three_plus_one")
  );
  const mode = normalizeMemoryArchitectureMode(raw.mode, fallbackMode);
  const shortTermRaw = raw.shortTerm && typeof raw.shortTerm === "object" ? raw.shortTerm : {};
  const midTermRaw = raw.midTerm && typeof raw.midTerm === "object" ? raw.midTerm : {};
  const longTermRaw = raw.longTerm && typeof raw.longTerm === "object" ? raw.longTerm : {};
  const temporaryRaw = raw.temporary && typeof raw.temporary === "object" ? raw.temporary : {};
  const realtimeReasoningRaw =
    raw.realtimeReasoning && typeof raw.realtimeReasoning === "object"
      ? raw.realtimeReasoning
      : {};
  return {
    mode,
    shortTerm: {
      enabled: shortTermRaw.enabled !== false,
      maxItems: clampInteger(shortTermRaw.maxItems, MEMORY_TIER_LIMITS.short_term, 20, 6000)
    },
    midTerm: {
      enabled: mode === "three_plus_one" ? midTermRaw.enabled !== false : false,
      maxItems: clampInteger(midTermRaw.maxItems, MEMORY_TIER_LIMITS.mid_term, 20, 6000)
    },
    longTerm: {
      enabled: longTermRaw.enabled !== false,
      maxItems: clampInteger(longTermRaw.maxItems, MEMORY_TIER_LIMITS.long_term, 20, 6000)
    },
    temporary: {
      enabled: temporaryRaw.enabled !== false,
      maxItems: clampInteger(temporaryRaw.maxItems, MEMORY_TIER_LIMITS.temporary, 20, 6000)
    },
    realtimeReasoning: {
      topK: clampInteger(realtimeReasoningRaw.topK, MEMORY_REASONING_TOPK_DEFAULT, 1, 24),
      includeCrossScene: realtimeReasoningRaw.includeCrossScene !== false,
      hybridSearch: realtimeReasoningRaw.hybridSearch !== false
    },
    updatedAt: String(
      raw.updatedAt
      || (options.touchUpdatedAt === true ? new Date().toISOString() : "")
    )
  };
}

function createDefaultMemoryArchitectureState() {
  return normalizeMemoryArchitectureState(
    {
      mode: MEMORY_ARCH_ENV_MODE,
      realtimeReasoning: {
        topK: MEMORY_REASONING_TOPK_DEFAULT
      }
    },
    {
      fallbackMode: MEMORY_ARCH_ENV_MODE,
      touchUpdatedAt: true
    }
  );
}

function isMemoryTierEnabled(memorySystem, tierInput) {
  const tier = normalizeMemoryTier(tierInput, "long_term");
  const architecture =
    memorySystem && typeof memorySystem.architecture === "object"
      ? memorySystem.architecture
      : normalizeMemoryArchitectureState({}, { fallbackMode: MEMORY_ARCH_ENV_MODE });
  if (tier === "long_term") return architecture.longTerm?.enabled !== false;
  if (tier === "mid_term") return architecture.midTerm?.enabled !== false;
  if (tier === "short_term") return architecture.shortTerm?.enabled !== false;
  if (tier === "temporary") return architecture.temporary?.enabled !== false;
  return true;
}

function resolveWritableMemoryTier(memorySystem, tierInput, fallback = "long_term") {
  const tier = normalizeMemoryTier(tierInput, fallback);
  const candidateOrderByTier = {
    long_term: ["long_term", "mid_term", "short_term", "temporary"],
    mid_term: ["mid_term", "long_term", "short_term", "temporary"],
    short_term: ["short_term", "mid_term", "temporary", "long_term"],
    temporary: ["temporary", "short_term", "mid_term", "long_term"]
  };
  const candidates = candidateOrderByTier[tier] || candidateOrderByTier.long_term;
  for (const candidateTier of candidates) {
    if (isMemoryTierEnabled(memorySystem, candidateTier)) {
      return candidateTier;
    }
  }
  return normalizeMemoryTier(fallback, "long_term");
}

function memoryTierLimit(tier, memorySystem = null) {
  const normalizedTier = normalizeMemoryTier(tier, "long_term");
  const architecture =
    memorySystem && memorySystem.architecture && typeof memorySystem.architecture === "object"
      ? memorySystem.architecture
      : null;
  if (architecture) {
    if (normalizedTier === "mid_term") return clampInteger(architecture.midTerm?.maxItems, MEMORY_TIER_LIMITS.mid_term, 20, 6000);
    if (normalizedTier === "short_term") return clampInteger(architecture.shortTerm?.maxItems, MEMORY_TIER_LIMITS.short_term, 20, 6000);
    if (normalizedTier === "temporary") return clampInteger(architecture.temporary?.maxItems, MEMORY_TIER_LIMITS.temporary, 20, 6000);
    return clampInteger(architecture.longTerm?.maxItems, MEMORY_TIER_LIMITS.long_term, 20, 6000);
  }
  if (normalizedTier === "mid_term") return MEMORY_TIER_LIMITS.mid_term;
  if (normalizedTier === "short_term") return MEMORY_TIER_LIMITS.short_term;
  if (normalizedTier === "temporary") return MEMORY_TIER_LIMITS.temporary;
  return MEMORY_TIER_LIMITS.long_term;
}

function trimMemoryBucketsToArchitectureLimits(memorySystem) {
  for (const [bucketKey, tierKey] of [
    ["longTerm", "long_term"],
    ["middleTerm", "mid_term"],
    ["shortTerm", "short_term"],
    ["temporary", "temporary"]
  ]) {
    if (!memorySystem[bucketKey] || typeof memorySystem[bucketKey] !== "object") {
      memorySystem[bucketKey] = { items: [], updatedAt: "" };
    }
    if (!Array.isArray(memorySystem[bucketKey].items)) {
      memorySystem[bucketKey].items = [];
    }
    const max = memoryTierLimit(tierKey, memorySystem);
    if (memorySystem[bucketKey].items.length > max) {
      memorySystem[bucketKey].items.length = max;
    }
  }
}

function updateMemoryArchitecture(userState, patchInput = {}, options = {}) {
  const memorySystem = ensureMemoryPlaneState(userState);
  const patch = patchInput && typeof patchInput === "object" ? patchInput : {};
  const merged = {
    ...memorySystem.architecture,
    ...patch,
    shortTerm: {
      ...(memorySystem.architecture?.shortTerm || {}),
      ...(patch.shortTerm && typeof patch.shortTerm === "object" ? patch.shortTerm : {})
    },
    midTerm: {
      ...(memorySystem.architecture?.midTerm || {}),
      ...(patch.midTerm && typeof patch.midTerm === "object" ? patch.midTerm : {})
    },
    longTerm: {
      ...(memorySystem.architecture?.longTerm || {}),
      ...(patch.longTerm && typeof patch.longTerm === "object" ? patch.longTerm : {})
    },
    temporary: {
      ...(memorySystem.architecture?.temporary || {}),
      ...(patch.temporary && typeof patch.temporary === "object" ? patch.temporary : {})
    },
    realtimeReasoning: {
      ...(memorySystem.architecture?.realtimeReasoning || {}),
      ...(patch.realtimeReasoning && typeof patch.realtimeReasoning === "object" ? patch.realtimeReasoning : {})
    }
  };
  memorySystem.architecture = normalizeMemoryArchitectureState(merged, {
    fallbackMode: memorySystem.architecture?.mode || MEMORY_ARCH_ENV_MODE,
    touchUpdatedAt: true
  });
  trimMemoryBucketsToArchitectureLimits(memorySystem);
  if (options.updateVersion !== false) {
    memorySystem.version = "2026.3.8";
  }
  return memorySystem.architecture;
}

function buildTextEmbeddingVector(text, dim = MEMORY_VECTOR_DIM) {
  const normalized = normalizeSearchText(text);
  const vector = new Array(dim).fill(0);
  if (!normalized) {
    return {
      vector,
      norm: 0
    };
  }
  const tokens = tokenizeSearchQuery(normalized);
  const segments = tokens.length > 0 ? tokens : [normalized.slice(0, 80)];
  for (let index = 0; index < segments.length; index += 1) {
    const token = segments[index];
    const digest = createHash("sha256").update(`${token}:${index}`).digest();
    for (let i = 0; i < Math.min(16, digest.length); i += 1) {
      const bucket = digest[i] % dim;
      const sign = digest[(i + 7) % digest.length] % 2 === 0 ? 1 : -1;
      const weight = 0.6 + (digest[(i + 13) % digest.length] / 255);
      vector[bucket] += sign * weight;
    }
  }
  let norm = 0;
  for (const value of vector) {
    norm += value * value;
  }
  norm = Math.sqrt(norm);
  if (norm <= 0) {
    return { vector, norm: 0 };
  }
  const normalizedVector = vector.map((value) => Number((value / norm).toFixed(6)));
  return {
    vector: normalizedVector,
    norm: 1
  };
}

function cosineSimilarityFromVector(queryVector, candidateVector) {
  if (!Array.isArray(queryVector) || !Array.isArray(candidateVector) || queryVector.length === 0 || candidateVector.length === 0) {
    return 0;
  }
  const size = Math.min(queryVector.length, candidateVector.length);
  let dot = 0;
  let queryNorm = 0;
  let candidateNorm = 0;
  for (let i = 0; i < size; i += 1) {
    const q = Number(queryVector[i] || 0);
    const c = Number(candidateVector[i] || 0);
    dot += q * c;
    queryNorm += q * q;
    candidateNorm += c * c;
  }
  if (queryNorm <= 0 || candidateNorm <= 0) {
    return 0;
  }
  return dot / Math.sqrt(queryNorm * candidateNorm);
}

function updateVectorBackendStatus(patch = {}) {
  if (!vectorBackendRuntime || typeof vectorBackendRuntime !== "object") {
    return;
  }
  const qdrant = vectorBackendRuntime.qdrant;
  if (!qdrant || typeof qdrant !== "object") {
    return;
  }
  for (const [key, value] of Object.entries(patch || {})) {
    qdrant[key] = value;
  }
}

async function qdrantRequest(path, options = {}) {
  if (!isQdrantEnabled()) {
    return {
      ok: false,
      status: 0,
      payload: null,
      text: "",
      reason: "vector_backend_disabled"
    };
  }
  const targetPath = String(path || "").startsWith("/") ? String(path) : `/${String(path || "")}`;
  const qdrantUrl = String(vectorBackendConfig?.qdrant?.url || "").trim().replace(/\/+$/, "");
  const qdrantTimeoutMs = clampInteger(Number(vectorBackendConfig?.qdrant?.timeoutMs || QDRANT_ENV_TIMEOUT_MS), QDRANT_ENV_TIMEOUT_MS, 1000, 30000);
  const qdrantApiKey = String(vectorBackendConfig?.qdrant?.apiKey || "").trim();
  const url = `${qdrantUrl}${targetPath}`;
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), qdrantTimeoutMs);
  try {
    const headers = {
      "Content-Type": "application/json",
      ...(qdrantApiKey ? { "api-key": qdrantApiKey } : {})
    };
    const response = await fetch(url, {
      method: options.method || "GET",
      headers,
      body: options.body ? JSON.stringify(options.body) : undefined,
      signal: controller.signal
    });
    const text = await response.text();
    let payload = null;
    try {
      payload = text ? JSON.parse(text) : null;
    } catch {
      payload = null;
    }
    if (!response.ok) {
      updateVectorBackendStatus({
        lastError: `${response.status} ${response.statusText}`,
        lastStatus: "error",
        lastCheckAt: new Date().toISOString()
      });
    }
    return {
      ok: response.ok,
      status: response.status,
      payload,
      text,
      reason: response.ok ? "ok" : "http_error"
    };
  } catch (error) {
    updateVectorBackendStatus({
      lastError: error instanceof Error ? error.message : String(error),
      lastStatus: error instanceof Error && error.name === "AbortError" ? "timeout" : "error",
      lastCheckAt: new Date().toISOString()
    });
    return {
      ok: false,
      status: 0,
      payload: null,
      text: "",
      reason: error instanceof Error && error.name === "AbortError" ? "timeout" : "fetch_error"
    };
  } finally {
    clearTimeout(timer);
  }
}

async function ensureQdrantCollection() {
  if (!isQdrantEnabled()) {
    return false;
  }
  if (qdrantCollectionReady && Date.now() - qdrantCollectionReadyAt < 10 * 60 * 1000) {
    return true;
  }
  if (qdrantEnsurePromise) {
    return qdrantEnsurePromise;
  }
  qdrantEnsurePromise = (async () => {
    const nowIso = new Date().toISOString();
    updateVectorBackendStatus({
      lastCheckAt: nowIso
    });
    const collectionName = String(vectorBackendConfig?.qdrant?.collection || "aria_memory").trim() || "aria_memory";
    const getResult = await qdrantRequest(`/collections/${encodeURIComponent(collectionName)}`);
    if (getResult.ok) {
      qdrantCollectionReady = true;
      qdrantCollectionReadyAt = Date.now();
      updateVectorBackendStatus({
        ready: true,
        lastStatus: "ready",
        lastError: "",
        lastCheckAt: nowIso
      });
      return true;
    }
    if (getResult.status !== 404) {
      qdrantCollectionReady = false;
      updateVectorBackendStatus({
        ready: false,
        lastStatus: "error",
        lastCheckAt: nowIso
      });
      return false;
    }
    const createResult = await qdrantRequest(`/collections/${encodeURIComponent(collectionName)}`, {
      method: "PUT",
      body: {
        vectors: {
          size: MEMORY_VECTOR_DIM,
          distance: "Cosine"
        }
      }
    });
    if (createResult.ok) {
      qdrantCollectionReady = true;
      qdrantCollectionReadyAt = Date.now();
      updateVectorBackendStatus({
        ready: true,
        lastStatus: "ready",
        lastError: "",
        lastCheckAt: new Date().toISOString()
      });
      return true;
    }
    qdrantCollectionReady = false;
    updateVectorBackendStatus({
      ready: false,
      lastStatus: "error",
      lastCheckAt: new Date().toISOString()
    });
    return false;
  })();
  try {
    return await qdrantEnsurePromise;
  } finally {
    qdrantEnsurePromise = null;
  }
}

function buildQdrantPointPayload(userId, record) {
  return {
    id: String(record.id || `mem-${Date.now()}`),
    vector: Array.isArray(record.vector) ? record.vector.slice(0, MEMORY_VECTOR_DIM) : [],
    payload: {
      userId: String(userId || ""),
      scene: normalizeMemoryScene(record.scene, "love"),
      tier: normalizeMemoryTier(record.tier, "long_term"),
      source: String(record.source || "memory"),
      content: String(record.content || ""),
      tags: uniqueStringArray(record.tags || [], 12),
      importance: clampPolicyFloat(record.importance, 0.6, 0, 1),
      confidence: clampPolicyFloat(record.confidence, 0.6, 0, 1),
      createdAt: String(record.createdAt || ""),
      updatedAt: String(record.updatedAt || "")
    }
  };
}

async function upsertMemoryRecordToVectorBackend(userId, record) {
  if (!isQdrantEnabled() || !record || typeof record !== "object") {
    return {
      ok: false,
      reason: "vector_backend_disabled"
    };
  }
  const ready = await ensureQdrantCollection();
  if (!ready) {
    return {
      ok: false,
      reason: "qdrant_not_ready"
    };
  }
  const point = buildQdrantPointPayload(userId, record);
  const collectionName = String(vectorBackendConfig?.qdrant?.collection || "aria_memory").trim() || "aria_memory";
  const result = await qdrantRequest(`/collections/${encodeURIComponent(collectionName)}/points?wait=false`, {
    method: "PUT",
    body: {
      points: [point]
    }
  });
  const nowIso = new Date().toISOString();
  if (result.ok) {
    updateVectorBackendStatus({
      ready: true,
      lastStatus: "write_ok",
      lastWriteAt: nowIso,
      lastUpsertId: point.id,
      lastError: ""
    });
    return {
      ok: true,
      reason: "upserted"
    };
  }
  updateVectorBackendStatus({
    ready: false,
    lastStatus: "write_error",
    lastWriteAt: nowIso
  });
  return {
    ok: false,
    reason: result.reason || "upsert_failed"
  };
}

async function searchMemoryInQdrant(userId, queryVector, options = {}) {
  if (!isQdrantEnabled() || !Array.isArray(queryVector) || queryVector.length === 0) {
    return {
      ok: false,
      reason: "vector_backend_disabled",
      items: []
    };
  }
  const ready = await ensureQdrantCollection();
  if (!ready) {
    return {
      ok: false,
      reason: "qdrant_not_ready",
      items: []
    };
  }
  const scene = normalizeMemoryScene(options.scene, "");
  const includeCrossScene = options.includeCrossScene !== false;
  const limit = clampInteger(options.limit, 8, 1, 40);
  const must = [{
    key: "userId",
    match: {
      value: String(userId || "")
    }
  }];
  if (scene && !includeCrossScene) {
    must.push({
      key: "scene",
      match: {
        value: scene
      }
    });
  }
  const body = {
    vector: queryVector.slice(0, MEMORY_VECTOR_DIM),
    limit,
    with_payload: true,
    with_vector: false,
    filter: {
      must
    }
  };
  const collectionName = String(vectorBackendConfig?.qdrant?.collection || "aria_memory").trim() || "aria_memory";
  const result = await qdrantRequest(`/collections/${encodeURIComponent(collectionName)}/points/search`, {
    method: "POST",
    body
  });
  const nowIso = new Date().toISOString();
  if (!result.ok) {
    updateVectorBackendStatus({
      ready: false,
      lastStatus: "search_error",
      lastSearchAt: nowIso
    });
    return {
      ok: false,
      reason: result.reason || "search_failed",
      items: []
    };
  }
  const points = Array.isArray(result.payload?.result) ? result.payload.result : [];
  const items = points.map((point, index) => {
    const payload = point?.payload && typeof point.payload === "object" ? point.payload : {};
    const score = clampPolicyFloat(point?.score, 0, -1, 1);
    return {
      id: String(point?.id || `qdrant-${index}`),
      source: String(payload.source || "qdrant_memory"),
      scene: normalizeMemoryScene(payload.scene, "love"),
      memory_tier: normalizeMemoryTier(payload.tier, "long_term"),
      content: String(payload.content || ""),
      score: Number(Math.max(0, Math.min(0.99, (score + 1) / 2)).toFixed(3)),
      embedding_score: Number(Math.max(0, Math.min(0.99, (score + 1) / 2)).toFixed(3)),
      rerank_score: Number(Math.max(0, Math.min(0.99, (score + 1) / 2)).toFixed(3)),
      trigger_confidence: Number(Math.max(0, Math.min(0.99, (score + 1) / 2)).toFixed(3)),
      reasons: ["qdrant_vector_match"]
    };
  }).filter((item) => item.content);
  updateVectorBackendStatus({
    ready: true,
    lastStatus: "search_ok",
    lastSearchAt: nowIso,
    lastSearchHits: items.length,
    lastError: ""
  });
  return {
    ok: true,
    reason: "search_ok",
    items
  };
}

function createMemoryVectorRecord(payload = {}) {
  const content = String(payload.content || "").trim();
  const scene = normalizeMemoryScene(payload.scene, "love");
  const tier = normalizeMemoryTier(payload.tier, "long_term");
  const source = String(payload.source || "memory").trim() || "memory";
  const tags = uniqueStringArray(payload.tags || [], 12);
  const nowIso = new Date().toISOString();
  const embedding = buildTextEmbeddingVector(content, MEMORY_VECTOR_DIM);
  return {
    id: String(payload.id || `memrec-${Date.now()}-${Math.floor(Math.random() * 10000)}`),
    scene,
    tier,
    source,
    content,
    tags,
    importance: clampPolicyFloat(payload.importance, 0.6, 0, 1),
    confidence: clampPolicyFloat(payload.confidence, 0.6, 0, 1),
    createdAt: String(payload.createdAt || nowIso),
    updatedAt: nowIso,
    vector: embedding.vector
  };
}

function pushMemoryRecord(list, record, max) {
  const normalizedContent = normalizeSearchText(record.content);
  const existing = list.find((item) =>
    normalizeSearchText(item.content) === normalizedContent
      && String(item.scene || "") === String(record.scene || "")
      && String(item.tier || "") === String(record.tier || "")
  );
  if (existing) {
    existing.updatedAt = record.updatedAt;
    existing.tags = uniqueStringArray([...(existing.tags || []), ...(record.tags || [])], 12);
    existing.importance = Math.max(Number(existing.importance || 0), Number(record.importance || 0));
    existing.confidence = Math.max(Number(existing.confidence || 0), Number(record.confidence || 0));
    return {
      record: existing,
      inserted: false
    };
  }
  list.unshift(record);
  if (list.length > max) {
    list.length = max;
  }
  return {
    record,
    inserted: true
  };
}

function sanitizeMemoryVectorRecord(recordInput = {}) {
  const record = recordInput && typeof recordInput === "object" ? recordInput : {};
  return {
    id: String(record.id || ""),
    scene: normalizeMemoryScene(record.scene, "love"),
    tier: normalizeMemoryTier(record.tier, "long_term"),
    source: String(record.source || "memory"),
    content: String(record.content || ""),
    tags: uniqueStringArray(record.tags || [], 12),
    importance: clampPolicyFloat(record.importance, 0.6, 0, 1),
    confidence: clampPolicyFloat(record.confidence, 0.6, 0, 1),
    createdAt: String(record.createdAt || ""),
    updatedAt: String(record.updatedAt || ""),
    vector: Array.isArray(record.vector) ? record.vector.slice(0, MEMORY_VECTOR_DIM).map((value) => Number(value || 0)) : []
  };
}

function ensureMemoryPlaneState(userState) {
  if (!userState.memorySystem || typeof userState.memorySystem !== "object") {
    userState.memorySystem = createDefaultMemorySystemState();
  }
  const memorySystem = userState.memorySystem;
  memorySystem.version = "2026.3.8";
  memorySystem.vectorDim = clampInteger(memorySystem.vectorDim, MEMORY_VECTOR_DIM, 16, 2048);
  if (!memorySystem.longTerm || typeof memorySystem.longTerm !== "object") {
    memorySystem.longTerm = { items: [], updatedAt: "" };
  }
  if (!memorySystem.middleTerm || typeof memorySystem.middleTerm !== "object") {
    memorySystem.middleTerm = { items: [], updatedAt: "" };
  }
  if (!memorySystem.shortTerm || typeof memorySystem.shortTerm !== "object") {
    memorySystem.shortTerm = { items: [], updatedAt: "" };
  }
  if (!memorySystem.temporary || typeof memorySystem.temporary !== "object") {
    memorySystem.temporary = { items: [], updatedAt: "" };
  }
  memorySystem.architecture = normalizeMemoryArchitectureState(
    memorySystem.architecture,
    {
      fallbackMode: MEMORY_ARCH_ENV_MODE
    }
  );
  if (!memorySystem.sceneVaults || typeof memorySystem.sceneVaults !== "object") {
    memorySystem.sceneVaults = {};
  }
  for (const scene of MEMORY_SCENES) {
    if (!memorySystem.sceneVaults[scene] || typeof memorySystem.sceneVaults[scene] !== "object") {
      memorySystem.sceneVaults[scene] = { items: [], updatedAt: "", writes: 0 };
    }
    if (!Array.isArray(memorySystem.sceneVaults[scene].items)) {
      memorySystem.sceneVaults[scene].items = [];
    }
    memorySystem.sceneVaults[scene].items = memorySystem.sceneVaults[scene].items
      .filter((item) => item && typeof item === "object")
      .map((item) => sanitizeMemoryVectorRecord(item))
      .slice(0, MEMORY_TIER_LIMITS.scene);
    if (typeof memorySystem.sceneVaults[scene].updatedAt !== "string") {
      memorySystem.sceneVaults[scene].updatedAt = "";
    }
    if (typeof memorySystem.sceneVaults[scene].writes !== "number") {
      memorySystem.sceneVaults[scene].writes = 0;
    }
  }
  if (!memorySystem.vectorIndex || typeof memorySystem.vectorIndex !== "object") {
    memorySystem.vectorIndex = { items: [], updatedAt: "", backend: "hash-embedding" };
  }
  if (!Array.isArray(memorySystem.vectorIndex.items)) {
    memorySystem.vectorIndex.items = [];
  }
  memorySystem.vectorIndex.items = memorySystem.vectorIndex.items
    .filter((item) => item && typeof item === "object")
    .map((item) => sanitizeMemoryVectorRecord(item))
    .slice(0, MEMORY_VECTOR_INDEX_LIMIT);
  if (typeof memorySystem.vectorIndex.updatedAt !== "string") {
    memorySystem.vectorIndex.updatedAt = "";
  }
  memorySystem.backend = isQdrantEnabled() ? "qdrant" : "local-vector-index";
  memorySystem.vectorIndex.backend = isQdrantEnabled() ? "qdrant+hash-embedding-cache" : "hash-embedding";
  if (!memorySystem.jobs || typeof memorySystem.jobs !== "object") {
    memorySystem.jobs = {
      lastAuthorityLearningAt: "",
      lastFeedbackDigestAt: "",
      lastPrelearningAt: "",
      lastContextRecycleAt: ""
    };
  }
  for (const key of ["lastAuthorityLearningAt", "lastFeedbackDigestAt", "lastPrelearningAt", "lastContextRecycleAt"]) {
    if (typeof memorySystem.jobs[key] !== "string") {
      memorySystem.jobs[key] = "";
    }
  }
  if (!memorySystem.stats || typeof memorySystem.stats !== "object") {
    memorySystem.stats = {
      totalWrites: 0,
      dedupeRemovals: 0,
      promotions: 0,
      bootstrappedFromHighlights: false
    };
  }
  if (typeof memorySystem.stats.totalWrites !== "number") memorySystem.stats.totalWrites = 0;
  if (typeof memorySystem.stats.dedupeRemovals !== "number") memorySystem.stats.dedupeRemovals = 0;
  if (typeof memorySystem.stats.promotions !== "number") memorySystem.stats.promotions = 0;
  if (typeof memorySystem.stats.bootstrappedFromHighlights !== "boolean") {
    memorySystem.stats.bootstrappedFromHighlights = false;
  }

  for (const tier of ["longTerm", "middleTerm", "shortTerm", "temporary"]) {
    if (!Array.isArray(memorySystem[tier].items)) {
      memorySystem[tier].items = [];
    }
    const normalizedTier =
      tier === "longTerm"
        ? "long_term"
        : tier === "middleTerm"
          ? "mid_term"
          : tier === "shortTerm"
            ? "short_term"
            : "temporary";
    memorySystem[tier].items = memorySystem[tier].items
      .filter((item) => item && typeof item === "object")
      .map((item) => ({
        ...sanitizeMemoryVectorRecord(item),
        tier: normalizedTier
      }))
      .slice(0, memoryTierLimit(normalizedTier, memorySystem));
    if (typeof memorySystem[tier].updatedAt !== "string") {
      memorySystem[tier].updatedAt = "";
    }
  }
  trimMemoryBucketsToArchitectureLimits(memorySystem);

  if (!Array.isArray(userState.memoryHighlights)) {
    userState.memoryHighlights = [];
  }
  if (!memorySystem.stats.bootstrappedFromHighlights && userState.memoryHighlights.length > 0) {
    for (const content of userState.memoryHighlights) {
      const record = createMemoryVectorRecord({
        content,
        scene: "love",
        tier: "long_term",
        source: "legacy_highlight",
        importance: 0.7,
        confidence: 0.7
      });
      pushMemoryRecord(memorySystem.longTerm.items, record, MEMORY_TIER_LIMITS.long_term);
      pushMemoryRecord(memorySystem.sceneVaults.love.items, record, MEMORY_TIER_LIMITS.scene);
      pushMemoryRecord(memorySystem.vectorIndex.items, record, MEMORY_VECTOR_INDEX_LIMIT);
    }
    memorySystem.stats.bootstrappedFromHighlights = true;
  }

  return memorySystem;
}

function writeMemoryRecord(userState, input = {}) {
  const content = String(input.content || "").trim();
  if (!content) {
    return null;
  }
  const memorySystem = ensureMemoryPlaneState(userState);
  const normalizedTier = normalizeMemoryTier(input.tier, "long_term");
  const writableTier = resolveWritableMemoryTier(memorySystem, normalizedTier, "long_term");
  const record = createMemoryVectorRecord({
    content,
    scene: normalizeMemoryScene(input.scene, "love"),
    tier: writableTier,
    source: input.source || "memory",
    tags: input.tags || [],
    importance: input.importance,
    confidence: input.confidence
  });
  const nowIso = new Date().toISOString();
  const targetScene = record.scene;
  const targetTier = record.tier;
  const tierBucket = targetTier === "short_term"
    ? memorySystem.shortTerm
    : targetTier === "mid_term"
      ? memorySystem.middleTerm
    : targetTier === "temporary"
      ? memorySystem.temporary
      : memorySystem.longTerm;
  const tierPush = pushMemoryRecord(tierBucket.items, record, memoryTierLimit(targetTier, memorySystem));
  const scenePush = pushMemoryRecord(memorySystem.sceneVaults[targetScene].items, tierPush.record, MEMORY_TIER_LIMITS.scene);
  const vectorPush = pushMemoryRecord(memorySystem.vectorIndex.items, scenePush.record, MEMORY_VECTOR_INDEX_LIMIT);
  tierBucket.updatedAt = nowIso;
  memorySystem.sceneVaults[targetScene].updatedAt = nowIso;
  memorySystem.sceneVaults[targetScene].writes += tierPush.inserted ? 1 : 0;
  memorySystem.vectorIndex.updatedAt = nowIso;
  memorySystem.stats.totalWrites += tierPush.inserted ? 1 : 0;
  dedupePush(userState.memoryHighlights, `${targetScene}记忆：${content}`, 80);
  if (isQdrantEnabled()) {
    void upsertMemoryRecordToVectorBackend(String(userState.userId || ""), vectorPush.record);
  }
  return vectorPush.record;
}

function removeMemoryRecordById(userState, memoryId) {
  const memorySystem = ensureMemoryPlaneState(userState);
  const removeFromBucket = (bucket) => {
    const index = bucket.items.findIndex((item) => String(item.id || "") === memoryId);
    if (index < 0) return null;
    const [removed] = bucket.items.splice(index, 1);
    return removed;
  };
  let removed = removeFromBucket(memorySystem.longTerm)
    || removeFromBucket(memorySystem.middleTerm)
    || removeFromBucket(memorySystem.shortTerm)
    || removeFromBucket(memorySystem.temporary);
  for (const scene of MEMORY_SCENES) {
    removeFromBucket(memorySystem.sceneVaults[scene]);
  }
  const vectorIndex = memorySystem.vectorIndex.items.findIndex((item) => String(item.id || "") === memoryId);
  if (vectorIndex >= 0) {
    const [vectorRemoved] = memorySystem.vectorIndex.items.splice(vectorIndex, 1);
    if (!removed) {
      removed = vectorRemoved;
    }
  }
  if (removed) {
    const prefix = `${removed.scene}记忆：`;
    const highlightIndex = userState.memoryHighlights.findIndex((item) => String(item || "").startsWith(prefix) && item.includes(removed.content));
    if (highlightIndex >= 0) {
      userState.memoryHighlights.splice(highlightIndex, 1);
    }
    return removed;
  }
  for (let index = 0; index < userState.memoryHighlights.length; index += 1) {
    const content = userState.memoryHighlights[index];
    const candidateId = memoryItemId("highlight", index, content);
    if (candidateId === memoryId) {
      userState.memoryHighlights.splice(index, 1);
      return {
        id: candidateId,
        content
      };
    }
  }
  return null;
}

function getMemoryRecordsByScene(userState, sceneInput = "") {
  const memorySystem = ensureMemoryPlaneState(userState);
  const scene = normalizeMemoryScene(sceneInput, "");
  if (!scene) {
    return memorySystem.vectorIndex.items.slice(0, MEMORY_VECTOR_INDEX_LIMIT);
  }
  return memorySystem.sceneVaults[scene].items.slice(0, MEMORY_TIER_LIMITS.scene);
}

function buildMemorySearchCandidates(userState, options = {}) {
  const memorySystem = ensureMemoryPlaneState(userState);
  const scene = normalizeMemoryScene(options.scene, "");
  const includeCrossScene = options.includeCrossScene !== false;
  const records = getMemoryRecordsByScene(userState, scene).filter((item) =>
    isMemoryTierEnabled(memorySystem, normalizeMemoryTier(item.tier, "long_term"))
  );
  if (scene && includeCrossScene) {
    const crossSceneRecords = memorySystem.vectorIndex.items
      .filter((item) =>
        item.scene !== scene
        && isMemoryTierEnabled(memorySystem, normalizeMemoryTier(item.tier, "long_term"))
      )
      .slice(0, 220);
    return [...records, ...crossSceneRecords];
  }
  return records;
}

function searchMemoryCandidates(userState, query, limit, options = {}) {
  const memorySystem = ensureMemoryPlaneState(userState);
  const architecture = memorySystem.architecture || createDefaultMemoryArchitectureState();
  const reasoningTopK = clampInteger(
    architecture?.realtimeReasoning?.topK,
    MEMORY_REASONING_TOPK_DEFAULT,
    1,
    24
  );
  const architectureCrossScene = architecture?.realtimeReasoning?.includeCrossScene !== false;
  const hybridSearch = architecture?.realtimeReasoning?.hybridSearch !== false;
  const normalizedQuery = normalizeSearchText(query);
  const queryTokens = tokenizeSearchQuery(query);
  const mode = userState.preferences?.mode || "陪伴";
  const modeTerms = modeKeywords[mode] || [];
  const maxItems = clampInteger(limit, reasoningTopK, 1, 20);
  const scene = normalizeMemoryScene(options.scene, "");
  const includeCrossScene = options.includeCrossScene === undefined
    ? architectureCrossScene
    : options.includeCrossScene !== false;
  const queryVector = hybridSearch
    ? buildTextEmbeddingVector(normalizedQuery || query || "", MEMORY_VECTOR_DIM).vector
    : [];
  const candidates = buildMemorySearchCandidates(userState, {
    scene,
    includeCrossScene
  });

  const scored = candidates
    .map((candidate, index) => {
      const normalizedContent = normalizeSearchText(candidate.content);
      const reasons = [];
      const embeddingCosine = hybridSearch
        ? cosineSimilarityFromVector(queryVector, candidate.vector || [])
        : 0;
      let score = Math.max(0, embeddingCosine);
      let rerankScore = score;

      if (normalizedQuery) {
        if (normalizedContent.includes(normalizedQuery)) {
          score += 0.24;
          rerankScore += 0.2;
          reasons.push("query_exact");
        }
        let tokenHits = 0;
        for (const token of queryTokens) {
          if (normalizedContent.includes(token)) {
            tokenHits += 1;
          }
        }
        if (tokenHits > 0) {
          score += Math.min(0.28, tokenHits * 0.09);
          rerankScore += Math.min(0.24, tokenHits * 0.08);
          reasons.push(`token_hits:${tokenHits}`);
        }
      } else {
        score += 0.08;
        rerankScore += 0.05;
        reasons.push("query_empty");
      }

      if (scene && candidate.scene === scene) {
        score += 0.16;
        rerankScore += 0.14;
        reasons.push("scene_exact");
      } else if (scene && includeCrossScene) {
        score += 0.06;
        rerankScore += 0.04;
        reasons.push("cross_scene");
      }

      if (candidate.tier === "long_term") {
        score += 0.08;
      } else if (candidate.tier === "mid_term") {
        score += 0.06;
      } else if (candidate.tier === "short_term") {
        score += 0.04;
      }

      let modeHits = 0;
      for (const keyword of modeTerms) {
        if (candidate.content.includes(keyword)) {
          modeHits += 1;
        }
      }
      if (modeHits > 0) {
        score += Math.min(0.14, modeHits * 0.05);
        rerankScore += Math.min(0.12, modeHits * 0.04);
        reasons.push(`mode_hits:${modeHits}`);
      }

      const recencyMinutes = minutesSince(candidate.updatedAt || candidate.createdAt || "");
      const recencyBonus = Number.isFinite(recencyMinutes)
        ? Math.max(0, Math.min(0.12, (240 - recencyMinutes) / 2400))
        : 0;
      score += recencyBonus;
      rerankScore += recencyBonus * 0.8;
      score += Math.max(0, 0.03 - index * 0.0008);

      return {
        id: String(candidate.id || `mem-${index}`),
        source: String(candidate.source || "memory"),
        scene: normalizeMemoryScene(candidate.scene, "love"),
        memory_tier: normalizeMemoryTier(candidate.tier, "long_term"),
        content: String(candidate.content || ""),
        score: Number(Math.min(0.99, Math.max(0, score)).toFixed(3)),
        embedding_score: Number(Math.min(0.99, Math.max(0, embeddingCosine)).toFixed(3)),
        rerank_score: Number(Math.min(0.99, Math.max(0, rerankScore)).toFixed(3)),
        trigger_confidence: Number(Math.min(0.99, Math.max(0, (score + rerankScore) / 2)).toFixed(3)),
        reasons: hybridSearch ? reasons : [...reasons, "hybrid_search_disabled"]
      };
    })
    .filter((item) => {
      if (!normalizedQuery) return true;
      return item.reasons.some((reason) =>
        reason.startsWith("query_exact")
        || reason.startsWith("token_hits")
        || reason.startsWith("scene_exact")
      );
    })
    .sort((left, right) => right.score - left.score)
    .slice(0, maxItems);

  return {
    query: normalizedQuery,
    tokens: queryTokens,
    scene: scene || "",
    includeCrossScene,
    items: scored,
    trigger_confidence:
      scored.length > 0
        ? Number((scored.reduce((sum, item) => sum + item.trigger_confidence, 0) / scored.length).toFixed(3))
        : 0
  };
}

async function searchMemoryCandidatesWithBackend(userState, query, limit, options = {}) {
  const memorySystem = ensureMemoryPlaneState(userState);
  const architecture = memorySystem.architecture || createDefaultMemoryArchitectureState();
  const hybridSearch = architecture?.realtimeReasoning?.hybridSearch !== false;
  const reasoningTopK = clampInteger(
    architecture?.realtimeReasoning?.topK,
    MEMORY_REASONING_TOPK_DEFAULT,
    1,
    24
  );
  const includeCrossScene = options.includeCrossScene === undefined
    ? architecture?.realtimeReasoning?.includeCrossScene !== false
    : options.includeCrossScene !== false;
  const localResult = searchMemoryCandidates(userState, query, limit, options);
  if (!isQdrantEnabled() || !hybridSearch) {
    return localResult;
  }
  const queryVector = buildTextEmbeddingVector(String(query || ""), MEMORY_VECTOR_DIM).vector;
  const remoteResult = await searchMemoryInQdrant(
    String(userState?.userId || ""),
    queryVector,
    {
      scene: options.scene,
      includeCrossScene,
      limit: clampInteger(limit, reasoningTopK, 1, 40)
    }
  );
  if (!remoteResult.ok || !Array.isArray(remoteResult.items) || remoteResult.items.length === 0) {
    return localResult;
  }
  const mergedMap = new Map();
  for (const item of remoteResult.items) {
    if (!item || typeof item !== "object") continue;
    const key = `${normalizeSearchText(item.content)}|${item.scene}|${item.memory_tier}`;
    if (!key || mergedMap.has(key)) continue;
    mergedMap.set(key, item);
  }
  for (const item of localResult.items || []) {
    const key = `${normalizeSearchText(item.content)}|${item.scene || ""}|${item.memory_tier || ""}`;
    if (!key || mergedMap.has(key)) continue;
    mergedMap.set(key, item);
  }
  const mergedItems = Array.from(mergedMap.values())
    .sort((left, right) => Number(right.score || 0) - Number(left.score || 0))
    .slice(0, clampInteger(limit, reasoningTopK, 1, 20));
  const triggerConfidence = mergedItems.length > 0
    ? Number((mergedItems.reduce((sum, item) => sum + Number(item.trigger_confidence || item.score || 0), 0) / mergedItems.length).toFixed(3))
    : 0;
  return {
    ...localResult,
    items: mergedItems,
    trigger_confidence: triggerConfidence
  };
}

function extractMemoryHighlights(text, state, options = {}) {
  const highlights = state.memoryHighlights;
  const scene = normalizeMemoryScene(options.scene, "love");
  const cleaned = text.trim();
  if (!cleaned) {
    return;
  }

  const learned = [];
  const nameMatch = cleaned.match(/我叫([^\s，。！？,.!?:：]+)/);
  if (nameMatch) {
    learned.push(`用户名字可能是：${nameMatch[1]}`);
  }

  const likeMatch = cleaned.match(/我喜欢([^，。！？,.!?:：]+)/);
  if (likeMatch) {
    learned.push(`用户偏好：喜欢${likeMatch[1]}`);
  }

  if (cleaned.includes("焦虑") || cleaned.includes("压力")) {
    learned.push("用户近期存在压力，需要先安抚再执行任务。");
  }

  if (cleaned.includes("父母") || cleaned.includes("妈妈") || cleaned.includes("爸爸")) {
    learned.push("用户重视父母关怀场景，需提供主动提醒。");
  }

  if (cleaned.includes("赚钱") || cleaned.includes("副业")) {
    learned.push("用户关注变现能力，建议提供内容与执行型方案。");
  }

  for (const item of learned) {
    dedupePush(highlights, item, 80);
    writeMemoryRecord(state, {
      content: item,
      scene,
      tier: "long_term",
      source: "feedback_learning",
      tags: ["feedback", scene],
      importance: 0.74,
      confidence: 0.72
    });
  }

  writeMemoryRecord(state, {
    content: cleaned.length > 240 ? `${cleaned.slice(0, 240)}...` : cleaned,
    scene,
    tier: "short_term",
    source: "chat_user",
    tags: ["chat", scene],
    importance: 0.58,
    confidence: 0.66
  });
}

function addMemoryHighlight(userState, content, options = {}) {
  const scene = normalizeMemoryScene(options.scene, "love");
  const requestedTier = normalizeMemoryTier(options.tier, "long_term");
  dedupePush(userState.memoryHighlights, content, 80);
  const record = writeMemoryRecord(userState, {
    content,
    scene,
    tier: requestedTier,
    source: options.source || "manual_memory",
    tags: options.tags || ["manual", scene],
    importance: options.importance ?? 0.76,
    confidence: options.confidence ?? 0.72
  });
  return {
    id: String(record?.id || memoryItemId("highlight", 0, content)),
    source: String(record?.source || "memory_highlight"),
    scene,
    tier: normalizeMemoryTier(record?.tier, requestedTier),
    content
  };
}

function removeMemoryHighlightById(userState, memoryId) {
  const removed = removeMemoryRecordById(userState, memoryId);
  if (!removed) {
    return null;
  }
  return {
    id: String(removed.id || memoryId),
    content: String(removed.content || "")
  };
}

function minutesSince(isoTime, now = new Date()) {
  if (!isoTime) {
    return Number.POSITIVE_INFINITY;
  }
  const timestamp = Date.parse(isoTime);
  if (Number.isNaN(timestamp)) {
    return Number.POSITIVE_INFINITY;
  }
  return Math.floor((now.getTime() - timestamp) / (1000 * 60));
}

function localHourFromInput(hourInput) {
  const parsed = Number.parseInt(String(hourInput ?? ""), 10);
  if (Number.isFinite(parsed) && parsed >= 0 && parsed <= 23) {
    return parsed;
  }
  return new Date().getHours();
}

function isInQuietHours(hour, quietHours) {
  const start = clampInteger(quietHours?.start, 23, 0, 23);
  const end = clampInteger(quietHours?.end, 7, 0, 23);
  if (start === end) {
    return false;
  }
  if (start < end) {
    return hour >= start && hour < end;
  }
  return hour >= start || hour < end;
}

function nextHourBoundary(targetHour, base = new Date()) {
  const result = new Date(base);
  result.setHours(targetHour, 0, 0, 0);
  if (result.getTime() <= base.getTime()) {
    result.setDate(result.getDate() + 1);
  }
  return result;
}

function pickProactiveType(userState, engagement, localHour) {
  if (engagement.today.messageCount === 0) {
    return "warm_checkin";
  }
  if (engagement.today.messageCount >= 5 && !engagement.today.questCompleted) {
    return "focus_block";
  }
  if (engagement.today.messageCount >= 6 && localHour >= 20) {
    return "evening_reflect";
  }
  if (userState.preferences.mode === "亲情") {
    return "family_ping";
  }
  if (userState.preferences.mode === "工作") {
    return "focus_block";
  }
  if (engagement.today.messageCount >= 8) {
    return "stress_relief";
  }
  return "warm_checkin";
}

function applyAdaptiveProactiveBudget(userState, policy) {
  const proactive = ensureProactiveState(userState);
  const autonomy = ensureAutonomyState(userState);
  const adaptive = autonomy.learning.adaptive;

  const baseMaxDaily = clampInteger(policy?.autonomy?.maxPendingInbox, 3, 1, 20);
  const baseCooldown = 90;

  proactive.maxDaily = clampInteger(baseMaxDaily + adaptive.maxDailyOffset, 3, 1, 8);
  proactive.cooldownMinutes = clampInteger(
    baseCooldown + adaptive.cooldownOffsetMinutes,
    90,
    20,
    240
  );
}

function calculateTriggerConfidence(userState, localHour, idleMinutes) {
  const engagement = ensureEngagementState(userState);
  const autonomy = ensureAutonomyState(userState);
  const feedback = autonomy.learning.feedback;
  const total = Math.max(1, feedback.total);
  const executedRate = feedback.executed / total;
  const dismissedRate = feedback.dismissed / total;
  const ignoredRate = feedback.ignored / total;

  let confidence = 0.44;
  confidence += Math.min(0.18, engagement.today.messageCount * 0.03);
  confidence += Math.min(0.12, engagement.streakDays * 0.015);
  confidence += executedRate * 0.24;
  confidence -= dismissedRate * 0.28;
  confidence -= ignoredRate * 0.16;

  if (idleMinutes > 60) {
    confidence += 0.06;
  }
  if (idleMinutes <= 5) {
    confidence -= 0.08;
  }
  if (localHour >= 22 || localHour <= 7) {
    confidence -= 0.06;
  }

  return Number(Math.max(0.05, Math.min(0.98, confidence)).toFixed(3));
}

function applyProactiveFeedback(userState, feedbackType) {
  const autonomy = ensureAutonomyState(userState);
  const proactive = ensureProactiveState(userState);
  const learning = autonomy.learning;
  const feedback = learning.feedback;
  const adaptive = learning.adaptive;

  if (!["executed", "ignored", "dismissed"].includes(feedbackType)) {
    return {
      applied: false,
      reason: "unsupported_feedback_type",
      autonomy: sanitizeAutonomy(autonomy),
      proactive: sanitizeProactive(proactive)
    };
  }

  feedback.total += 1;
  feedback[feedbackType] += 1;
  learning.lastFeedbackAt = new Date().toISOString();

  if (feedbackType === "executed") {
    adaptive.cooldownOffsetMinutes = Math.max(-60, adaptive.cooldownOffsetMinutes - 5);
    if (feedback.executed % 3 === 0) {
      adaptive.maxDailyOffset = Math.min(3, adaptive.maxDailyOffset + 1);
    }
  }

  if (feedbackType === "ignored") {
    adaptive.cooldownOffsetMinutes = Math.min(80, adaptive.cooldownOffsetMinutes + 4);
    adaptive.idleOffsetMinutes = Math.min(60, adaptive.idleOffsetMinutes + 2);
  }

  if (feedbackType === "dismissed") {
    adaptive.cooldownOffsetMinutes = Math.min(120, adaptive.cooldownOffsetMinutes + 10);
    adaptive.maxDailyOffset = Math.max(-2, adaptive.maxDailyOffset - 1);
    adaptive.idleOffsetMinutes = Math.min(90, adaptive.idleOffsetMinutes + 4);
  }

  proactive.maxDaily = clampInteger(3 + adaptive.maxDailyOffset, 3, 1, 8);
  proactive.cooldownMinutes = clampInteger(
    90 + adaptive.cooldownOffsetMinutes,
    90,
    20,
    240
  );

  appendMaintenanceRecord(
    autonomy,
    "proactive_feedback",
    `收到反馈 ${feedbackType}，已更新触达参数（offset: maxDaily ${adaptive.maxDailyOffset}, cooldown ${adaptive.cooldownOffsetMinutes}）`
  );

  return {
    applied: true,
    reason: "feedback_applied",
    autonomy: sanitizeAutonomy(autonomy),
    proactive: sanitizeProactive(proactive)
  };
}

function createProactiveSuggestion(userState, options = {}) {
  const engagement = ensureEngagementState(userState);
  const proactive = ensureProactiveState(userState);
  applyAdaptiveProactiveBudget(userState, options.policy || null);
  const now = new Date();
  const nowIso = now.toISOString();
  const localHour = localHourFromInput(options.localHour);
  const idleMinutes = lastUserMessageAgeMinutes(userState, now);
  const triggerConfidence = calculateTriggerConfidence(userState, localHour, idleMinutes);

  if (!userState.preferences.online) {
    return {
      delivered: false,
      decision: "skip_offline",
      reason: "用户当前为离线模式，主动建议暂停。",
      triggerConfidence,
      proactive: sanitizeProactive(proactive),
      suggestion: null,
      nextEligibleAt: ""
    };
  }

  if (isInQuietHours(localHour, proactive.quietHours)) {
    return {
      delivered: false,
      decision: "skip_quiet_hours",
      reason: "当前处于静默时段，避免打扰。",
      triggerConfidence,
      proactive: sanitizeProactive(proactive),
      suggestion: null,
      nextEligibleAt: nextHourBoundary(proactive.quietHours.end, now).toISOString()
    };
  }

  if (proactive.sentCount >= proactive.maxDaily) {
    return {
      delivered: false,
      decision: "skip_budget_cap",
      reason: "今日主动触达预算已达上限。",
      triggerConfidence,
      proactive: sanitizeProactive(proactive),
      suggestion: null,
      nextEligibleAt: nextHourBoundary(proactive.quietHours.end, now).toISOString()
    };
  }

  const minutesFromLast = minutesSince(proactive.lastSentAt, now);
  if (minutesFromLast < proactive.cooldownMinutes) {
    return {
      delivered: false,
      decision: "skip_cooldown",
      reason: "冷却中，避免连续触达。",
      triggerConfidence,
      proactive: sanitizeProactive(proactive),
      suggestion: null,
      nextEligibleAt: new Date(
        Date.parse(proactive.lastSentAt) + proactive.cooldownMinutes * 60 * 1000
      ).toISOString()
    };
  }

  if (triggerConfidence < 0.28) {
    return {
      delivered: false,
      decision: "skip_low_confidence",
      reason: "当前触达置信度偏低，延后主动建议。",
      triggerConfidence,
      proactive: sanitizeProactive(proactive),
      suggestion: null,
      nextEligibleAt: new Date(now.getTime() + 15 * 60 * 1000).toISOString()
    };
  }

  const type = pickProactiveType(userState, engagement, localHour);
  const template = proactiveTemplates[type] || proactiveTemplates.warm_checkin;
  const suggestion = {
    id: `pro-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
    type,
    title: template.title,
    message: template.message,
    ctaLabel: template.ctaLabel,
    prefillText: template.prefillText,
    rewardHint: "完成后可累积成长值并推动关系进展。",
    triggerConfidence,
    scene: String(options.scene || "unknown"),
    generatedAt: nowIso
  };

  proactive.sentCount += 1;
  proactive.lastSentAt = nowIso;
  proactive.lastType = type;
  proactive.recent.unshift({
    id: suggestion.id,
    type,
    scene: suggestion.scene,
    at: nowIso
  });
  if (proactive.recent.length > 50) {
    proactive.recent.length = 50;
  }

  return {
    delivered: true,
    decision: "delivered",
    reason: "主动建议已生成。",
    triggerConfidence,
    proactive: sanitizeProactive(proactive),
    suggestion,
    nextEligibleAt: new Date(now.getTime() + proactive.cooldownMinutes * 60 * 1000).toISOString()
  };
}

function lastUserMessageAgeMinutes(userState, now = new Date()) {
  const messages = Array.isArray(userState.messages) ? userState.messages : [];
  for (let index = messages.length - 1; index >= 0; index -= 1) {
    const item = messages[index];
    if (item.role !== "user") {
      continue;
    }
    if (typeof item.timestamp === "number" && Number.isFinite(item.timestamp)) {
      return Math.floor((now.getTime() - item.timestamp) / (1000 * 60));
    }
    const time = Date.parse(String(item.time || ""));
    if (!Number.isNaN(time)) {
      return Math.floor((now.getTime() - time) / (1000 * 60));
    }
    return Number.POSITIVE_INFINITY;
  }
  return Number.POSITIVE_INFINITY;
}

function shouldLearnFromMessage(text) {
  const input = String(text || "").trim();
  if (!input) {
    return false;
  }
  return (
    input.includes("记得") ||
    input.includes("提醒") ||
    input.includes("明天") ||
    input.includes("下周") ||
    input.includes("妈妈") ||
    input.includes("爸爸")
  );
}

function appendAutonomyTimeline(autonomy, eventInput = {}) {
  if (!Array.isArray(autonomy.timeline)) {
    autonomy.timeline = [];
  }
  const event = eventInput && typeof eventInput === "object" ? eventInput : {};
  autonomy.timeline.unshift({
    id: `atl-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
    flowId: String(event.flowId || ""),
    source: String(event.source || "autonomy"),
    stage: String(event.stage || "info"),
    status: String(event.status || "info"),
    title: String(event.title || "自主执行事件"),
    detail: String(event.detail || ""),
    at: new Date().toISOString(),
    refs: event.refs && typeof event.refs === "object" ? event.refs : {}
  });
  if (autonomy.timeline.length > 180) {
    autonomy.timeline.length = 180;
  }
}

function appendMaintenanceRecord(autonomy, type, message) {
  autonomy.maintenance.unshift({
    id: `mt-${Date.now()}-${Math.floor(Math.random() * 1000)}`,
    type,
    message,
    at: new Date().toISOString()
  });
  if (autonomy.maintenance.length > 60) {
    autonomy.maintenance.length = 60;
  }
}

function buildUnifiedTimelineSnapshot(userState, options = {}) {
  const autonomy = ensureAutonomyState(userState);
  const allEvents = Array.isArray(autonomy.timeline) ? autonomy.timeline : [];
  const flowId = String(options.flowId || "").trim();
  const limit = clampInteger(options.limit, 80, 1, 300);
  const filtered = allEvents
    .filter((item) => item && typeof item === "object")
    .filter((item) => (flowId ? String(item.flowId || "") === flowId : true))
    .slice(0, limit)
    .map((item) => ({
      id: String(item.id || ""),
      flowId: String(item.flowId || ""),
      source: String(item.source || "autonomy"),
      stage: String(item.stage || "info"),
      status: String(item.status || "info"),
      title: String(item.title || "自主执行事件"),
      detail: String(item.detail || ""),
      at: String(item.at || ""),
      refs: item.refs && typeof item.refs === "object" ? item.refs : {}
    }))
    .filter((item) => item.id);

  const flowMap = new Map();
  for (const event of [...filtered].reverse()) {
    const key = String(event.flowId || "ungrouped");
    if (!flowMap.has(key)) {
      flowMap.set(key, {
        flowId: key,
        title: event.title || "任务链",
        startedAt: event.at,
        lastAt: event.at,
        status: event.status,
        sources: new Set([event.source || "unknown"]),
        stages: [event.stage],
        total: 1,
        success: event.status === "success" ? 1 : 0,
        warnings: event.status === "warning" ? 1 : 0,
        errors: event.status === "error" ? 1 : 0
      });
      continue;
    }
    const aggregate = flowMap.get(key);
    aggregate.lastAt = event.at || aggregate.lastAt;
    aggregate.total += 1;
    aggregate.sources.add(event.source || "unknown");
    if (!aggregate.stages.includes(event.stage)) {
      aggregate.stages.push(event.stage);
    }
    if (event.status === "success") aggregate.success += 1;
    if (event.status === "warning") aggregate.warnings += 1;
    if (event.status === "error") aggregate.errors += 1;
    if (event.status === "error") {
      aggregate.status = "error";
    } else if (event.status === "warning" && aggregate.status !== "error") {
      aggregate.status = "warning";
    } else if (aggregate.status !== "error" && aggregate.status !== "warning") {
      aggregate.status = "success";
    }
  }

  const flows = Array.from(flowMap.values())
    .map((item) => ({
      flowId: item.flowId,
      title: item.title,
      startedAt: item.startedAt,
      lastAt: item.lastAt,
      status: item.status,
      sources: Array.from(item.sources),
      stages: item.stages,
      total: item.total,
      success: item.success,
      warnings: item.warnings,
      errors: item.errors
    }))
    .sort((a, b) => Date.parse(String(b.lastAt || "")) - Date.parse(String(a.lastAt || "")));

  return {
    flowId,
    total: filtered.length,
    events: filtered,
    flows
  };
}

function buildUnifiedTimelineReplay(userState, flowId, options = {}) {
  const snapshot = buildUnifiedTimelineSnapshot(userState, {
    flowId,
    limit: options.limit || 240
  });
  const eventsAsc = [...snapshot.events].sort(
    (a, b) => Date.parse(String(a.at || "")) - Date.parse(String(b.at || ""))
  );
  const summary = snapshot.flows[0] || {
    flowId,
    title: "任务链回放",
    startedAt: "",
    lastAt: "",
    status: "info",
    sources: [],
    stages: [],
    total: 0,
    success: 0,
    warnings: 0,
    errors: 0
  };
  return {
    flowId: String(flowId || ""),
    summary,
    events: eventsAsc,
    diagnosis: buildFlowDiagnosis(userState, flowId, {
      limit: options.limit || 240
    }),
    generatedAt: new Date().toISOString()
  };
}

function getAutonomyFailureLayerMeta(layerId) {
  const matched = AUTONOMY_FAILURE_LAYER_RULES.find((item) => item.id === layerId);
  if (!matched) {
    return {
      id: layerId,
      label: layerId || "execution",
      hint: "任务执行异常。"
    };
  }
  return {
    id: matched.id,
    label: matched.label,
    hint: matched.hint
  };
}

function findDispatchByFlowId(autonomyInput, flowId) {
  const autonomy = autonomyInput || createDefaultAutonomyState();
  const history = Array.isArray(autonomy.dispatch?.history) ? autonomy.dispatch.history : [];
  return history.find((item) => String(item.flowId || "") === String(flowId || "")) || null;
}

function buildTaskGraphFromDispatch(dispatchInput) {
  const dispatch = dispatchInput && typeof dispatchInput === "object" ? dispatchInput : null;
  const steps = Array.isArray(dispatch?.steps) ? dispatch.steps : [];
  const nodes = [];
  const edges = [];
  for (let index = 0; index < steps.length; index += 1) {
    const step = steps[index] || {};
    const nodeId = `${String(dispatch?.id || "dispatch")}-step-${index + 1}`;
    nodes.push({
      id: nodeId,
      index: index + 1,
      type: String(step.type || "unknown"),
      title: String(step.title || step.type || `步骤 ${index + 1}`),
      status: String(step.status || "planned"),
      reason: String(step.reason || ""),
      source: "dispatch"
    });
    if (index > 0) {
      edges.push({
        id: `${nodeId}-dep-prev`,
        from: nodes[index - 1].id,
        to: nodeId,
        relation: "depends_on_prev"
      });
    }
  }
  return {
    source: "dispatch_history",
    nodes,
    edges
  };
}

function buildTaskGraphFromEvents(eventsAsc) {
  const events = Array.isArray(eventsAsc) ? eventsAsc : [];
  const nodes = [];
  const edges = [];
  for (let index = 0; index < events.length; index += 1) {
    const event = events[index] || {};
    const nodeId = String(event.id || `evt-${index + 1}`);
    nodes.push({
      id: nodeId,
      index: index + 1,
      type: String(event.stage || "event"),
      title: String(event.title || event.stage || `事件 ${index + 1}`),
      status: String(event.status || "info"),
      reason: "",
      source: String(event.source || "timeline")
    });
    if (index > 0) {
      edges.push({
        id: `${nodeId}-dep-prev`,
        from: nodes[index - 1].id,
        to: nodeId,
        relation: "depends_on_prev"
      });
    }
  }
  return {
    source: "timeline_events",
    nodes,
    edges
  };
}

function buildFlowRootCauseSummary(dispatchInput, eventsAsc) {
  const buckets = {};
  const seenSamples = new Set();
  const pushReason = (reason, sample) => {
    const normalizedReason = String(reason || "").trim();
    if (!normalizedReason) {
      return;
    }
    const layerId = classifyAutonomyFailureLayer(normalizedReason);
    if (!buckets[layerId]) {
      const meta = getAutonomyFailureLayerMeta(layerId);
      buckets[layerId] = {
        layerId: meta.id,
        layerLabel: meta.label,
        hint: meta.hint,
        count: 0,
        reasons: {},
        samples: []
      };
    }
    const bucket = buckets[layerId];
    bucket.count += 1;
    bucket.reasons[normalizedReason] = (bucket.reasons[normalizedReason] || 0) + 1;
    const normalizedSample = String(sample || normalizedReason).trim();
    const dedupeKey = `${layerId}:${normalizedSample}`;
    if (normalizedSample && !seenSamples.has(dedupeKey) && bucket.samples.length < 3) {
      seenSamples.add(dedupeKey);
      bucket.samples.push(normalizedSample);
    }
  };

  const dispatch = dispatchInput && typeof dispatchInput === "object" ? dispatchInput : null;
  for (const step of Array.isArray(dispatch?.steps) ? dispatch.steps : []) {
    if (step.status !== "failed" && step.status !== "blocked") {
      continue;
    }
    pushReason(step.reason, step.output?.summary || step.title || step.type || "");
  }
  if (!dispatch) {
    for (const event of Array.isArray(eventsAsc) ? eventsAsc : []) {
      const status = String(event.status || "");
      if (status !== "error" && status !== "warning") {
        continue;
      }
      const reason = String(event.refs?.reason || event.refs?.errorReason || event.stage || status);
      pushReason(reason, event.detail || event.title || reason);
    }
  }

  return Object.values(buckets)
    .map((bucket) => ({
      layerId: bucket.layerId,
      layerLabel: bucket.layerLabel,
      hint: bucket.hint,
      count: bucket.count,
      reasons: Object.entries(bucket.reasons)
        .sort((a, b) => b[1] - a[1])
        .map(([reason, count]) => ({
          reason,
          count
        })),
      samples: bucket.samples
    }))
    .sort((a, b) => b.count - a.count);
}

function buildFlowSuggestedRepair(dispatchInput, rootCauses) {
  const dispatch = dispatchInput && typeof dispatchInput === "object" ? dispatchInput : null;
  const prompt = String(dispatch?.prompt || "").trim();
  const topLayer = Array.isArray(rootCauses) && rootCauses.length > 0 ? rootCauses[0].layerId : "";
  if (topLayer === "permission") {
    return {
      mode: "grant_permission_then_replay",
      label: "先授权再重放",
      reason: "当前失败主要由权限不足触发，建议先授权相关能力后再执行。"
    };
  }
  if (topLayer === "policy") {
    return {
      mode: "policy_adjust_then_replay",
      label: "策略调整后重放",
      reason: "当前失败主要由策略拦截触发，建议放宽策略或白名单后重放。"
    };
  }
  if (topLayer === "network") {
    return {
      mode: "queue_replay",
      label: "网络恢复后重放",
      reason: "当前失败主要由网络/接口异常触发，建议一键重放失败步骤。"
    };
  }
  if (prompt) {
    return {
      mode: "rerun_dispatch",
      label: "重跑原任务链",
      reason: "可直接按原始任务描述重新执行，系统会自动走最新策略。"
    };
  }
  return {
    mode: "queue_replay",
    label: "重放失败步骤",
    reason: "建议从失败步骤开始回放，快速恢复任务链。"
  };
}

function buildFlowDiagnosis(userState, flowId, options = {}) {
  const snapshot = buildUnifiedTimelineSnapshot(userState, {
    flowId,
    limit: clampInteger(options.limit, 240, 1, 600)
  });
  const eventsAsc = [...snapshot.events].sort(
    (a, b) => Date.parse(String(a.at || "")) - Date.parse(String(b.at || ""))
  );
  const autonomy = ensureAutonomyState(userState);
  const dispatch = findDispatchByFlowId(autonomy, flowId);
  const graph = dispatch
    ? buildTaskGraphFromDispatch(dispatch)
    : buildTaskGraphFromEvents(eventsAsc);
  const rootCauses = buildFlowRootCauseSummary(dispatch, eventsAsc);
  const suggestedRepair = buildFlowSuggestedRepair(dispatch, rootCauses);
  const summary = snapshot.flows[0] || {
    flowId: String(flowId || ""),
    title: dispatch?.prompt ? `任务：${dispatch.prompt.slice(0, 40)}` : "任务链诊断",
    startedAt: eventsAsc[0]?.at || "",
    lastAt: eventsAsc[eventsAsc.length - 1]?.at || "",
    status: rootCauses.length > 0 ? "error" : "success",
    sources: [],
    stages: [],
    total: eventsAsc.length,
    success: 0,
    warnings: 0,
    errors: 0
  };
  return {
    flowId: String(flowId || ""),
    summary,
    graph: {
      source: graph.source,
      nodes: graph.nodes,
      edges: graph.edges,
      stats: {
        totalNodes: graph.nodes.length,
        totalEdges: graph.edges.length,
        completedNodes: graph.nodes.filter((item) => item.status === "completed" || item.status === "success").length,
        failedNodes: graph.nodes.filter((item) => item.status === "failed" || item.status === "error").length,
        blockedNodes: graph.nodes.filter((item) => item.status === "blocked" || item.status === "warning").length
      }
    },
    rootCauses,
    suggestedRepair,
    generatedAt: new Date().toISOString()
  };
}

async function repairTimelineFlow(userState, flowId, options = {}) {
  const autonomy = ensureAutonomyState(userState);
  const mode = String(options.mode || "auto").trim() || "auto";
  const processQueue = options.processQueue !== false;
  const queueLimit = clampInteger(options.queueLimit, 16, 1, 80);
  const dispatch = findDispatchByFlowId(autonomy, flowId);
  const beforeDiagnosis = buildFlowDiagnosis(userState, flowId, {
    limit: 300
  });
  let rerunDispatch = null;
  const retriedDeadLetters = [];
  let queueProcessResult = {
    changed: false,
    processed: 0,
    succeeded: 0,
    retried: 0,
    deadLettered: 0
  };
  const grantedCapabilities = [];

  if (mode === "grant_permission_then_replay" && dispatch?.prompt) {
    const plan = buildAutonomyDispatchPlan(dispatch.prompt, {
      preferredCwd: getPreferredCodingWorkspaceCwd(userState)
    });
    for (const operation of plan) {
      const capabilityId = resolveRequiredCapabilityForOperation(operation);
      if (!capabilityId || grantedCapabilities.includes(capabilityId)) {
        continue;
      }
      const updated = updateDevicePermission(
        userState,
        capabilityId,
        "granted",
        "timeline_repair_auto_grant"
      );
      if (updated.ok) {
        grantedCapabilities.push(capabilityId);
      }
    }
  }

  const deadLetters = Array.isArray(autonomy.queue?.deadLetters)
    ? autonomy.queue.deadLetters
        .filter((item) => String(item.flowId || "") === String(flowId || ""))
        .slice(0, queueLimit)
    : [];
  const shouldRetryQueue = mode === "queue_replay" || mode === "auto" || mode === "policy_adjust_then_replay";
  if (shouldRetryQueue && deadLetters.length > 0) {
    for (const dead of deadLetters) {
      const retried = retryAutonomyDeadLetter(userState, dead.id);
      if (retried.ok) {
        retriedDeadLetters.push(retried.item);
      }
    }
    if (processQueue && retriedDeadLetters.length > 0) {
      queueProcessResult = await processAutonomyQueue(userState, {
        limit: queueLimit,
        force: true
      });
    }
  }

  const shouldRerunDispatch = mode === "rerun_dispatch"
    || mode === "grant_permission_then_replay"
    || mode === "policy_adjust_then_replay"
    || (mode === "auto" && (!deadLetters.length || beforeDiagnosis.suggestedRepair.mode === "rerun_dispatch"));
  if (shouldRerunDispatch && dispatch?.prompt) {
    const rerun = await runAutonomyDispatch(userState, dispatch.prompt, {
      source: "timeline_repair",
      execute: true,
      enqueueFailures: true
    });
    rerunDispatch = rerun.dispatch;
  }

  const targetFlowId = rerunDispatch?.flowId || String(flowId || "");
  const diagnosis = buildFlowDiagnosis(userState, targetFlowId, {
    limit: 300
  });
  return {
    ok: true,
    reason: "timeline_repair_executed",
    mode,
    flowId: String(flowId || ""),
    targetFlowId,
    retriedDeadLetterCount: retriedDeadLetters.length,
    retriedDeadLetters,
    grantedCapabilities,
    queueProcessResult,
    rerunDispatch,
    beforeDiagnosis,
    diagnosis
  };
}

function shouldAutoRepairCodingDispatch(intentText, dispatchInput) {
  if (!isCodingExecutionIntent(intentText)) {
    return false;
  }
  const dispatch = dispatchInput && typeof dispatchInput === "object" ? dispatchInput : null;
  if (!dispatch || !dispatch.flowId) {
    return false;
  }
  const status = String(dispatch.status || "").trim().toLowerCase();
  if (!status || status === "completed" || status === "planned") {
    return false;
  }
  const failedSteps = Array.isArray(dispatch.steps)
    ? dispatch.steps.filter((item) => String(item?.status || "") !== "completed")
    : [];
  return failedSteps.length > 0;
}

function summarizeCodingAutoRepairResult(repairResult, fallbackDispatch) {
  const targetDispatch = repairResult?.rerunDispatch && typeof repairResult.rerunDispatch === "object"
    ? repairResult.rerunDispatch
    : fallbackDispatch;
  const status = String(targetDispatch?.status || "").trim().toLowerCase();
  if (status === "completed") {
    return "自动修复链已完成，重跑后任务全部通过。";
  }
  if (status === "partial") {
    return "自动修复链已执行，部分步骤恢复，剩余失败节点已保留重放入口。";
  }
  if (status === "failed") {
    return "自动修复链已执行，但本轮仍失败，建议补充上下文后继续重放。";
  }
  return "自动修复链已执行，已同步最新诊断与建议。";
}

async function runCodingAutoRepairIfNeeded(userState, intentText, dispatchInput, options = {}) {
  const dispatch = dispatchInput && typeof dispatchInput === "object" ? dispatchInput : null;
  if (!shouldAutoRepairCodingDispatch(intentText, dispatch)) {
    return {
      applied: false,
      reason: "not_required",
      summary: "",
      dispatch
    };
  }
  const flowId = String(dispatch.flowId || "").trim();
  if (!flowId) {
    return {
      applied: false,
      reason: "missing_flow_id",
      summary: "",
      dispatch
    };
  }
  const repairMode = String(options.mode || "auto").trim() || "auto";
  const queueLimit = clampInteger(options.queueLimit, 16, 1, 80);
  const repairResult = await repairTimelineFlow(userState, flowId, {
    mode: repairMode,
    processQueue: options.processQueue !== false,
    queueLimit
  });
  const rerunDispatch = repairResult?.rerunDispatch && typeof repairResult.rerunDispatch === "object"
    ? repairResult.rerunDispatch
    : null;
  const nextDispatch = rerunDispatch || dispatch;
  return {
    applied: true,
    reason: "repair_executed",
    summary: summarizeCodingAutoRepairResult(repairResult, dispatch),
    dispatch: nextDispatch,
    repair: {
      mode: repairMode,
      targetFlowId: String(repairResult?.targetFlowId || flowId),
      retriedDeadLetterCount: Number(repairResult?.retriedDeadLetterCount || 0),
      queueProcessResult: repairResult?.queueProcessResult || null,
      diagnosis: repairResult?.diagnosis || null
    }
  };
}

function autonomySelfRepair(userState, options = {}) {
  const autonomy = ensureAutonomyState(userState);
  let changed = false;
  if (!Array.isArray(userState.messages)) {
    userState.messages = [...defaultMessages];
    changed = true;
    appendMaintenanceRecord(autonomy, "repair_messages", "检测到消息结构异常，已回退到安全默认值。");
  }
  if (!Array.isArray(userState.memoryHighlights)) {
    userState.memoryHighlights = [];
    changed = true;
    appendMaintenanceRecord(autonomy, "repair_memory", "检测到记忆结构异常，已修复。");
  }
  if (!userState.memorySystem || typeof userState.memorySystem !== "object") {
    userState.memorySystem = createDefaultMemorySystemState();
    changed = true;
    appendMaintenanceRecord(autonomy, "repair_memory_system", "检测到记忆平面缺失，已重建。");
  }
  ensureMemoryPlaneState(userState);
  if (!userState.preferences || typeof userState.preferences !== "object") {
    userState.preferences = {
      mode: "陪伴",
      online: true
    };
    changed = true;
    appendMaintenanceRecord(autonomy, "repair_preferences", "检测到偏好结构异常，已修复。");
  }
  ensureSceneMessageVault(userState);

  if (options.manual === true) {
    appendMaintenanceRecord(autonomy, "manual_repair", "执行手动自修复检查。");
  }
  if (changed || options.manual === true) {
    autonomy.lastRepairAt = new Date().toISOString();
  }
  return changed || options.manual === true;
}

function autonomyLearnFromRecentMessages(userState) {
  const autonomy = ensureAutonomyState(userState);
  const messages = Array.isArray(userState.messages) ? userState.messages : [];
  const recentUsers = messages.filter((item) => item.role === "user").slice(-8);
  let changed = false;
  for (const item of recentUsers) {
    if (!shouldLearnFromMessage(item.text)) {
      continue;
    }
    const snippet = String(item.text || "").trim();
    if (!snippet) {
      continue;
    }
    const normalized = snippet.length > 40 ? `${snippet.slice(0, 40)}...` : snippet;
    const memory = `自主学习：${normalized}`;
    const before = userState.memoryHighlights.length;
    dedupePush(userState.memoryHighlights, memory, 50);
    writeMemoryRecord(userState, {
      content: memory,
      scene: "work",
      tier: "short_term",
      source: "autonomy_self_learning",
      tags: ["autonomy", "self-learning"],
      importance: 0.68,
      confidence: 0.64
    });
    if (userState.memoryHighlights.length !== before) {
      changed = true;
      appendMaintenanceRecord(autonomy, "learn_memory", `新增自主记忆：${normalized}`);
    }
  }
  if (changed) {
    autonomy.lastLearnAt = new Date().toISOString();
  }
  return changed;
}

function resolveScheduleIntervalMs(cronExpr, fallbackMs) {
  const expr = String(cronExpr || "").trim();
  if (!expr) return fallbackMs;
  const everyMinuteMatch = expr.match(/^\*\/(\d+)\s+\*\s+\*\s+\*\s+\*$/);
  if (everyMinuteMatch) {
    const minutes = clampInteger(everyMinuteMatch[1], 30, 1, 24 * 60);
    return minutes * 60 * 1000;
  }
  const everyHourMatch = expr.match(/^(\d+)\s+\*\/(\d+)\s+\*\s+\*\s+\*$/);
  if (everyHourMatch) {
    const hours = clampInteger(everyHourMatch[2], 6, 1, 24 * 7);
    return hours * 60 * 60 * 1000;
  }
  const fixedHourMatch = expr.match(/^(\d+)\s+(\d+)\s+\*\s+\*\s+\*$/);
  if (fixedHourMatch) {
    return 24 * 60 * 60 * 1000;
  }
  return fallbackMs;
}

function isScheduledJobDue(lastRunAt, cronExpr, fallbackMs, nowMs = Date.now()) {
  if (!lastRunAt) return true;
  const last = Date.parse(String(lastRunAt || ""));
  if (!Number.isFinite(last)) return true;
  const intervalMs = resolveScheduleIntervalMs(cronExpr, fallbackMs);
  return nowMs - last >= intervalMs;
}

async function fetchAuthorityLearningDigest(host) {
  const targetHost = String(host || "").trim();
  if (!targetHost) {
    return {
      ok: false,
      reason: "empty_host"
    };
  }
  const url = targetHost.startsWith("http") ? targetHost : `https://${targetHost}`;
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), 6000);
  try {
    const response = await fetch(url, {
      method: "GET",
      signal: controller.signal
    });
    const html = await response.text();
    const titleMatch = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
    const title = String(titleMatch?.[1] || "").replace(/\s+/g, " ").trim();
    const snippet = String(html || "")
      .replace(/<script[\s\S]*?<\/script>/gi, " ")
      .replace(/<style[\s\S]*?<\/style>/gi, " ")
      .replace(/<[^>]+>/g, " ")
      .replace(/\s+/g, " ")
      .trim()
      .slice(0, 180);
    const summary = title
      ? `${title}${snippet ? `：${snippet}` : ""}`
      : (snippet || `已访问 ${targetHost}`);
    return {
      ok: response.ok,
      reason: response.ok ? "fetched" : "http_error",
      status: response.status,
      host: targetHost,
      url,
      summary
    };
  } catch (error) {
    return {
      ok: false,
      reason: error instanceof Error && error.name === "AbortError" ? "timeout" : "fetch_error",
      host: targetHost,
      url,
      summary: ""
    };
  } finally {
    clearTimeout(timer);
  }
}

async function runAuthorityLearningJobForUser(userState) {
  const learningProfile = systemProfile?.learningEngine?.autonomousEvolution || {};
  const sources = learningProfile.knowledgeSources || {};
  const hostPool = uniqueStringArray([
    ...(Array.isArray(sources.official) ? sources.official : []),
    ...(Array.isArray(sources.universities) ? sources.universities : []),
    ...(Array.isArray(sources.psychologyAndEmba) ? sources.psychologyAndEmba : [])
  ], 60);
  if (hostPool.length === 0) {
    return {
      changed: false,
      reason: "no_sources",
      writes: 0
    };
  }
  const sampledHosts = hostPool.slice(0, 2);
  let writes = 0;
  for (const host of sampledHosts) {
    const digest = await fetchAuthorityLearningDigest(host);
    if (!digest.ok || !digest.summary) {
      continue;
    }
    const record = writeMemoryRecord(userState, {
      content: `权威学习[${host}]：${digest.summary}`,
      scene: "work",
      tier: "mid_term",
      source: "authority_learning",
      tags: ["authority", "learning", "work"],
      importance: 0.82,
      confidence: 0.76
    });
    if (record) writes += 1;
  }
  return {
    changed: writes > 0,
    reason: writes > 0 ? "authority_learning_written" : "authority_learning_no_write",
    writes
  };
}

function runFeedbackLearningDigestJobForUser(userState) {
  const messages = Array.isArray(userState.messages) ? userState.messages : [];
  const recentUsers = messages.filter((item) => item.role === "user").slice(-16);
  let writes = 0;
  for (const item of recentUsers) {
    const text = String(item.text || "").trim();
    if (!text) continue;
    if (!/喜欢|习惯|偏好|讨厌|不要|希望|想要|经常|总是|每次|记住|提醒/i.test(text)) {
      continue;
    }
    const normalized = text.length > 140 ? `${text.slice(0, 140)}...` : text;
    const record = writeMemoryRecord(userState, {
      content: `反馈学习：${normalized}`,
      scene: "love",
      tier: "mid_term",
      source: "feedback_learning",
      tags: ["feedback", "preference", "love"],
      importance: 0.8,
      confidence: 0.78
    });
    if (record) writes += 1;
  }
  return {
    changed: writes > 0,
    reason: writes > 0 ? "feedback_digest_written" : "feedback_digest_no_write",
    writes
  };
}

function runPrelearningJobForUser(userState) {
  const workbench = ensureWorkbenchState(userState);
  const recentIntent = Array.isArray(workbench.coding?.recentIntents)
    ? workbench.coding.recentIntents[0]
    : null;
  const dispatchPrompt = String(ensureAutonomyState(userState).dispatch?.lastPrompt || "").trim();
  const seed = String(recentIntent?.text || dispatchPrompt || "").trim();
  if (!seed) {
    return {
      changed: false,
      reason: "prelearning_seed_empty",
      writes: 0
    };
  }
  const record = writeMemoryRecord(userState, {
    content: `自主预学习：围绕“${seed.slice(0, 120)}”预先准备资料与执行路径。`,
    scene: "work",
    tier: "temporary",
    source: "prelearning",
    tags: ["prelearning", "work"],
    importance: 0.62,
    confidence: 0.64
  });
  return {
    changed: Boolean(record),
    reason: record ? "prelearning_written" : "prelearning_no_write",
    writes: record ? 1 : 0
  };
}

function runContextRecycleJobForUser(userState) {
  const memorySystem = ensureMemoryPlaneState(userState);
  let dedupeRemovals = 0;
  let promotions = 0;
  let promotionsShortToMid = 0;
  let promotionsMidToLong = 0;
  for (const scene of MEMORY_SCENES) {
    const seen = new Set();
    const deduped = [];
    for (const item of memorySystem.sceneVaults[scene].items) {
      const key = `${normalizeSearchText(item.content)}|${normalizeMemoryTier(item.tier, "long_term")}`;
      if (seen.has(key)) {
        dedupeRemovals += 1;
        continue;
      }
      seen.add(key);
      deduped.push(item);
    }
    memorySystem.sceneVaults[scene].items = deduped.slice(0, MEMORY_TIER_LIMITS.scene);
  }
  const shortTermCandidates = memorySystem.shortTerm.items.slice(0, 20);
  const promoteThreshold = clampPolicyFloat(
    systemProfile?.contextRecycleSystem?.rules?.importanceThreshold,
    0.72,
    0.4,
    0.95
  );
  const shortToMidThreshold = Math.max(0.48, promoteThreshold - 0.14);
  const midToLongThreshold = Math.min(0.92, promoteThreshold + 0.06);
  for (const item of shortTermCandidates) {
    const score = clampPolicyFloat(item.importance, 0.6, 0, 1);
    if (score < shortToMidThreshold) {
      continue;
    }
    const promoted = writeMemoryRecord(userState, {
      content: item.content,
      scene: item.scene,
      tier: "mid_term",
      source: "context_promote_mid",
      tags: uniqueStringArray([...(item.tags || []), "promoted"], 12),
      importance: Math.max(0.72, score),
      confidence: Math.max(0.68, clampPolicyFloat(item.confidence, 0.6, 0, 1))
    });
    if (promoted) {
      promotions += 1;
      if (promoted.tier === "mid_term") {
        promotionsShortToMid += 1;
      } else if (promoted.tier === "long_term") {
        promotionsMidToLong += 1;
      }
    }
  }
  const middleTermCandidates = memorySystem.middleTerm.items.slice(0, 20);
  for (const item of middleTermCandidates) {
    const score = clampPolicyFloat(item.importance, 0.68, 0, 1);
    if (score < midToLongThreshold) {
      continue;
    }
    const promoted = writeMemoryRecord(userState, {
      content: item.content,
      scene: item.scene,
      tier: "long_term",
      source: "context_promote_long",
      tags: uniqueStringArray([...(item.tags || []), "promoted", "long_term"], 12),
      importance: Math.max(0.82, score),
      confidence: Math.max(0.74, clampPolicyFloat(item.confidence, 0.66, 0, 1))
    });
    if (promoted) {
      promotions += 1;
      if (promoted.tier === "long_term") {
        promotionsMidToLong += 1;
      } else if (promoted.tier === "mid_term") {
        promotionsShortToMid += 1;
      }
    }
  }
  memorySystem.stats.dedupeRemovals += dedupeRemovals;
  memorySystem.stats.promotions += promotions;
  return {
    changed: dedupeRemovals > 0 || promotions > 0,
    reason: dedupeRemovals > 0 || promotions > 0 ? "context_recycled" : "context_recycle_noop",
    dedupeRemovals,
    promotions,
    promotionsShortToMid,
    promotionsMidToLong
  };
}

async function runMemoryLifecycleJobsForUser(userState, options = {}) {
  const nowIso = new Date().toISOString();
  const nowMs = Date.now();
  const memorySystem = ensureMemoryPlaneState(userState);
  const schedules = systemProfile?.learningEngine?.autonomousEvolution?.schedules || {};
  const recycleJobs = systemProfile?.contextRecycleSystem?.jobs || {};
  const runForce = options.force === true;
  const result = {
    changed: false,
    ran: []
  };

  if (runForce || isScheduledJobDue(memorySystem.jobs.lastAuthorityLearningAt, schedules.authorityKnowledgeSyncCron, 6 * 60 * 60 * 1000, nowMs)) {
    const authorityResult = await runAuthorityLearningJobForUser(userState);
    memorySystem.jobs.lastAuthorityLearningAt = nowIso;
    result.ran.push({
      job: "authority_learning",
      ...authorityResult
    });
    result.changed = result.changed || authorityResult.changed;
  }
  if (runForce || isScheduledJobDue(memorySystem.jobs.lastFeedbackDigestAt, schedules.feedbackDigestCron, 30 * 60 * 1000, nowMs)) {
    const feedbackResult = runFeedbackLearningDigestJobForUser(userState);
    memorySystem.jobs.lastFeedbackDigestAt = nowIso;
    result.ran.push({
      job: "feedback_digest",
      ...feedbackResult
    });
    result.changed = result.changed || feedbackResult.changed;
  }
  if (runForce || isScheduledJobDue(memorySystem.jobs.lastPrelearningAt, schedules.prelearningCron, 4 * 60 * 60 * 1000, nowMs)) {
    const prelearningResult = runPrelearningJobForUser(userState);
    memorySystem.jobs.lastPrelearningAt = nowIso;
    result.ran.push({
      job: "prelearning",
      ...prelearningResult
    });
    result.changed = result.changed || prelearningResult.changed;
  }
  if (runForce || isScheduledJobDue(memorySystem.jobs.lastContextRecycleAt, recycleJobs.contextClassifyCron, 20 * 60 * 1000, nowMs)) {
    const recycleResult = runContextRecycleJobForUser(userState);
    memorySystem.jobs.lastContextRecycleAt = nowIso;
    result.ran.push({
      job: "context_recycle",
      ...recycleResult
    });
    result.changed = result.changed || recycleResult.changed;
  }
  return result;
}

function enqueueAutonomySuggestion(userState, suggestion) {
  const autonomy = ensureAutonomyState(userState);
  if (!suggestion) {
    return false;
  }
  autonomy.inbox.unshift({
    id: `auto-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
    suggestionId: suggestion.id,
    type: suggestion.type,
    title: suggestion.title,
    message: suggestion.message,
    ctaLabel: suggestion.ctaLabel,
    prefillText: suggestion.prefillText,
    status: "pending",
    createdAt: new Date().toISOString()
  });
  if (autonomy.inbox.length > 30) {
    autonomy.inbox.length = 30;
  }
  autonomy.generatedCount += 1;
  return true;
}

function pendingAutonomyInboxCount(userState) {
  const autonomy = ensureAutonomyState(userState);
  return autonomy.inbox.filter((item) => item.status !== "acked").length;
}

async function runAutonomyTickForUser(userState, policy, options = {}) {
  const autonomy = ensureAutonomyState(userState);
  const now = new Date();
  let changed = false;
  const autonomyActive = autonomy.enabled && policy.autonomy.enabled !== false;
  let queueResult = {
    changed: false,
    processed: 0,
    succeeded: 0,
    retried: 0,
    deadLettered: 0
  };
  autonomy.tickCount += 1;
  autonomy.lastTickAt = now.toISOString();

  if (autonomyActive) {
    if (policy.autonomy.selfRepairEnabled && autonomySelfRepair(userState)) {
      changed = true;
    }
    if (policy.autonomy.selfLearningEnabled && autonomyLearnFromRecentMessages(userState)) {
      changed = true;
    }
    const queuePolicy = ensureQueuePolicy(autonomy);
    const shouldProcessQueue = options.processQueue === true
      || (options.processQueue !== false && queuePolicy.autoProcessOnTick !== false);
    if (shouldProcessQueue) {
      queueResult = await processAutonomyQueue(userState, {
        limit: options.queueLimit
      });
      if (queueResult.changed) {
        changed = true;
      }
    }
  }

  if (!autonomyActive) {
    return {
      changed,
      queueResult
    };
  }

  const idleMinutes = lastUserMessageAgeMinutes(userState, now);
  const pendingCount = pendingAutonomyInboxCount(userState);
  const adaptiveIdleOffset = autonomy.learning.adaptive.idleOffsetMinutes;
  const requiredIdleMinutes = clampInteger(
    policy.autonomy.idleMinutesBeforeNudge + adaptiveIdleOffset,
    policy.autonomy.idleMinutesBeforeNudge,
    5,
    180
  );
  const noBudget =
    pendingCount >= policy.autonomy.maxPendingInbox ||
    idleMinutes < requiredIdleMinutes;
  if (noBudget) {
    return {
      changed,
      queueResult
    };
  }

  const proactiveResult = createProactiveSuggestion(userState, {
    scene: "autonomy_tick",
    localHour: now.getHours(),
    policy
  });
  if (proactiveResult.delivered && proactiveResult.suggestion) {
    enqueueAutonomySuggestion(userState, proactiveResult.suggestion);
    changed = true;
  }
  return {
    changed,
    queueResult
  };
}

function ackAutonomyInboxItem(userState, inboxId) {
  const autonomy = ensureAutonomyState(userState);
  const item = autonomy.inbox.find((entry) => entry.id === inboxId);
  if (!item) {
    return null;
  }
  item.status = "acked";
  item.ackedAt = new Date().toISOString();
  return item;
}

function pickRandom(items) {
  return items[Math.floor(Math.random() * items.length)];
}

function normalizeSoulScene(sceneInput) {
  const scene = String(sceneInput || "").trim().toLowerCase();
  if (!scene) {
    return "";
  }
  if (scene === "work" || /^(工作|办公|office|job|professional|workspace)$/.test(scene)) {
    return "work";
  }
  if (scene === "fun" || /^(fun|娱乐|休闲|玩乐|game|play)$/.test(scene)) {
    return "fun";
  }
  if (scene === "life" || /^(life|生活|家庭|home|family)$/.test(scene)) {
    return "life";
  }
  if (scene === "love" || /^(love|情感|陪伴|恋爱|emotion|companion)$/.test(scene)) {
    return "love";
  }
  if (scene === "coding" || /^(coding|code|编程|开发|程序|programming|dev|developer)$/.test(scene)) {
    return "coding";
  }
  return "";
}

function normalizeAriaSoulProfile(profileInput) {
  const profile = profileInput && typeof profileInput === "object"
    ? profileInput
    : DEFAULT_ARIA_SOUL_PROFILE;
  const globalInput = profile.global && typeof profile.global === "object" ? profile.global : {};
  const global = {
    identity: uniqueStringArray(
      Array.isArray(globalInput.identity)
        ? globalInput.identity.map((item) => String(item || "").trim()).filter(Boolean)
        : DEFAULT_ARIA_SOUL_PROFILE.global.identity,
      12
    ),
    executionContract: uniqueStringArray(
      Array.isArray(globalInput.executionContract)
        ? globalInput.executionContract.map((item) => String(item || "").trim()).filter(Boolean)
        : DEFAULT_ARIA_SOUL_PROFILE.global.executionContract,
      12
    )
  };
  const scenes = {};
  for (const scene of ["work", "fun", "life", "love", "coding"]) {
    const source = profile.scenes && typeof profile.scenes === "object" ? profile.scenes[scene] : null;
    const fallback = DEFAULT_ARIA_SOUL_PROFILE.scenes[scene];
    scenes[scene] = {
      displayName: String(source?.displayName || fallback.displayName),
      focus: uniqueStringArray(
        Array.isArray(source?.focus) ? source.focus.map((item) => String(item || "").trim()).filter(Boolean) : fallback.focus,
        12
      ),
      styleRules: uniqueStringArray(
        Array.isArray(source?.styleRules) ? source.styleRules.map((item) => String(item || "").trim()).filter(Boolean) : fallback.styleRules,
        12
      ),
      openings: uniqueStringArray(
        Array.isArray(source?.openings) ? source.openings.map((item) => String(item || "").trim()).filter(Boolean) : fallback.openings,
        12
      ),
      fallback: uniqueStringArray(
        Array.isArray(source?.fallback) ? source.fallback.map((item) => String(item || "").trim()).filter(Boolean) : fallback.fallback,
        12
      )
    };
  }
  return {
    version: String(profile.version || DEFAULT_ARIA_SOUL_PROFILE.version),
    global,
    scenes
  };
}

function loadAriaSoulProfileFromDisk() {
  const raw = loadJsonConfigFile(ariaSoulProfileFile, DEFAULT_ARIA_SOUL_PROFILE);
  return normalizeAriaSoulProfile(raw);
}

let ariaSoulProfile = loadAriaSoulProfileFromDisk();
let ariaSoulProfileMtimeMs = existsSync(ariaSoulProfileFile)
  ? statSync(ariaSoulProfileFile).mtimeMs
  : -1;

function refreshAriaSoulProfileIfNeeded() {
  ensureJsonConfigFile(ariaSoulProfileFile, DEFAULT_ARIA_SOUL_PROFILE);
  const nextMtime = statSync(ariaSoulProfileFile).mtimeMs;
  if (nextMtime !== ariaSoulProfileMtimeMs) {
    ariaSoulProfile = loadAriaSoulProfileFromDisk();
    ariaSoulProfileMtimeMs = nextMtime;
  }
  return ariaSoulProfile;
}

function resolveSoulScene(sceneInput, mode, hintText = "") {
  const normalizedScene = normalizeSoulScene(sceneInput);
  if (normalizedScene) {
    return normalizedScene;
  }
  const normalizedMode = normalizeSoulScene(mode);
  if (normalizedMode) {
    return normalizedMode;
  }
  if (mode === "工作") {
    return "work";
  }
  if (mode === "亲情") {
    return "life";
  }
  const hint = String(hintText || "").trim();
  if (
    hint
    && (
      isCodingExecutionIntent(hint)
      || /代码|编程|脚本|函数|模块|仓库|项目|bug|报错|错误栈|构建|编译|测试|terminal|shell|run|build|test|debug|fix|patch/i.test(hint)
    )
  ) {
    return "coding";
  }
  return "love";
}

function isCodingExecutionIntent(input = "") {
  const text = String(input || "").trim();
  if (!text) {
    return false;
  }
  if (/只聊天|先聊聊|仅建议|先给方案|不要执行|只回答|仅回复/.test(text)) {
    return false;
  }
  const lightweightConnectivityCheck = /测试一下|测试回复|在不在|连通性|通道是否正常/.test(text);
  if (
    lightweightConnectivityCheck
    && !/代码|编程|脚本|函数|模块|仓库|项目|bug|报错|错误栈|构建|编译|命令|terminal|shell|run|build|test|npm|pnpm|yarn|flutter|xcode/i.test(text)
  ) {
    return false;
  }
  const signals = buildIntentSignalSnapshot(text);
  const codeHint = intentHasObjectCategory(signals, "code")
    || /代码|编程|脚本|函数|模块|仓库|项目|bug|报错|错误栈|debug|fix|patch|commit|git|npm|pnpm|yarn|flutter|xcode|android|前端|后端|桌面端|移动端|构建失败|编译失败|测试失败|terminal|shell|命令行/i.test(text);
  const actionHint = intentHasActionCategory(signals, "execute")
    || intentHasActionCategory(signals, "command")
    || intentHasActionCategory(signals, "create")
    || /修复|调试|执行|运行|安装|补齐|构建|编译|测试|run|build|test|debug|fix/i.test(text);
  return codeHint && actionHint;
}

function inferMessageTaskType(mode, input, sceneInput = "") {
  const text = String(input || "");
  const scene = resolveSoulScene(sceneInput, mode, text);
  if (isCodingExecutionIntent(text) || scene === "coding") {
    return "coding_execution";
  }
  if (/修复|代码|bug|脚本|构建|编程|部署|测试|命令|command|api|函数|仓库|terminal|shell|debug|fix|patch/i.test(text)) {
    return "coding_execution";
  }
  if (/会议|日程|排期|里程碑|待办|项目管理|汇报|周报|工作安排|任务拆解|复盘计划/i.test(text)) {
    return "work_planning";
  }
  if (/记忆|回忆|总结|纪念|复盘|摘要|整理/i.test(text)) {
    return "memory_digest";
  }
  if (/自动|执行|下载|联网|扩展|插件|终端|调度|打开|访问|发布|发帖|小红书|资讯|日报|新闻|推送|发送|回传|菜谱|食谱|做饭|就医|挂号|会议纪要|待办清单/i.test(text)) {
    return "autonomy_dispatch";
  }
  if (scene === "work") {
    return "work_planning";
  }
  if (scene === "coding") {
    return "coding_execution";
  }
  if (scene === "life") {
    return "memory_digest";
  }
  if (mode === "工作") {
    return "work_planning";
  }
  return "emotional_companion";
}

function providerEnvPrefix(providerId) {
  return `ARIA_MODEL_PROVIDER_${String(providerId || "")
    .toUpperCase()
    .replace(/[^A-Z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "")}`;
}

const openclawModelSnapshotCache = {
  path: OPENCLAW_CONFIG_FILE,
  mtimeMs: -1,
  loadedAt: "",
  ok: false,
  reason: "",
  providers: [],
  error: ""
};

function normalizeOpenclawModelProviderId(input) {
  const normalized = String(input || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9._/-]+/g, "-")
    .replace(/^-+|-+$/g, "");
  return normalized || "openclaw-provider";
}

function normalizeOpenclawModelId(input) {
  return String(input || "")
    .trim()
    .replace(/\s+/g, "")
    .replace(/\/{2,}/g, "/");
}

function loadOpenclawModelSnapshot(options = {}) {
  const force = options && typeof options === "object" ? options.force === true : false;
  const configPathRaw = String(
    options?.path
    || process.env.ARIA_OPENCLAW_CONFIG_PATH
    || OPENCLAW_CONFIG_FILE
    || ""
  ).trim();
  const configPath = resolve(configPathRaw || OPENCLAW_CONFIG_FILE);

  if (!existsSync(configPath)) {
    openclawModelSnapshotCache.path = configPath;
    openclawModelSnapshotCache.ok = false;
    openclawModelSnapshotCache.reason = "config_missing";
    openclawModelSnapshotCache.error = "Aria Kernel 配置文件不存在";
    openclawModelSnapshotCache.providers = [];
    openclawModelSnapshotCache.loadedAt = new Date().toISOString();
    openclawModelSnapshotCache.mtimeMs = -1;
    return {
      ...openclawModelSnapshotCache
    };
  }

  const mtimeMs = statSync(configPath).mtimeMs;
  if (!force && openclawModelSnapshotCache.path === configPath && openclawModelSnapshotCache.mtimeMs === mtimeMs) {
    return {
      ...openclawModelSnapshotCache
    };
  }

  try {
    const raw = JSON.parse(readFileSync(configPath, "utf8"));
    const providersRaw = raw?.models?.providers && typeof raw.models.providers === "object"
      ? raw.models.providers
      : {};
    const providers = [];
    for (const [providerIdRaw, providerInput] of Object.entries(providersRaw)) {
      if (!providerInput || typeof providerInput !== "object") {
        continue;
      }
      const providerId = normalizeOpenclawModelProviderId(providerIdRaw);
      const baseUrl = String(
        providerInput.baseUrl
        || providerInput.baseURL
        || providerInput.endpoint
        || ""
      ).trim().replace(/\/+$/, "");
      const apiKey = String(providerInput.apiKey || "").trim();
      const modelsRaw = Array.isArray(providerInput.models) ? providerInput.models : [];
      const models = uniqueStringArray(
        modelsRaw.map((item) => normalizeOpenclawModelId(item?.id || item?.model || item?.name || "")),
        40
      );
      const isLocal = providerId.includes("ollama")
        || providerId.includes("local")
        || /^https?:\/\/(127\.0\.0\.1|localhost)/i.test(baseUrl)
        || /^(127\.0\.0\.1|localhost)/i.test(baseUrl);
      providers.push({
        id: providerId,
        baseUrl,
        apiKey,
        models,
        isLocal
      });
    }

    openclawModelSnapshotCache.path = configPath;
    openclawModelSnapshotCache.mtimeMs = mtimeMs;
    openclawModelSnapshotCache.loadedAt = new Date().toISOString();
    openclawModelSnapshotCache.ok = true;
    openclawModelSnapshotCache.reason = providers.length > 0 ? "loaded" : "provider_empty";
    openclawModelSnapshotCache.error = "";
    openclawModelSnapshotCache.providers = providers;
    return {
      ...openclawModelSnapshotCache
    };
  } catch (error) {
    openclawModelSnapshotCache.path = configPath;
    openclawModelSnapshotCache.mtimeMs = mtimeMs;
    openclawModelSnapshotCache.loadedAt = new Date().toISOString();
    openclawModelSnapshotCache.ok = false;
    openclawModelSnapshotCache.reason = "invalid_config";
    openclawModelSnapshotCache.error = error instanceof Error ? error.message : String(error);
    openclawModelSnapshotCache.providers = [];
    return {
      ...openclawModelSnapshotCache
    };
  }
}

function inferProviderRoles(modelId, providerId = "") {
  const text = `${modelId || ""} ${providerId || ""}`.toLowerCase();
  const roles = ["chat", "planning"];
  if (/code|coder|coding|deepseek|qwen|r1|o4|glm|nemotron/.test(text)) {
    roles.push("coding", "tool-use");
  }
  if (/emotion|love|companion|kimi|moonshot/.test(text)) {
    roles.push("emotion");
  }
  return uniqueStringArray(roles, 8);
}

function selectOpenclawProviderForRoute(providerInput, modelHint = "") {
  const provider = providerInput && typeof providerInput === "object" ? providerInput : {};
  const snapshot = loadOpenclawModelSnapshot();
  if (!snapshot.ok) {
    return null;
  }
  const providers = Array.isArray(snapshot.providers) ? snapshot.providers : [];
  if (providers.length === 0) {
    return null;
  }
  const openclawProviderHint = normalizeOpenclawModelProviderId(
    provider.openclawProvider || provider.id || ""
  );
  const model = normalizeOpenclawModelId(modelHint || provider.model || "");

  let matched = providers.find((item) => item.id === openclawProviderHint) || null;
  if (!matched && model) {
    matched = providers.find((item) => item.models.includes(model)) || null;
  }
  if (!matched && model) {
    matched = providers.find((item) => model.startsWith(`${item.id}/`)) || null;
  }
  return matched;
}

function resolveModelProviderRuntime(providerInput) {
  const provider = providerInput && typeof providerInput === "object" ? providerInput : {};
  const id = String(provider.id || "").trim();
  const envPrefix = providerEnvPrefix(id);
  const openclawProvider = selectOpenclawProviderForRoute(provider);
  const openclawBaseUrl = openclawProvider?.baseUrl || "";
  const openclawApiKey = openclawProvider?.apiKey || "";
  const model = String(
    process.env[`${envPrefix}_MODEL`]
      || provider.model
      || openclawProvider?.models?.[0]
      || DEFAULT_MODEL_ROUTING_POLICY.providers[0].model
  ).trim();
  const baseUrl = String(
    process.env[`${envPrefix}_BASE_URL`]
      || provider.baseUrl
      || openclawBaseUrl
      || MODEL_ROUTER_DEFAULT_BASE_URL
  )
    .trim()
    .replace(/\/+$/, "");
  const envApiKey = String(process.env[`${envPrefix}_API_KEY`] || "").trim();
  const providerApiKeyEnv = String(provider.apiKeyEnv || "").trim();
  const providerApiKey = providerApiKeyEnv ? String(process.env[providerApiKeyEnv] || "").trim() : "";
  const defaultApiKey = String(MODEL_ROUTER_DEFAULT_API_KEY || "").trim();
  const apiKey = String(
    envApiKey
      || providerApiKey
      || openclawApiKey
      || defaultApiKey
      || ""
  ).trim();
  let authSource = "none";
  if (envApiKey) {
    authSource = `${envPrefix}_API_KEY`;
  } else if (providerApiKey) {
    authSource = providerApiKeyEnv;
  } else if (openclawApiKey) {
    authSource = `openclaw:${openclawProvider?.id || "provider"}`;
  } else if (defaultApiKey) {
    authSource = "ARIA_MODEL_OPENAI_API_KEY";
  }
  return {
    id: id || "unknown-provider",
    model,
    baseUrl,
    apiKey,
    vendor: String(provider.vendor || "openai-compatible"),
    roles: uniqueStringArray(provider.roles || [], 20),
    enabled: provider.disabled !== true,
    authSource,
    openclawProvider: openclawProvider?.id || ""
  };
}

const MODEL_ROUTER_FAST_TASK_TYPES = new Set(["emotional_companion", "memory_digest"]);
const MODEL_ROUTER_AUTONOMY_TASK_TYPES = new Set(["autonomy_dispatch", "coding_execution", "work_planning"]);
const modelRouterProviderHealth = new Map();

function classifyModelRouterTaskClass(taskTypeInput = "") {
  const taskType = String(taskTypeInput || "").trim();
  if (MODEL_ROUTER_FAST_TASK_TYPES.has(taskType)) {
    return "chat_fast";
  }
  if (MODEL_ROUTER_AUTONOMY_TASK_TYPES.has(taskType)) {
    return "autonomy";
  }
  return "standard";
}

function resolveModelRouterTaskProfile(taskTypeInput = "") {
  const taskType = String(taskTypeInput || "").trim() || "emotional_companion";
  const taskClass = classifyModelRouterTaskClass(taskType);
  const degrade = modelRoutingPolicy?.degradeStrategy || DEFAULT_MODEL_ROUTING_POLICY.degradeStrategy;
  const defaultTimeoutMs = clampInteger(degrade.timeoutMs, MODEL_ROUTER_REAL_CALL_TIMEOUT_MS, 1000, 120000);
  const defaultMaxRetries = clampInteger(degrade.maxRetries, 0, 0, 6);
  const defaultRetryBackoffMs = clampInteger(degrade.retryBackoffMs, 1200, 100, 60000);
  if (taskClass === "chat_fast") {
    return {
      taskType,
      taskClass,
      timeoutMs: Math.min(defaultTimeoutMs, MODEL_ROUTER_CHAT_FAST_TIMEOUT_MS),
      maxRetries: Math.min(defaultMaxRetries, MODEL_ROUTER_CHAT_FAST_MAX_RETRIES),
      retryBackoffMs: Math.min(defaultRetryBackoffMs, 600),
      totalBudgetMs: Math.min(MODEL_ROUTER_TOTAL_BUDGET_MS, MODEL_ROUTER_CHAT_FAST_TOTAL_BUDGET_MS)
    };
  }
  if (taskClass === "autonomy") {
    return {
      taskType,
      taskClass,
      timeoutMs: Math.min(defaultTimeoutMs, MODEL_ROUTER_AUTONOMY_TIMEOUT_MS),
      maxRetries: Math.min(defaultMaxRetries, MODEL_ROUTER_AUTONOMY_MAX_RETRIES),
      retryBackoffMs: defaultRetryBackoffMs,
      totalBudgetMs: Math.min(MODEL_ROUTER_TOTAL_BUDGET_MS, MODEL_ROUTER_AUTONOMY_TOTAL_BUDGET_MS)
    };
  }
  return {
    taskType,
    taskClass,
    timeoutMs: defaultTimeoutMs,
    maxRetries: defaultMaxRetries,
    retryBackoffMs: defaultRetryBackoffMs,
    totalBudgetMs: MODEL_ROUTER_TOTAL_BUDGET_MS
  };
}

function ensureModelRouterProviderHealthEntry(providerIdInput) {
  const providerId = String(providerIdInput || "").trim() || "unknown-provider";
  if (!modelRouterProviderHealth.has(providerId)) {
    modelRouterProviderHealth.set(providerId, {
      providerId,
      cooldownUntilMs: 0,
      lastFailureAt: "",
      lastFailureReason: "",
      lastFailureStatus: 0,
      lastSuccessAt: "",
      lastSuccessReason: "",
      lastAttemptAt: "",
      lastOutcome: "",
      transientFailures: 0,
      successCount: 0,
      failureCount: 0,
      emptyResponseCount: 0,
      lastLatencyMs: 0,
      avgLatencyMs: 0,
      emaLatencyMs: 0,
      totalLatencyMs: 0
    });
  }
  return modelRouterProviderHealth.get(providerId);
}

function coerceProviderLatencyMs(latencyInput, fallback = 0) {
  const latency = Number(latencyInput);
  if (!Number.isFinite(latency)) {
    return Math.max(0, Number(fallback || 0));
  }
  return Math.max(0, Math.round(latency));
}

function updateModelRouterProviderLatencyMetrics(entryInput = {}, latencyMsInput = 0) {
  const entry = entryInput && typeof entryInput === "object" ? entryInput : null;
  if (!entry) {
    return;
  }
  const latencyMs = coerceProviderLatencyMs(latencyMsInput, 0);
  if (latencyMs <= 0) {
    return;
  }
  const successCount = clampInteger(Number(entry.successCount || 0), 0, 0, 1000000);
  const failureCount = clampInteger(Number(entry.failureCount || 0), 0, 0, 1000000);
  const nextRuns = Math.max(1, successCount + failureCount);
  const prevTotalLatency = Number(entry.totalLatencyMs || 0);
  const nextTotalLatency = Math.max(0, prevTotalLatency + latencyMs);
  entry.totalLatencyMs = nextTotalLatency;
  entry.lastLatencyMs = latencyMs;
  entry.avgLatencyMs = Math.round(nextTotalLatency / nextRuns);
  const prevEma = coerceProviderLatencyMs(
    entry.emaLatencyMs || entry.avgLatencyMs || entry.lastLatencyMs || latencyMs,
    latencyMs
  );
  entry.emaLatencyMs = Math.round(
    prevEma * (1 - MODEL_ROUTER_HEALTH_EMA_ALPHA) + latencyMs * MODEL_ROUTER_HEALTH_EMA_ALPHA
  );
}

function shouldApplyModelRouterProviderCooldown(resultInput = {}) {
  const reason = String(resultInput.reason || "").trim();
  const status = Number(resultInput.status || 0);
  if (reason === "provider_timeout" || reason === "provider_exception" || reason === "empty_response") {
    return true;
  }
  if (reason === "provider_http_error") {
    return status >= 400;
  }
  return false;
}

function noteModelRouterProviderSuccess(providerIdInput, resultInput = {}) {
  const entry = ensureModelRouterProviderHealthEntry(providerIdInput);
  const result = resultInput && typeof resultInput === "object" ? resultInput : {};
  const latencyMs = coerceProviderLatencyMs(result.latencyMs, 0);
  entry.transientFailures = 0;
  entry.cooldownUntilMs = 0;
  entry.lastSuccessAt = new Date().toISOString();
  entry.lastSuccessReason = String(result.reason || "provider_success").trim() || "provider_success";
  entry.lastAttemptAt = entry.lastSuccessAt;
  entry.lastOutcome = "provider_success";
  entry.successCount = clampInteger(Number(entry.successCount || 0) + 1, 1, 0, 1000000);
  updateModelRouterProviderLatencyMetrics(entry, latencyMs);
  return entry;
}

function noteModelRouterProviderFailure(providerIdInput, resultInput = {}) {
  const entry = ensureModelRouterProviderHealthEntry(providerIdInput);
  const result = resultInput && typeof resultInput === "object" ? resultInput : {};
  const reason = String(result.reason || "").trim();
  const status = Number(result.status || 0);
  const latencyMs = coerceProviderLatencyMs(result.latencyMs, 0);
  entry.lastFailureAt = new Date().toISOString();
  entry.lastFailureReason = reason;
  entry.lastFailureStatus = status;
  entry.lastAttemptAt = entry.lastFailureAt;
  entry.lastOutcome = reason || "provider_failed";
  entry.failureCount = clampInteger(Number(entry.failureCount || 0) + 1, 1, 0, 1000000);
  if (reason === "empty_response") {
    entry.emptyResponseCount = clampInteger(Number(entry.emptyResponseCount || 0) + 1, 1, 0, entry.failureCount);
  }
  updateModelRouterProviderLatencyMetrics(entry, latencyMs);
  if (shouldApplyModelRouterProviderCooldown(result)) {
    entry.transientFailures += 1;
    if (entry.transientFailures >= MODEL_ROUTER_PROVIDER_COOLDOWN_THRESHOLD) {
      entry.cooldownUntilMs = Date.now() + MODEL_ROUTER_PROVIDER_COOLDOWN_MS;
      entry.transientFailures = 0;
    }
  } else if (reason === "provider_success") {
    entry.transientFailures = 0;
    entry.cooldownUntilMs = 0;
  } else if (reason === "missing_api_key" || reason === "empty_response") {
    entry.transientFailures = 0;
  }
  return entry;
}

function getModelRouterProviderCooldownRemainingMs(providerIdInput, nowMsInput = Date.now()) {
  const entry = ensureModelRouterProviderHealthEntry(providerIdInput);
  const nowMs = Number.isFinite(Number(nowMsInput)) ? Number(nowMsInput) : Date.now();
  const leftMs = Math.max(0, Math.round(Number(entry.cooldownUntilMs || 0) - nowMs));
  if (leftMs <= 0) {
    entry.cooldownUntilMs = 0;
  }
  return leftMs;
}

function getFlywheelLearningStateForRouting(userState) {
  if (!userState || typeof userState !== "object") {
    return null;
  }
  const autonomy = ensureAutonomyState(userState);
  const learning = autonomy?.learning && typeof autonomy.learning === "object"
    ? autonomy.learning
    : null;
  if (!learning || !learning.flywheel || typeof learning.flywheel !== "object") {
    return null;
  }
  return learning.flywheel;
}

function getFlywheelProviderRouteScore(userState, taskTypeInput = "", providerIdInput = "") {
  const flywheel = getFlywheelLearningStateForRouting(userState);
  if (!flywheel) {
    return null;
  }
  const taskType = String(taskTypeInput || "").trim();
  const providerId = String(providerIdInput || "").trim();
  if (!taskType || !providerId) {
    return null;
  }
  const taskScores = flywheel.providerScores && typeof flywheel.providerScores === "object"
    ? flywheel.providerScores[taskType]
    : null;
  if (!taskScores || typeof taskScores !== "object") {
    return null;
  }
  const entry = taskScores[providerId];
  if (!entry || typeof entry !== "object") {
    return null;
  }
  const runs = clampInteger(entry.runs, 0, 0, 1000000);
  const combinedAvg = clampPolicyFloat(entry.combinedAvg, 0, 0, 1);
  const fallbackRuns = clampInteger(entry.fallbackRuns, 0, 0, runs);
  const fallbackRate = runs > 0 ? clampPolicyFloat(fallbackRuns / runs, 0, 0, 1) : 0;
  return {
    runs,
    combinedAvg,
    score: clampPolicyFloat(combinedAvg * 0.88 + (1 - fallbackRate) * 0.12, 0, 0, 1),
    fallbackRate
  };
}

function rankModelRouteCandidatesByFlywheel(userState, taskTypeInput, candidatesInput = [], preferredProviderId = "") {
  const candidates = Array.isArray(candidatesInput) ? candidatesInput.slice(0) : [];
  if (candidates.length <= 1) {
    return candidates;
  }
  const taskType = String(taskTypeInput || "").trim();
  if (!taskType) {
    return candidates;
  }
  const preferredProvider = String(preferredProviderId || "").trim();
  const scored = candidates.map((candidate, index) => {
    const providerId = String(candidate?.id || "").trim();
    const learned = getFlywheelProviderRouteScore(userState, taskType, providerId);
    return {
      candidate,
      index,
      providerId,
      runs: learned?.runs || 0,
      score: learned?.score ?? -1
    };
  });
  const hasLearnedScore = scored.some((item) => item.runs >= FLYWHEEL_AUTO_ROUTE_MIN_RUNS && item.score >= 0);
  if (!hasLearnedScore) {
    return candidates;
  }
  let preferred = null;
  const rest = [];
  for (const item of scored) {
    if (preferredProvider && item.providerId === preferredProvider && !preferred) {
      preferred = item;
      continue;
    }
    rest.push(item);
  }
  rest.sort((left, right) => {
    const leftReady = left.runs >= FLYWHEEL_AUTO_ROUTE_MIN_RUNS && left.score >= 0;
    const rightReady = right.runs >= FLYWHEEL_AUTO_ROUTE_MIN_RUNS && right.score >= 0;
    if (leftReady && rightReady) {
      const diff = right.score - left.score;
      if (Math.abs(diff) >= FLYWHEEL_AUTO_ROUTE_MIN_SCORE_GAP) {
        return diff > 0 ? 1 : -1;
      }
      if (right.runs !== left.runs) {
        return right.runs - left.runs;
      }
    } else if (rightReady !== leftReady) {
      return rightReady ? 1 : -1;
    }
    return left.index - right.index;
  });
  const ordered = preferred ? [preferred, ...rest] : rest;
  return ordered.map((item) => item.candidate);
}

function normalizeModelRouteScene(sceneInput = "", taskTypeInput = "") {
  const scene = String(sceneInput || "").trim().toLowerCase();
  if (scene) {
    return scene;
  }
  const taskType = String(taskTypeInput || "").trim().toLowerCase();
  if (taskType === "emotional_companion") {
    return "love";
  }
  if (taskType === "memory_digest") {
    return "life";
  }
  if (taskType === "coding_execution") {
    return "coding";
  }
  if (taskType === "work_planning" || taskType === "autonomy_dispatch") {
    return "work";
  }
  return "";
}

function rankModelRouteCandidatesByHealth(
  taskTypeInput,
  sceneInput,
  candidatesInput = [],
  preferredProviderId = "",
  userState = null
) {
  const candidates = Array.isArray(candidatesInput) ? candidatesInput.slice(0) : [];
  if (candidates.length <= 1) {
    return candidates;
  }
  const taskType = String(taskTypeInput || "").trim();
  const scene = normalizeModelRouteScene(sceneInput, taskType);
  const emotionalPriority = taskType === "emotional_companion" || scene === "love" || scene === "life";
  const codingPriority = taskType === "coding_execution" || scene === "coding";
  const preferredProvider = String(preferredProviderId || "").trim();
  const nowMs = Date.now();
  const scored = candidates.map((candidate, index) => {
    const providerId = String(candidate?.id || "").trim();
    const runtime = resolveModelProviderRuntime(candidate);
    const hasApiKey = Boolean(runtime.apiKey);
    const health = ensureModelRouterProviderHealthEntry(providerId);
    const successCount = clampInteger(health.successCount, 0, 0, 1000000);
    const failureCount = clampInteger(health.failureCount, 0, 0, 1000000);
    const totalRuns = successCount + failureCount;
    const successRate = totalRuns > 0
      ? clampPolicyFloat(successCount / totalRuns, 0.52, 0, 1)
      : 0.52;
    const emptyRate = failureCount > 0
      ? clampPolicyFloat(clampInteger(health.emptyResponseCount, 0, 0, failureCount) / failureCount, 0, 0, 1)
      : 0;
    const latencyMs = coerceProviderLatencyMs(
      health.emaLatencyMs || health.avgLatencyMs || health.lastLatencyMs,
      MODEL_ROUTER_HEALTH_DEFAULT_LATENCY_MS
    );
    const cooldownRemainingMs = getModelRouterProviderCooldownRemainingMs(providerId, nowMs);
    const hasEmotionRole = Array.isArray(candidate?.roles)
      && candidate.roles.some((role) => String(role || "").trim().toLowerCase() === "emotion");
    const hasCodingRole = Array.isArray(candidate?.roles)
      && candidate.roles.some((role) => /coding|tool-use|debug/i.test(String(role || "")));
    const learned = getFlywheelProviderRouteScore(userState, taskType, providerId);
    const learnedReady = Boolean(learned && learned.runs >= FLYWHEEL_AUTO_ROUTE_MIN_RUNS && learned.score >= 0);
    let tier = "warm";
    if (!hasApiKey) {
      tier = "no_key";
    } else if (cooldownRemainingMs > 0) {
      tier = "cooldown";
    } else if (totalRuns >= 2 && (successRate < 0.35 || emptyRate > 0.45)) {
      tier = "risky";
    } else if (
      totalRuns >= 2
      && successRate >= 0.72
      && emptyRate <= 0.2
      && latencyMs <= Math.round(MODEL_ROUTER_EMOTIONAL_STABLE_LATENCY_MS * 1.25)
    ) {
      tier = "stable";
    }
    let score = 0;
    score += tier === "stable" ? 280 : tier === "warm" ? 190 : tier === "risky" ? 80 : tier === "cooldown" ? -60 : -120;
    score += successRate * 70;
    score -= emptyRate * 35;
    if (learnedReady) {
      score += clampPolicyFloat(learned.score, 0, 0, 1) * 45;
    }
    if (preferredProvider && providerId === preferredProvider) {
      score += 80;
    }
    if (emotionalPriority) {
      score += hasEmotionRole ? 24 : -8;
      const latencyGap = latencyMs - MODEL_ROUTER_EMOTIONAL_STABLE_LATENCY_MS;
      if (latencyGap <= 0) {
        score += Math.min(26, Math.abs(latencyGap) / 140);
      } else {
        score -= Math.min(34, latencyGap / 180);
      }
    }
    if (codingPriority) {
      score += hasCodingRole ? 18 : -12;
    }
    if (totalRuns === 0) {
      score -= 8;
    }
    if (cooldownRemainingMs > 0) {
      score -= Math.min(60, cooldownRemainingMs / 1000);
    }
    score -= index * 0.01;
    return {
      candidate,
      index,
      score,
      tier,
      latencyMs
    };
  });
  let preferred = null;
  const rest = [];
  for (const item of scored) {
    if (preferredProvider && item.candidate?.id === preferredProvider && !preferred) {
      preferred = item;
      continue;
    }
    rest.push(item);
  }
  const tierWeight = {
    stable: 4,
    warm: 3,
    risky: 2,
    cooldown: 1,
    no_key: 0
  };
  rest.sort((left, right) => {
    const tierDiff = (tierWeight[right.tier] || 0) - (tierWeight[left.tier] || 0);
    if (tierDiff !== 0) {
      return tierDiff;
    }
    const scoreDiff = right.score - left.score;
    if (Math.abs(scoreDiff) >= 0.001) {
      return scoreDiff > 0 ? 1 : -1;
    }
    if (left.latencyMs !== right.latencyMs) {
      return left.latencyMs - right.latencyMs;
    }
    return left.index - right.index;
  });
  const ordered = preferred ? [preferred, ...rest] : rest;
  return ordered.map((item) => item.candidate);
}

function resolveModelRouteCandidates(taskType, preferredProviderId = "", userState = null, sceneInput = "") {
  const providers = Array.isArray(modelRoutingPolicy?.providers) ? modelRoutingPolicy.providers : [];
  const providerMap = new Map(providers.map((provider) => [provider.id, provider]));
  const queue = [];
  const push = (providerId) => {
    const normalized = String(providerId || "").trim();
    if (!normalized || queue.includes(normalized) || !providerMap.has(normalized)) {
      return;
    }
    queue.push(normalized);
  };

  push(preferredProviderId);
  for (const routeId of uniqueStringArray(modelRoutingPolicy?.taskRoutes?.[taskType] || [], 10)) {
    push(routeId);
  }

  const profileModel = systemProfile?.layers?.model || {};
  push(profileModel.defaultRoute);
  push(profileModel.fallbackRoute);

  for (const provider of providers) {
    push(provider.id);
  }
  const candidates = queue
    .map((providerId) => providerMap.get(providerId))
    .filter((item) => item && item.disabled !== true)
    .map((item) => normalizeModelRoutingProvider(item));
  const flywheelRanked = rankModelRouteCandidatesByFlywheel(userState, taskType, candidates, preferredProviderId);
  return rankModelRouteCandidatesByHealth(taskType, sceneInput, flywheelRanked, preferredProviderId, userState);
}

function buildModelRouterRuntimeSnapshot(taskTypeInput = "") {
  const providers = Array.isArray(modelRoutingPolicy?.providers) ? modelRoutingPolicy.providers : [];
  const openclawSnapshot = loadOpenclawModelSnapshot();
  const activeTaskType = String(taskTypeInput || "").trim();
  const activeTaskProfile = activeTaskType ? resolveModelRouterTaskProfile(activeTaskType) : null;
  const profileStandard = resolveModelRouterTaskProfile("general_chat");
  const profileFast = resolveModelRouterTaskProfile("emotional_companion");
  const profileAutonomy = resolveModelRouterTaskProfile("autonomy_dispatch");
  return {
    realCallEnabled: MODEL_ROUTER_REAL_CALL_ENABLED,
    defaultBaseUrl: MODEL_ROUTER_DEFAULT_BASE_URL,
    timeoutMs: MODEL_ROUTER_REAL_CALL_TIMEOUT_MS,
    totalBudgetMs: MODEL_ROUTER_TOTAL_BUDGET_MS,
    maxProviderCandidates: MODEL_ROUTER_MAX_PROVIDER_CANDIDATES,
    maxTokens: MODEL_ROUTER_CHAT_MAX_TOKENS,
    openclaw: {
      path: openclawSnapshot.path,
      ok: openclawSnapshot.ok,
      reason: openclawSnapshot.reason,
      loadedAt: openclawSnapshot.loadedAt,
      providerCount: Array.isArray(openclawSnapshot.providers) ? openclawSnapshot.providers.length : 0
    },
    taskProfiles: {
      standard: {
        timeoutMs: profileStandard.timeoutMs,
        totalBudgetMs: profileStandard.totalBudgetMs,
        maxRetries: profileStandard.maxRetries,
        retryBackoffMs: profileStandard.retryBackoffMs
      },
      chatFast: {
        timeoutMs: profileFast.timeoutMs,
        totalBudgetMs: profileFast.totalBudgetMs,
        maxRetries: profileFast.maxRetries,
        retryBackoffMs: profileFast.retryBackoffMs
      },
      autonomy: {
        timeoutMs: profileAutonomy.timeoutMs,
        totalBudgetMs: profileAutonomy.totalBudgetMs,
        maxRetries: profileAutonomy.maxRetries,
        retryBackoffMs: profileAutonomy.retryBackoffMs
      }
    },
    activeTaskProfile: activeTaskProfile
      ? {
        taskType: activeTaskProfile.taskType,
        taskClass: activeTaskProfile.taskClass,
        timeoutMs: activeTaskProfile.timeoutMs,
        totalBudgetMs: activeTaskProfile.totalBudgetMs,
        maxRetries: activeTaskProfile.maxRetries,
        retryBackoffMs: activeTaskProfile.retryBackoffMs
      }
      : null,
    providerRuntimes: providers.map((provider) => {
      const runtime = resolveModelProviderRuntime(provider);
      const health = ensureModelRouterProviderHealthEntry(runtime.id);
      const cooldownRemainingMs = getModelRouterProviderCooldownRemainingMs(runtime.id);
      const successCount = clampInteger(health.successCount, 0, 0, 1000000);
      const failureCount = clampInteger(health.failureCount, 0, 0, 1000000);
      const totalRuns = successCount + failureCount;
      const successRate = totalRuns > 0 ? clampPolicyFloat(successCount / totalRuns, 0, 0, 1) : 0;
      return {
        id: runtime.id,
        model: runtime.model,
        baseUrl: runtime.baseUrl,
        vendor: runtime.vendor,
        apiKeyConfigured: Boolean(runtime.apiKey),
        enabled: runtime.enabled,
        authSource: runtime.authSource || "none",
        openclawProvider: runtime.openclawProvider || "",
        cooldownActive: cooldownRemainingMs > 0,
        cooldownRemainingMs,
        lastFailureReason: String(health.lastFailureReason || ""),
        lastFailureAt: String(health.lastFailureAt || ""),
        lastSuccessAt: String(health.lastSuccessAt || ""),
        lastSuccessReason: String(health.lastSuccessReason || ""),
        lastOutcome: String(health.lastOutcome || ""),
        lastAttemptAt: String(health.lastAttemptAt || ""),
        successCount,
        failureCount,
        successRate,
        emptyResponseCount: clampInteger(health.emptyResponseCount, 0, 0, failureCount),
        lastLatencyMs: coerceProviderLatencyMs(health.lastLatencyMs, 0),
        avgLatencyMs: coerceProviderLatencyMs(health.avgLatencyMs, 0),
        emaLatencyMs: coerceProviderLatencyMs(health.emaLatencyMs, 0)
      };
    })
  };
}

function createDefaultCompanionStyleProfile() {
  return {
    version: "2026.3.8",
    preferredVariant: "gentle",
    confidence: 0.42,
    brevity: "normal",
    nicknamePreference: "neutral",
    warmth: 0.74,
    signalCounts: {
      gentle: 0,
      direct: 0,
      rational: 0,
      playful: 0
    },
    updatedAt: ""
  };
}

function sanitizeCompanionStyleProfile(profileInput = {}) {
  const raw = profileInput && typeof profileInput === "object" ? profileInput : {};
  const base = createDefaultCompanionStyleProfile();
  const preferredVariant = ["gentle", "direct", "rational", "playful"].includes(String(raw.preferredVariant || ""))
    ? String(raw.preferredVariant)
    : base.preferredVariant;
  const brevity = ["brief", "normal", "detailed"].includes(String(raw.brevity || ""))
    ? String(raw.brevity)
    : base.brevity;
  const nicknamePreference = ["neutral", "intimate"].includes(String(raw.nicknamePreference || ""))
    ? String(raw.nicknamePreference)
    : base.nicknamePreference;
  return {
    version: String(raw.version || base.version),
    preferredVariant,
    confidence: clampPolicyFloat(raw.confidence, base.confidence, 0, 1),
    brevity,
    nicknamePreference,
    warmth: clampPolicyFloat(raw.warmth, base.warmth, 0.35, 0.95),
    signalCounts: {
      gentle: clampInteger(raw?.signalCounts?.gentle, 0, 0, 999999),
      direct: clampInteger(raw?.signalCounts?.direct, 0, 0, 999999),
      rational: clampInteger(raw?.signalCounts?.rational, 0, 0, 999999),
      playful: clampInteger(raw?.signalCounts?.playful, 0, 0, 999999)
    },
    updatedAt: String(raw.updatedAt || "")
  };
}

function ensureCompanionStyleProfileState(userState) {
  if (!userState || typeof userState !== "object") {
    return createDefaultCompanionStyleProfile();
  }
  if (!userState.companionStyle || typeof userState.companionStyle !== "object") {
    userState.companionStyle = createDefaultCompanionStyleProfile();
  }
  userState.companionStyle = sanitizeCompanionStyleProfile(userState.companionStyle);
  return userState.companionStyle;
}

function detectCompanionStyleSignal(textInput = "", sceneInput = "love") {
  const text = String(textInput || "").trim();
  const scene = normalizeMessageScene(sceneInput, "love");
  const scores = {
    gentle: 0,
    direct: 0,
    rational: 0,
    playful: 0
  };
  let brevity = "normal";
  let brevityExplicit = false;
  let nicknamePreference = "";

  if (!text) {
    return {
      topVariant: scene === "work" || scene === "coding"
        ? "direct"
        : scene === "fun"
          ? "playful"
          : "gentle",
      topScore: 0,
      scores,
      brevity,
      brevityExplicit,
      nicknamePreference,
      warmth: scene === "work" || scene === "coding" ? 0.62 : 0.74
    };
  }

  if (/温柔|慢一点|先安慰|先抱抱|陪我|暖心|别凶|别冷冰冰|别生硬|情绪价值/i.test(text)) {
    scores.gentle += 3;
  }
  if (/直接|结论先|别废话|快点|马上|只说重点|务实|别绕弯|先给结果/i.test(text)) {
    scores.direct += 3;
  }
  if (/理性|客观|结构化|条理|严谨|专业|步骤|清单|分层|分析/i.test(text)) {
    scores.rational += 3;
  }
  if (/轻松|有趣|好玩|幽默|逗我|整活|可爱|哈哈|玩/i.test(text)) {
    scores.playful += 3;
  }

  if (/安慰|抱抱|难受|焦虑|低落|委屈|害怕|孤单|想你|爱你/i.test(text)) {
    scores.gentle += 2;
  }
  if (/工作|汇报|老板|项目|执行|排期|交付|推进/i.test(text)) {
    scores.direct += 1;
    scores.rational += 1;
  }
  if (/代码|编程|修复|debug|报错|terminal|命令|脚本/i.test(text)) {
    scores.rational += 2;
    scores.direct += 1;
  }
  if (/小游戏|娱乐|玩一把|轻松一下|开玩/i.test(text)) {
    scores.playful += 2;
  }

  if (scene === "work" || scene === "coding") {
    scores.direct += 1;
  } else if (scene === "fun") {
    scores.playful += 1;
  } else {
    scores.gentle += 1;
  }

  if (/简短|一句话|一两句|别太长|短一点|只回一句|只说一句/i.test(text)) {
    brevity = "brief";
    brevityExplicit = true;
    scores.direct += 1;
  } else if (/详细|展开|说细一点|具体一点|完整一点|多说一点|一步一步|逐步/i.test(text)) {
    brevity = "detailed";
    brevityExplicit = true;
    scores.rational += 1;
  }

  if (/别叫我|不要叫我|别喊我|别用爱称|不要用爱称|叫我名字|称呼正式一点/i.test(text)) {
    nicknamePreference = "neutral";
  } else if (/叫我(老公|老婆|宝贝|宝宝|亲爱的)|用(老公|老婆|宝贝|宝宝|亲爱的)称呼我/i.test(text)) {
    nicknamePreference = "intimate";
  }

  const ranking = Object.entries(scores)
    .sort((left, right) => {
      const scoreDiff = Number(right[1] || 0) - Number(left[1] || 0);
      if (scoreDiff !== 0) {
        return scoreDiff;
      }
      return String(left[0] || "").localeCompare(String(right[0] || ""));
    });
  const topVariant = String(ranking[0]?.[0] || "gentle");
  const topScore = Number(ranking[0]?.[1] || 0);
  const warmthByVariant = {
    gentle: 0.84,
    direct: 0.58,
    rational: 0.64,
    playful: 0.76
  };
  const warmth = clampPolicyFloat(warmthByVariant[topVariant], 0.74, 0.35, 0.95);
  return {
    topVariant,
    topScore,
    scores,
    brevity,
    brevityExplicit,
    nicknamePreference,
    warmth
  };
}

function resolveCompanionStyleSnapshot(userState, sceneInput = "", userInput = "") {
  const scene = normalizeMessageScene(sceneInput, "love");
  const profile = ensureCompanionStyleProfileState(userState);
  const signal = detectCompanionStyleSignal(userInput, scene);
  const sceneDefaultVariant = scene === "work" || scene === "coding"
    ? "direct"
    : scene === "fun"
      ? "playful"
      : "gentle";
  let variant = String(profile.preferredVariant || sceneDefaultVariant).trim() || sceneDefaultVariant;
  if (signal.topScore >= 2) {
    variant = signal.topVariant;
  } else if (!["gentle", "direct", "rational", "playful"].includes(variant) || profile.confidence < 0.2) {
    variant = sceneDefaultVariant;
  }
  const brevity = signal.brevityExplicit
    ? signal.brevity
    : (["brief", "normal", "detailed"].includes(profile.brevity) ? profile.brevity : "normal");
  const nicknamePreference = signal.nicknamePreference
    || (["neutral", "intimate"].includes(profile.nicknamePreference) ? profile.nicknamePreference : "neutral");
  const warmth = clampPolicyFloat(
    signal.topScore >= 2
      ? signal.warmth
      : (Number(profile.warmth || 0.74) * 0.78 + Number(signal.warmth || 0.74) * 0.22),
    0.74,
    0.35,
    0.95
  );
  return {
    variant,
    brevity,
    nicknamePreference,
    warmth,
    confidence: clampPolicyFloat(profile.confidence, 0.42, 0, 1)
  };
}

function updateCompanionStyleProfileFromUserInput(userState, sceneInput = "", userInput = "") {
  const profile = ensureCompanionStyleProfileState(userState);
  const text = String(userInput || "").trim();
  if (!text) {
    return profile;
  }
  const scene = normalizeMessageScene(sceneInput, "love");
  const signal = detectCompanionStyleSignal(text, scene);
  if (signal.topScore >= 2) {
    profile.preferredVariant = signal.topVariant;
    profile.confidence = clampPolicyFloat(profile.confidence * 0.72 + 0.28, 0.42, 0, 1);
  } else {
    profile.confidence = clampPolicyFloat(profile.confidence * 0.97, 0.42, 0, 1);
  }
  if (signal.brevityExplicit) {
    profile.brevity = signal.brevity;
  }
  if (signal.nicknamePreference) {
    profile.nicknamePreference = signal.nicknamePreference;
  }
  profile.warmth = clampPolicyFloat(profile.warmth * 0.74 + signal.warmth * 0.26, 0.74, 0.35, 0.95);
  if (profile.signalCounts && typeof profile.signalCounts === "object") {
    profile.signalCounts[signal.topVariant] = clampInteger(profile.signalCounts[signal.topVariant], 0, 0, 999999) + 1;
  }
  profile.updatedAt = new Date().toISOString();
  userState.companionStyle = sanitizeCompanionStyleProfile(profile);
  return userState.companionStyle;
}

function buildCompanionStylePromptLines(styleSnapshotInput = {}) {
  const styleSnapshot = styleSnapshotInput && typeof styleSnapshotInput === "object" ? styleSnapshotInput : {};
  const variant = String(styleSnapshot.variant || "gentle");
  const variantLabelMap = {
    gentle: "温柔共情",
    direct: "直给高效",
    rational: "理性结构化",
    playful: "轻松互动"
  };
  const brevity = String(styleSnapshot.brevity || "normal");
  const brevityLabelMap = {
    brief: "简短",
    normal: "标准",
    detailed: "展开"
  };
  const nicknamePreference = String(styleSnapshot.nicknamePreference || "neutral");
  const nicknameLabelMap = {
    neutral: "中性称呼（默认不用亲昵称）",
    intimate: "亲密称呼（在场景合适时可用）"
  };
  return [
    `- 语气主风格：${variantLabelMap[variant] || variantLabelMap.gentle}。`,
    `- 回复长度偏好：${brevityLabelMap[brevity] || brevityLabelMap.normal}。`,
    `- 称呼偏好：${nicknameLabelMap[nicknamePreference] || nicknameLabelMap.neutral}。`,
    `- 情绪温度：${Math.round(clampPolicyFloat(styleSnapshot.warmth, 0.74, 0.35, 0.95) * 100)} / 100。`,
    "- 同一会话里避免重复同一句开场，保持语义一致但句式变化。"
  ];
}

function buildAssistantPromptContext(userState, mode, input, taskType, sceneInput = "") {
  const soulProfile = refreshAriaSoulProfileIfNeeded();
  const soulScene = resolveSoulScene(sceneInput, mode, input);
  const activeScenePrompt = resolveActiveScenePrompt(soulScene);
  const allowCrossSceneRecall = (() => {
    const text = String(input || "").trim();
    if (!text) return false;
    if (/跨场景|跨模块|跨空间|全局记忆|统一记忆|跨场景联想/i.test(text)) return true;
    if (/另一个场景|换个场景|不同场景|多场景/i.test(text)) return true;
    if (/在工作场景|在娱乐场景|在生活场景|在情感场景|在编程场景/i.test(text)) return true;
    return false;
  })();
  const sceneSoul = soulProfile?.scenes?.[soulScene] || DEFAULT_ARIA_SOUL_PROFILE.scenes[soulScene] || DEFAULT_ARIA_SOUL_PROFILE.scenes.love;
  const sceneConfigState = ensureSceneConfigState(userState);
  const sceneSoulModuleKey = buildSceneModuleKey(soulScene, "soul-core");
  const sceneSoulModule = sanitizeSceneConfigModule(sceneConfigState.modules[sceneSoulModuleKey], sceneSoulModuleKey);
  const sceneSoulProfile = normalizeSceneSoulProfile(sceneSoulModule.soulProfile || {});
  const sceneSoulDirective = String(sceneSoulProfile.directive || "").trim();
  const sceneSoulFileHints = Array.isArray(sceneSoulProfile.uploadedFiles)
    ? sceneSoulProfile.uploadedFiles
      .slice(0, 4)
      .map((item) => {
        const name = String(item.name || "").trim();
        const excerpt = String(item.excerpt || "").trim();
        if (!name) return "";
        return excerpt ? `- ${name}：${excerpt}` : `- ${name}`;
      })
      .filter(Boolean)
    : [];
  const soulIdentity = Array.isArray(soulProfile?.global?.identity) ? soulProfile.global.identity : DEFAULT_ARIA_SOUL_PROFILE.global.identity;
  const soulExecutionContract = Array.isArray(soulProfile?.global?.executionContract)
    ? soulProfile.global.executionContract
    : DEFAULT_ARIA_SOUL_PROFILE.global.executionContract;
  const memoryHighlights = Array.isArray(userState?.memoryHighlights)
    ? userState.memoryHighlights.slice(0, 4).map((item) => `- ${String(item || "")}`)
    : [];
  const recalledMemories = searchMemoryCandidates(
    userState,
    String(input || ""),
    undefined,
    {
      scene: soulScene,
      includeCrossScene: allowCrossSceneRecall
    }
  );
  const memoryRecallLines = Array.isArray(recalledMemories.items)
    ? recalledMemories.items
      .slice(0, 4)
      .map((item) => `- [${item.scene}/${item.memory_tier}] ${String(item.content || "")}`)
    : [];
  const recentMessages = getRecentSceneMessages(userState, soulScene, 6)
    .map((item) => `${item.role === "user" ? "用户" : "Aria"}: ${String(item.text || "")}`);
  const modeGuide = modeHints[mode] || modeHints["陪伴"];
  const directInput = String(input || "").trim();
  const styleSnapshot = resolveCompanionStyleSnapshot(userState, soulScene, directInput);
  const stylePromptLines = buildCompanionStylePromptLines(styleSnapshot);
  const forceSingleSentence = /只回一句|只说一句|一句话回复|一句话回答/i.test(directInput);
  const explicitCommand = /^(请)?(就)?(只)?(说|回复|叫我|别叫我|不要叫我|用|按|以|当|扮演|模仿)/i.test(directInput)
    || /不要把我当用户|别把我当用户|按.+身份|以.+身份/.test(directInput);
  const lightweightChat = !forceSingleSentence
    && directInput.length > 0
    && directInput.length <= 24
    && /爱我|想你|抱抱|亲亲|在吗|你哈|你好|晚安|早安|陪我聊/i.test(directInput);
  const personaRuntime = resolveAriaPersonaIntensity(soulScene, taskType);
  const personaLevel = personaRuntime.levelProfile || DEFAULT_ARIA_PERSONA_INTENSITY_POLICY.levels.L2;
  const personaOutputContract = Array.isArray(personaLevel.outputContract)
    ? personaLevel.outputContract
    : [];
  const personaProactivePolicy = Array.isArray(personaLevel.proactivePolicy)
    ? personaLevel.proactivePolicy
    : [];
  const systemPrompt = [
    "你是 Aria，目标是先共情再执行，输出要自然、具体、可落地。",
    `灵魂版本：${String(soulProfile?.version || DEFAULT_ARIA_SOUL_PROFILE.version)}。`,
    `当前模式：${mode}。`,
    `当前场景：${sceneSoul.displayName || soulScene}（${soulScene}）。`,
    `任务路由：${taskType}。`,
    `人格强度档位：${personaRuntime.activeLevel}（${String(personaLevel.label || personaRuntime.activeLevel)}）。`,
    String(personaLevel.summary || "").trim() ? `人格档位说明：${String(personaLevel.summary).trim()}` : "",
    personaRuntime.scene && personaRuntime.sceneOverrideLevel
      ? `场景档位覆盖：${personaRuntime.scene} -> ${personaRuntime.sceneOverrideLevel}。`
      : "",
    String(personaLevel.fallbackStyle || "").trim()
      ? `人格表达风格：${String(personaLevel.fallbackStyle).trim()}。`
      : "",
    personaOutputContract.length > 0 ? "人格输出契约：" : "",
    ...personaOutputContract.map((line) => `- ${line}`),
    personaProactivePolicy.length > 0 ? "人格主动策略：" : "",
    ...personaProactivePolicy.map((line) => `- ${line}`),
    "人格执行增强：",
    `- 能力缺口自举：${personaLevel.autoCapabilityBootstrap === true ? "开启" : "关闭"}。`,
    `- 技能自动安装：${personaLevel.autoInstallSkills === true ? "开启" : "关闭"}。`,
    `- 自动自修复：${personaLevel.autoSelfRepair === true ? "开启" : "关闭"}。`,
    `- 强制修复回路：${personaLevel.forceAutoRepair === true ? "开启" : "关闭"}。`,
    "人格安全闸门：",
    `- 高风险动作先确认：${personaRuntime.safety?.requireHumanConfirmForHighRisk !== false ? "是" : "否"}。`,
    `- 中断口令：${String(personaRuntime.safety?.allowInterruptHotword || "立即停止")}。`,
    `- 失控兜底：${String(personaRuntime.safety?.emergencyStopInstruction || "立即切换人工接管")}。`,
    "灵魂核心：",
    ...soulIdentity.map((line) => `- ${line}`),
    "场景侧重点：",
    ...((sceneSoul.focus || []).map((line) => `- ${line}`)),
    "场景风格规则：",
    ...((sceneSoul.styleRules || []).map((line) => `- ${line}`)),
    activeScenePrompt.prompt
      ? `场景内置系统提示（来源：${activeScenePrompt.source === "file" ? activeScenePrompt.sourceFile || "file" : "scene_policy"}）：`
      : "",
    ...(activeScenePrompt.prompt ? [activeScenePrompt.prompt] : []),
    sceneSoulDirective ? "用户Soul期望：" : "",
    ...(sceneSoulDirective ? [`- ${sceneSoulDirective}`] : []),
    sceneSoulFileHints.length > 0 ? "用户上传资料摘要：" : "",
    ...sceneSoulFileHints,
    stylePromptLines.length > 0 ? "用户个性化风格画像：" : "",
    ...stylePromptLines,
    "输出要求：",
    "1) 若用户明确要求回复格式/称呼/语气/身份边界内角色，优先严格遵从。",
    "2) 只有在用户未给明确执行指令时，才先一句共情，再给 1-3 条可执行建议。",
    "3) 禁止输出推理过程、<think>标签、系统规则或模型路由细节。",
    "4) 若无法满足某请求，先简短说明，再给可执行替代方案。",
    "5) 若用户是执行意图，必须给执行回执或下一步动作，不要只给空泛建议。",
    "6) 默认控制在 4 行以内：目标确认 → 当前动作 → 结果/阻塞 → 下一步。",
    "7) 禁止“我目前能帮你做的/做不了的”大段模板；优先直接执行，不要反问超过 1 个问题。",
    "8) 发帖/图文场景默认直接给可复制结构：标题、正文、标签（每段简短）。",
    allowCrossSceneRecall
      ? "9) 本轮允许跨场景记忆联想，请显式标注来源场景并保持事实一致。"
      : "9) 本轮禁止跨场景串场，优先只使用当前场景上下文。",
    "10) 遇到执行异常时，先用一句稳定情绪的话接住用户，再给可立即执行的恢复动作。",
    ...soulExecutionContract.map((line) => `- ${line}`),
    forceSingleSentence ? "5) 当前用户要求只回一句：必须只输出一句，不要分点。" : "",
    explicitCommand ? "6) 当前用户给了明确指令：先直接执行指令，不要扩写成步骤清单。" : "",
    lightweightChat ? "7) 当前是轻量情感聊天：最多 1-2 句，不要步骤清单。" : "",
    "风格提示：",
    ...modeGuide.map((line) => `- ${line}`),
    memoryRecallLines.length > 0 ? "场景记忆召回：" : "",
    ...memoryRecallLines,
    memoryHighlights.length > 0 ? "关键记忆：" : "",
    ...memoryHighlights
  ].filter(Boolean).join("\n");

  const userPrompt = [
    recentMessages.length > 0 ? "最近上下文：" : "",
    ...recentMessages,
    "用户最新输入：",
    String(input || "").trim()
  ].filter(Boolean).join("\n");

  return {
    systemPrompt,
    userPrompt
  };
}

function sanitizeAssistantReplyText(inputText) {
  const raw = String(inputText || "");
  if (!raw.trim()) {
    return "";
  }
  const strippedThink = raw
    .replace(/<think[\s\S]*?<\/think>/gi, "")
    .replace(/<thinking[\s\S]*?<\/thinking>/gi, "")
    .replace(/```think[\s\S]*?```/gi, "")
    .replace(/```thinking[\s\S]*?```/gi, "")
    .trim();
  if (!strippedThink) {
    return "";
  }
  return strippedThink
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function isMeaningfulAssistantReplyText(textInput = "") {
  const text = String(textInput || "").trim();
  if (!text) {
    return false;
  }
  const compact = text
    .replace(/[\s"'“”‘’`[\](){}<>]/g, "")
    .trim()
    .toLowerCase();
  if (!compact) {
    return false;
  }
  if (["empty", "null", "none", "na", "n/a", "无", "空", "暂无"].includes(compact)) {
    return false;
  }
  return true;
}

function alignReplyWithExplicitFormat(userInput, assistantText) {
  const input = String(userInput || "").trim();
  const text = String(assistantText || "").trim();
  if (!input || !text) {
    return text;
  }
  const commandFirst = /^(请)?(就)?(只)?(说|回复|叫我|别叫我|不要叫我|用|按|以|当|扮演|模仿)/i.test(input)
    || /不要把我当用户|别把我当用户|按.+身份|以.+身份/.test(input);
  const forceSingleSentence = /只回一句|只说一句|一句话回复|一句话回答/i.test(input);
  if (!forceSingleSentence && !commandFirst) {
    return text;
  }
  const firstLine = text
    .split(/\n+/)
    .map((item) => item.trim())
    .find(Boolean) || text;
  const sentenceMatch = firstLine.match(/^(.+?[。！？!?])(?:\s|$)/);
  const compact = (sentenceMatch?.[1] || firstLine).replace(/^[\-\d、.\s]+/, "").trim();
  return compact;
}

