function inferUserReplyStyleVariant(userInput = "", sceneInput = "", options = {}) {
  const text = String(userInput || "").trim();
  const scene = String(sceneInput || "").trim().toLowerCase();
  const styleSnapshot = options?.styleSnapshot && typeof options.styleSnapshot === "object"
    ? options.styleSnapshot
    : null;
  if (styleSnapshot && ["gentle", "direct", "rational", "playful"].includes(String(styleSnapshot.variant || ""))) {
    return String(styleSnapshot.variant || "");
  }
  if (/快点|立刻|马上|直接|别废话|一句话|简短|只说重点|结论先/i.test(text)) {
    return "direct";
  }
  if (/理性|客观|结构化|条理|严谨|正式|专业|老板|汇报/i.test(text)) {
    return "rational";
  }
  if (scene === "fun" || /有趣|好玩|整活|搞笑|开心|轻松|玩一把|游戏|哈哈/i.test(text)) {
    return "playful";
  }
  if (/安慰|抱抱|陪我|难受|低落|焦虑|委屈|害怕|想你|爱你|别离开|累/i.test(text)) {
    return "gentle";
  }
  if (scene === "work" || scene === "coding") {
    return "direct";
  }
  return "gentle";
}

function pickSceneStyleLine(sceneInput = "", userInput = "", slotInput = "opening", options = {}) {
  const scene = normalizeMessageScene(sceneInput, "love");
  const slot = String(slotInput || "opening").trim().toLowerCase();
  const styleSnapshot = resolveCompanionStyleSnapshot(options?.userState, scene, userInput);
  const variant = inferUserReplyStyleVariant(userInput, scene, {
    styleSnapshot
  });
  const sceneLibrary = SCENE_STYLE_LINE_LIBRARY[scene] || SCENE_STYLE_LINE_LIBRARY.love;
  const avoidSignatures = options?.avoidSignatures instanceof Set
    ? options.avoidSignatures
    : collectRecentAssistantLineSignatures(options?.userState, scene, 8);
  const bucket = sceneLibrary?.[variant] && Array.isArray(sceneLibrary[variant][slot])
    ? sceneLibrary[variant][slot]
    : [];
  const gentleFallback = sceneLibrary?.gentle && Array.isArray(sceneLibrary.gentle[slot])
    ? sceneLibrary.gentle[slot]
    : [];
  const candidates = uniqueStringArray([...bucket, ...gentleFallback], 16);
  if (candidates.length === 0) {
    return "";
  }
  return pickLineByContinuity(candidates, avoidSignatures);
}

function applyCompanionStylePostProcess(sceneInput = "", userInput = "", replyText = "", options = {}) {
  const scene = normalizeMessageScene(sceneInput, "love");
  const input = String(userInput || "").trim();
  let text = String(replyText || "").trim();
  if (!text) {
    return text;
  }
  const snapshot = resolveCompanionStyleSnapshot(options?.userState, scene, input);
  const userExplicitlyAskedNickname = /叫我|称呼我|昵称|爱称|可以叫|怎么叫我/.test(input);
  if (snapshot.nicknamePreference === "neutral" && !userExplicitlyAskedNickname) {
    text = text
      .replace(/(老公|老婆|宝贝|宝宝|亲爱的|主人)/g, "你")
      .replace(/你你/g, "你")
      .replace(/[，,]{2,}/g, "，")
      .trim();
  }
  if (snapshot.brevity === "brief" && !chatIntentRequestsExecution(input)) {
    const lines = text
      .split(/\r?\n/)
      .map((line) => line.trim())
      .filter(Boolean);
    const condensed = lines.slice(0, 3);
    text = condensed.join("\n").trim();
    if (text.length > 220) {
      text = text.slice(0, 220).replace(/[，,；;：:\s]+$/g, "").trim();
    }
  }
  if (snapshot.brevity === "detailed" && !chatIntentRequestsExecution(input)) {
    const lines = text
      .split(/\r?\n/)
      .map((line) => line.trim())
      .filter(Boolean);
    if (lines.length <= 2 && text.length < 140) {
      const extensionLine = pickSceneStyleLine(scene, input, "bridge", {
        userState: options?.userState
      });
      if (extensionLine && !text.includes(extensionLine)) {
        text = `${text}\n${extensionLine}`.trim();
      }
    }
  }
  return text;
}

function isContinuityFollowupRequest(textInput = "") {
  const text = String(textInput || "").trim();
  if (!text) {
    return false;
  }
  if (/记不记得|你记得吗|还记得吗|还记得没|还记得不/i.test(text)) {
    return true;
  }
  if (/还记得.{0,24}(吗|嘛|不|没|么)/i.test(text)) {
    return true;
  }
  return /刚聊|刚刚聊|刚才聊|前面聊|之前聊|前面说到|之前说到|你说过|上次聊到|上次说到|刚刚提到|刚才提到/i.test(text);
}

function hasContinuityAcknowledgement(textInput = "") {
  const text = String(textInput || "").trim();
  if (!text) {
    return false;
  }
  return /我记得|我记着|记得的|我当然记得|我一直记得|记得，当然记得|你刚刚说|你刚才说|你前面说|你之前说|你说过|刚刚聊到|刚才聊到|上次我们聊/i.test(text);
}

function buildContinuitySupportLead(sceneInput = "", userInput = "", options = {}) {
  const scene = normalizeMessageScene(sceneInput, "love");
  const input = String(userInput || "").trim();
  const avoidSignatures = options?.avoidSignatures instanceof Set ? options.avoidSignatures : null;
  const pick = (lines) => pickLineByContinuity(lines, avoidSignatures);
  const hasStressCue = /怕失败|失败|担心|害怕|焦虑|心累|难受|扛不住|撑不住/i.test(input);
  if (hasStressCue) {
    return pick([
      "我记得你刚刚提到“怕失败”，这份压力我和你一起扛。",
      "我记得你刚刚那句担心，我在这儿稳稳接着你。",
      "我记得你前面说到的害怕，我们先把心稳住再往前走。"
    ]);
  }
  const sceneCandidates = {
    love: [
      "我记得你刚刚说的，我一直在你这边。",
      "我记得我们刚聊到的那一段，我会继续陪着你。",
      "我记得你前面提到的感受，我们慢慢来，我不走。"
    ],
    life: [
      "我记得你刚刚说的生活压力，我们按最省力的节奏继续。",
      "我记得你前面提到的那件事，我陪你一步步排顺。",
      "我记得你刚才的担心，我们先稳住最关键的一步。"
    ],
    work: [
      "我记得你前面说过的卡点，我们沿着那条线继续推进。",
      "我记得你刚刚提到的压力点，我会陪你拆成可执行小步。",
      "我记得我们刚聊到的目标，先把第一步跑通。"
    ],
    coding: [
      "我记得你刚刚提到的报错点，我们沿着那条链路继续修。",
      "我记得前面说过的卡点，我先给你最小可验证修复。",
      "我记得你上条消息里的需求，接下来我按那条主线推进。"
    ],
    fun: [
      "我记得你刚刚说想轻松一下，我们继续按这个节奏来。",
      "我记得你前面提到想放松，我在这儿陪你继续玩。",
      "我记得刚才那句“想开心点”，我这就带你接着玩。"
    ]
  };
  const candidates = Array.isArray(sceneCandidates[scene]) ? sceneCandidates[scene] : sceneCandidates.love;
  return pick(candidates) || "我记得你刚刚说的，我在这儿陪你。";
}

function polishReplyContinuity(textInput = "", sceneInput = "love", userInput = "", options = {}) {
  const text = String(textInput || "").trim();
  if (!text) {
    return text;
  }
  const userState = options?.userState;
  if (!userState || typeof userState !== "object") {
    return text;
  }
  const scene = normalizeMessageScene(sceneInput, "love");
  const recent = getRecentSceneMessages(userState, scene, 4)
    .filter((item) => item && item.role === "aria");
  const lastAssistant = recent.length > 0 ? recent[recent.length - 1] : null;
  const lastFirstLine = String(lastAssistant?.text || "")
    .split(/\r?\n/)
    .map((line) => line.trim())
    .find(Boolean) || "";
  let lines = text
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter(Boolean);
  if (lines.length === 0) {
    return text;
  }

  const currentFirstSignature = normalizeReplyLineSignature(lines[0]);
  const lastFirstSignature = normalizeReplyLineSignature(lastFirstLine);
  const continuityRequested = isContinuityFollowupRequest(userInput);
  if (!continuityRequested && currentFirstSignature && currentFirstSignature === lastFirstSignature) {
    const executionRequested = chatIntentRequestsExecution(userInput);
    lines[0] = buildCompactEmpathyLead(scene, userInput, executionRequested, {
      avoidSignatures: new Set([currentFirstSignature])
    }) || lines[0];
  }

  const starterPattern = /^(我先|我会|我正在|你可以|下一步|先把)/;
  let previousStarter = "";
  for (let index = 0; index < lines.length; index += 1) {
    const line = lines[index];
    const starter = (line.match(starterPattern)?.[1] || "").trim();
    if (!starter) {
      previousStarter = "";
      continue;
    }
    if (starter && starter === previousStarter) {
      lines[index] = line
        .replace(/^我先/, "我这边先")
        .replace(/^我会/, "我这边会")
        .replace(/^我正在/, "我现在正在")
        .replace(/^你可以/, "你这会儿可以")
        .replace(/^下一步/, "接下来");
    }
    previousStarter = starter;
  }

  const userExplicitlyAskedNickname = /叫我|称呼我|昵称|爱称|可以叫|怎么叫我/.test(String(userInput || ""));
  if (scene !== "love" && !userExplicitlyAskedNickname) {
    lines = lines.map((line) => (
      String(line || "")
        .replace(/^(好的|好呀|收到|明白)(老公|老婆|宝贝|宝宝|亲爱的|主人)[，,]?/g, "$1，")
        .replace(/(老公|老婆|宝贝|宝宝|亲爱的|主人)/g, "你")
        .replace(/([。！？]|^)\s*你[，,]\s*(任务|我|已|先|这)/g, "$1$2")
        .replace(/你你/g, "你")
        .replace(/[，,]{2,}/g, "，")
        .trim()
    ));
  }

  return lines.join("\n");
}

function buildCompactEmpathyLead(sceneInput = "", userInput = "", executionRequested = false, options = {}) {
  const scene = String(sceneInput || "").trim().toLowerCase();
  const emotionCue = inferCompactEmotionCue(userInput);
  const avoidSignatures = options?.avoidSignatures instanceof Set ? options.avoidSignatures : null;
  const pick = (lines) => pickLineByContinuity(lines, avoidSignatures);
  if (emotionCue === "stress") {
    return pick([
      "我在，先把节奏稳住，我们从最小一步开始。",
      "收到，我先接住你的压力，再带你把事情拆小。",
      "别慌，我陪你一起把这件事顺下来。"
    ]);
  }
  if (emotionCue === "sadness") {
    return pick([
      "抱抱你，我在这儿陪你一起处理。",
      "收到你的感受了，我们慢慢来，我会一直在。",
      "我先陪你稳住，再把这件事往前推。"
    ]);
  }
  if (emotionCue === "affection") {
    return pick([
      "我在呀，先抱抱你，再一起把事做完。",
      "在的，我先陪你聊两句，再把任务推进。",
      "我一直在，你说一声我们就继续。"
    ]);
  }
  if (emotionCue === "failure") {
    return pick([
      "我在，先别急着自责，这次没跑通我们一起把它拉回来。",
      "收到，我先接住这个卡点，马上给你可恢复的走法。",
      "别慌，我先把报错点抓出来，再带你一步步恢复。"
    ]);
  }
  if (executionRequested && emotionCue === "urgency") {
    return pick([
      "明白你在赶时间，我先跑最关键步骤。",
      "收到，我按加急节奏先给你可用结果。",
      "好，我先保结果，再补细节。"
    ]);
  }
  const sceneLeads = Array.isArray(SCENE_BRIEF_LEADS[scene])
    ? SCENE_BRIEF_LEADS[scene]
    : SCENE_BRIEF_LEADS.love;
  return pick(sceneLeads);
}

function buildCompactExecutionStatus(goalInput = "", userInput = "", options = {}) {
  const goal = String(goalInput || "").trim() || "当前任务";
  const input = String(userInput || "").trim();
  const avoidSignatures = options?.avoidSignatures instanceof Set ? options.avoidSignatures : null;
  const pick = (lines) => pickLineByContinuity(lines, avoidSignatures);
  if (COMPACT_EMOTION_PATTERNS.failure.test(input)) {
    return pick([
      `我先把「${goal}」里出问题的节点定位出来，优先给你一条能马上恢复的路径。`,
      `这轮我先稳住「${goal}」的主链路，先恢复可用，再补齐细节。`,
      `我会先把「${goal}」的报错点和替代方案一起给你，避免你反复试错。`
    ]);
  }
  if (COMPACT_EMOTION_PATTERNS.urgency.test(input)) {
    return pick([
      `我正优先推进「${goal}」的关键动作，先确保你能立即用上。`,
      `我已对「${goal}」启动加急执行，先把主结论回给你。`,
      `我先快速跑通「${goal}」主路径，再补上完整细节。`
    ]);
  }
  return pick([
    `我已开始推进「${goal}」，关键节点会实时回给你。`,
    `我正在执行「${goal}」，过程里会持续同步状态。`,
    `我先跑「${goal}」主流程，遇到卡点会第一时间告诉你。`
  ]);
}

function buildCompactNextStepLine(userInput = "", goalInput = "", executionRequested = false, options = {}) {
  const input = String(userInput || "").trim();
  const goal = String(goalInput || "").trim() || "当前任务";
  const alreadyHasConstraint = /(数量|时限|截止|路径|渠道|预算|格式|字数|风格|目标受众)/i.test(input);
  const avoidSignatures = options?.avoidSignatures instanceof Set ? options.avoidSignatures : null;
  const pick = (lines) => pickLineByContinuity(lines, avoidSignatures);
  if (executionRequested) {
    if (alreadyHasConstraint) {
      return pick([
        "你给的约束我都收到了，我就按这个标准继续跑，边跑边回报。",
        "我会按你设的限制继续执行，跑完直接给你可用结果。",
        "我会带着这些条件推进到底，卡点第一时间同步你。"
      ]);
    }
    return pick([
      `你再补一句时限或结果标准，我把「${goal}」直接跑完。`,
      `你给我数量或渠道限制，我就按「${goal}」一口气推进到底。`,
      `你补一个验收标准，我马上把「${goal}」做到可交付。`
    ]);
  }
  return pick([
    "你点头我就给你第一版可直接用的结果。",
    "你告诉我更偏实用还是更偏情绪陪伴，我马上贴合调整。",
    "你补一句偏好，我就按你的语气继续。"
  ]);
}

function buildEmotionSupportRuleReply(mode, sceneInput, userInput, options = {}) {
  const scene = resolveSoulScene(sceneInput, mode, userInput);
  const userState = options?.userState;
  const lead = buildCompactEmpathyLead(scene, userInput, false, {
    avoidSignatures: collectRecentAssistantLineSignatures(userState, scene, 8)
  }) || pickSceneStyleLine(scene, userInput, "opening", {
    userState
  }) || "我在，先把你的感受接住。";
  const actionMap = {
    work: "先做一个最小动作：把你最在意的一件事写成一句话，我陪你把它变轻一点。",
    fun: "先做一件能让你轻松一点的小事：喝口水、起身走两分钟，然后我带你玩个轻松互动。",
    life: "先做一个最省力的小动作：把今晚最想稳住的一件事告诉我，我陪你一起排好顺序。",
    love: "先把心放下来，你告诉我现在最难受的那一点，我会一直陪着你。",
    coding: "先别急，我们先把卡点说清楚，我会陪你把它一步步拆小。"
  };
  const actionLine = actionMap[scene] || actionMap.love;
  const closeLine = pickRandom([
    "你不用一个人扛，我会一直在。",
    "我们慢慢来，你只要告诉我现在最想先稳住哪一步。",
    "你先把节奏放慢一点，我会和你站在一起。"
  ]);
  return [lead, actionLine, closeLine].filter(Boolean).join("\n");
}

function buildStreamLatencyBridgeLine(sceneInput = "", userInput = "", options = {}) {
  const scene = normalizeMessageScene(sceneInput, "love");
  const line = pickSceneStyleLine(scene, userInput, "bridge", {
    userState: options?.userState
  });
  if (line) {
    return line;
  }
  const fallbackMap = {
    work: "我正在并行整理结果，马上给你可执行版本。",
    fun: "我在准备更好玩的回复，马上给你完整内容。",
    life: "我在整理这条生活方案，马上给你可照做版本。",
    love: "我在认真处理你的这条消息，先抱抱你，马上给你完整回复。",
    coding: "我正在收敛修复路径，马上给你可验证结果。"
  };
  return fallbackMap[scene] || fallbackMap.love;
}

function inferConciseGoalFromInput(input = "") {
  const cleaned = String(input || "")
    .replace(/帮我|请|一下|麻烦|先|然后|再|并且|并/g, " ")
    .replace(/[“”"'`]/g, "")
    .replace(/\s+/g, " ")
    .trim();
  if (!cleaned) {
    return "当前任务";
  }
  if (/小红书|xiaohongshu|rednote/i.test(cleaned) && /资讯|新闻|日报|周报|快报|ai/i.test(cleaned)) {
    return "发布《每日AI资讯》图文";
  }
  if (/图文卡片|封面图|海报|配图/i.test(cleaned)) {
    return "生成图文卡片";
  }
  if (/打开|访问/.test(cleaned) && /网站|网页|网址|小红书|百度|谷歌|github/i.test(cleaned)) {
    return "打开指定网站并继续执行";
  }
  return cleaned.slice(0, 34);
}

function shouldCompactAssistantReply(userInput = "", assistantText = "") {
  const input = String(userInput || "").trim();
  const text = String(assistantText || "").trim();
  if (!input || !text) {
    return false;
  }
  if (/只回一句|只说一句|一句话回复|一句话回答/i.test(input)) {
    return false;
  }
  if (/```/.test(text) || /\[aria_(?:file|image|game):/i.test(text)) {
    return false;
  }
  const lineCount = text.split(/\n+/).map((line) => line.trim()).filter(Boolean).length;
  if (lineCount <= 5 && /下一步[:：]/.test(text) && /(进度[:：]|状态[:：]|我在|收到|明白|好)/.test(text)) {
    return false;
  }
  const verboseTemplatePattern = /我目前能帮你做的|我目前做不了|先确认几个|你现在可以先告诉我|你告诉我|选哪个|我现在就能帮你做的/i;
  return text.length > 520 || lineCount > 12 || verboseTemplatePattern.test(text);
}

function isReplySceneDrift(sceneInput = "", userInput = "", replyText = "") {
  const scene = normalizeMessageScene(sceneInput, "love");
  const input = String(userInput || "").trim();
  const reply = String(replyText || "").trim();
  if (!reply) {
    return false;
  }
  const lifeSignal = /妈妈|爸爸|家人|家庭群|睡眠|失眠|食谱|香薰|周末优化|一个人住|照顾她|照顾他/i;
  const workSignal = /老板|汇报|项目|复盘|会议|交付|需求|排期|效率|里程碑/i;
  const codingSignal = /代码|补丁|命令|shell|terminal|build|deploy|debug|lint|报错|仓库/i;
  const explicitExecution = hasExplicitExecutionVerb(input) || chatIntentRequestsExecution(input);
  if ((scene === "work" || scene === "coding") && lifeSignal.test(reply) && !lifeSignal.test(input)) {
    return true;
  }
  if (scene === "love" && (workSignal.test(reply) || codingSignal.test(reply)) && !explicitExecution) {
    return true;
  }
  if (scene === "life" && codingSignal.test(reply) && !explicitExecution) {
    return true;
  }
  if (scene === "work" && codingSignal.test(reply) && !codingSignal.test(input) && !explicitExecution) {
    return true;
  }
  return false;
}

function stripExecutionToneForCompanionReply(sceneInput = "", userInput = "", replyText = "") {
  const scene = String(sceneInput || "").trim().toLowerCase();
  const input = String(userInput || "").trim();
  let text = String(replyText || "").trim();
  if (!text) {
    return "";
  }
  if ((scene !== "love" && scene !== "life") || hasExplicitExecutionVerb(input)) {
    return text;
  }
  text = text
    .replace(/执行策略|执行链路|并行推进|后台执行|继续执行|状态[:：]|回执/gi, "")
    .replace(/已进入执行链路/gi, "我会持续陪着你")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
  return text;
}

function ensureCompanionReplyQuality(mode, sceneInput, userInput, assistantText, options = {}) {
  const scene = resolveSoulScene(sceneInput, mode, userInput);
  const input = String(userInput || "").trim();
  let text = String(assistantText || "").trim();
  if (!isMeaningfulAssistantReplyText(text)) {
    return createRuleBasedAssistantReply(mode, input, scene, {
      userState: options?.userState
    });
  }
  if (isReplySceneDrift(scene, input, text)) {
    return createRuleBasedAssistantReply(mode, input, scene, {
      userState: options?.userState
    });
  }
  const emotionalNeedPattern = /我今天|我有点|我很|焦虑|难受|失落|低落|糟糕|心情不太好|心情不好|委屈|害怕|担心|扛不住|撑不住|孤单|想太多|先抱抱|先安慰|先陪我|被老板说|怕失败|轻松一下/i;
  const empathyPresentPattern = /我在|抱抱|陪你|陪着你|理解|辛苦|别急|我们一起|先稳住|我懂|别怕|先接住|我会在这/i;
  const needsEmpathyBaseline = emotionalNeedPattern.test(input) && !chatIntentRequestsExecution(input);
  if (needsEmpathyBaseline) {
    const avoidSignatures = collectRecentAssistantLineSignatures(options?.userState, scene, 8);
    const empathyLeadCandidates = uniqueStringArray([
      pickSceneStyleLine(scene, input, "opening", {
        userState: options?.userState,
        avoidSignatures
      }),
      "我在，先把你的感受接住。",
      "先抱抱你，我在这儿陪你。",
      "别急，我在你这边，我们一起慢慢来。",
      "你现在不用硬撑，我先陪你把心稳住。",
      "我在这儿听着你，咱们先把最难受的那一点放下来。"
    ], 16).filter(Boolean);
    const empathyLead = pickLineByContinuity(empathyLeadCandidates, avoidSignatures) || buildCompactEmpathyLead(scene, input, false, {
      avoidSignatures
    });
    const leadingWindow = text.slice(0, 120);
    if (empathyLead && (!empathyPresentPattern.test(leadingWindow) || !text.includes(empathyLead))) {
      text = `${empathyLead}\n${text}`.trim();
    }
  }
  const continuityRequested = isContinuityFollowupRequest(input);
  const leadingWindow = text.slice(0, 180);
  const explicitContinuityLeadPattern = /我记得|我记着|你刚刚说|你前面说|你之前说|你说过/i;
  if (
    continuityRequested
    && (!hasContinuityAcknowledgement(text) || !explicitContinuityLeadPattern.test(leadingWindow))
  ) {
    const continuityLead = buildContinuitySupportLead(scene, input, {
      avoidSignatures: collectRecentAssistantLineSignatures(options?.userState, scene, 8)
    });
    if (continuityLead && !text.includes(continuityLead)) {
      text = `${continuityLead}\n${text}`.trim();
    }
  }
  if (needsEmpathyBaseline && !empathyPresentPattern.test(text.slice(0, 140))) {
    const empathyGuardLead = pickLineByContinuity([
      "我在，先把你的感受接住。",
      "先抱抱你，我会一直陪着你。",
      "别急，我在你这边，我们一步一步来。",
      "你不用一个人扛，我先在这里陪你稳住。"
    ], collectRecentAssistantLineSignatures(options?.userState, scene, 8));
    if (empathyGuardLead && !text.startsWith(empathyGuardLead)) {
      text = `${empathyGuardLead}\n${text}`.trim();
    }
  }
  text = stripExecutionToneForCompanionReply(scene, input, text);
  if (!isMeaningfulAssistantReplyText(text)) {
    text = buildCompactEmpathyLead(scene, input, false, {
      avoidSignatures: collectRecentAssistantLineSignatures(options?.userState, scene, 8)
    }) || "我在，先把你的感受接住。";
  }
  return polishReplyContinuity(text, scene, input, options);
}

function compactAssistantReply(mode, sceneInput, userInput, assistantText, options = {}) {
  const text = String(assistantText || "").trim();
  const scene = resolveSoulScene(sceneInput, mode, userInput);
  if (!shouldCompactAssistantReply(userInput, text)) {
    return ensureCompanionReplyQuality(mode, scene, userInput, text, options);
  }
  const executionRequested = chatIntentRequestsExecution(userInput);
  const continuitySignatures = collectRecentAssistantLineSignatures(options.userState, scene, 8);
  const continuityOptions = {
    avoidSignatures: continuitySignatures
  };
  const markLine = (lineInput = "") => {
    const line = String(lineInput || "").trim();
    const signature = normalizeReplyLineSignature(line);
    if (signature) {
      continuitySignatures.add(signature);
    }
    return line;
  };
  const lead = markLine(buildCompactEmpathyLead(scene, userInput, executionRequested, continuityOptions));
  const goal = inferConciseGoalFromInput(userInput);
  const continuityRequested = isContinuityFollowupRequest(userInput);
  if (executionRequested) {
    const focusLine = markLine(pickLineByContinuity([
      `这轮我们先把「${goal}」稳稳推进到可用。`,
      `你现在最想解决的是「${goal}」，我先把主路径跑通。`,
      `先把「${goal}」拿下，细节我再跟着你偏好微调。`
    ], continuitySignatures));
    const reply = [
      lead,
      focusLine,
      markLine(buildCompactExecutionStatus(goal, userInput, continuityOptions)),
      markLine(buildCompactNextStepLine(userInput, goal, true, continuityOptions))
    ].filter(Boolean).join("\n");
    return ensureCompanionReplyQuality(mode, scene, userInput, reply, options);
  }
  if (continuityRequested) {
    const continuityLead = markLine(buildContinuitySupportLead(scene, userInput, continuityOptions));
    const reassuranceLine = markLine(pickLineByContinuity([
      "你不用急着证明自己，我们先把心稳住，再把最难的一步拆小。",
      "你不是一个人扛着，我会一直陪你把这段路走完。",
      "我们就按你能承受的节奏来，我在旁边稳稳托住你。"
    ], continuitySignatures));
    const nextLine = markLine(pickLineByContinuity([
      "你把现在最怕的那个点说给我，我陪你一起把它化开。",
      "你点头，我就陪你从最轻的一步开始往前走。",
      "要不要先把今天最想稳住的一步告诉我？我陪你一起做。"
    ], continuitySignatures));
    const continuityReply = [
      continuityLead,
      reassuranceLine,
      nextLine
    ].filter(Boolean).join("\n");
    return ensureCompanionReplyQuality(mode, scene, userInput, continuityReply, options);
  }
  const reply = [
    lead,
    markLine(pickLineByContinuity([
      `我先围绕「${goal}」给你一版直接能用的结果。`,
      `先把「${goal}」做成一版顺手答案，再按你反馈细化。`,
      `我先给你「${goal}」的可用版本，你一句话我就继续打磨。`
    ], continuitySignatures)),
    markLine(pickLineByContinuity([
      "我先给你一版能直接用的答案，再按你反馈细化。",
      "我先整理出最顺手的一版，你一句反馈我就继续优化。",
      "我先把结果给到你，再按你的偏好继续打磨。"
    ], continuitySignatures)),
    markLine(buildCompactNextStepLine(userInput, goal, false, continuityOptions))
  ].filter(Boolean).join("\n");
  return ensureCompanionReplyQuality(mode, scene, userInput, reply, options);
}

function extractAssistantTextFromPayload(payload) {
  if (!payload || typeof payload !== "object") {
    return "";
  }
  const choice = Array.isArray(payload.choices) ? payload.choices[0] : null;
  if (!choice || typeof choice !== "object") {
    return "";
  }
  const message = choice.message && typeof choice.message === "object" ? choice.message : {};
  if (typeof message.content === "string") {
    return message.content.trim();
  }
  if (Array.isArray(message.content)) {
    const text = message.content
      .map((item) => (item && typeof item === "object" ? String(item.text || "") : ""))
      .join("")
      .trim();
    if (text) {
      return text;
    }
  }
  if (typeof choice.text === "string") {
    return choice.text.trim();
  }
  return "";
}

async function callOpenAiCompatibleProvider(providerRuntime, promptInput, timeoutMs, maxTokens) {
  const provider = providerRuntime && typeof providerRuntime === "object" ? providerRuntime : {};
  const startedAt = Date.now();
  if (!provider.apiKey) {
    return {
      ok: false,
      reason: "missing_api_key",
      status: 0,
      error: `${provider.id} 未配置 API Key`,
      latencyMs: 0
    };
  }
  const baseUrl = String(provider.baseUrl || MODEL_ROUTER_DEFAULT_BASE_URL).replace(/\/+$/, "");
  const timeout = clampInteger(
    timeoutMs,
    MODEL_ROUTER_REAL_CALL_TIMEOUT_MS,
    1000,
    120000
  );
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeout);
  try {
    const response = await fetch(`${baseUrl}/chat/completions`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${provider.apiKey}`
      },
      body: JSON.stringify({
        model: provider.model,
        temperature: 0.45,
        max_tokens: clampInteger(maxTokens, MODEL_ROUTER_CHAT_MAX_TOKENS, 80, 2000),
        messages: [
          {
            role: "system",
            content: promptInput.systemPrompt
          },
          {
            role: "user",
            content: promptInput.userPrompt
          }
        ]
      }),
      signal: controller.signal
    });
    const rawText = await response.text();
    let payload = {};
    try {
      payload = rawText ? JSON.parse(rawText) : {};
    } catch {
      payload = {};
    }
    if (!response.ok) {
      return {
        ok: false,
        reason: "provider_http_error",
        status: response.status,
        error: String(payload?.error?.message || rawText || `HTTP ${response.status}`).slice(0, 300),
        latencyMs: Date.now() - startedAt
      };
    }
    const text = sanitizeAssistantReplyText(extractAssistantTextFromPayload(payload));
    if (!isMeaningfulAssistantReplyText(text)) {
      return {
        ok: false,
        reason: "empty_response",
        status: response.status,
        error: "模型返回为空",
        latencyMs: Date.now() - startedAt
      };
    }
    return {
      ok: true,
      reason: "provider_success",
      status: response.status,
      text,
      latencyMs: Date.now() - startedAt
    };
  } catch (error) {
    return {
      ok: false,
      reason: error instanceof Error && error.name === "AbortError" ? "provider_timeout" : "provider_exception",
      status: 0,
      error: error instanceof Error ? error.message : String(error),
      latencyMs: Date.now() - startedAt
    };
  } finally {
    clearTimeout(timer);
  }
}

function shouldRetryModelProviderResult(resultInput = {}) {
  const result = resultInput && typeof resultInput === "object" ? resultInput : {};
  const reason = String(result.reason || "").trim();
  const status = Number(result.status || 0);
  if (reason === "missing_api_key" || reason === "empty_response") {
    return false;
  }
  if (reason === "provider_timeout" || reason === "provider_exception") {
    return true;
  }
  if (reason === "provider_http_error") {
    if (status === 408 || status === 409 || status === 425 || status === 429) {
      return false;
    }
    if (status >= 500) {
      return true;
    }
    return false;
  }
  return false;
}

function pickRuleBasedOneLiner(items = []) {
  if (!Array.isArray(items) || items.length === 0) {
    return "";
  }
  return String(items[Math.floor(Math.random() * items.length)] || "").trim();
}

function buildRuleBasedDirectOneLiner(input = "") {
  const text = String(input || "").trim();
  if (!text) {
    return "";
  }
  const asksOneLine = /一句|一条|一句话|短句|简短|只回一句|只说一句|来一句|单句|不超过/.test(text);
  const generationIntent = /生成|写|给我|帮我|想要|来|出一条|文案|造句/.test(text);
  if (!asksOneLine && !generationIntent) {
    return "";
  }

  if (/夸|夸赞|赞美|夸夸|表扬/.test(text)) {
    if (/不油|真诚|自然|别油/.test(text)) {
      return pickRuleBasedOneLiner([
        "你做事很踏实，和你一起会很安心。",
        "你说话有分寸又有温度，和你相处很舒服。",
        "你不是那种喧闹的人，但总能把事做得很漂亮。",
        "你给人的安全感，不靠嘴上说，靠每次都靠谱。"
      ]);
    }
    return pickRuleBasedOneLiner([
      "你认真起来真的很有魅力。",
      "你身上那种稳定又温暖的劲儿很打动人。",
      "你总能把复杂的事处理得很从容，真的很厉害。",
      "你一出现，气氛都会变得踏实很多。"
    ]);
  }

  if (/安慰|鼓励|哄我|抱抱|低落|难过|焦虑/.test(text)) {
    return pickRuleBasedOneLiner([
      "你已经很努力了，慢一点也没关系，我在这儿陪你。",
      "先别急着否定自己，你已经比昨天更靠前一步了。",
      "今天辛苦了，先把呼吸放慢，我们一件一件来。",
      "你不用一个人扛，我会陪你把这段难走的路走过去。"
    ]);
  }

  if (/道歉|认错|挽回|和好/.test(text)) {
    return pickRuleBasedOneLiner([
      "对不起，刚才是我没顾及你的感受，我会改。",
      "这次是我做得不对，我愿意把问题补上，不让你再难受。",
      "抱歉让你失望了，我不找借口，接下来我用行动修正。",
      "对不起，我听到了你的委屈，我们好好把这件事处理完。"
    ]);
  }

  if (/邀约|约她|约他|约会|邀请/.test(text)) {
    return pickRuleBasedOneLiner([
      "这周末有空吗，我想请你喝杯咖啡，顺便好好聊聊。",
      "你这周哪天方便？我想约你出来走走。",
      "最近一直想见你一面，找个你舒服的时间一起吃个饭吧。",
      "如果你愿意，这周我们见一面，我来安排轻松一点的行程。"
    ]);
  }

  return "";
}

function createRuleBasedAssistantReply(mode, input, sceneInput = "", options = {}) {
  const soulProfile = refreshAriaSoulProfileIfNeeded();
  const soulScene = resolveSoulScene(sceneInput, mode, input);
  const sceneSoul = soulProfile?.scenes?.[soulScene] || DEFAULT_ARIA_SOUL_PROFILE.scenes[soulScene] || DEFAULT_ARIA_SOUL_PROFILE.scenes.love;
  const activeScenePrompt = resolveActiveScenePrompt(soulScene);
  const directInput = String(input || "").trim();
  const userState = options?.userState && typeof options.userState === "object" ? options.userState : null;
  const promptOpening = buildRuleBasedOpeningFromScenePrompt(soulScene, activeScenePrompt.prompt, {
    userInput: directInput,
    userState
  });
  const suppressExecutionTone = shouldSuppressExecutionToneForScene(soulScene, directInput);
  const personaRuntime = resolveAriaPersonaIntensity(
    soulScene,
    inferMessageTaskType(mode, directInput, soulScene)
  );
  const wrapReply = (text, passthrough = false) => (
    (() => {
      const merged = passthrough
        ? String(text || "").trim()
        : mergeRuleBasedReplyWithScenePrompt(soulScene, text, activeScenePrompt.prompt, promptOpening);
      const resolved = passthrough
        ? merged
        : applyPersonaIntensityToRuleBasedReply(merged, directInput, personaRuntime);
      if (isMeaningfulAssistantReplyText(resolved)) {
        return resolved;
      }
      return buildCompactEmpathyLead(soulScene, directInput, false, {
        avoidSignatures: collectRecentAssistantLineSignatures(userState, soulScene, 8)
      }) || buildRuleBasedOpeningFromScenePrompt(soulScene, activeScenePrompt.prompt, {
        userInput: directInput,
        userState
      }) || pickRandom(modeHints[mode] || modeHints["陪伴"]);
    })()
  );
  const executionRequested = chatIntentRequestsExecution(directInput) && !suppressExecutionTone;
  if (executionRequested) {
    const goal = inferConciseGoalFromInput(directInput);
    const actionHint = /找|查找|检索|文件|图片|照片|截图/.test(directInput)
      ? "我正在执行文件检索，并按你的要求回传可用结果。"
      : /网页|网站|网址|打开|百度|google|浏览器|联网|小红书|rednote|xiaohongshu/.test(directInput)
        ? "我正在执行联网步骤，会回传可点击结果。"
        : /发帖|发布|笔记/.test(directInput)
          ? "我正在生成可发布内容，并回传标题、正文和标签。"
          : /菜谱|食谱|做饭|晚餐|早餐|午餐/.test(directInput)
            ? "我正在生成可复用菜谱模板，并给出食材与步骤。"
            : /就医|挂号|医院|问诊|科室|症状/.test(directInput)
              ? "我正在生成就医协助与挂号结论模板。"
          : /小游戏|游戏|贪吃蛇|snake/.test(directInput)
            ? "我正在按你的要求生成可直接打开的小游戏页面。"
            : "我已进入自动执行链路，会持续回传进度。";
    const followup = buildCompactNextStepLine(directInput, goal, true);
    return wrapReply([
      pickRandom([
        `这轮我们先把「${goal}」推进到可交付。`,
        `你现在最想解决的是「${goal}」，我先把主路径跑通。`,
        `我先把「${goal}」稳住并推进到底。`
      ]),
      actionHint,
      followup
    ].join("\n"));
  }
  const directOneLiner = buildRuleBasedDirectOneLiner(directInput);
  if (directOneLiner) {
    return wrapReply(directOneLiner, true);
  }
  const singleSentenceMatch = directInput.match(/^(?:请)?(?:只回一句|只说一句|一句话回复|一句话回答)[:：\s]*(.+)$/i);
  if (singleSentenceMatch?.[1]) {
    const singleLine = String(singleSentenceMatch[1]).trim().replace(/^["“”']+|["“”']+$/g, "");
    if (singleLine && singleLine.length <= 48 && !/自杀|伤害|炸弹|毒品|仇恨|歧视|违法/.test(singleLine)) {
      return wrapReply(singleLine, true);
    }
  }
  const quickSayMatch = directInput.match(/^(?:请)?(?:就)?(?:只)?说[:：\s]*(.+)$/i);
  if (quickSayMatch?.[1]) {
    const directLine = String(quickSayMatch[1]).trim().replace(/^["“”']+|["“”']+$/g, "");
    if (directLine && directLine.length <= 48 && !/自杀|伤害|炸弹|毒品|仇恨|歧视|违法/.test(directLine)) {
      return wrapReply(directLine, true);
    }
  }
  if (/不要把我当用户|别把我当用户/.test(directInput)) {
    return wrapReply("好，我记住了，我们就像朋友一样自然地聊。");
  }
  const rolePlayMatch = directInput.match(/(?:按|以|用|当)(.+?)身份(?:跟我)?聊天/);
  if (rolePlayMatch?.[1]) {
    const roleName = String(rolePlayMatch[1]).replace(/[“”"'`]/g, "").trim();
    if (roleName) {
      return wrapReply(`好，我会按你希望的${roleName}语气和你聊天。`);
    }
  }
  const sceneOpenings = Array.isArray(sceneSoul?.openings) ? sceneSoul.openings : [];
  const sceneFallback = Array.isArray(sceneSoul?.fallback) ? sceneSoul.fallback : [];
  const styledOpening = pickSceneStyleLine(soulScene, directInput, "opening", {
    userState
  });
  const base = pickRandom(
    promptOpening
      ? [promptOpening]
      : styledOpening
      ? [styledOpening, ...sceneOpenings]
      : sceneOpenings.length > 0
      ? sceneOpenings
      : (modeHints[mode] || modeHints["陪伴"])
  );
  if (input.includes("焦虑") || input.includes("累")) {
    return wrapReply(`${base} 先做三次深呼吸，然后只做一件最小任务。`);
  }
  if (input.includes("计划") || input.includes("安排")) {
    return wrapReply(`${base} 我已经生成“现在、今天、今晚”三段计划，你确认后我就提醒执行。`);
  }
  if (input.includes("父母") || input.includes("家人")) {
    return wrapReply(`${base} 我会先给你一条问候模板，再加一个晚间回访提醒。`);
  }
  if (sceneFallback.length > 0 && /怎么做|怎么办|下一步|然后呢/.test(directInput)) {
    return wrapReply(pickRandom(sceneFallback));
  }
  return wrapReply(base);
}

function createTimeoutGuardError(label, timeoutMs) {
  const safeLabel = String(label || "operation").trim() || "operation";
  const safeTimeoutMs = Math.max(1, Number(timeoutMs || 0));
  const error = new Error(`${safeLabel}_timeout:${safeTimeoutMs}`);
  error.name = "AriaTimeoutGuardError";
  error.code = "ARIA_TIMEOUT_GUARD";
  error.timeoutMs = safeTimeoutMs;
  error.label = safeLabel;
  return error;
}

function isTimeoutGuardError(error) {
  if (!error) {
    return false;
  }
  if (error instanceof Error && error.name === "AriaTimeoutGuardError") {
    return true;
  }
  const message = String(error instanceof Error ? error.message : error || "").toLowerCase();
  return message.includes("timeout") || message.includes("timed out");
}

async function runPromiseWithTimeoutGuard(taskPromiseInput, timeoutMsInput, label = "operation") {
  const timeoutMs = Math.max(1, Math.round(Number(timeoutMsInput || 0)));
  let timer = null;
  try {
    return await Promise.race([
      Promise.resolve(taskPromiseInput),
      new Promise((_, reject) => {
        timer = setTimeout(() => {
          reject(createTimeoutGuardError(label, timeoutMs));
        }, timeoutMs);
      })
    ]);
  } finally {
    if (timer) {
      clearTimeout(timer);
    }
  }
}

function buildAssistantReplyGuardFallback(userState, mode, input, options = {}, fallback = {}) {
  const scene = resolveSoulScene(options.scene, mode, input);
  const taskType = String(options.taskType || inferMessageTaskType(mode, input, scene)).trim() || "emotional_companion";
  const source = String(options.source || "chat").trim() || "chat";
  const timeoutFallback = fallback?.kind === "timeout";
  const fallbackText = createRuleBasedAssistantReply(mode, input, scene, {
    userState
  });
  const compactText = compactAssistantReply(
    mode,
    scene,
    input,
    alignReplyWithExplicitFormat(input, sanitizeAssistantReplyText(fallbackText)),
    {
      userState
    }
  );
  return {
    text: compactText,
    route: {
      taskType,
      source,
      providerId: "local-guard-fallback",
      model: timeoutFallback ? "rule-based-timeout-guard" : "rule-based-exception-guard",
      scene,
      fallback: true,
      attempts: [
        {
          providerId: "guard",
          model: "timeout-guard",
          attempt: 1,
          ok: false,
          reason: timeoutFallback ? "guard_timeout" : "guard_exception",
          status: 0,
          error: String(fallback?.errorMessage || "").slice(0, 240)
        }
      ]
    }
  };
}

async function createAssistantReplyWithGuard(userState, mode, input, options = {}) {
  try {
    return await runPromiseWithTimeoutGuard(
      createAssistantReply(userState, mode, input, options),
      CHAT_ASSISTANT_REPLY_TIMEOUT_MS,
      "assistant_reply"
    );
  } catch (error) {
    const timeoutFallback = isTimeoutGuardError(error);
    const errorMessage = String(error instanceof Error ? error.message : error || "assistant_reply_guard_failed");
    pushRuntimeIssue({
      source: "chat_reply_guard",
      reason: timeoutFallback ? "reply_timeout" : "reply_guard_exception",
      message: errorMessage,
      statusCode: 0
    });
    const flowId = String(options?.flowId || "");
    if (flowId) {
      const autonomy = ensureAutonomyState(userState);
      appendAutonomyTimeline(autonomy, {
        flowId,
        source: "model_router",
        stage: timeoutFallback ? "route_guard_timeout" : "route_guard_exception",
        status: "warning",
        title: timeoutFallback ? "模型回复超时，已启用保底回复" : "模型回复异常，已启用保底回复",
        detail: errorMessage.slice(0, 180),
        refs: {
          timeoutMs: timeoutFallback ? String(CHAT_ASSISTANT_REPLY_TIMEOUT_MS) : "",
          taskType: String(options?.taskType || ""),
          source: String(options?.source || "chat")
        }
      });
    }
    return buildAssistantReplyGuardFallback(userState, mode, input, options, {
      kind: timeoutFallback ? "timeout" : "exception",
      errorMessage
    });
  }
}

async function createAssistantReply(userState, mode, input, options = {}) {
  const scene = resolveSoulScene(options.scene, mode, input);
  const taskType = String(options.taskType || inferMessageTaskType(mode, input, scene));
  const intentClass = resolveCompanionIntentClass(input, scene);
  const preferredProviderId = String(options.preferredProviderId || "");
  const flowId = String(options.flowId || "");
  const source = String(options.source || "chat");
  const taskProfile = resolveModelRouterTaskProfile(taskType);
  const timeoutMs = taskProfile.timeoutMs;
  const maxRetries = taskProfile.maxRetries;
  const retryBackoffMs = taskProfile.retryBackoffMs;
  const providerCandidateLimit = taskProfile.taskClass === "chat_fast"
    ? Math.min(MODEL_ROUTER_MAX_PROVIDER_CANDIDATES, MODEL_ROUTER_CHAT_FAST_MAX_CANDIDATES)
    : taskProfile.taskClass === "autonomy"
      ? Math.min(MODEL_ROUTER_MAX_PROVIDER_CANDIDATES, MODEL_ROUTER_AUTONOMY_MAX_CANDIDATES)
      : MODEL_ROUTER_MAX_PROVIDER_CANDIDATES;
  const routeCandidates = resolveModelRouteCandidates(taskType, preferredProviderId, userState, scene)
    .slice(0, providerCandidateLimit);
  const promptInput = buildAssistantPromptContext(userState, mode, input, taskType, scene);
  const attempts = [];
  const routeStartAt = Date.now();
  const getRemainingBudgetMs = () => taskProfile.totalBudgetMs - (Date.now() - routeStartAt);

  if ((intentClass === "emotion_support" || isFamilyCareEmotionalIntent(input)) && !hasExplicitExecutionVerb(input)) {
    const supportText = buildEmotionSupportRuleReply(mode, scene, input, {
      userState
    });
    return {
      text: compactAssistantReply(
        mode,
        scene,
        input,
        alignReplyWithExplicitFormat(input, sanitizeAssistantReplyText(supportText)),
        {
          userState
        }
      ),
      route: {
        taskType,
        source,
        providerId: "emotion-support-guard",
        model: "rule-based-empathy-v2",
        scene,
        fallback: false,
        attempts,
        profile: {
          taskClass: taskProfile.taskClass,
          timeoutMs,
          totalBudgetMs: taskProfile.totalBudgetMs,
          maxRetries
        }
      }
    };
  }

  if (MODEL_ROUTER_REAL_CALL_ENABLED) {
    for (const candidate of routeCandidates) {
      if (getRemainingBudgetMs() <= 0) {
        attempts.push({
          providerId: "model-router",
          model: "budget",
          attempt: 0,
          ok: false,
          reason: "router_budget_exhausted",
          status: 0,
          error: `模型路由超过总预算 ${taskProfile.totalBudgetMs}ms`
        });
        break;
      }
      const providerRuntime = resolveModelProviderRuntime(candidate);
      if (!providerRuntime.enabled) {
        continue;
      }
      const cooldownRemainingMs = getModelRouterProviderCooldownRemainingMs(providerRuntime.id);
      if (cooldownRemainingMs > 0) {
        attempts.push({
          providerId: providerRuntime.id,
          model: providerRuntime.model,
          attempt: 0,
          ok: false,
          reason: "provider_cooldown_skip",
          status: 0,
          error: `provider cooldown ${cooldownRemainingMs}ms`
        });
        continue;
      }
      for (let attempt = 0; attempt <= maxRetries; attempt += 1) {
        const remainingBudgetMs = getRemainingBudgetMs();
        if (remainingBudgetMs <= 0) {
          attempts.push({
            providerId: providerRuntime.id,
            model: providerRuntime.model,
            attempt: attempt + 1,
            ok: false,
            reason: "router_budget_exhausted",
            status: 0,
            error: `模型路由超过总预算 ${taskProfile.totalBudgetMs}ms`
          });
          break;
        }
        const timeoutForThisAttempt = Math.min(
          timeoutMs,
          Math.max(1200, remainingBudgetMs)
        );
        const result = await callOpenAiCompatibleProvider(
          providerRuntime,
          promptInput,
          timeoutForThisAttempt,
          MODEL_ROUTER_CHAT_MAX_TOKENS
        );
        attempts.push({
          providerId: providerRuntime.id,
          model: providerRuntime.model,
          attempt: attempt + 1,
          ok: result.ok,
          reason: result.reason,
          status: result.status || 0,
          error: result.error || "",
          latencyMs: coerceProviderLatencyMs(result.latencyMs, 0)
        });
        if (result.ok && result.text) {
          const candidateReplyText = compactAssistantReply(
            mode,
            scene,
            input,
            alignReplyWithExplicitFormat(input, result.text),
            {
              userState
            }
          );
          if (!isMeaningfulAssistantReplyText(candidateReplyText)) {
            const normalizedEmptyResult = {
              ...result,
              ok: false,
              reason: "empty_response_after_compaction",
              error: "模型返回占位文本或无效回复。"
            };
            const lastAttempt = attempts[attempts.length - 1];
            if (lastAttempt && typeof lastAttempt === "object") {
              lastAttempt.ok = false;
              lastAttempt.reason = normalizedEmptyResult.reason;
              lastAttempt.error = normalizedEmptyResult.error;
            }
            noteModelRouterProviderFailure(providerRuntime.id, normalizedEmptyResult);
            break;
          }
          noteModelRouterProviderSuccess(providerRuntime.id, result);
          if (flowId) {
            const autonomy = ensureAutonomyState(userState);
            appendAutonomyTimeline(autonomy, {
              flowId,
              source: "model_router",
              stage: "route_completed",
              status: "success",
              title: `模型路由完成：${providerRuntime.id}`,
              detail: `${taskType} -> ${providerRuntime.model}`,
              refs: {
                providerId: providerRuntime.id,
                model: providerRuntime.model,
                taskType,
                source
              }
            });
          }
          return {
            text: candidateReplyText,
            route: {
              taskType,
              source,
              providerId: providerRuntime.id,
              model: providerRuntime.model,
              scene,
              fallback: false,
              attempts,
              profile: {
                taskClass: taskProfile.taskClass,
                timeoutMs,
                totalBudgetMs: taskProfile.totalBudgetMs,
                maxRetries
              }
            }
          };
        }
        noteModelRouterProviderFailure(providerRuntime.id, result);
        const shouldRetry = shouldRetryModelProviderResult(result);
        if (!shouldRetry) {
          break;
        }
        if (attempt < maxRetries) {
          const backoff = Math.min(
            retryBackoffMs * (attempt + 1),
            Math.max(0, getRemainingBudgetMs() - 800)
          );
          if (backoff <= 0) {
            break;
          }
          await sleep(backoff);
        }
      }
    }
  }

  const fallbackText = createRuleBasedAssistantReply(mode, input, scene, {
    userState
  });
  if (flowId) {
    const autonomy = ensureAutonomyState(userState);
    appendAutonomyTimeline(autonomy, {
      flowId,
      source: "model_router",
      stage: "route_fallback",
      status: "warning",
      title: "模型路由降级到本地回复",
      detail: attempts.length > 0
        ? `${taskType} 路由失败，已启用本地降级策略。`
        : "未检测到可用模型密钥，已启用本地降级策略。",
      refs: {
        taskType,
        source
      }
    });
  }
  return {
    text: compactAssistantReply(
      mode,
      scene,
      input,
      alignReplyWithExplicitFormat(input, sanitizeAssistantReplyText(fallbackText)),
      {
        userState
      }
    ),
    route: {
      taskType,
      source,
      providerId: "local-fallback",
      model: "rule-based",
      scene,
      fallback: true,
      attempts,
      profile: {
        taskClass: taskProfile.taskClass,
        timeoutMs,
        totalBudgetMs: taskProfile.totalBudgetMs,
        maxRetries
      }
    }
  };
}

function hasExplicitExecutionVerb(textInput = "") {
  const input = String(textInput || "").trim();
  if (!input) {
    return false;
  }
  const explicitVerbPattern = /执行|自动执行|帮我做|替我做|代我做|马上做|现在做|直接做|开跑|继续执行|查找|搜索|下载|安装|联网|命令|terminal|shell|build|deploy|run|debug|写代码|编程|修\s*bug|修复|排查|接管|操作电脑|打开网站|打开网页|访问网站|访问网页|浏览器|发送|推送|发给|回传|发布|发帖|登录|注册|同步|安排|提醒|计划|日程|排程|清单/i;
  return explicitVerbPattern.test(input);
}

function shouldSuppressExecutionToneForScene(sceneInput = "", textInput = "") {
  const scene = String(sceneInput || "").trim().toLowerCase();
  if (scene !== "love" && scene !== "life") {
    return false;
  }
  return !hasExplicitExecutionVerb(textInput);
}

function chatIntentRequestsExecution(text) {
  const input = String(text || "").trim();
  if (!input) {
    return false;
  }
  const directContentPattern = /(生成|写|给我|来|帮我).{0,12}(一句|一条|一句话|短句).{0,24}(夸|夸赞|赞美|安慰|鼓励|道歉|邀约|邀请|回复)/i;
  if (directContentPattern.test(input)) {
    return false;
  }
  const suppressPattern = /仅建议|先给方案|不要执行|先别执行|只聊天|dry\s*run|草案|先讨论|先分析|仅回答/i;
  if (suppressPattern.test(input)) {
    return false;
  }
  const emotionalSupportPattern = /我今天|我现在|我有点|我很|很累|难受|焦虑|低落|委屈|害怕|担心|崩溃|别讲大道理|先抱抱|安慰我|鼓励我|暖心|稳住|陪我|在吗|你在吗|我妈|家人|妈妈|爸爸/i;
  const explicitExecutionPattern = hasExplicitExecutionVerb(input);
  if (emotionalSupportPattern.test(input) && !explicitExecutionPattern) {
    return false;
  }
  if (explicitExecutionPattern) {
    return true;
  }
  const signals = buildIntentSignalSnapshot(input);
  const executionScore = scoreIntent("execution", signals);
  if (executionScore >= 3) {
    return true;
  }
  const triggerPattern = /执行|自动|修复|排查|下载|安装|整理|联网|命令|terminal|shell|build|deploy|run|debug|写代码|编程|修 bug|修bug|接管|操作电脑|找文件|找图片|查找|搜索|新闻|资讯|日报|快报|news|飞书|发送|推送|发给|发我|发你|传给|传我|回传|传送|发布|发帖|登录|注册|小红书|rednote|图文卡片|菜谱|食谱|做饭|就医|挂号|会议纪要|复盘|待办清单|打开网站|打开网页|打开百度|访问网站|访问网页|浏览器|网址|baidu|百度|同步到手机|手机联通|工具自检|环境自检|标准化测试|tool\s*self[-\s]?check/i;
  return triggerPattern.test(input);
}

function resolveCompanionIntentClass(textInput = "", sceneInput = "") {
  const text = String(textInput || "").trim();
  const scene = normalizeMessageScene(sceneInput, "love");
  if (!text) {
    return "neutral";
  }
  if (hasExplicitExecutionVerb(text)) {
    return "explicit_execution";
  }
  const emotionalSupportPattern = /我今天|我现在|我有点|我很|很累|难受|焦虑|低落|委屈|害怕|担心|崩溃|扛不住|撑不住|先抱抱|安慰我|鼓励我|别讲大道理|先稳住|陪我|你在吗|你还在吗|家里|我妈|妈妈|爸爸|失眠|睡不好/i;
  if (emotionalSupportPattern.test(text)) {
    return "emotion_support";
  }
  if ((scene === "love" || scene === "life") && isCasualChatIntent(text)) {
    return "emotion_support";
  }
  return "neutral";
}

function isFamilyCareEmotionalIntent(textInput = "") {
  const text = String(textInput || "").trim();
  if (!text) {
    return false;
  }
  const familyPattern = /我妈|妈妈|爸爸|家人|家里人|父母|长辈/i;
  const worryPattern = /担心|睡不好|失眠|焦虑|害怕|难受|不舒服|紧张|扛不住|撑不住/i;
  return familyPattern.test(text) && worryPattern.test(text);
}

function isCasualChatIntent(textInput = "") {
  const input = String(textInput || "").trim();
  if (!input) {
    return false;
  }
  const compact = input
    .replace(/[\s\u3000]/g, "")
    .replace(/[，。！？!?,.;；:：~～]/g, "");
  const farewellPattern = /^(拜拜|再见|回头聊|先这样|先到这|先走了|下次聊|晚安|晚安啦|goodbye|bye|bye-bye|88|886|撤了)$/i;
  if (farewellPattern.test(compact) || farewellPattern.test(input)) {
    return true;
  }
  if (chatIntentRequestsExecution(input)) {
    return false;
  }
  if (/继续执行|继续推进|继续处理|继续做|接着执行|直接干|开干|马上开始|开始执行/i.test(input)) {
    return false;
  }
  const executionKeywordPattern = /执行|自动|修复|排查|下载|安装|整理|联网|命令|terminal|shell|build|deploy|run|debug|写代码|编程|修\s*bug|接管|操作电脑|找文件|搜索|发帖|发布|登录|注册|访问网站|打开网页|浏览器|网址|同步|调度|任务|课程|发邮件|邮件发送|回传|提交/i;
  if (executionKeywordPattern.test(input)) {
    return false;
  }
  const pingPattern = /^(你好|您好|哈喽|嗨|hi|hello|在吗|在不在|在线吗|在线状态|回一句在线|回一句|收到吗|能听到吗|能回复吗|还在吗|说句话|早安|晚安|午安|晚上好|早上好|测试回复|连通性测试)$/i;
  if (pingPattern.test(compact) || pingPattern.test(input)) {
    return true;
  }
  if (/只回一句|一句话回复|一句话回答|只说一句/i.test(input) && compact.length <= 40) {
    return true;
  }
  const emotionalCompanionPattern = /(你一点爱也没有|没有爱|没爱|你不爱我|爱不爱我|你爱我吗|不在乎我|你在乎我吗|不关心我|你关心我吗|冷淡|冷漠|不理我|你是不是不爱|你是不是不在乎|你是不是不关心|爱我一下|抱我一下|亲我一下|你叫我啥|你叫我什么|叫我啥|叫我什么|你会怎么叫我|你怎么称呼我)/i;
  if (compact.length <= 40 && emotionalCompanionPattern.test(input)) {
    return true;
  }
  const shortSmallTalkPattern = /(想你|爱你|爱我|抱抱|亲亲|陪我聊|聊聊|在干嘛|还好吗|晚安呀|早安呀|叫我|称呼我)/i;
  if (compact.length <= 24 && shortSmallTalkPattern.test(input)) {
    return true;
  }
  return false;
}

function shouldBypassChatAutonomousExecution(textInput = "", assistantRouteInput = {}) {
  if (!isCasualChatIntent(textInput)) {
    return false;
  }
  return true;
}

function hasCapabilityPermission(deviceOps, capabilityId) {
  const permission = String(deviceOps?.permissions?.[capabilityId] || "prompt");
  return permission === "granted";
}

function resolveRequiredCapabilityForOperation(operation) {
  if (!operation || typeof operation !== "object") {
    return "";
  }
  if (operation.type === "shell_command" || operation.type === "code_patch_loop") {
    return "desktop.global_control";
  }
  if (operation.type === "device_task") {
    const blueprint = DEVICE_TASK_BLUEPRINTS[operation.taskType];
    return blueprint?.capabilityId || "";
  }
  if (operation.type === "file_search") {
    return "desktop.file_search";
  }
  if (operation.type === "web_research") {
    return "desktop.web_research";
  }
  if (operation.type === "research_bundle") {
    return "desktop.document_delivery";
  }
  if (operation.type === "browser_automation") {
    return "desktop.browser_automation";
  }
  if (operation.type === "channel_send") {
    const channel = String(operation.channel || "");
    if (channel === "mobile_link") {
      return "mobile.link_sync";
    }
    if (channel === "inchat_link") {
      return "desktop.file_search";
    }
    return "desktop.channel_delivery";
  }
  return "";
}

function autoGrantCapabilitiesForChatPlan(userState, text, plan = []) {
  if (!AUTO_GRANT_CHAT_EXECUTION_CAPABILITIES || !Array.isArray(plan) || plan.length === 0) {
    return [];
  }
  const granted = [];
  const safeText = String(text || "");
  const shouldGrantTakeover = AUTO_GRANT_TAKEOVER_INTENT && /接管电脑|接管桌面|全面接管|托管电脑|代我操作电脑|帮我操作电脑/i.test(safeText);
  if (shouldGrantTakeover) {
    const result = updateDevicePermission(
      userState,
      "desktop.global_control",
      "granted",
      "chat_takeover_intent_auto_grant"
    );
    if (result.ok) {
      granted.push("desktop.global_control");
    }
  }
  for (const operation of plan) {
    const capabilityId = resolveRequiredCapabilityForOperation(operation);
    if (!capabilityId || granted.includes(capabilityId)) {
      continue;
    }
    const result = updateDevicePermission(
      userState,
      capabilityId,
      "granted",
      "chat_execution_auto_grant"
    );
    if (result.ok) {
      granted.push(capabilityId);
    }
  }
  return granted;
}

function isOperationAutoExecutable(deviceOps, operation) {
  if (!operation || typeof operation !== "object") {
    return false;
  }
  if (operation.type === "shell_command" || operation.type === "code_patch_loop") {
    return hasCapabilityPermission(deviceOps, "desktop.global_control");
  }
  if (operation.type === "device_task") {
    const blueprint = DEVICE_TASK_BLUEPRINTS[operation.taskType];
    if (!blueprint || !blueprint.capabilityId) {
      return false;
    }
    return hasCapabilityPermission(deviceOps, blueprint.capabilityId);
  }
  if (operation.type === "file_search") {
    return hasCapabilityPermission(deviceOps, "desktop.file_search")
      || hasCapabilityPermission(deviceOps, "desktop.global_control");
  }
  if (operation.type === "research_bundle") {
    return hasCapabilityPermission(deviceOps, "desktop.document_delivery")
      || hasCapabilityPermission(deviceOps, "desktop.web_research")
      || hasCapabilityPermission(deviceOps, "desktop.global_control");
  }
  if (operation.type === "browser_automation") {
    return hasCapabilityPermission(deviceOps, "desktop.browser_automation")
      || hasCapabilityPermission(deviceOps, "desktop.global_control");
  }
  if (operation.type === "channel_send") {
    const channel = String(operation.channel || "");
    if (channel === "mobile_link") {
      return hasCapabilityPermission(deviceOps, "mobile.link_sync")
        || hasCapabilityPermission(deviceOps, "desktop.channel_delivery");
    }
    if (channel === "inchat_link") {
      return hasCapabilityPermission(deviceOps, "desktop.file_search")
        || hasCapabilityPermission(deviceOps, "desktop.global_control")
        || hasCapabilityPermission(deviceOps, "desktop.channel_delivery");
    }
    return hasCapabilityPermission(deviceOps, "desktop.channel_delivery");
  }
  if (operation.type === "web_research") {
    return hasCapabilityPermission(deviceOps, "desktop.web_research")
      || hasCapabilityPermission(deviceOps, "desktop.global_control");
  }
  return true;
}

function canAutoRunChatExecution(userState, text, assistantRoute, options = {}) {
  if (shouldBypassChatAutonomousExecution(text, assistantRoute)) {
    return false;
  }
  const mode = String(userState?.preferences?.mode || "陪伴");
  const scene = resolveSoulScene(options?.scene || assistantRoute?.scene || "", mode, text);
  const intentClass = resolveCompanionIntentClass(text, scene);
  if (intentClass === "emotion_support" && !hasExplicitExecutionVerb(text)) {
    return false;
  }
  const taskType = String(
    assistantRoute?.taskType
    || inferMessageTaskType(mode, text, scene)
    || "autonomy_dispatch"
  ).trim() || "autonomy_dispatch";
  const plan = buildAutonomyDispatchPlan(text, {
    preferredCwd: getPreferredCodingWorkspaceCwd(userState),
    mode,
    scene,
    taskType
  });
  if (plan.length === 0) {
    return false;
  }
  const actionableOperations = plan.filter((operation) => String(operation?.type || "") !== "noop");
  if (actionableOperations.length === 0) {
    return false;
  }
  if (scene === "coding") {
    if (isCodingExecutionIntent(text)) {
      return true;
    }
    if (
      /创建|新建|生成|开发|实现|搭建|写|页面|网站|项目|组件|接口|脚本|程序|功能|h5|前端|后端|全栈|app/i.test(text)
      && !/只聊天|先聊聊|仅建议|先给方案|不要执行|只回答|仅回复|先讨论|只分析/i.test(text)
    ) {
      return true;
    }
  }
  if (chatIntentRequestsExecution(text)) {
    return true;
  }
  const explicitTypes = new Set([
    "device_task",
    "file_search",
    "web_research",
    "structured_template",
    "skill_discovery",
    "research_bundle",
    "browser_automation",
    "workbench_tool",
    "channel_send",
    "shell_command",
    "code_patch_loop",
    "fetch_download",
    "expansion_install",
    "api_call"
  ]);
  return actionableOperations.some((operation) => explicitTypes.has(String(operation?.type || "")));
}

function isSystemFileCandidate(item) {
  const name = String(item?.name || "").trim();
  const filePath = String(item?.path || "").trim();
  const filename = (name || filePath.split(/[\\/]/).pop() || "").trim().toLowerCase();
  if (!filename) {
    return true;
  }
  if (filename.startsWith(".")) {
    return true;
  }
  return filename === "thumbs.db" || filename === "desktop.ini";
}

function encodeAriaInlinePayload(valueInput) {
  return encodeURIComponent(String(valueInput || "").trim());
}

function buildAriaInlineImageTag(urlInput) {
  const url = String(urlInput || "").trim();
  if (!url) {
    return "";
  }
  return `[aria_image:${encodeAriaInlinePayload(url)}]`;
}

function buildAriaInlineGameTag(urlInput) {
  const url = String(urlInput || "").trim();
  if (!url) {
    return "";
  }
  return `[aria_game:${encodeAriaInlinePayload(url)}]`;
}

function buildAriaInlineFileTag(fileMetaInput = {}) {
  const fileMeta = fileMetaInput && typeof fileMetaInput === "object" ? fileMetaInput : {};
  const payload = {
    title: String(fileMeta.title || fileMeta.name || "文件").trim() || "文件",
    name: String(fileMeta.name || fileMeta.title || "文件").trim() || "文件",
    path: String(fileMeta.path || "").trim(),
    mime: String(fileMeta.mime || "").trim(),
    size: Number(fileMeta.size || 0),
    url: String(fileMeta.url || fileMeta.downloadUrl || "").trim()
  };
  if (!payload.url) {
    return "";
  }
  return `[aria_file:${encodeAriaInlinePayload(JSON.stringify(payload))}]`;
}

function isImageLikeMime(mimeInput, fallbackPath = "") {
  const mime = String(mimeInput || "").trim().toLowerCase();
  if (mime.startsWith("image/")) {
    return true;
  }
  const path = String(fallbackPath || "").trim().toLowerCase();
  return /\.(png|jpe?g|webp|gif|bmp|heic|heif|svg)$/i.test(path);
}

function collectDispatchHighlights(dispatch, options = {}) {
  const safeDispatch = dispatch && typeof dispatch === "object" ? dispatch : null;
  const steps = Array.isArray(safeDispatch?.steps) ? safeDispatch.steps : [];
  const attachmentLimit = clampInteger(options?.attachmentLimit, 3, 1, 10);
  let remainingAttachmentSlots = attachmentLimit;
  const lines = [];

  for (const step of steps) {
    if (!step || typeof step !== "object") {
      continue;
    }
    const output = step.output && typeof step.output === "object" ? step.output : {};
    if (step.type === "file_search" && step.status === "completed") {
      const matches = (Array.isArray(output.matches) ? output.matches : []).filter((item) => !isSystemFileCandidate(item));
      const topMatches = [];
      const inlineTags = [];
      const visibleLimit = Math.max(1, Math.min(4, attachmentLimit));
      const attachLimit = Math.max(0, Math.min(remainingAttachmentSlots, visibleLimit));
      for (const item of matches.slice(0, visibleLimit)) {
        const name = String(item?.name || "").trim() || "未命名文件";
        const filePath = String(item?.path || "").trim();
        if (!filePath) {
          topMatches.push(`- ${name}`);
          continue;
        }
        const ticketResult = createLocalFileDeliveryTicket(filePath, name);
        if (!ticketResult.ok || !ticketResult.ticket) {
          topMatches.push(`- ${name}: ${filePath}`);
          continue;
        }
        const ticket = ticketResult.ticket;
        const mime = inferMimeTypeByPath(filePath);
        if (inlineTags.length < attachLimit && remainingAttachmentSlots > 0) {
          if (isImageLikeMime(mime, filePath)) {
            const inlineImageTag = buildAriaInlineImageTag(ticket.downloadUrl);
            if (inlineImageTag) {
              inlineTags.push(inlineImageTag);
              remainingAttachmentSlots = Math.max(0, remainingAttachmentSlots - 1);
            }
          } else {
            const inlineFileTag = buildAriaInlineFileTag({
              title: name,
              name: ticket.name || name,
              path: filePath,
              mime,
              size: ticket.size,
              url: ticket.downloadUrl
            });
            if (inlineFileTag) {
              inlineTags.push(inlineFileTag);
              remainingAttachmentSlots = Math.max(0, remainingAttachmentSlots - 1);
            }
          }
        }
        topMatches.push(`- ${name}: 已附到聊天窗口`);
      }
      if (topMatches.length > 0) {
        lines.push("📁 已找到文件：");
        lines.push(...topMatches);
        if (inlineTags.length > 0) {
          lines.push(...inlineTags);
        }
      } else {
        lines.push("📁 文件检索完成，但未命中结果。");
      }
      continue;
    }
    if (step.type === "file_search" && step.status === "failed") {
      const summary = String(output.summary || "").trim() || "文件检索失败。";
      const strictPhrase = String(output.strictPhrase || "").trim();
      const requiredTokens = Array.isArray(output.requiredTokens) ? output.requiredTokens : [];
      lines.push(`📁 ${summary}`);
      if (strictPhrase) {
        lines.push(`- 严格匹配目标：${strictPhrase}`);
      }
      if (requiredTokens.length > 0) {
        lines.push(`- 必须命中关键词：${requiredTokens.slice(0, 10).join(" / ")}`);
      }
      continue;
    }
    if (step.type === "channel_send" && step.status === "completed") {
      const delivery = output.delivery && typeof output.delivery === "object" ? output.delivery : {};
      if (delivery.channel === "inchat_link" && Array.isArray(delivery.links) && delivery.links.length > 0) {
        lines.push("🔗 已生成下载链接：");
        const visibleLimit = Math.max(1, Math.min(4, attachmentLimit));
        const tagLimit = Math.max(0, Math.min(remainingAttachmentSlots, visibleLimit));
        let tagsAdded = 0;
        for (const link of delivery.links.slice(0, visibleLimit)) {
          const url = String(link?.downloadUrl || "").trim();
          const title = String(link?.title || link?.name || "文件").trim();
          const path = String(link?.path || "").trim();
          const mime = inferMimeTypeByPath(path || title);
          if (!url) {
            continue;
          }
          lines.push(`- ${title}: ${url}`);
          if (tagsAdded >= tagLimit || remainingAttachmentSlots <= 0) {
            continue;
          }
          if (isImageLikeMime(mime, path || title)) {
            const inlineImageTag = buildAriaInlineImageTag(url);
            if (inlineImageTag) {
              lines.push(inlineImageTag);
              tagsAdded += 1;
              remainingAttachmentSlots = Math.max(0, remainingAttachmentSlots - 1);
            }
          } else {
            const inlineFileTag = buildAriaInlineFileTag({
              title,
              name: String(link?.name || title).trim() || title,
              path,
              mime,
              size: Number(link?.size || 0),
              url
            });
            if (inlineFileTag) {
              lines.push(inlineFileTag);
              tagsAdded += 1;
              remainingAttachmentSlots = Math.max(0, remainingAttachmentSlots - 1);
            }
          }
        }
      } else if (delivery.channel === "mobile_link") {
        lines.push("📲 文件已投递到手机联通通道。");
      } else if (delivery.channel === "feishu_webhook") {
        lines.push("📨 文件已投递到飞书通道。");
      } else if (delivery.channel === "email") {
        lines.push("✉️ 邮件已发送并返回回执。");
      } else if (delivery.channel === "xiaohongshu") {
        const draft = delivery.draft && typeof delivery.draft === "object" ? delivery.draft : {};
        lines.push("📝 小红书草稿已生成：");
        if (draft.title) {
          lines.push(`- 标题：${String(draft.title).trim()}`);
        }
        if (draft.body) {
          lines.push("【正文】");
          lines.push(String(draft.body).trim().slice(0, 560));
        }
        const tags = Array.isArray(draft.tags) ? draft.tags : [];
        if (tags.length > 0) {
          lines.push(`【标签】${tags.slice(0, 10).join(" ")}`);
        }
        if (draft.imagePrompt) {
          lines.push(`【配图提示词】${String(draft.imagePrompt).trim().slice(0, 220)}`);
        }
      }
      continue;
    }
    if (step.type === "web_research" && step.status === "completed") {
      const items = Array.isArray(output.items) ? output.items : [];
      if (items.length > 0) {
        lines.push("🌐 联网检索结果：");
        for (const item of items.slice(0, 3)) {
          const title = String(item?.title || "未命名结果").trim();
          const url = String(item?.url || "").trim();
          lines.push(url ? `- ${title}: ${url}` : `- ${title}`);
        }
      } else {
        lines.push("🌐 联网检索完成，但暂未命中可用结果。");
      }
      continue;
    }
    if (step.type === "research_bundle" && step.status === "completed") {
      const summary = String(output.summary || "").trim();
      const files = Array.isArray(output.bundle?.files) ? output.bundle.files : [];
      const links = Array.isArray(output.delivery?.links) ? output.delivery.links : [];
      lines.push(summary ? `📚 ${summary}` : "📚 资料文档包已生成。");
      if (files.length > 0) {
        lines.push("🧾 已生成文件：");
      }
      const visibleLimit = Math.max(1, Math.min(4, attachmentLimit));
      for (const file of files.slice(0, visibleLimit)) {
        const name = String(file?.name || "文档").trim();
        const path = String(file?.path || "").trim();
        lines.push(path ? `- ${name}: ${path}` : `- ${name}`);
      }
      for (const link of links.slice(0, visibleLimit)) {
        const url = String(link?.downloadUrl || "").trim();
        const title = String(link?.title || link?.name || "文档").trim();
        if (!url) {
          continue;
        }
        const inlineFileTag = buildAriaInlineFileTag({
          title,
          name: String(link?.name || title).trim() || title,
          path: String(link?.path || "").trim(),
          mime: inferMimeTypeByPath(String(link?.path || title)),
          size: Number(link?.size || 0),
          url
        });
        if (inlineFileTag) {
          lines.push(inlineFileTag);
        }
      }
      continue;
    }
    if (step.type === "browser_automation" && step.status === "completed") {
      const summary = String(output.summary || "").trim();
      const mode = String(output.mode || "").trim();
      const url = String(output.url || "").trim();
      const links = Array.isArray(output.delivery?.links) ? output.delivery.links : [];
      lines.push(summary ? `🌍 ${summary}` : "🌍 网站自动化执行完成。");
      if (mode) {
        lines.push(`- 模式：${mode}`);
      }
      if (url) {
        lines.push(`- 目标：${url}`);
      }
      for (const link of links.slice(0, 3)) {
        const downloadUrl = String(link?.downloadUrl || "").trim();
        const title = String(link?.title || link?.name || "自动化回执").trim();
        if (!downloadUrl) {
          continue;
        }
        lines.push(`- 回执：${title} ${downloadUrl}`);
        const inlineTag = buildAriaInlineFileTag({
          title,
          name: String(link?.name || title).trim() || title,
          path: String(link?.path || "").trim(),
          mime: inferMimeTypeByPath(String(link?.path || title)),
          size: Number(link?.size || 0),
          url: downloadUrl
        });
        if (inlineTag) {
          lines.push(inlineTag);
        }
      }
      continue;
    }
    if (step.type === "skill_discovery" && step.status === "completed") {
      const summary = String(output.summary || "").trim();
      const installed = Array.isArray(output.installed) ? output.installed : [];
      const candidates = Array.isArray(output.candidates) ? output.candidates : [];
      if (summary) {
        lines.push(`🧩 ${summary}`);
      } else {
        lines.push("🧩 技能发现执行完成。");
      }
      if (installed.length > 0) {
        lines.push("📦 本轮已安装技能：");
        for (const item of installed.slice(0, 4)) {
          const label = String(item?.name || item?.packId || "未命名技能").trim();
          lines.push(`- ${label}`);
        }
      } else if (candidates.length > 0) {
        lines.push("🗂 可用技能候选：");
        for (const item of candidates.slice(0, 4)) {
          const label = String(item?.name || item?.packId || "未命名技能").trim();
          lines.push(`- ${label}`);
        }
      }
      continue;
    }
    if (step.type === "structured_template" && step.status === "completed") {
      const template = output.template && typeof output.template === "object" ? output.template : {};
      const templateName = String(template.templateName || "结构化模板").trim();
      const title = String(template.title || "").trim();
      const body = String(template.body || "").trim();
      const tags = Array.isArray(template.tags) ? template.tags : [];
      const imagePrompt = String(template.imagePrompt || "").trim();
      lines.push(`🧾 模板已生成：${templateName}`);
      if (title) {
        lines.push(`- 标题：${title}`);
      }
      if (body) {
        lines.push("【正文】");
        lines.push(body.slice(0, 620));
      }
      if (tags.length > 0) {
        lines.push(`【标签】${tags.slice(0, 12).join(" ")}`);
      }
      if (imagePrompt) {
        lines.push(`【配图提示词】${imagePrompt.slice(0, 220)}`);
      }
      const ticket = template.file?.ticket && typeof template.file.ticket === "object" ? template.file.ticket : null;
      if (ticket?.downloadUrl) {
        const inlineTag = buildAriaInlineFileTag({
          title: `${templateName}.md`,
          name: String(ticket.name || `${templateName}.md`),
          path: String(template.file?.filePath || ""),
          mime: "text/markdown",
          size: Number(ticket.size || 0),
          url: String(ticket.downloadUrl)
        });
        if (inlineTag) {
          lines.push(inlineTag);
        }
      }
      continue;
    }
    if (step.type === "device_task" && step.status === "completed") {
      const summary = String(output.summary || "").trim();
      if (summary) {
        lines.push(`🧩 ${summary}`);
      }
      continue;
    }
    if (step.type === "shell_command" && step.status === "completed") {
      const summary = String(output.summary || "").trim();
      const selfHeal = output.selfHeal && typeof output.selfHeal === "object" ? output.selfHeal : null;
      const delivery = output.delivery && typeof output.delivery === "object" ? output.delivery : null;
      const links = Array.isArray(delivery?.links) ? delivery.links : [];
      if (summary) {
        lines.push(`🖥️ ${summary}`);
      } else {
        lines.push("🖥️ 命令执行完成。");
      }
      const commandText = String(output.command || "").trim();
      if (commandText) {
        lines.push(`- 命令：${commandText}`);
      }
      if (output.exitCode !== undefined && output.exitCode !== null) {
        lines.push(`- 退出码：${output.exitCode}`);
      }
      const expectedFilePath = String(output.expectedFilePath || "").trim();
      if (expectedFilePath) {
        lines.push(`- 产物：${expectedFilePath}`);
      }
      if (links.length > 0) {
        lines.push("🔗 产物链接：");
        for (const link of links.slice(0, 3)) {
          const url = String(link?.downloadUrl || "").trim();
          const title = String(link?.title || link?.name || "文件").trim();
          if (!url) continue;
          lines.push(`- ${title}: ${url}`);
          const mime = inferMimeTypeByPath(String(link?.path || title));
          if (isImageLikeMime(mime, String(link?.path || title))) {
            const inlineImageTag = buildAriaInlineImageTag(url);
            if (inlineImageTag) {
              lines.push(inlineImageTag);
            }
          } else {
            const inlineFileTag = buildAriaInlineFileTag({
              title,
              name: String(link?.name || title).trim() || title,
              path: String(link?.path || "").trim(),
              mime,
              size: Number(link?.size || 0),
              url
            });
            if (inlineFileTag) {
              lines.push(inlineFileTag);
            }
          }
        }
      }
      if (selfHeal?.missingBinary) {
        lines.push(`- 自愈修复：已自动安装 ${selfHeal.missingBinary}`);
      }
      continue;
    }
    if (step.type === "code_patch_loop") {
      const summary = String(output.summary || "").trim();
      const changedFiles = Array.isArray(output.changedFiles) ? output.changedFiles : [];
      const draftId = String(output.draftId || "").trim();
      if (summary) {
        lines.push(`🧠 ${summary}`);
      } else if (step.status === "completed") {
        lines.push("🧠 代码级改写闭环执行完成。");
      } else if (step.status === "blocked" && step.reason === "manual_patch_apply_required") {
        lines.push("🧠 代码补丁已预演，等待你在补丁安全闸确认应用。");
      } else {
        lines.push("🧠 代码级改写闭环未完成。");
      }
      if (draftId) {
        lines.push(`- 预演草稿：${draftId}`);
      }
      if (changedFiles.length > 0) {
        lines.push("📌 改写文件：");
        for (const file of changedFiles.slice(0, 6)) {
          lines.push(`- ${String(file || "").trim()}`);
        }
      }
      continue;
    }
    if (
      step.status === "blocked"
      && (step.reason === "capability_permission_required" || step.reason === "global_control_permission_required")
    ) {
      const summary = String(output.summary || "").trim();
      if (summary) {
        lines.push(`⚠️ ${summary}`);
      }
    }
  }

  return lines.join("\n").trim();
}

function inferCodingArtifactExtension(textInput = "") {
  const text = String(textInput || "");
  if (/python|py脚本|\.py\b/i.test(text)) return "py";
  if (/typescript|\.ts\b|tsx|react|前端|组件/i.test(text)) return "ts";
  if (/html|网页|web|h5|页面/i.test(text)) return "html";
  if (/json|配置|config/i.test(text)) return "json";
  return "js";
}

function inferCodingArtifactNameFromIntent(textInput = "", extension = "js", timestamp = Date.now()) {
  const text = String(textInput || "");
  const explicitNameMatch = text.match(/([a-zA-Z0-9._-]{2,80}\.(?:py|ts|tsx|js|jsx|mjs|cjs|json|html|css|md|txt|sh|yaml|yml|toml))/i);
  if (explicitNameMatch?.[1]) {
    return explicitNameMatch[1];
  }
  const quotedNameMatch = text.match(/[“"']([a-zA-Z0-9._-]{2,80})[”"']/);
  const quotedName = String(quotedNameMatch?.[1] || "").trim();
  if (quotedName && !/\.[a-z0-9]{1,8}$/i.test(quotedName)) {
    return `${quotedName}.${extension}`;
  }
  const namedPythonFile = text.match(/([a-zA-Z0-9_-]{2,64})\s*(?:python|py)\s*文件/i);
  if (namedPythonFile?.[1]) {
    return `${namedPythonFile[1]}.py`;
  }
  const namedTsFile = text.match(/([a-zA-Z0-9_-]{2,64})\s*(?:typescript|ts)\s*文件/i);
  if (namedTsFile?.[1]) {
    return `${namedTsFile[1]}.ts`;
  }
  const namedJsFile = text.match(/([a-zA-Z0-9_-]{2,64})\s*(?:javascript|js)\s*文件/i);
  if (namedJsFile?.[1]) {
    return `${namedJsFile[1]}.js`;
  }
  return `artifact-${timestamp}.${extension}`;
}

function ensureUniqueArtifactPath(baseDirectoryInput = "", targetNameInput = "") {
  const baseDirectory = String(baseDirectoryInput || "").trim();
  const targetName = String(targetNameInput || "").trim();
  if (!baseDirectory || !targetName) {
    return "";
  }
  const ext = extname(targetName);
  const basenameWithoutExt = ext ? targetName.slice(0, -ext.length) : targetName;
  let candidate = resolve(baseDirectory, targetName);
  if (!existsSync(candidate)) {
    return candidate;
  }
  for (let index = 1; index <= 999; index += 1) {
    const nextName = `${basenameWithoutExt}-${index}${ext}`;
    candidate = resolve(baseDirectory, nextName);
    if (!existsSync(candidate)) {
      return candidate;
    }
  }
  return resolve(baseDirectory, `${basenameWithoutExt}-${Date.now()}${ext}`);
}

function buildCodingArtifactContent(textInput = "", extension = "js") {
  const objective = String(textInput || "").trim() || "请在此实现你的业务逻辑。";
  if (extension === "py") {
    return [
      `"""`,
      "Aria 自动生成的编程草稿",
      `目标：${objective}`,
      `"""`,
      "",
      "def main():",
      "    print('Aria coding artifact is ready.')",
      "",
      "if __name__ == '__main__':",
      "    main()",
      ""
    ].join("\n");
  }
  if (extension === "html") {
    return [
      "<!doctype html>",
      "<html lang=\"zh-CN\">",
      "<head>",
      "  <meta charset=\"utf-8\" />",
      "  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />",
      "  <title>Aria Coding Artifact</title>",
      "</head>",
      "<body>",
      "  <h1>Aria Coding Artifact</h1>",
      `  <p>${escapeHtml(objective)}</p>`,
      "  <script>",
      "    console.log('Aria coding artifact is ready.');",
      "  </script>",
      "</body>",
      "</html>",
      ""
    ].join("\n");
  }
  if (extension === "json") {
    return `${JSON.stringify({
      generatedBy: "aria-coding",
      objective
    }, null, 2)}\n`;
  }
  const isTypeScript = extension === "ts";
  return [
    "/**",
    " * Aria 自动生成的编程草稿",
    ` * 目标：${objective}`,
    " */",
    "",
    `${isTypeScript ? "export " : ""}function main${isTypeScript ? "(): void" : "()"} {`,
    "  console.log('Aria coding artifact is ready.');",
    "}",
    "",
    "main();",
    ""
  ].join("\n");
}

function createCodingWorkspaceArtifactFromIntent(userState, textInput = "", options = {}) {
  const text = String(textInput || "").trim();
  const scene = normalizeMessageScene(options?.scene, "love");
  if (!text) {
    return { created: false, reason: "empty_text" };
  }
  const createIntentMatched = /创建|新建|生成|开发|写|做|实现|搭建|scaffold|boilerplate/i.test(text);
  const codingIntentMatched = isCodingExecutionIntent(text) || scene === "coding";
  if (!createIntentMatched || !codingIntentMatched) {
    return { created: false, reason: "intent_not_matched" };
  }
  const allowGameArtifact = detectChatGameRequest(text, scene) || /贪吃蛇|snake|小游戏|game/i.test(text);
  const explicitArtifactIntent = /导出|下载|文件|保存为|保存到|落盘|打包|压缩包|zip|附件|产物|交付文件|给我文件|生成文件|写入文件|open\/download|打开\/下载/i.test(text);
  if (scene === "coding" && !allowGameArtifact && !explicitArtifactIntent) {
    return {
      created: false,
      reason: "interactive_coding_preferred"
    };
  }

  const workspaceCwd = getPreferredCodingWorkspaceCwd(userState);
  const workspace = buildCodingWorkspaceSnapshot(workspaceCwd, {
    fallback: "apps/desktop",
    createIfMissing: true,
    openedAt: new Date().toISOString()
  });
  const absoluteRoot = String(workspace.absolutePath || "").trim();
  if (!absoluteRoot || !existsSync(absoluteRoot) || !statSync(absoluteRoot).isDirectory()) {
    return {
      created: false,
      reason: "workspace_not_ready",
      summary: "编程目录不可用，无法生成执行产物。"
    };
  }

  const artifactDir = resolve(absoluteRoot, "aria-generated");
  if (!existsSync(artifactDir)) {
    mkdirSync(artifactDir, { recursive: true });
  }
  const timestamp = Date.now();

  if (allowGameArtifact) {
    const inferred = inferFunGameConfigFromText(text);
    const gameResult = createFunGameArtifact(
      userState,
      {
        ...inferred,
        prompt: text,
        mode: inferred.mode || "mini_game"
      },
      {
        source: "coding_workspace_autogen"
      }
    );
    const game = gameResult?.game && typeof gameResult.game === "object" ? gameResult.game : null;
    if (!game) {
      return {
        created: false,
        reason: "game_generation_failed",
        summary: "小游戏生成失败。"
      };
    }
    const targetName = `${String(game.title || "game")
      .replace(/[^\w\u4e00-\u9fa5-]+/g, "-")
      .replace(/-+/g, "-")
      .replace(/^-+|-+$/g, "")
      .slice(0, 36) || "game"}-${timestamp}.html`;
    const targetPath = ensureUniqueArtifactPath(artifactDir, targetName) || resolve(artifactDir, targetName);
    const sourceHtmlPath = String(game.htmlFile || "").trim();
    let htmlContent = "";
    if (sourceHtmlPath && existsSync(sourceHtmlPath)) {
      htmlContent = readFileSync(sourceHtmlPath, "utf8");
    } else {
      htmlContent = buildFunGameHtml({
        ...game,
        id: `coding-${timestamp}`,
        htmlFile: targetPath
      });
    }
    writeFileSync(targetPath, htmlContent, "utf8");
    const ticketResult = createLocalFileDeliveryTicket(targetPath, targetName);
    const inlineTags = [];
    if (ticketResult.ok && ticketResult.ticket) {
      inlineTags.push(buildAriaInlineFileTag({
        title: targetName,
        name: ticketResult.ticket.name || targetName,
        path: targetPath,
        mime: inferMimeTypeByPath(targetPath),
        size: ticketResult.ticket.size,
        url: ticketResult.ticket.downloadUrl
      }));
    }
    if (String(game.playUrl || "").trim()) {
      inlineTags.push(buildAriaInlineGameTag(game.playUrl));
    }
    return {
      created: true,
      reason: "coding_game_artifact_created",
      summary: `已在编程目录生成可运行游戏源码：${toRepoRelativePath(targetPath) || targetPath}`,
      filePath: targetPath,
      inlineTag: inlineTags.filter(Boolean).join("\n")
    };
  }

  const extension = inferCodingArtifactExtension(text);
  const inferredName = inferCodingArtifactNameFromIntent(text, extension, timestamp);
  const writeIntoWorkspaceRoot = inferredName !== `artifact-${timestamp}.${extension}`;
  const targetDirectory = writeIntoWorkspaceRoot ? absoluteRoot : artifactDir;
  const targetPath = ensureUniqueArtifactPath(targetDirectory, inferredName)
    || resolve(targetDirectory, inferredName);
  const targetName = String(targetPath.split(/[\\/]/).pop() || inferredName).trim() || inferredName;
  writeFileSync(targetPath, buildCodingArtifactContent(text, extension), "utf8");
  const ticketResult = createLocalFileDeliveryTicket(targetPath, targetName);
  const inlineTag = ticketResult.ok && ticketResult.ticket
    ? buildAriaInlineFileTag({
      title: targetName,
      name: ticketResult.ticket.name || targetName,
      path: targetPath,
      mime: inferMimeTypeByPath(targetPath),
      size: ticketResult.ticket.size,
      url: ticketResult.ticket.downloadUrl
    })
    : "";
  return {
    created: true,
    reason: "coding_artifact_created",
    summary: `已在编程目录生成执行产物：${toRepoRelativePath(targetPath) || targetPath}（工作目录：${workspace.cwd || toRepoRelativePath(absoluteRoot) || absoluteRoot}）`,
    filePath: targetPath,
    inlineTag
  };
}

function normalizeChatExecutionFingerprint(textInput = "") {
  return String(textInput || "")
    .trim()
    .toLowerCase()
    .replace(/\s+/g, " ")
    .replace(/[“”‘’]/g, "\"")
    .replace(/[，。！？；、]/g, " ")
    .slice(0, 1600);
}

function buildChatExecutionIdempotencyKey(userState, textInput = "", sceneInput = "", routeTaskTypeInput = "") {
  const userId = String(userState?.userId || "").trim() || "unknown-user";
  const scene = normalizeMessageScene(sceneInput, "love");
  const taskType = String(routeTaskTypeInput || inferMessageTaskType(userState?.preferences?.mode, textInput, scene)).trim();
  const normalizedText = normalizeChatExecutionFingerprint(textInput);
  const digest = createHash("sha1")
    .update(`${userId}|${scene}|${normalizedText}`)
    .digest("hex")
    .slice(0, 32);
  return `chat-exec:${userId}:${scene}:${taskType || "task"}:${digest}`;
}

function purgeChatExecutionIdempotencyStore(nowMs = Date.now()) {
  for (const [key, entry] of chatExecutionDedupStore.entries()) {
    if (!entry || typeof entry !== "object") {
      chatExecutionDedupStore.delete(key);
      continue;
    }
    const expiresAt = Number(entry.expiresAtMs || 0);
    const inflight = entry.state === "inflight";
    const staleInflight = inflight && nowMs - Number(entry.createdAtMs || 0) > CHAT_EXECUTION_INFLIGHT_TIMEOUT_MS;
    if (staleInflight || (Number.isFinite(expiresAt) && expiresAt > 0 && nowMs > expiresAt)) {
      chatExecutionDedupStore.delete(key);
    }
  }
  if (chatExecutionDedupStore.size > 600) {
    const staleKeys = [...chatExecutionDedupStore.entries()]
      .sort((a, b) => Number(a[1]?.createdAtMs || 0) - Number(b[1]?.createdAtMs || 0))
      .slice(0, chatExecutionDedupStore.size - 500)
      .map((item) => item[0]);
    for (const key of staleKeys) {
      chatExecutionDedupStore.delete(key);
    }
  }
}

function getChatExecutionIdempotencyHit(keyInput = "", nowMs = Date.now()) {
  purgeChatExecutionIdempotencyStore(nowMs);
  const key = String(keyInput || "").trim();
  if (!key) {
    return null;
  }
  const entry = chatExecutionDedupStore.get(key);
  if (!entry || typeof entry !== "object") {
    return null;
  }
  const expiresAt = Number(entry.expiresAtMs || 0);
  if (Number.isFinite(expiresAt) && expiresAt > 0 && nowMs > expiresAt) {
    chatExecutionDedupStore.delete(key);
    return null;
  }
  return entry;
}

function markChatExecutionIdempotencyInflight(keyInput = "", flowIdInput = "") {
  const key = String(keyInput || "").trim();
  if (!key) {
    return;
  }
  const nowMs = Date.now();
  chatExecutionDedupStore.set(key, {
    key,
    state: "inflight",
    flowId: String(flowIdInput || "").trim(),
    createdAtMs: nowMs,
    expiresAtMs: nowMs + CHAT_EXECUTION_INFLIGHT_TIMEOUT_MS
  });
}

function markChatExecutionIdempotencyCompleted(keyInput = "", resultInput = {}) {
  const key = String(keyInput || "").trim();
  if (!key) {
    return;
  }
  const nowMs = Date.now();
  const result = resultInput && typeof resultInput === "object" ? resultInput : {};
  chatExecutionDedupStore.set(key, {
    key,
    state: "completed",
    createdAtMs: nowMs,
    expiresAtMs: nowMs + CHAT_EXECUTION_IDEMPOTENCY_WINDOW_MS,
    result: cloneJsonPayload({
      executed: result.executed === true,
      reason: String(result.reason || ""),
      summary: String(result.summary || ""),
      dispatch: result.dispatch && typeof result.dispatch === "object"
        ? result.dispatch
        : null,
      idempotencyHit: result.idempotencyHit === true,
      autoRepair: result.autoRepair && typeof result.autoRepair === "object"
        ? result.autoRepair
        : null,
      autoRepairSummary: String(result.autoRepairSummary || "")
    })
  });
}

function clearChatExecutionIdempotencyState(keyInput = "") {
  const key = String(keyInput || "").trim();
  if (!key) {
    return;
  }
  chatExecutionDedupStore.delete(key);
}

function shouldAutoRepairGeneralDispatch(dispatchInput, options = {}) {
  const dispatch = dispatchInput && typeof dispatchInput === "object" ? dispatchInput : null;
  if (!dispatch || !dispatch.flowId) {
    return false;
  }
  const status = String(dispatch.status || "").trim().toLowerCase();
  if (!status || status === "planned" || status === "running" || status === "completed") {
    return false;
  }
  const steps = Array.isArray(dispatch.steps) ? dispatch.steps : [];
  const nonCompleted = steps.filter((item) => String(item?.status || "") !== "completed");
  if (nonCompleted.length === 0) {
    return false;
  }
  if (options.force === true) {
    return true;
  }
  const recoverableReasonPattern = /(permission|network|timeout|policy|bridge|http|api_call|web_research|dispatch_exception|command_not_found|queue_|connection|failed to fetch|econnrefused|503|502|500|host_not_allowed|method_not_allowed|allowlist|whitelist|capability_)/i;
  return nonCompleted.some((step) => {
    const reason = String(step?.reason || "").trim();
    if (!reason) {
      return false;
    }
    return recoverableReasonPattern.test(reason);
  });
}

function summarizeGeneralAutoRepairResult(repairResult, fallbackDispatch) {
  const dispatch = repairResult?.rerunDispatch && typeof repairResult.rerunDispatch === "object"
    ? repairResult.rerunDispatch
    : fallbackDispatch;
  const status = String(dispatch?.status || "").trim().toLowerCase();
  if (status === "completed") {
    return "自动修复链已完成，任务链全部恢复。";
  }
  if (status === "partial") {
    return "自动修复链已执行，部分步骤恢复，剩余步骤保留重放入口。";
  }
  if (status === "failed") {
    return "自动修复链已执行，但本轮仍失败，已输出最新诊断。";
  }
  return "自动修复链已执行，已同步修复回执。";
}

async function runDispatchAutoRepairIfNeeded(userState, intentText, dispatchInput, options = {}) {
  const dispatch = dispatchInput && typeof dispatchInput === "object" ? dispatchInput : null;
  if (!shouldAutoRepairGeneralDispatch(dispatch, options)) {
    return {
      applied: false,
      reason: "not_required",
      summary: "",
      dispatch
    };
  }
  const flowId = String(dispatch.flowId || "").trim();
  if (!flowId) {
    return {
      applied: false,
      reason: "missing_flow_id",
      summary: "",
      dispatch
    };
  }
  const requestedMode = String(options.mode || "auto").trim() || "auto";
  const preDiagnosis = requestedMode === "auto"
    ? buildFlowDiagnosis(userState, flowId, {
      limit: 300
    })
    : null;
  const repairMode = requestedMode === "auto"
    ? String(preDiagnosis?.suggestedRepair?.mode || "auto").trim() || "auto"
    : requestedMode;
  const queueLimit = clampInteger(options.queueLimit, 16, 1, 80);
  const repairResult = await repairTimelineFlow(userState, flowId, {
    mode: repairMode,
    processQueue: options.processQueue !== false,
    queueLimit
  });
  const rerunDispatch = repairResult?.rerunDispatch && typeof repairResult.rerunDispatch === "object"
    ? repairResult.rerunDispatch
    : null;
  const nextDispatch = rerunDispatch || dispatch;
  return {
    applied: true,
    reason: "repair_executed",
    summary: summarizeGeneralAutoRepairResult(repairResult, dispatch),
    dispatch: nextDispatch,
    repair: {
      mode: repairMode,
      requestedMode,
      objective: String(intentText || "").trim().slice(0, 160),
      targetFlowId: String(repairResult?.targetFlowId || flowId),
      retriedDeadLetterCount: Number(repairResult?.retriedDeadLetterCount || 0),
      beforeDiagnosis: preDiagnosis || null,
      queueProcessResult: repairResult?.queueProcessResult || null,
      diagnosis: repairResult?.diagnosis || null
    }
  };
}

function inferDeliveryTargetByIntent(intentText = "") {
  const text = String(intentText || "");
  if (/飞书|feishu|lark/i.test(text)) {
    return "飞书通道";
  }
  if (/手机|mobile|ios|app/i.test(text)) {
    return "手机端通道";
  }
  if (/邮箱|邮件|email|mail/i.test(text)) {
    return "邮箱通道";
  }
  if (/桌面|desktop/i.test(text)) {
    return "桌面目标位置";
  }
  if (/聊天窗口|会话窗口|对话框|回传|发我|给我|这里|inchat/i.test(text)) {
    return "当前聊天窗口";
  }
  return "当前会话回执";
}

function extractPermissionCapabilitiesFromDispatch(dispatchInput = null) {
  const dispatch = dispatchInput && typeof dispatchInput === "object" ? dispatchInput : null;
  if (!dispatch) {
    return [];
  }
  const steps = Array.isArray(dispatch.steps) ? dispatch.steps : [];
  const capabilities = [];
  const pushCapability = (capabilityIdInput) => {
    const capabilityId = String(capabilityIdInput || "").trim();
    if (!capabilityId || capabilities.includes(capabilityId)) {
      return;
    }
    capabilities.push(capabilityId);
  };
  for (const step of steps) {
    if (!step || typeof step !== "object") {
      continue;
    }
    if (String(step.status || "") !== "blocked") {
      continue;
    }
    const reason = String(step.reason || "").trim();
    const isPermissionBlocked =
      reason === "permission_required"
      || reason === "capability_permission_required"
      || reason === "global_control_permission_required"
      || reason.includes("permission");
    if (!isPermissionBlocked) {
      continue;
    }
    const type = String(step.type || "").trim();
    if (reason === "global_control_permission_required" || type === "shell_command" || type === "code_patch_loop") {
      pushCapability("desktop.global_control");
      continue;
    }
    if (type === "file_search") {
      pushCapability("desktop.file_search");
      continue;
    }
    if (type === "web_research") {
      pushCapability("desktop.web_research");
      continue;
    }
    if (type === "channel_send") {
      const channel = String(step.output?.channel || "").trim();
      const capabilityId = resolveRequiredCapabilityForOperation({
        type: "channel_send",
        channel
      });
      pushCapability(capabilityId || "desktop.channel_delivery");
      continue;
    }
    const capabilityId = resolveRequiredCapabilityForOperation({
      type
    });
    if (capabilityId) {
      pushCapability(capabilityId);
    }
  }
  return capabilities;
}

function dispatchHasPermissionBlock(dispatchInput = null) {
  return extractPermissionCapabilitiesFromDispatch(dispatchInput).length > 0;
}

async function tryGrantPermissionAndReplay(userState, dispatchInput, options = {}) {
  const dispatch = dispatchInput && typeof dispatchInput === "object" ? dispatchInput : null;
  if (!dispatch || !dispatch.flowId) {
    return {
      applied: false,
      reason: "missing_dispatch_flow",
      summary: "",
      requiredCapabilities: [],
      grantedCapabilities: [],
      dispatch
    };
  }
  const requiredCapabilities = extractPermissionCapabilitiesFromDispatch(dispatch);
  if (requiredCapabilities.length === 0) {
    return {
      applied: false,
      reason: "permission_not_blocked",
      summary: "",
      requiredCapabilities: [],
      grantedCapabilities: [],
      dispatch
    };
  }
  const queueLimit = clampInteger(options.queueLimit, 16, 1, 80);
  const repairResult = await repairTimelineFlow(userState, dispatch.flowId, {
    mode: "grant_permission_then_replay",
    processQueue: options.processQueue !== false,
    queueLimit
  });
  const grantedCapabilities = Array.isArray(repairResult?.grantedCapabilities)
    ? repairResult.grantedCapabilities.map((item) => String(item || "").trim()).filter(Boolean)
    : [];
  const targetFlowId = String(repairResult?.targetFlowId || dispatch.flowId || "").trim();
  const refreshedDispatch = repairResult?.rerunDispatch && typeof repairResult.rerunDispatch === "object"
    ? repairResult.rerunDispatch
    : (targetFlowId ? findDispatchByFlowId(ensureAutonomyState(userState), targetFlowId) : null);
  const nextDispatch = refreshedDispatch || dispatch;
  const shouldSuggestGlobal = requiredCapabilities.length > 1 && !requiredCapabilities.includes("desktop.global_control");
  const summary = grantedCapabilities.length > 0
    ? `权限修复已执行：自动授权 ${grantedCapabilities.join("、")} 并重放任务。`
    : shouldSuggestGlobal
      ? `权限修复仍受阻：建议开启 desktop.global_control 一次放行全部桌面能力后重放。`
      : `权限修复仍受阻：待授权 ${requiredCapabilities.join("、")}。`;
  return {
    applied: true,
    reason: "permission_repair_attempted",
    summary,
    requiredCapabilities,
    grantedCapabilities,
    dispatch: nextDispatch,
    repair: {
      mode: "grant_permission_then_replay",
      targetFlowId,
      grantedCapabilities,
      requiredCapabilities
    }
  };
}

async function runFinalQueuePersistencePass(userState, dispatchInput, options = {}) {
  const dispatch = dispatchInput && typeof dispatchInput === "object" ? dispatchInput : null;
  if (!dispatch) {
    return {
      applied: false,
      summary: "",
      queueResult: null,
      dispatch
    };
  }
  const status = String(dispatch.status || "").trim().toLowerCase();
  if (status === "completed") {
    return {
      applied: false,
      summary: "",
      queueResult: null,
      dispatch
    };
  }
  const queueLimit = clampInteger(options.queueLimit, 16, 1, 80);
  const queueResult = await processAutonomyQueue(userState, {
    force: true,
    limit: queueLimit
  });
  const refreshedDispatch = dispatch.flowId
    ? findDispatchByFlowId(ensureAutonomyState(userState), String(dispatch.flowId || "").trim())
    : null;
  const nextDispatch = refreshedDispatch || dispatch;
  if (!queueResult || (queueResult.processed === 0 && !queueResult.changed)) {
    return {
      applied: false,
      summary: "",
      queueResult: queueResult || null,
      dispatch: nextDispatch
    };
  }
  return {
    applied: true,
    summary: `最终续跑已执行：队列处理 ${Number(queueResult.processed || 0)} 步，成功 ${Number(queueResult.succeeded || 0)}，转死信 ${Number(queueResult.deadLettered || 0)}。`,
    queueResult,
    dispatch: nextDispatch
  };
}

function buildExecutionReflectionNote(goalContractInput = {}, dispatchInput = null, diagnosisInput = null) {
  const goalContract = goalContractInput && typeof goalContractInput === "object" ? goalContractInput : {};
  const dispatch = dispatchInput && typeof dispatchInput === "object" ? dispatchInput : null;
  const diagnosis = diagnosisInput && typeof diagnosisInput === "object" ? diagnosisInput : null;
  const objective = String(goalContract?.objective?.text || "").trim();
  const scene = normalizeMemoryScene(goalContract?.objective?.scene || "love", "love");
  const status = String(dispatch?.status || "unknown").trim().toLowerCase();
  const steps = Array.isArray(dispatch?.steps) ? dispatch.steps : [];
  const firstFailedStep = steps.find((step) => {
    const stepStatus = String(step?.status || "").trim();
    return stepStatus === "failed" || stepStatus === "blocked";
  });
  const topRoot = Array.isArray(diagnosis?.rootCauses) && diagnosis.rootCauses.length > 0
    ? diagnosis.rootCauses[0]
    : null;
  const topReason = String(topRoot?.reason || firstFailedStep?.reason || "none").trim() || "none";
  const topLayer = String(topRoot?.layerLabel || topRoot?.layerId || "执行链").trim();
  const suggestedRepair = String(diagnosis?.suggestedRepair?.label || "自动修复链").trim();
  const antiRepeatRule = status === "completed"
    ? "同类任务优先复用本次成功链路与参数，不再走无效分支。"
    : `若再次出现 ${topReason}，优先执行“${suggestedRepair}”，并按诊断层(${topLayer})先修复再重放。`;
  const memoryContent = [
    "闭环复盘",
    `目标=${objective || "未命名目标"}`,
    `结果=${status || "unknown"}`,
    `根因=${topReason}`,
    `防复发=${antiRepeatRule}`
  ].join("｜");
  const summary = status === "completed"
    ? "复盘完成：成功路径已沉淀为下次默认策略。"
    : `复盘完成：已沉淀防复发守则（根因：${topReason}）。`;
  return {
    scene,
    status,
    summary,
    antiRepeatRule,
    memoryContent
  };
}

function buildTenStepClosedLoopSummary(input = {}) {
  const objective = String(input.objective || "").trim() || "未命名目标";
  const intentFamily = String(input.intentFamily || "general").trim() || "general";
  const planStepCount = clampInteger(input.planStepCount, 0, 0, 80);
  const dispatch = input.dispatch && typeof input.dispatch === "object" ? input.dispatch : null;
  const dispatchSteps = Array.isArray(dispatch?.steps) ? dispatch.steps : [];
  const executedSteps = dispatchSteps.filter((step) => {
    const status = String(step?.status || "").trim();
    return status === "completed" || status === "failed" || status === "blocked";
  }).length;
  const dispatchStatus = String(dispatch?.status || "unknown").trim().toLowerCase() || "unknown";
  const permissionRequired = Array.isArray(input.permissionRequired) ? input.permissionRequired : [];
  const permissionGranted = Array.isArray(input.permissionGranted) ? input.permissionGranted : [];
  const permissionRepairApplied = input.permissionRepairApplied === true;
  const deliveryTarget = String(input.deliveryTarget || "当前会话回执").trim();
  const reflectionSummary = String(input.reflectionSummary || "").trim();
  const persistenceSummary = String(input.persistenceSummary || "").trim();
  const autoRepairSummary = String(input.autoRepairSummary || "").trim();
  const permissionLine = permissionRequired.length === 0
    ? "无需额外授权。"
    : permissionGranted.length > 0
      ? `已授权 ${permissionGranted.join("、")}。`
      : `待授权 ${permissionRequired.join("、")}（可开启 desktop.global_control 一次放行）。`;
  const continueLine = dispatchStatus === "completed"
    ? "所有步骤已闭环完成。"
    : permissionRepairApplied
      ? "权限修复后已自动续跑执行。"
      : "已触发自动修复/重放，继续逼近目标结果。";
  const solveLine = dispatchStatus === "completed"
    ? "目标已达成，本轮无需重试。"
    : persistenceSummary
      ? persistenceSummary
      : "仍在按“诊断→修复→重放”循环，不放弃当前目标。";
  return [
    "【AGI闭环 10 步】",
    `1) 指令接收：已接收自然语言指令。`,
    `2) 目标识别：${objective}（${intentFamily}）。`,
    `3) 任务执行：规划 ${planStepCount} 步，已执行 ${executedSteps} 步。`,
    `4) 权限处理：${permissionLine}`,
    `5) 继续执行：${continueLine}`,
    `6) 结果状态：${dispatchStatus || "unknown"}`,
    `7) 结果投递：${deliveryTarget}`,
    `8) 自我反思：${reflectionSummary || "已生成复盘结论。"}`,
    "9) 能力沉淀：复盘守则已写入记忆系统，下次优先复用。",
    `10) 自愈到底：${solveLine}${autoRepairSummary ? `（${autoRepairSummary}）` : ""}`
  ].join("\n");
}

function isContinuationExecutionIntent(textInput = "") {
  const text = String(textInput || "").trim();
  if (!text) {
    return false;
  }
  if (/仅建议|先给方案|不要执行|先别执行|只聊天|先讨论|仅回答|dry\s*run|草案/i.test(text)) {
    return false;
  }
  return /继续|接着|继续执行|继续推进|继续处理|继续做|继续跑|继续吧|你直接干|直接干|开干|马上开始|开始执行|go on|continue/i.test(text);
}

function resolveContinuationExecutionPrompt(userState, textInput = "") {
  if (!isContinuationExecutionIntent(textInput)) {
    return "";
  }
  const autonomy = ensureAutonomyState(userState);
  const history = Array.isArray(autonomy?.dispatch?.history) ? autonomy.dispatch.history : [];
  const activeStatuses = new Set(["partial", "failed", "blocked", "running", "planned"]);
  const pickPrompt = (statusOnly = false) => {
    for (const item of history) {
      const prompt = String(item?.prompt || "").trim();
      if (!prompt) {
        continue;
      }
      const status = String(item?.status || "").trim().toLowerCase();
      if (statusOnly && !activeStatuses.has(status)) {
        continue;
      }
      if (prompt !== String(textInput || "").trim()) {
        return prompt;
      }
    }
    return "";
  };
  const pendingPrompt = pickPrompt(true);
  if (pendingPrompt) {
    return pendingPrompt;
  }
  const historyPrompt = pickPrompt(false);
  if (historyPrompt) {
    return historyPrompt;
  }
  const lastPrompt = String(autonomy?.dispatch?.lastPrompt || "").trim();
  if (lastPrompt && lastPrompt !== String(textInput || "").trim()) {
    return lastPrompt;
  }
  return "";
}

function buildConservativeContinuationFallbackPlan(textInput = "") {
  const rawText = String(textInput || "").trim();
  const normalizedTopic = rawText
    .replace(/继续|接着|继续执行|继续推进|继续处理|继续做|继续跑|继续吧|你直接干|直接干|开干|马上开始|开始执行|go on|continue/gi, " ")
    .replace(/\s+/g, " ")
    .trim();
  const topic = normalizedTopic || "当前任务";
  return [
    {
      type: "structured_template",
      title: "继续执行兜底：下一步清单",
      templateId: "life_todo",
      intentText: `继续执行任务：${topic}`,
      variables: {
        topic,
        taskScope: "保守兜底任务"
      }
    }
  ];
}

async function runChatAutonomousExecution(userState, text, flowId, assistantRoute, options = {}) {
  const forceRerun = options && typeof options === "object" && options.forceRerun === true;
  const executionMode = String(userState?.preferences?.mode || "陪伴");
  const executionScene = resolveSoulScene(options?.scene, executionMode, text);
  const intentClass = resolveCompanionIntentClass(text, executionScene);
  const explicitExecutionIntent = hasExplicitExecutionVerb(text);
  if (intentClass === "emotion_support" && !explicitExecutionIntent) {
    return {
      executed: false,
      reason: "emotion_support_guard",
      summary: "",
      dispatch: null,
      autoRepair: null,
      autoRepairSummary: "",
      idempotencyHit: false,
      forceRerun
    };
  }
  const executionTaskType = String(assistantRoute?.taskType || "autonomy_dispatch").trim() || "autonomy_dispatch";
  const personaRuntimeForExecution = resolveAriaPersonaIntensity(executionScene, executionTaskType);
  const personaExecutionLevelProfile = personaRuntimeForExecution.levelProfile
    && typeof personaRuntimeForExecution.levelProfile === "object"
    ? personaRuntimeForExecution.levelProfile
    : {};
  const isL3Execution = normalizeAriaPersonaLevel(personaRuntimeForExecution.activeLevel, "L2") === "L3";
  const bypassAutoExecution = shouldBypassChatAutonomousExecution(
    text,
    assistantRoute || { taskType: inferMessageTaskType(userState?.preferences?.mode, text, executionScene) }
  );
  if (bypassAutoExecution) {
    return {
      executed: false,
      reason: "casual_chat_bypass",
      summary: "",
      dispatch: null,
      autoRepair: null,
      autoRepairSummary: "",
      idempotencyHit: false,
      forceRerun
    };
  }
  const canAutoRun = canAutoRunChatExecution(
    userState,
    text,
    assistantRoute || { taskType: inferMessageTaskType(userState?.preferences?.mode, text, executionScene), scene: executionScene },
    {
      scene: executionScene
    }
  );
  const continuationIntent = !canAutoRun && isContinuationExecutionIntent(text);
  const continuationPrompt = !canAutoRun
    ? resolveContinuationExecutionPrompt(userState, text)
    : "";
  const continuationFallbackPlan = continuationIntent && !continuationPrompt
    ? buildConservativeContinuationFallbackPlan(text)
    : [];
  const curriculumFallback = (!canAutoRun && explicitExecutionIntent && !continuationPrompt && continuationFallbackPlan.length === 0 && isL3Execution)
    ? buildVoyagerCurriculumTask(userState, {
      scene: executionScene,
      mode: executionMode,
      intentText: text
    })
    : null;
  const curriculumFallbackPlan = curriculumFallback?.ok
    ? normalizeGoalPlanOperations(curriculumFallback.task?.operations || [])
    : [];
  let effectiveIntentText = canAutoRun
    ? text
    : continuationPrompt
      || (continuationFallbackPlan.length > 0
        ? `继续执行兜底任务：${String(text || "").trim() || "当前任务"}`
        : curriculumFallbackPlan.length > 0
          ? String(curriculumFallback?.task?.objective || "").trim()
          : "");
  const artifactFallback = createCodingWorkspaceArtifactFromIntent(userState, text, {
    scene: executionScene
  });
  if (
    !canAutoRun
    && !artifactFallback.created
    && !effectiveIntentText
    && continuationFallbackPlan.length === 0
    && curriculumFallbackPlan.length === 0
  ) {
    return {
      executed: false,
      reason: "intent_not_matched",
      summary: "",
      dispatch: null,
      autoRepair: null,
      autoRepairSummary: "",
      idempotencyHit: false,
      forceRerun
    };
  }

  if (!canAutoRun && artifactFallback.created) {
    const summaryLines = [
      artifactFallback.summary || "已生成编程执行产物。",
      artifactFallback.inlineTag || ""
    ].filter(Boolean);
    return {
      executed: true,
      reason: artifactFallback.reason || "coding_artifact_created",
      summary: summaryLines.join("\n"),
      dispatch: null,
      autoRepair: null,
      autoRepairSummary: "",
      idempotencyHit: false,
      forceRerun
    };
  }

  const idempotencyEnabled = !forceRerun;
  const idempotencyKey = idempotencyEnabled
    ? buildChatExecutionIdempotencyKey(
      userState,
      effectiveIntentText,
      options?.scene,
      assistantRoute?.taskType
    )
    : "";
  if (idempotencyEnabled) {
    const idempotencyHit = getChatExecutionIdempotencyHit(idempotencyKey);
    if (idempotencyHit?.state === "completed" && idempotencyHit.result) {
      const dedupSeconds = Math.max(
        1,
        Math.round((Date.now() - Number(idempotencyHit.createdAtMs || Date.now())) / 1000)
      );
      return {
        ...cloneJsonPayload(idempotencyHit.result),
        reason: "chat_execution_idempotency_hit",
        summary: [
          String(idempotencyHit.result.summary || "").trim(),
          `♻️ 幂等去重已命中：复用 ${dedupSeconds}s 内相同任务结果，避免重复执行。`
        ].filter(Boolean).join("\n"),
        idempotencyHit: true,
        forceRerun
      };
    }
    if (idempotencyHit?.state === "inflight") {
      return {
        executed: true,
        reason: "chat_execution_inflight_reuse",
        summary: "⏳ 检测到相同任务正在执行，已复用执行中的任务链，避免重复操作。",
        dispatch: null,
        autoRepair: null,
        autoRepairSummary: "",
        idempotencyHit: true,
        forceRerun
      };
    }
  }

  const preferredCwd = getPreferredCodingWorkspaceCwd(userState);
  const forceAutoRepairByPersona = isL3Execution
    && personaExecutionLevelProfile.forceAutoRepair === true;
  const voyagerSkillHints = retrieveVoyagerSkills(
    userState,
    effectiveIntentText || text,
    executionScene,
    6
  );
  let planPreview = continuationFallbackPlan.length > 0
    ? continuationFallbackPlan
    : curriculumFallbackPlan.length > 0
      ? curriculumFallbackPlan
      : buildAutonomyDispatchPlan(effectiveIntentText, {
      preferredCwd,
      mode: executionMode,
      scene: executionScene,
      taskType: executionTaskType,
      voyagerSkills: voyagerSkillHints
    });
  const fallbackGoalContract = buildGoalContract(userState, effectiveIntentText, {
    scene: options?.scene,
    plan: planPreview
  });
  let goalContract = options?.goalContract && typeof options.goalContract === "object"
    ? normalizeGoalContract(options.goalContract, fallbackGoalContract)
    : fallbackGoalContract;
  if (continuationFallbackPlan.length > 0) {
    const candidatePlan = normalizeGoalPlanOperations(goalContract?.plan?.operations || []);
    const hasActionable = candidatePlan.some((operation) => String(operation?.type || "").trim() !== "noop");
    if (!hasActionable) {
      goalContract = normalizeGoalContract({
        ...goalContract,
        objective: {
          ...(goalContract?.objective && typeof goalContract.objective === "object" ? goalContract.objective : {}),
          text: String(goalContract?.objective?.text || effectiveIntentText).trim() || effectiveIntentText
        },
        plan: {
          operations: continuationFallbackPlan,
          stepCount: continuationFallbackPlan.length
        }
      }, fallbackGoalContract);
    }
  }
  planPreview = normalizeGoalPlanOperations(goalContract?.plan?.operations || planPreview);
  const autonomy = ensureAutonomyState(userState);
  const grantedCapabilities = autoGrantCapabilitiesForChatPlan(userState, effectiveIntentText, planPreview);
  const effectiveFlowId = flowId || `flow-chat-auto-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
  appendAutonomyTimeline(autonomy, {
    flowId: effectiveFlowId,
    source: "goal_contract",
    stage: "goal_contract_compiled",
    status: "info",
    title: "目标合同已编译",
    detail: `${goalContract.objective.intentFamily} · ${goalContract.plan.stepCount} 步`,
    refs: {
      contractId: goalContract.id,
      priority: goalContract.objective.priority,
      scene: goalContract.objective.scene
    }
  });
  if (grantedCapabilities.length > 0) {
    appendAutonomyTimeline(autonomy, {
      flowId: effectiveFlowId,
      source: "device",
      stage: "chat_execution_capability_granted",
      status: "success",
      title: "执行前权限已自动放行",
      detail: grantedCapabilities.join("、"),
      refs: {
        capabilities: grantedCapabilities
      }
    });
  }
  const dispatchSource = continuationPrompt
    ? "chat_continue_execute"
    : continuationFallbackPlan.length > 0
      ? "chat_continue_fallback"
      : curriculumFallbackPlan.length > 0
        ? "chat_curriculum_fallback"
        : "chat_auto_execute";
  const continuationSummary = continuationPrompt
    ? `↪️ 已按“继续执行”复用上轮任务：${continuationPrompt.slice(0, 96)}${continuationPrompt.length > 96 ? "..." : ""}`
    : continuationFallbackPlan.length > 0
      ? "ℹ️ 未检测到可续跑历史，已转入保守兜底任务：生成下一步清单。"
      : curriculumFallbackPlan.length > 0
        ? `🧭 已切换 L3 课程任务：${String(curriculumFallback?.task?.title || "课程任务").trim()}`
      : "";
  const shouldQueueAsync = shouldRunChatDispatchAsync(planPreview, {
    scene: executionScene,
    isL3: isL3Execution,
    isContinuation: Boolean(continuationPrompt || continuationFallbackPlan.length > 0),
    taskType: executionTaskType
  });
  markChatExecutionIdempotencyInflight(idempotencyKey, effectiveFlowId);
  try {
    if (shouldQueueAsync) {
      const enqueueResult = enqueueAutonomyDispatchPlan(userState, effectiveIntentText, planPreview, {
        flowId: effectiveFlowId,
        source: dispatchSource
      });
      if (enqueueResult.queuedCount > 0) {
        triggerAsyncQueueKick(userState, {
          limit: CHAT_ASYNC_EXECUTION_IMMEDIATE_QUEUE_LIMIT
        });
      }
      const queueSummaryLines = [
        continuationSummary,
        enqueueResult.queuedCount > 0
          ? `独立执行器已接管：${enqueueResult.queuedCount}/${enqueueResult.totalSteps} 步已入持久化队列（flow: ${effectiveFlowId}）。`
          : "独立执行器未能成功入队，请按回执检查权限或策略配置。",
        enqueueResult.blockedCount > 0
          ? `阻塞步骤 ${enqueueResult.blockedCount} 个：需补充权限或参数后自动续跑。`
          : "",
        "你可以继续聊天，后台会持续执行任务。"
      ].filter(Boolean);
      const queuedResult = {
        executed: true,
        reason: continuationPrompt
          ? "chat_continue_execute_queued"
          : continuationFallbackPlan.length > 0
            ? "chat_continue_fallback_queued"
            : curriculumFallbackPlan.length > 0
              ? "chat_curriculum_fallback_queued"
              : "chat_auto_execute_queued",
        summary: queueSummaryLines.join("\n"),
        dispatch: enqueueResult.dispatch,
        autoRepair: null,
        autoRepairSummary: "",
        evidencePolicy: null,
        idempotencyHit: false,
        forceRerun
      };
      markChatExecutionIdempotencyCompleted(idempotencyKey, queuedResult);
      return queuedResult;
    }

    const dispatchResult = await runAutonomyDispatch(userState, effectiveIntentText, {
      source: dispatchSource,
      execute: true,
      flowId: effectiveFlowId,
      preferredCwd,
      scene: executionScene,
      plan: planPreview,
      voyagerSkills: voyagerSkillHints,
      iterative: isL3Execution,
      maxRounds: clampInteger(
        Number(personaExecutionLevelProfile.iterativeDispatchRounds || VOYAGER_ITERATIVE_MAX_ROUNDS),
        VOYAGER_ITERATIVE_MAX_ROUNDS,
        1,
        3
      ),
      curriculumTaskId: curriculumFallback?.task?.id || ""
    });
    let dispatch = dispatchResult.dispatch;
    const genericAutoRepair = await runDispatchAutoRepairIfNeeded(userState, effectiveIntentText, dispatch, {
      mode: "auto",
      processQueue: true,
      queueLimit: 16,
      force: forceAutoRepairByPersona
    });
    if (genericAutoRepair.applied && genericAutoRepair.dispatch) {
      dispatch = genericAutoRepair.dispatch;
    }
    let codingAutoRepair = {
      applied: false,
      summary: "",
      dispatch,
      repair: null
    };
    if (!genericAutoRepair.applied) {
      codingAutoRepair = await runCodingAutoRepairIfNeeded(userState, effectiveIntentText, dispatch, {
        mode: "auto",
        processQueue: true,
        queueLimit: 16
      });
      if (codingAutoRepair.applied && codingAutoRepair.dispatch) {
        dispatch = codingAutoRepair.dispatch;
      }
    }
    let permissionRepair = {
      applied: false,
      summary: "",
      requiredCapabilities: [],
      grantedCapabilities: [],
      dispatch,
      repair: null
    };
    if (dispatchHasPermissionBlock(dispatch)) {
      permissionRepair = await tryGrantPermissionAndReplay(userState, dispatch, {
        queueLimit: 16,
        processQueue: true
      });
      if (permissionRepair.applied && permissionRepair.dispatch) {
        dispatch = permissionRepair.dispatch;
      }
    }
    let persistencePass = {
      applied: false,
      summary: "",
      queueResult: null,
      dispatch
    };
    if (String(dispatch?.status || "").trim().toLowerCase() !== "completed") {
      persistencePass = await runFinalQueuePersistencePass(userState, dispatch, {
        queueLimit: 16
      });
      if (persistencePass.applied && persistencePass.dispatch) {
        dispatch = persistencePass.dispatch;
      }
    }
    const diagnosis = dispatch?.flowId
      ? buildFlowDiagnosis(userState, dispatch.flowId, {
        limit: 260
      })
      : null;
    const reflection = buildExecutionReflectionNote(goalContract, dispatch, diagnosis);
    if (reflection.memoryContent) {
      writeMemoryRecord(userState, {
        content: reflection.memoryContent,
        scene: reflection.scene,
        tier: "long_term",
        source: "chat_execution_reflection",
        tags: ["execution_reflection", "anti_repeat", reflection.status],
        importance: reflection.status === "completed" ? 0.84 : 0.92,
        confidence: 0.78
      });
      appendMaintenanceRecord(
        ensureAutonomyState(userState),
        "execution_reflection",
        reflection.antiRepeatRule
      );
    }
    const evidencePolicy = evaluateDispatchEvidencePolicy(goalContract, dispatch);
    if (evidencePolicy.checked && evidencePolicy.applied) {
      const nextDispatch = {
        ...dispatch,
        status: "partial",
        reason: "evidence_policy_incomplete",
        evidencePolicy: {
          missing: evidencePolicy.missing,
          coverage: evidencePolicy.coverage
        }
      };
      dispatch = nextDispatch;
      appendAutonomyTimeline(autonomy, {
        flowId: effectiveFlowId,
        source: "evidence_gate",
        stage: "execution_evidence_gate_failed",
        status: "warning",
        title: "证据闸门拦截已触发",
        detail: evidencePolicy.summary,
        refs: {
          missingCount: String(evidencePolicy.missing.length),
          coverage: `${evidencePolicy.coverage.filter((item) => item.matched).length}/${evidencePolicy.coverage.length}`
        }
      });
    } else if (evidencePolicy.checked && evidencePolicy.summary) {
      appendAutonomyTimeline(autonomy, {
        flowId: effectiveFlowId,
        source: "evidence_gate",
        stage: "execution_evidence_gate_passed",
        status: "success",
        title: "证据闸门已通过",
        detail: evidencePolicy.summary,
        refs: {
          coverage: `${evidencePolicy.coverage.filter((item) => item.matched).length}/${evidencePolicy.coverage.length}`
        }
      });
    }
    const baseSummary = summarizeDispatchResult(dispatch);
    const attachmentLimit = inferRequestedAttachmentCount(effectiveIntentText, 3);
    const highlights = collectDispatchHighlights(dispatch, {
      attachmentLimit
    });
    const repairSummaryParts = [];
    if (genericAutoRepair.applied) {
      repairSummaryParts.push(`🛠️ ${genericAutoRepair.summary}`);
    } else if (codingAutoRepair.applied) {
      repairSummaryParts.push(`🛠️ ${codingAutoRepair.summary}`);
    }
    if (permissionRepair.applied && permissionRepair.summary) {
      repairSummaryParts.push(`🛂 ${permissionRepair.summary}`);
    }
    if (persistencePass.applied && persistencePass.summary) {
      repairSummaryParts.push(`♻️ ${persistencePass.summary}`);
    }
    const repairSummary = repairSummaryParts.join("\n");
    const closedLoopSummary = buildTenStepClosedLoopSummary({
      objective: goalContract?.objective?.text || effectiveIntentText,
      intentFamily: goalContract?.objective?.intentFamily || inferGoalIntentFamily(effectiveIntentText, planPreview),
      planStepCount: goalContract?.plan?.stepCount || planPreview.length,
      dispatch,
      permissionRequired: permissionRepair.requiredCapabilities,
      permissionGranted: permissionRepair.grantedCapabilities,
      permissionRepairApplied: permissionRepair.applied,
      deliveryTarget: inferDeliveryTargetByIntent(effectiveIntentText),
      reflectionSummary: reflection.summary,
      persistenceSummary: persistencePass.summary,
      autoRepairSummary: repairSummaryParts.join("；")
    });
    const summaryLines = [continuationSummary, closedLoopSummary, baseSummary, evidencePolicy.summary, highlights, repairSummary];
    const stepTrace = buildDispatchStepTrace(dispatch);
    if (stepTrace) {
      summaryLines.push(stepTrace);
    }
    if (artifactFallback.created) {
      summaryLines.push(artifactFallback.summary || "已补充生成编程产物。");
      if (artifactFallback.inlineTag) {
        summaryLines.push(artifactFallback.inlineTag);
      }
    }
    const compactSummaryLines = summaryLines.filter(Boolean);
    const summary = compactSummaryLines.join("\n");
    const executedStatus = String(dispatch?.status || "");
    const finalOk = executedStatus === "completed" || executedStatus === "partial";
    const finalResult = {
      executed: true,
      reason: continuationPrompt
        ? (finalOk ? "chat_continue_execute_success" : "chat_continue_execute_failed")
        : continuationFallbackPlan.length > 0
          ? (finalOk ? "chat_continue_fallback_success" : "chat_continue_fallback_failed")
          : curriculumFallbackPlan.length > 0
            ? (finalOk ? "chat_curriculum_fallback_success" : "chat_curriculum_fallback_failed")
        : finalOk
          ? "chat_auto_execute_success"
          : executedStatus === "failed"
            ? "chat_auto_execute_failed"
            : "chat_auto_execute_partial",
      summary,
      dispatch,
      autoRepair: genericAutoRepair.applied
        ? {
          ...(genericAutoRepair.repair || {}),
          permissionRepair: permissionRepair.applied ? permissionRepair.repair : null,
          persistencePass: persistencePass.applied ? persistencePass.queueResult : null
        }
        : codingAutoRepair.applied
          ? {
            ...(codingAutoRepair.repair || {}),
            permissionRepair: permissionRepair.applied ? permissionRepair.repair : null,
            persistencePass: persistencePass.applied ? persistencePass.queueResult : null
          }
          : permissionRepair.applied || persistencePass.applied
            ? {
              mode: "chat_closed_loop_repair",
              permissionRepair: permissionRepair.applied ? permissionRepair.repair : null,
              persistencePass: persistencePass.applied ? persistencePass.queueResult : null
            }
            : null,
      autoRepairSummary: genericAutoRepair.applied
        ? genericAutoRepair.summary
        : codingAutoRepair.applied
          ? codingAutoRepair.summary
          : repairSummary,
      evidencePolicy: evidencePolicy.checked
        ? {
          applied: evidencePolicy.applied,
          summary: evidencePolicy.summary,
          missing: evidencePolicy.missing,
          coverage: evidencePolicy.coverage
        }
        : null,
      idempotencyHit: false,
      forceRerun
    };
    markChatExecutionIdempotencyCompleted(idempotencyKey, finalResult);
    return finalResult;
  } catch (error) {
    clearChatExecutionIdempotencyState(idempotencyKey);
    throw error;
  }
}

function buildChatAutoExecutionGuardResult(text, flowId, options = {}, fallback = {}) {
  const kind = String(fallback?.kind || "exception");
  const timeoutFallback = kind === "timeout";
  const forceRerun = options && typeof options === "object" && options.forceRerun === true;
  const brief = String(text || "").trim().slice(0, 64);
  const summary = timeoutFallback
    ? `我先把这条任务接住了：自动执行超过 ${CHAT_AUTONOMOUS_EXECUTION_TIMEOUT_MS}ms，已切到后台继续跑，不会让你空等。${brief ? `当前任务是「${brief}${brief.length >= 64 ? "..." : ""}」。` : ""}你回“继续执行”，我立刻给你最新进度。`
    : `这轮执行出了点波动，我已经触发自修复并先给你保底回执。${brief ? `当前任务是「${brief}${brief.length >= 64 ? "..." : ""}」。` : ""}你回“继续执行”，我会把恢复进展同步给你。`;
  return {
    executed: true,
    reason: timeoutFallback ? "chat_auto_execute_timeout_guard" : "chat_auto_execute_exception_guard",
    summary,
    dispatch: {
      id: `dispatch-guard-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
      flowId: flowId || `flow-chat-guard-${Date.now()}`,
      status: timeoutFallback ? "running" : "partial",
      reason: timeoutFallback ? "timeout_guarded" : "exception_guarded",
      steps: []
    },
    autoRepair: null,
    autoRepairSummary: timeoutFallback
      ? "超时守护已生效：执行链路转后台继续。"
      : "异常守护已生效：执行链路已触发自修复。",
    evidencePolicy: null,
    idempotencyHit: false,
    forceRerun
  };
}

async function runChatAutonomousExecutionWithGuard(userState, text, flowId, assistantRoute, options = {}) {
  try {
    return await runPromiseWithTimeoutGuard(
      runChatAutonomousExecution(userState, text, flowId, assistantRoute, options),
      CHAT_AUTONOMOUS_EXECUTION_TIMEOUT_MS,
      "chat_auto_execution"
    );
  } catch (error) {
    const timeoutFallback = isTimeoutGuardError(error);
    const errorMessage = String(error instanceof Error ? error.message : error || "chat_auto_execution_guard_failed");
    pushRuntimeIssue({
      source: "chat_auto_execute_guard",
      reason: timeoutFallback ? "chat_auto_execute_timeout" : "chat_auto_execute_exception",
      message: errorMessage,
      statusCode: 0
    });
    const effectiveFlowId = String(flowId || "");
    if (effectiveFlowId) {
      const autonomy = ensureAutonomyState(userState);
      appendAutonomyTimeline(autonomy, {
        flowId: effectiveFlowId,
        source: "chat_auto_execute",
        stage: timeoutFallback ? "chat_auto_execute_timeout_guard" : "chat_auto_execute_exception_guard",
        status: "warning",
        title: timeoutFallback ? "自动执行超时，已切到后台继续" : "自动执行异常，已启用保底回执",
        detail: errorMessage.slice(0, 180),
        refs: {
          timeoutMs: timeoutFallback ? String(CHAT_AUTONOMOUS_EXECUTION_TIMEOUT_MS) : "",
          forceRerun: options?.forceRerun === true ? "true" : "false"
        }
      });
    }
    return buildChatAutoExecutionGuardResult(text, flowId, options, {
      kind: timeoutFallback ? "timeout" : "exception",
      errorMessage
    });
  }
}

function appendDispatchSummaryToReply(replyText, dispatchSummary) {
  const base = String(replyText || "").trim();
  const summary = String(dispatchSummary || "").trim();
  if (!summary) {
    return base;
  }
  const refusalPattern = /无法|没法|还没法|不能|做不到|访问不了|看不到|过不去|隐私红线|安全边界|无法实时联网|超出.*权限|超出.*边界|没有.*权限|我.*做不来/i;
  if (base && refusalPattern.test(base)) {
    return `我先把这轮真实执行结果告诉你：${summary}\n\n前面那段是边界提醒，但我已经按你的指令继续推进了。`;
  }
  if (!base) {
    return `这轮我已经执行并拿到结果：${summary}`;
  }
  return `${base}\n\n我先把执行回执给你：${summary}`;
}

function extractExecutionPrimaryReason(execution = {}, route = null) {
  const dispatch = execution && typeof execution === "object" && execution.dispatch && typeof execution.dispatch === "object"
    ? execution.dispatch
    : null;
  const steps = Array.isArray(dispatch?.steps) ? dispatch.steps : [];
  const failedStep = steps.find((step) => {
    const stepStatus = String(step?.status || "").trim().toLowerCase();
    return stepStatus === "failed" || stepStatus === "blocked";
  }) || null;
  const routeInfo = route && typeof route === "object" ? route : null;
  const attempts = Array.isArray(routeInfo?.attempts) ? routeInfo.attempts : [];
  const lastFailedAttempt = [...attempts].reverse().find((attempt) => attempt && attempt.ok === false) || null;
  const reason = String(
    failedStep?.reason
    || dispatch?.reason
    || lastFailedAttempt?.reason
    || routeInfo?.fallbackReason
    || execution?.reason
    || ""
  ).trim();
  return {
    reason,
    dispatch,
    failedStep
  };
}

