function resolveExecutionExceptionKind(reasonInput = "", statusInput = "") {
  const reason = String(reasonInput || "").trim().toLowerCase();
  const status = String(statusInput || "").trim().toLowerCase();
  if (/captcha|human_verification|required_verification|verification_required/.test(reason)) {
    return "verification";
  }
  if (/permission|unauthorized|forbidden|auth|token|capability/.test(reason)) {
    return "permission";
  }
  if (/command_prefix_not_allowed|policy|recursive_guard|guard_blocked|action_disabled_by_policy/.test(reason)) {
    return "policy";
  }
  if (/skill_not_found|tool_not_found|command_not_found|no_browser_opener/.test(reason)) {
    return "missing_tool";
  }
  if (/provider_timeout|reply_timeout|router_budget_exhausted|timeout|timed out/.test(reason)) {
    return "timeout";
  }
  if (/bridge_unavailable|bridge_unreachable|network|fetch|http_error|api_call_exception/.test(reason)) {
    return "network";
  }
  if (status === "failed" || status === "blocked" || status === "partial") {
    return "generic";
  }
  return "generic";
}

function buildExecutionExceptionCompanionLine(reasonInput = "", statusInput = "") {
  const kind = resolveExecutionExceptionKind(reasonInput, statusInput);
  const pack = EXECUTION_EXCEPTION_REPLY_ATOMS[kind] || EXECUTION_EXCEPTION_REPLY_ATOMS.generic;
  return pickRandom(pack.soothe || EXECUTION_EXCEPTION_REPLY_ATOMS.generic.soothe);
}

function buildExecutionExceptionActionLine(reasonInput = "", statusInput = "") {
  const kind = resolveExecutionExceptionKind(reasonInput, statusInput);
  const pack = EXECUTION_EXCEPTION_REPLY_ATOMS[kind] || EXECUTION_EXCEPTION_REPLY_ATOMS.generic;
  return pickRandom(pack.action || EXECUTION_EXCEPTION_REPLY_ATOMS.generic.action);
}

function translateExecutionReasonToHuman(reasonInput = "", statusInput = "") {
  const reason = String(reasonInput || "").trim().toLowerCase();
  const status = String(statusInput || "").trim().toLowerCase();
  if (!reason) {
    if (status === "blocked") {
      return "还差一个授权或必要信息";
    }
    if (status === "failed") {
      return "执行链路里有一步没跑通";
    }
    if (status === "partial") {
      return "还有步骤没收尾";
    }
    return "";
  }
  if (/captcha|human_verification|required_verification|verification_required/.test(reason)) {
    return "遇到人工验证，需要你手动确认";
  }
  if (/permission|unauthorized|forbidden|auth|token|capability/.test(reason)) {
    return "当前权限不足";
  }
  if (/command_prefix_not_allowed|policy|recursive_guard|guard_blocked|action_disabled_by_policy/.test(reason)) {
    return "安全策略拦截了关键步骤";
  }
  if (/provider_timeout|reply_timeout|router_budget_exhausted|timeout|timed out/.test(reason)) {
    return "对方响应偏慢，这轮超时了";
  }
  if (/bridge_unavailable|bridge_unreachable|network|fetch|http_error|api_call_exception/.test(reason)) {
    return "执行服务暂时连不上";
  }
  if (/skill_not_found|tool_not_found|command_not_found|no_browser_opener/.test(reason)) {
    return "缺少对应技能或工具";
  }
  if (/command_failed|shell_command|exit/.test(reason)) {
    return "命令执行报错";
  }
  if (/evidence_policy_incomplete/.test(reason)) {
    return "结果证据还不完整";
  }
  return "执行链路遇到异常";
}

function buildExecutionSosGuidance(execution = {}, reasonInput = "", statusInput = "") {
  const status = String(statusInput || "").trim().toLowerCase();
  const reason = String(reasonInput || "").trim().toLowerCase();
  const needAssistance = status === "failed"
    || status === "blocked"
    || (status === "partial" && /permission|auth|policy|guard|captcha|verification/.test(reason));
  if (!needAssistance) {
    return "";
  }
  return buildExecutionExceptionActionLine(reason, status);
}

function normalizeExecutionDispatchStatus(statusInput = "") {
  const status = String(statusInput || "").trim().toLowerCase();
  if (!status) {
    return "unknown";
  }
  return status;
}

function isExecutionInFlightStatus(statusInput = "") {
  const status = normalizeExecutionDispatchStatus(statusInput);
  return status === "running" || status === "queued" || status === "pending" || status === "planned" || status === "retrying";
}

function isExecutionTerminalStatus(statusInput = "") {
  const status = normalizeExecutionDispatchStatus(statusInput);
  return status === "completed" || status === "partial" || status === "failed" || status === "blocked";
}

function isLikelyFilesystemPathCandidate(valueInput = "") {
  const value = String(valueInput || "").trim();
  if (!value) {
    return false;
  }
  if (/^https?:\/\//i.test(value)) {
    return false;
  }
  if (/^[a-z]+:\/\//i.test(value)) {
    return false;
  }
  return value.startsWith("/") || /^[a-zA-Z]:[\\/]/.test(value) || value.startsWith("./") || value.startsWith("../");
}

function isVerifiedFilesystemPath(valueInput = "") {
  const rawValue = String(valueInput || "").trim();
  if (!rawValue) {
    return false;
  }
  if (!isLikelyFilesystemPathCandidate(rawValue)) {
    return true;
  }
  const candidatePath = isAbsolute(rawValue) ? rawValue : resolve(rawValue);
  try {
    return existsSync(candidatePath);
  } catch {
    return false;
  }
}

function pushUniqueExecutionArtifact(artifacts, dedupe, artifactInput = {}) {
  const artifact = artifactInput && typeof artifactInput === "object" ? artifactInput : {};
  const label = String(artifact.label || "").trim();
  const value = String(artifact.value || "").trim();
  const kind = String(artifact.kind || "artifact").trim() || "artifact";
  if (!value) {
    return false;
  }
  const key = `${kind}:${value.toLowerCase()}`;
  if (dedupe.has(key)) {
    return false;
  }
  dedupe.add(key);
  artifacts.push({
    kind,
    label: label || kind,
    value
  });
  return true;
}

function collectDispatchEvidenceArtifacts(dispatchInput = {}) {
  const dispatch = dispatchInput && typeof dispatchInput === "object" ? dispatchInput : {};
  const steps = Array.isArray(dispatch.steps) ? dispatch.steps : [];
  const artifacts = [];
  const dedupe = new Set();
  let unverifiedArtifactCount = 0;
  const operationTypes = new Set();

  for (const step of steps) {
    if (!step || typeof step !== "object") {
      continue;
    }
    const stepType = String(step.type || "").trim();
    if (stepType) {
      operationTypes.add(stepType);
    }
    if (String(step.status || "").trim().toLowerCase() !== "completed") {
      continue;
    }
    const output = step.output && typeof step.output === "object" ? step.output : {};
    if (stepType === "file_search") {
      const matches = (Array.isArray(output.matches) ? output.matches : []).filter((item) => !isSystemFileCandidate(item));
      for (const item of matches.slice(0, 8)) {
        const filePath = String(item?.path || "").trim();
        if (!filePath) {
          continue;
        }
        if (!isVerifiedFilesystemPath(filePath)) {
          unverifiedArtifactCount += 1;
          continue;
        }
        pushUniqueExecutionArtifact(artifacts, dedupe, {
          kind: "file_path",
          label: String(item?.name || "文件").trim() || "文件",
          value: filePath
        });
      }
      continue;
    }
    if (stepType === "web_research") {
      for (const item of Array.isArray(output.items) ? output.items.slice(0, 6) : []) {
        const url = String(item?.url || "").trim();
        if (!url) {
          continue;
        }
        pushUniqueExecutionArtifact(artifacts, dedupe, {
          kind: "url",
          label: String(item?.title || "网页结果").trim() || "网页结果",
          value: url
        });
      }
      continue;
    }
    if (stepType === "research_bundle") {
      for (const file of Array.isArray(output.bundle?.files) ? output.bundle.files.slice(0, 8) : []) {
        const filePath = String(file?.path || "").trim();
        if (!filePath) {
          continue;
        }
        if (!isVerifiedFilesystemPath(filePath)) {
          unverifiedArtifactCount += 1;
          continue;
        }
        pushUniqueExecutionArtifact(artifacts, dedupe, {
          kind: "file_path",
          label: String(file?.name || "资料文件").trim() || "资料文件",
          value: filePath
        });
      }
      for (const link of Array.isArray(output.delivery?.links) ? output.delivery.links.slice(0, 8) : []) {
        const downloadUrl = String(link?.downloadUrl || "").trim();
        if (!downloadUrl) {
          continue;
        }
        pushUniqueExecutionArtifact(artifacts, dedupe, {
          kind: "download_link",
          label: String(link?.title || link?.name || "资料下载").trim() || "资料下载",
          value: downloadUrl
        });
      }
      continue;
    }
    if (stepType === "channel_send") {
      const delivery = output.delivery && typeof output.delivery === "object" ? output.delivery : {};
      const channel = String(delivery.channel || output.channel || "").trim();
      for (const link of Array.isArray(delivery.links) ? delivery.links.slice(0, 8) : []) {
        const downloadUrl = String(link?.downloadUrl || "").trim();
        if (!downloadUrl) {
          continue;
        }
        pushUniqueExecutionArtifact(artifacts, dedupe, {
          kind: "download_link",
          label: String(link?.title || link?.name || "投递文件").trim() || "投递文件",
          value: downloadUrl
        });
      }
      if (channel && channel !== "inchat_link") {
        pushUniqueExecutionArtifact(artifacts, dedupe, {
          kind: "channel_receipt",
          label: "通道回执",
          value: channel
        });
      }
      continue;
    }
    if (stepType === "browser_automation") {
      for (const link of Array.isArray(output.delivery?.links) ? output.delivery.links.slice(0, 6) : []) {
        const downloadUrl = String(link?.downloadUrl || "").trim();
        if (!downloadUrl) {
          continue;
        }
        pushUniqueExecutionArtifact(artifacts, dedupe, {
          kind: "download_link",
          label: String(link?.title || link?.name || "自动化回执").trim() || "自动化回执",
          value: downloadUrl
        });
      }
      continue;
    }
    if (stepType === "structured_template") {
      const template = output.template && typeof output.template === "object" ? output.template : {};
      const title = String(template.title || "").trim();
      const body = String(template.body || "").trim();
      const tags = Array.isArray(template.tags) ? template.tags.filter(Boolean) : [];
      if (title) {
        pushUniqueExecutionArtifact(artifacts, dedupe, {
          kind: "template_title",
          label: "模板标题",
          value: title
        });
      }
      if (body) {
        pushUniqueExecutionArtifact(artifacts, dedupe, {
          kind: "template_body",
          label: "模板正文",
          value: body.slice(0, 720)
        });
      }
      if (tags.length > 0) {
        pushUniqueExecutionArtifact(artifacts, dedupe, {
          kind: "template_tags",
          label: "模板标签",
          value: tags.slice(0, 12).join(" ")
        });
      }
      const ticket = template.file?.ticket && typeof template.file.ticket === "object" ? template.file.ticket : null;
      const templateDownloadUrl = String(ticket?.downloadUrl || "").trim();
      if (templateDownloadUrl) {
        pushUniqueExecutionArtifact(artifacts, dedupe, {
          kind: "download_link",
          label: "模板下载",
          value: templateDownloadUrl
        });
      }
      continue;
    }
    if (stepType === "shell_command") {
      const delivery = output.delivery && typeof output.delivery === "object" ? output.delivery : null;
      for (const link of Array.isArray(delivery?.links) ? delivery.links.slice(0, 6) : []) {
        const downloadUrl = String(link?.downloadUrl || "").trim();
        if (!downloadUrl) {
          continue;
        }
        pushUniqueExecutionArtifact(artifacts, dedupe, {
          kind: "download_link",
          label: String(link?.title || link?.name || "命令产物").trim() || "命令产物",
          value: downloadUrl
        });
      }
      continue;
    }
  }

  return {
    artifacts,
    operationTypes: Array.from(operationTypes),
    unverifiedArtifactCount
  };
}

function buildExecutionEvidenceEnvelope(executionInput = {}, routeInput = null) {
  const execution = executionInput && typeof executionInput === "object" ? executionInput : {};
  const route = routeInput && typeof routeInput === "object" ? routeInput : {};
  const dispatch = execution.dispatch && typeof execution.dispatch === "object"
    ? execution.dispatch
    : null;
  const status = normalizeExecutionDispatchStatus(
    dispatch?.status || execution.dispatchStatus || ""
  );
  const evidencePolicy = execution.evidencePolicy && typeof execution.evidencePolicy === "object"
    ? execution.evidencePolicy
    : null;
  const collected = collectDispatchEvidenceArtifacts(dispatch);
  const evidenceRequiredTypes = new Set([
    "file_search",
    "channel_send",
    "web_research",
    "research_bundle",
    "browser_automation",
    "fetch_download",
    "structured_template"
  ]);
  const requiresArtifactVerification = collected.operationTypes.some((type) => evidenceRequiredTypes.has(type))
    || evidencePolicy?.applied === true;
  const verifiedArtifacts = collected.artifacts.slice(0, 18);
  const missingVerifiedArtifact = requiresArtifactVerification && verifiedArtifacts.length === 0;
  return {
    status,
    inFlight: isExecutionInFlightStatus(status),
    terminal: isExecutionTerminalStatus(status),
    hasDispatch: Boolean(dispatch),
    dispatchId: String(dispatch?.id || execution.dispatchId || "").trim(),
    flowId: String(dispatch?.flowId || "").trim(),
    providerId: String(route.providerId || "").trim(),
    operationTypes: collected.operationTypes,
    requiresArtifactVerification,
    missingVerifiedArtifact,
    verifiedArtifactCount: verifiedArtifacts.length,
    unverifiedArtifactCount: collected.unverifiedArtifactCount,
    verifiedArtifacts,
    evidencePolicyApplied: evidencePolicy?.applied === true,
    evidencePolicyMissing: Array.isArray(evidencePolicy?.missing)
      ? evidencePolicy.missing.map((item) => String(item?.label || item?.type || "").trim()).filter(Boolean).slice(0, 6)
      : []
  };
}

function formatExecutionEvidenceArtifactLine(artifactInput = {}) {
  const artifact = artifactInput && typeof artifactInput === "object" ? artifactInput : {};
  const kind = String(artifact.kind || "").trim();
  const label = String(artifact.label || "回执").trim() || "回执";
  const value = String(artifact.value || "").trim();
  if (!value) {
    return "";
  }
  if (kind === "template_body") {
    return `- ${label}：${value.slice(0, 220)}${value.length > 220 ? "..." : ""}`;
  }
  return `- ${label}：${value}`;
}

function buildExecutionFrontChatStatus(execution = {}, route = null, options = {}) {
  const result = execution && typeof execution === "object" ? execution : {};
  const summary = String(result.summary || "").trim();
  const reason = String(result.reason || "").trim();
  const dispatch = result.dispatch && typeof result.dispatch === "object" ? result.dispatch : null;
  const status = normalizeExecutionDispatchStatus(dispatch?.status || result.dispatchStatus || "");
  const routeInfo = route && typeof route === "object" ? route : null;
  const evidenceEnvelope = options?.evidenceEnvelope && typeof options.evidenceEnvelope === "object"
    ? options.evidenceEnvelope
    : buildExecutionEvidenceEnvelope(result, routeInfo);

  if (reason === "chat_execution_inflight_reuse") {
    return "你这条任务正在执行中，我已经复用同一条链路，避免你重复等待。";
  }
  if (reason === "chat_execution_idempotency_hit") {
    return "这条和上一轮一致，我先复用最近结果给你，避免你空等。";
  }
  if (!dispatch) {
    if (/artifact_created|structured_template_generated|coding_artifact_created/.test(reason)) {
      const compact = summary
        .split(/\r?\n/)
        .map((line) => line.trim())
        .filter(Boolean)
        .slice(0, 2)
        .join(" ");
      return compact || "这轮产物我已经生成好了，正在把结果回传给你。";
    }
    if (summary) {
      return "我已经拿到执行回执，剩下的动作我会在后台继续补齐。";
    }
    return "";
  }

  const failureSignal = extractExecutionPrimaryReason(result, routeInfo);
  const humanReason = translateExecutionReasonToHuman(failureSignal.reason, status);
  const sosGuidance = buildExecutionSosGuidance(result, failureSignal.reason, status);

  if (status === "completed") {
    if (evidenceEnvelope.missingVerifiedArtifact) {
      return "这轮主流程已经跑完，但我还没拿到可验证回执（文件路径/链接），我会继续追到真实结果再回给你。";
    }
    return pickRandom([
      "任务已经执行完成啦，我把关键结果给你收好啦。",
      "这轮已经跑完并落地，结果你可以直接用。",
      "完成了，我把这次执行结果稳定交付给你。"
    ]);
  }
  if (status === "running" || status === "queued" || status === "pending" || status === "planned") {
    return "我已经在后台持续执行了，不会打断你聊天。你回“继续执行”，我就把最新进度告诉你。";
  }
  if (status === "partial") {
    const soothe = buildExecutionExceptionCompanionLine(failureSignal.reason, status);
    if (sosGuidance || humanReason) {
      const detail = humanReason ? `目前卡点是：${humanReason}。` : "";
      return `${soothe}这轮已经完成一大半。${detail}${sosGuidance || "我会继续在后台把剩余步骤补齐。"}`
        .trim();
    }
    return `${soothe}这轮已经完成一大半，我会继续在后台把剩余步骤补齐。`.trim();
  }
  if (status === "blocked") {
    const soothe = buildExecutionExceptionCompanionLine(failureSignal.reason, status);
    const detail = humanReason ? `目前被卡在：${humanReason}。` : "目前被卡住了。";
    return `${soothe}${detail}${sosGuidance || "你补一句关键信息后回我“继续执行”，我马上续跑。"}`
      .trim();
  }
  if (status === "failed") {
    const soothe = buildExecutionExceptionCompanionLine(failureSignal.reason, status);
    const detail = humanReason ? `这轮有一步没跑通：${humanReason}。` : "这轮有一步没跑通。";
    return `${soothe}${detail}${sosGuidance || "你回“重试”，我立刻换路重跑。"}`
      .trim();
  }
  if (routeInfo?.fallback) {
    return "刚才模型通道有点波动，我先用保底回复陪你，不让你空等；后台修复我正在继续。";
  }
  return "我已经收到回执了，接下来我会把剩余问题继续收尾。";
}

function buildGroundedExecutionReply(payloadInput = {}) {
  const payload = payloadInput && typeof payloadInput === "object" ? payloadInput : {};
  const execution = payload.execution && typeof payload.execution === "object" ? payload.execution : {};
  const route = payload.route && typeof payload.route === "object" ? payload.route : null;
  const userInput = String(payload.userInput || "").trim();
  const scene = normalizeMessageScene(payload.scene || route?.scene || "", "love");
  const userState = payload.userState && typeof payload.userState === "object" ? payload.userState : null;
  const base = String(payload.replyText || "").trim();
  const evidence = buildExecutionEvidenceEnvelope(execution, route);

  if (execution.executed !== true) {
    return {
      text: base,
      statusLine: "",
      evidence
    };
  }

  if (shouldSuppressExecutionToneForScene(scene, userInput)) {
    return {
      text: base,
      statusLine: "",
      evidence
    };
  }

  const statusLine = buildExecutionFrontChatStatus(execution, route, {
    evidenceEnvelope: evidence
  });
  const openingLine = pickSceneStyleLine(scene, userInput, "opening", {
    userState
  }) || buildCompactEmpathyLead(scene, userInput, true, {
    userState
  });
  const lines = [];
  if (openingLine) {
    lines.push(openingLine);
  }
  if (statusLine) {
    lines.push(statusLine);
  }

  if (evidence.inFlight) {
    lines.push("当前还在执行中，我会拿到可验证回执后再给你具体路径或链接，不会先报未核实结果。");
    return {
      text: lines.filter(Boolean).join("\n\n").trim() || statusLine || base,
      statusLine,
      evidence
    };
  }

  if (evidence.verifiedArtifactCount > 0) {
    const artifactLines = evidence.verifiedArtifacts
      .slice(0, 6)
      .map((artifact) => formatExecutionEvidenceArtifactLine(artifact))
      .filter(Boolean);
    if (artifactLines.length > 0) {
      lines.push("这轮可验证回执：");
      lines.push(...artifactLines);
    }
  } else if (evidence.missingVerifiedArtifact) {
    const missingHint = evidence.evidencePolicyMissing.length > 0
      ? `当前缺少：${evidence.evidencePolicyMissing.join("、")}。`
      : "";
    lines.push(`这轮还没拿到可验证结果（文件路径/链接），我不会编造结果。${missingHint}你回“继续执行”，我会继续追到真实回执。`.trim());
  }

  const text = lines.filter(Boolean).join("\n\n").trim();
  return {
    text: text || statusLine || base,
    statusLine,
    evidence
  };
}

function buildExecutionFirstReply(replyText, execution = {}, route = null, options = {}) {
  return buildGroundedExecutionReply({
    replyText,
    execution,
    route,
    scene: options?.scene || route?.scene || "",
    userInput: options?.userInput || "",
    userState: options?.userState || null
  }).text;
}

function scoreEmotionalQualityForFlywheel(assistantTextInput = "", routeInput = null, sceneInput = "") {
  const assistantText = String(assistantTextInput || "").trim();
  const route = routeInput && typeof routeInput === "object" ? routeInput : {};
  const scene = String(sceneInput || "").trim().toLowerCase();
  if (!assistantText) {
    return route.fallback ? 0.18 : 0.4;
  }
  const lineCount = assistantText
    .split(/\n+/)
    .map((item) => item.trim())
    .filter(Boolean).length;
  let score = 0.58;
  if (assistantText.length >= 24 && assistantText.length <= 360) {
    score += 0.08;
  }
  if (lineCount >= 2 && lineCount <= 5) {
    score += 0.04;
  }
  if (/我在|抱抱|辛苦了|理解你|先接住|我会陪你|别怕|我们一起|我会在这里/i.test(assistantText)) {
    score += 0.12;
  }
  if (/下一步|我先|马上|回执|会同步进度|后台执行/i.test(assistantText)) {
    score += 0.08;
  }
  if (/目标[:：]|进度[:：]|状态[:：]|下一步[:：]|先把「|我已经在后台|不会让你空等|从断点接着跑|可恢复|一大半/i.test(assistantText)) {
    score += 0.05;
  }
  if (/执行策略[:：]|我目前能帮你做的|你现在可以先告诉我|先确认几个/i.test(assistantText)) {
    score -= 0.1;
  }
  if (/收到，目标已锁定。|状态：已进入执行链路，完成后给你结果回执。|我先给你一版可直接使用的结果，再按你一句确认继续。/i.test(assistantText)) {
    score -= 0.09;
  }
  if (/你可以继续补充限制条件（数量\/路径\/时限）/i.test(assistantText)) {
    score -= 0.07;
  }
  if (/^(收到|明白|好的|好)[，。!！]/.test(assistantText) && assistantText.length <= 24) {
    score -= 0.08;
  }
  if (/我在|陪你|抱抱|接住/.test(assistantText) && /进度[:：]|下一步[:：]|回执/.test(assistantText)) {
    score += 0.05;
  }
  if (route.fallback) {
    const fallbackContainsWarmAction = /我在|陪你|抱抱|接住/.test(assistantText)
      && /下一步[:：]|进度[:：]|状态[:：]|回执/.test(assistantText);
    score -= fallbackContainsWarmAction ? 0.12 : 0.2;
  }
  if ((scene === "love" || scene === "life") && /我在|陪你|一起|抱抱/i.test(assistantText)) {
    score += 0.05;
  }
  return clampPolicyFloat(score, 0.56, 0, 1);
}

function scoreExecutionSuccessForFlywheel(executionInput = {}, userTextInput = "") {
  const execution = executionInput && typeof executionInput === "object" ? executionInput : {};
  const reason = String(execution.reason || "").trim().toLowerCase();
  const dispatchStatus = String(execution.dispatch?.status || execution.dispatchStatus || "").trim().toLowerCase();
  const executed = execution.executed === true;
  if (!executed) {
    if (/casual_chat_bypass|intent_not_matched/.test(reason)) {
      return 0.7;
    }
    if (chatIntentRequestsExecution(userTextInput)) {
      return 0.35;
    }
    return 0.62;
  }
  let score = 0.55;
  if (dispatchStatus === "completed") {
    score = 1;
  } else if (dispatchStatus === "partial") {
    score = 0.76;
  } else if (dispatchStatus === "running" || dispatchStatus === "queued" || dispatchStatus === "planned" || dispatchStatus === "pending" || dispatchStatus === "retrying") {
    score = 0.68;
  } else if (dispatchStatus === "blocked") {
    score = 0.42;
  } else if (dispatchStatus === "failed") {
    score = 0.16;
  }
  if (execution.idempotencyHit === true) {
    score = Math.max(score, 0.84);
  }
  if (execution.autoRepairApplied === true || execution.autoRepair) {
    score = Math.min(1, score + 0.06);
  }
  return clampPolicyFloat(score, 0.55, 0, 1);
}

function normalizeFlywheelSignal(signalInput = {}) {
  const signal = signalInput && typeof signalInput === "object" ? signalInput : {};
  return {
    id: String(signal.id || `fws-${Date.now()}-${Math.floor(Math.random() * 10000)}`),
    at: String(signal.at || new Date().toISOString()),
    flowId: String(signal.flowId || ""),
    scene: String(signal.scene || "").trim().toLowerCase(),
    taskType: String(signal.taskType || "emotional_companion").trim() || "emotional_companion",
    providerId: String(signal.providerId || "local-fallback").trim() || "local-fallback",
    model: String(signal.model || "").trim(),
    fallback: signal.fallback === true,
    emotionalScore: clampPolicyFloat(signal.emotionalScore, 0.5, 0, 1),
    executionScore: clampPolicyFloat(signal.executionScore, 0.5, 0, 1),
    combinedScore: clampPolicyFloat(signal.combinedScore, 0.5, 0, 1),
    executionEligible: signal.executionEligible === true,
    executed: signal.executed === true,
    dispatchStatus: String(signal.dispatchStatus || "").trim().toLowerCase(),
    reason: String(signal.reason || "").trim()
  };
}

function updateRunningAverage(prevAvgInput, nextValueInput, nextCountInput) {
  const prevAvg = Number.isFinite(Number(prevAvgInput)) ? Number(prevAvgInput) : 0;
  const nextValue = Number.isFinite(Number(nextValueInput)) ? Number(nextValueInput) : 0;
  const nextCount = Math.max(1, Number(nextCountInput || 1));
  return prevAvg + (nextValue - prevAvg) / nextCount;
}

function ensureFlywheelProviderScoreMap(flywheelInput = {}, taskTypeInput = "") {
  const flywheel = flywheelInput && typeof flywheelInput === "object"
    ? flywheelInput
    : createDefaultFlywheelLearningState();
  if (!flywheel.providerScores || typeof flywheel.providerScores !== "object") {
    flywheel.providerScores = {};
  }
  const taskType = String(taskTypeInput || "").trim() || "emotional_companion";
  if (!flywheel.providerScores[taskType] || typeof flywheel.providerScores[taskType] !== "object") {
    flywheel.providerScores[taskType] = {};
  }
  return flywheel.providerScores[taskType];
}

function applyFlywheelSignalToLearningState(flywheelInput = {}, signalInput = {}, options = {}) {
  const flywheel = flywheelInput && typeof flywheelInput === "object"
    ? flywheelInput
    : createDefaultFlywheelLearningState();
  const signal = normalizeFlywheelSignal(signalInput);
  if (options.appendSignal !== false) {
    if (!Array.isArray(flywheel.recentSignals)) {
      flywheel.recentSignals = [];
    }
    flywheel.recentSignals.unshift(signal);
    if (flywheel.recentSignals.length > FLYWHEEL_SIGNAL_HISTORY_LIMIT) {
      flywheel.recentSignals.length = FLYWHEEL_SIGNAL_HISTORY_LIMIT;
    }
  }
  const nextCount = clampInteger(Number(flywheel.totalSignals || 0) + 1, 1, 0, 1000000);
  flywheel.totalSignals = nextCount;
  flywheel.emotionalQualityAvg = updateRunningAverage(flywheel.emotionalQualityAvg, signal.emotionalScore, nextCount);
  flywheel.executionSuccessAvg = updateRunningAverage(flywheel.executionSuccessAvg, signal.executionScore, nextCount);
  flywheel.combinedScoreAvg = updateRunningAverage(flywheel.combinedScoreAvg, signal.combinedScore, nextCount);
  if (signal.fallback) {
    flywheel.fallbackCount = clampInteger(Number(flywheel.fallbackCount || 0) + 1, 1, 0, 1000000);
  }
  if (signal.executionEligible) {
    flywheel.executionEligibleCount = clampInteger(Number(flywheel.executionEligibleCount || 0) + 1, 1, 0, 1000000);
  }
  if (signal.dispatchStatus === "completed") {
    flywheel.executionCompletedCount = clampInteger(Number(flywheel.executionCompletedCount || 0) + 1, 1, 0, 1000000);
  } else if (signal.dispatchStatus === "partial") {
    flywheel.executionPartialCount = clampInteger(Number(flywheel.executionPartialCount || 0) + 1, 1, 0, 1000000);
  } else if (signal.dispatchStatus === "failed" || signal.dispatchStatus === "blocked") {
    flywheel.executionFailedCount = clampInteger(Number(flywheel.executionFailedCount || 0) + 1, 1, 0, 1000000);
  }
  const taskTypeScores = ensureFlywheelProviderScoreMap(flywheel, signal.taskType);
  if (!taskTypeScores[signal.providerId] || typeof taskTypeScores[signal.providerId] !== "object") {
    taskTypeScores[signal.providerId] = {
      providerId: signal.providerId,
      model: signal.model,
      taskType: signal.taskType,
      runs: 0,
      fallbackRuns: 0,
      emotionalAvg: 0,
      executionAvg: 0,
      combinedAvg: 0,
      lastAt: ""
    };
  }
  const providerEntry = taskTypeScores[signal.providerId];
  providerEntry.providerId = signal.providerId;
  providerEntry.model = signal.model || String(providerEntry.model || "");
  providerEntry.taskType = signal.taskType;
  providerEntry.runs = clampInteger(Number(providerEntry.runs || 0) + 1, 1, 0, 1000000);
  if (signal.fallback) {
    providerEntry.fallbackRuns = clampInteger(Number(providerEntry.fallbackRuns || 0) + 1, 1, 0, providerEntry.runs);
  } else if (typeof providerEntry.fallbackRuns !== "number") {
    providerEntry.fallbackRuns = 0;
  }
  providerEntry.emotionalAvg = updateRunningAverage(providerEntry.emotionalAvg, signal.emotionalScore, providerEntry.runs);
  providerEntry.executionAvg = updateRunningAverage(providerEntry.executionAvg, signal.executionScore, providerEntry.runs);
  providerEntry.combinedAvg = updateRunningAverage(providerEntry.combinedAvg, signal.combinedScore, providerEntry.runs);
  providerEntry.lastAt = signal.at;
  flywheel.lastSignalAt = signal.at;
  return signal;
}

function recordFlywheelSignalForChatTurn(userState, payloadInput = {}) {
  const payload = payloadInput && typeof payloadInput === "object" ? payloadInput : {};
  const route = payload.route && typeof payload.route === "object" ? payload.route : {};
  const execution = payload.execution && typeof payload.execution === "object" ? payload.execution : {};
  const userText = String(payload.userText || "").trim();
  const scene = resolveSoulScene(payload.scene, userState?.preferences?.mode || "陪伴", userText);
  const emotionalScore = scoreEmotionalQualityForFlywheel(payload.assistantText, route, scene);
  const executionScore = scoreExecutionSuccessForFlywheel(execution, userText);
  const combinedScore = clampPolicyFloat(emotionalScore * 0.55 + executionScore * 0.45, 0.5, 0, 1);
  const executionEligible = chatIntentRequestsExecution(userText) || execution.executed === true;
  const dispatchStatus = String(execution.dispatch?.status || execution.dispatchStatus || "").trim().toLowerCase();
  const signal = normalizeFlywheelSignal({
    id: `fws-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
    at: new Date().toISOString(),
    flowId: String(payload.flowId || ""),
    scene,
    taskType: String(route.taskType || inferMessageTaskType(userState?.preferences?.mode, userText, scene)),
    providerId: String(route.providerId || "local-fallback"),
    model: String(route.model || ""),
    fallback: route.fallback === true,
    emotionalScore,
    executionScore,
    combinedScore,
    executionEligible,
    executed: execution.executed === true,
    dispatchStatus,
    reason: String(execution.reason || "")
  });
  const autonomy = ensureAutonomyState(userState);
  const flywheel = autonomy.learning.flywheel || createDefaultFlywheelLearningState();
  autonomy.learning.flywheel = flywheel;
  const appliedSignal = applyFlywheelSignalToLearningState(flywheel, signal, {
    appendSignal: true
  });
  if (flywheel.totalSignals > 0 && flywheel.totalSignals % 8 === 0) {
    flywheel.learningRuns = clampInteger(Number(flywheel.learningRuns || 0) + 1, 1, 0, 1000000);
    flywheel.lastLearnedAt = new Date().toISOString();
  }
  return appliedSignal;
}

function replayFlywheelLearningForUser(userState, options = {}) {
  const autonomy = ensureAutonomyState(userState);
  const existing = autonomy.learning.flywheel || createDefaultFlywheelLearningState();
  const rawSignals = Array.isArray(existing.recentSignals) ? existing.recentSignals : [];
  const taskTypeFilter = String(options.taskType || "").trim();
  const replaySignals = taskTypeFilter
    ? rawSignals.filter((item) => String(item?.taskType || "").trim() === taskTypeFilter)
    : rawSignals.slice(0);
  const normalized = replaySignals
    .filter((item) => item && typeof item === "object")
    .map((item) => normalizeFlywheelSignal(item))
    .sort((left, right) => {
      const leftMs = Date.parse(left.at) || 0;
      const rightMs = Date.parse(right.at) || 0;
      return leftMs - rightMs;
    });
  const rebuilt = createDefaultFlywheelLearningState();
  rebuilt.version = String(existing.version || rebuilt.version);
  for (const signal of normalized) {
    applyFlywheelSignalToLearningState(rebuilt, signal, {
      appendSignal: true
    });
  }
  rebuilt.learningRuns = clampInteger(Number(existing.learningRuns || 0) + 1, 1, 0, 1000000);
  rebuilt.lastLearnedAt = new Date().toISOString();
  autonomy.learning.flywheel = rebuilt;
  return {
    ok: true,
    reason: "flywheel_replayed",
    replayed: normalized.length,
    taskType: taskTypeFilter || "",
    flywheel: sanitizeFlywheelLearningState(rebuilt)
  };
}

function buildFlywheelLearningSnapshot(userState, options = {}) {
  const autonomy = ensureAutonomyState(userState);
  const flywheel = autonomy.learning.flywheel || createDefaultFlywheelLearningState();
  const snapshot = sanitizeFlywheelLearningState(flywheel);
  const taskTypeFilter = String(options.taskType || "").trim();
  const routePolicyTaskRoutes = modelRoutingPolicy?.taskRoutes && typeof modelRoutingPolicy.taskRoutes === "object"
    ? modelRoutingPolicy.taskRoutes
    : {};
  const taskLeaderboards = snapshot.taskLeaderboards || {};
  const recommendedRoutes = {};
  const taskTypes = taskTypeFilter
    ? [taskTypeFilter]
    : Array.from(new Set([
      ...Object.keys(routePolicyTaskRoutes),
      ...Object.keys(taskLeaderboards)
    ]));
  for (const taskType of taskTypes) {
    const leaderboard = Array.isArray(taskLeaderboards[taskType]) ? taskLeaderboards[taskType] : [];
    const learnedProviders = leaderboard
      .filter((item) => Number(item.runs || 0) >= FLYWHEEL_AUTO_ROUTE_MIN_RUNS)
      .sort((left, right) => {
        if (Number(right.combinedAvg || 0) !== Number(left.combinedAvg || 0)) {
          return Number(right.combinedAvg || 0) - Number(left.combinedAvg || 0);
        }
        return Number(right.runs || 0) - Number(left.runs || 0);
      })
      .map((item) => String(item.providerId || "").trim())
      .filter(Boolean);
    const baseRoute = uniqueStringArray(routePolicyTaskRoutes[taskType] || [], 10);
    recommendedRoutes[taskType] = uniqueStringArray([...learnedProviders, ...baseRoute], 10);
  }
  return {
    ...snapshot,
    taskLeaderboards: taskTypeFilter
      ? { [taskTypeFilter]: Array.isArray(snapshot.taskLeaderboards?.[taskTypeFilter]) ? snapshot.taskLeaderboards[taskTypeFilter] : [] }
      : snapshot.taskLeaderboards,
    recommendedRoutes,
    runtime: {
      minRunsToLearn: FLYWHEEL_AUTO_ROUTE_MIN_RUNS,
      minScoreGap: FLYWHEEL_AUTO_ROUTE_MIN_SCORE_GAP,
      signalLimit: FLYWHEEL_SIGNAL_HISTORY_LIMIT
    }
  };
}

function sanitizeUnverifiedFunGameReply(replyText, options = {}) {
  const text = String(replyText || "").trim();
  if (!text) {
    return text;
  }
  if (options?.hasVerifiedGame === true) {
    return text;
  }
  const gameClaimPattern = /已生成可玩小游戏|小游戏已就绪|点击链接开玩|\[aria_game:|\/fun\/games\/[a-z0-9-]+\/play/i;
  if (!gameClaimPattern.test(text)) {
    return text;
  }
  const sanitized = text
    .replace(/\[aria_game:[^\]]+\]/gi, "")
    .replace(/https?:\/\/(?:127\.0\.0\.1|localhost)(?::\d+)?\/fun\/games\/[a-z0-9-]+\/play/gi, "")
    .replace(/🎮\s*已生成可玩小游戏[^\n]*\n?/g, "")
    .replace(/👉[^\n]*开玩[^\n]*\n?/g, "")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
  const fallback = "小游戏执行未成功，本轮不返回伪链接。你可以直接说“再做一个俄罗斯方块”。";
  if (!sanitized) {
    return fallback;
  }
  return `${sanitized}\n\n${fallback}`;
}

function splitStreamChunks(text) {
  const source = String(text || "").trim();
  if (!source) {
    return [];
  }

  const units = source
    .split(/([，。！？,.!?；;、\n])/)
    .map((item) => item.trim())
    .filter(Boolean);

  const chunks = [];
  let buffer = "";
  for (const unit of units) {
    buffer += unit;
    const isEnding = /[。！？.!?；;]$/.test(unit);
    if (buffer.length >= 12 || isEnding) {
      chunks.push(buffer);
      buffer = "";
    }
  }
  if (buffer) {
    chunks.push(buffer);
  }
  return chunks.length > 0 ? chunks : [source];
}

function sleep(ms) {
  return new Promise((resolveSleep) => setTimeout(resolveSleep, ms));
}

function sse(res, event, payload) {
  res.write(`event: ${event}\n`);
  res.write(`data: ${JSON.stringify(payload)}\n\n`);
}

function base64UrlEncode(value) {
  return Buffer.from(value).toString("base64url");
}

function base64UrlDecode(value) {
  return Buffer.from(value, "base64url").toString("utf8");
}

function signPayload(payloadJson) {
  return createHmac("sha256", TOKEN_SECRET).update(payloadJson).digest("base64url");
}

function normalizeClientScope(input) {
  const normalized = String(input || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9._-]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 48);
  return normalized || "legacy";
}

function buildDeviceBindingKey(deviceId, clientScope) {
  const safeDeviceId = String(deviceId || "").trim() || `device-${randomUUID()}`;
  const safeClientScope = normalizeClientScope(clientScope);
  return `${safeClientScope}:${safeDeviceId}`;
}

function issueToken(userId, profile, clientScope = "legacy") {
  const now = Math.floor(Date.now() / 1000);
  const payload = {
    sub: userId,
    name: profile.name,
    guest: true,
    cid: normalizeClientScope(clientScope),
    iat: now,
    exp: now + TOKEN_TTL_SECONDS
  };
  const payloadEncoded = base64UrlEncode(JSON.stringify(payload));
  const signature = signPayload(payloadEncoded);
  return `${payloadEncoded}.${signature}`;
}

function verifyToken(token) {
  if (!token || !token.includes(".")) {
    return { valid: false, reason: "Missing token structure" };
  }

  const [payloadEncoded, signature] = token.split(".");
  const expectedSignature = signPayload(payloadEncoded);
  if (signature !== expectedSignature) {
    return { valid: false, reason: "Signature mismatch" };
  }

  try {
    const payload = JSON.parse(base64UrlDecode(payloadEncoded));
    const now = Math.floor(Date.now() / 1000);
    if (!payload.sub || typeof payload.sub !== "string") {
      return { valid: false, reason: "Token subject missing" };
    }
    if (!payload.exp || now >= payload.exp) {
      return { valid: false, reason: "Token expired" };
    }
    return { valid: true, payload };
  } catch {
    return { valid: false, reason: "Token payload parse failed" };
  }
}

function extractTokenFromRequest(req) {
  const authHeader = req.headers.authorization || "";
  if (!authHeader.startsWith("Bearer ")) {
    return "";
  }
  return authHeader.slice("Bearer ".length);
}

function requireAuth(req) {
  const token = extractTokenFromRequest(req);
  const result = verifyToken(token);
  if (!result.valid) {
    return { ok: false, error: result.reason };
  }
  return { ok: true, userId: result.payload.sub, payload: result.payload };
}

function json(res, statusCode, payload) {
  finalizeRuntimeRequestMetric(res, statusCode);
  const body = JSON.stringify(payload);
  res.writeHead(statusCode, {
    "Content-Type": "application/json; charset=utf-8",
    "Content-Length": Buffer.byteLength(body),
    "Access-Control-Allow-Origin": "*",
    "Access-Control-Allow-Methods": "GET,POST,DELETE,OPTIONS",
    "Access-Control-Allow-Headers": "Content-Type, Authorization"
  });
  res.end(body);
}

function parseBody(req) {
  return new Promise((resolveBody, rejectBody) => {
    let raw = "";
    req.on("data", (chunk) => {
      raw += chunk;
      if (raw.length > 1024 * 256) {
        rejectBody(new Error("Payload too large"));
      }
    });
    req.on("end", () => {
      if (!raw) {
        resolveBody({});
        return;
      }
      try {
        resolveBody(JSON.parse(raw));
      } catch {
        rejectBody(new Error("Invalid JSON body"));
      }
    });
    req.on("error", (error) => rejectBody(error));
  });
}

function toLegacyResponse(state) {
  return { state: sanitizeState(state) };
}

