function normalizeConfigOpsActor(input = {}) {
  const actor = input && typeof input === "object" ? input : {};
  const actorId = String(actor.actorId || actor.id || "system").trim() || "system";
  const actorName = String(actor.actorName || actor.name || "").trim()
    || (actorId === "system" ? "系统" : actorId);
  const source = String(actor.source || "ui").trim() || "ui";
  return {
    actorId,
    actorName,
    source
  };
}

function inferConfigRiskLevel(changedSections = []) {
  const sections = Array.isArray(changedSections) ? changedSections : [];
  if (sections.includes("expansionSecurityPolicy")) return "high";
  if (sections.includes("openclawFusionProfile")) return "high";
  if (sections.includes("superAutonomyProfile")) return "high";
  if (sections.includes("openclawIncidentPlaybook")) return "medium";
  if (sections.includes("modelRoutingPolicy")) return "medium";
  if (sections.includes("systemProfile")) return "medium";
  return "low";
}

function summarizeChangedSections(changedSections = []) {
  const sectionLabels = {
    systemProfile: "系统基础配置",
    modelRoutingPolicy: "模型路由策略",
    openclawFusionProfile: "融合复用策略",
    superAutonomyProfile: "超级自主策略",
    expansionSecurityPolicy: "扩展安全策略",
    sceneOrchestrationPolicy: "场景编排策略",
    scenePromptRegistry: "场景提示词注册表",
    openclawIncidentPlaybook: "故障防复发手册"
  };
  const sections = Array.isArray(changedSections) ? changedSections : [];
  if (sections.length === 0) {
    return "配置未发生变更";
  }
  return sections
    .map((section) => sectionLabels[section] || section)
    .join("、");
}

