        const persist = payload.persist !== false;
        const candidatePolicy = payload.expansionSecurityPolicy
          && typeof payload.expansionSecurityPolicy === "object"
          ? payload.expansionSecurityPolicy
          : payload.expansionSecurityPatch && typeof payload.expansionSecurityPatch === "object"
            ? deepMergeConfig(expansionSecurityPolicy, payload.expansionSecurityPatch)
            : payload;
        const nextPolicy = normalizeExpansionSecurityPolicy(candidatePolicy);
        const changed = JSON.stringify(nextPolicy) !== JSON.stringify(expansionSecurityPolicy);
        if (changed) {
          expansionSecurityPolicy = nextPolicy;
          if (persist) {
            writeJsonConfigFile(expansionSecurityPolicyFile, expansionSecurityPolicy);
            expansionSecurityPolicyMtimeMs = existsSync(expansionSecurityPolicyFile)
              ? statSync(expansionSecurityPolicyFile).mtimeMs
              : Date.now();
          }
          updateRuntimeSystemConfigMeta();
        }
        json(res, 200, {
          userId: auth.userId,
          ok: true,
          changed,
          persisted: persist,
          runtime: runtimeSystemConfig,
          expansionSecurityPolicy,
          updatedAt: new Date().toISOString()
        });
        return;
